DELETE FROM public.questions;
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Your practice management team has reviewed the clinic-wide cancer screening rates and found that the frequency of cervical cancer screening appears to have fallen behind other cancer screenings. You are asked to lead a quality improvement project to increase rates of cervical cancer screening for appropriate patients. Which one of the following would be the most appropriate first step?', 1, 'Quality improvement is a key area for clinical practice, but initiating these projects can be challenging. In order to plan appropriate interventions, it must first be determined what barriers are responsible for hindering performance in a certain area. If evaluation shows that there is a systemic issue in capturing data, rather than a clinician issue, no other interventions will be beneficial. The initial step should be delineating any current issues prior to implementing a change.', 'Stone EG, Morton SC, Hulscher ME, et al. Interventions that increase use of adult immunization and cancer screening services: a meta-analysis. Ann Intern Med. 2002;136(9):641-651.', '["Establishing a system for reviewing charts and contacting patients who are overdue for cervical cancer screening","Evaluating barriers to cervical cancer screening and reporting","Placing posters with information about cervical cancer screening inside the clinic","Sending generalized reminders to patients who may qualify for cervical cancer screening","Sending generalized reminders to all clinicians regarding cervical cancer screening guidelines"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'You are seeing a 32-year-old male in the office. His most recent hemoglobin A1c was 6.1%, indicating prediabetes. Which one of the following is most likely to prevent the development of diabetes?', 0, 'Intensive lifestyle and behavior modification programs, such as the National Diabetes Prevention Program, are low-cost and can reduce the development of diabetes, with one U.S. study demonstrating a 27% reduction over 15 years. These programs help patients set weight loss goals >7% of their baseline, typically achieved through a caloric reduction of 500-1000 kcal per day, with activity goals >150 minutes per week, including up to 75 minutes per week of strength training.', 'American Diabetes Association Professional Practice Committee. 3. Prevention or delay of diabetes and associated comorbidities: standards of care in diabetes-2025. Diabetes Care. 2025;48(Supplement_1):S50-S58.', '["Intensive lifestyle and behavior change program","Low-carbohydrate diet","Reduction in daily caloric intake by 250 kcal per day","Strength training for 90 minutes per week"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'An otherwise healthy 47-year-old male presents to the urgent care clinic with pain and swelling of his right foot after sustaining an injury during a game of ultimate frisbee. He has significant pain and swelling of his right foot but is weight-bearing. His right lateral foot shows significant bruising and swelling. Sensation and circulation are intact. An x-ray reveals a 5th metatarsal shaft fracture. Which one of the following is the most appropriate next step in management?', 0, 'This patient''s imaging reveals a fifth metatarsal shaft fracture, which should be managed with a boot or hard-soled shoe for 3-6 weeks with weight-bearing. Foot fractures are typically caused by an axial or twisting force on the foot or a crush injury. A short leg cast is not appropriate because it is used to treat proximal fifth metatarsal and tarsal bone fractures.', 'Silver S, Williams E, Plunkett ML. Common foot fractures. Am Fam Physician. 2024;109(2):119-129.', '["Weight-bearing with a walking boot for 3-6 weeks","Non-weight-bearing with a walking boot for 3-6 weeks","Non-weight-bearing with a short leg cast for 6 weeks","Referral to a physical therapist","Referral to an orthopedic surgeon"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 78-year-old female presents to the emergency department with a 2-day history of cough and fever and a 2-hour history of confusion. Her vital signs include a temperature of 38.8 C (101.8 F) and a blood pressure of 72/44 mm Hg with a mean arterial pressure (MAP) of 53 mm Hg. A chest x-ray shows left lower lobe pneumonia. She is given 2 L of lactated Ringer solution and started on broad-spectrum antibiotics for sepsis secondary to pneumonia. Her blood pressure 3 hours later is 82/46 mm Hg with a MAP of 58 mm Hg. Which one of the following is the most appropriate immediate next step in management?', 2, 'This patient is in septic shock secondary to pneumonia. Surviving Sepsis Campaign guidelines recommend early goal-directed therapy (EGDT) consisting of initial fluid resuscitation with 30 mL/kg of crystalloid solution within the first 3 hours and appropriate antibiotics within 1 hour. The guidelines also recommend initiating vasopressor therapy with norepinephrine as the first-line agent if the mean arterial pressure remains <65 mm Hg after fluid resuscitation.', 'Evans L, Rhodes A, Alhazzani W, et al. Surviving Sepsis Campaign: international guidelines for management of sepsis and septic shock 2021. Critical Care Medicine. 2021;49(11):e1063-e1143.', '["A 1-L bolus of normal saline","A dopamine infusion","A norepinephrine infusion","A vasopressin infusion","Placement of a central line"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'You are called to the emergency department (ED) to admit a 48-year-old female with a past medical history of hyperthyroidism who presented with agitation, palpitations, and diarrhea. The ED team diagnosed thyroid storm secondary to the abrupt discontinuation of the patient''s methimazole 2 weeks ago due to a lapse in insurance. On examination, she is tachycardic and hypertensive but can sustain a conversation without dyspnea. Laboratory studies are significant for elevated free T3 and T4 levels and an undetectable TSH level. Which one of the following would be the most appropriate initial step in management?', 2, 'Thyroid storm is a medical emergency that must be treated promptly. The initial treatment for thyroid storm is propylthiouracil (PTU) or methimazole. Glucocorticoids (hydrocortisone and dexamethasone, not prednisone) can also be used to block the conversion of T4 to T3. While iodine is used to block the synthesis of new thyroid hormone, it should be started at least 1 hour after the initiation of PTU.', 'Ross DS, Burch HB, Cooper DS, et al. 2016 American Thyroid Association guidelines for diagnosis and management of hyperthyroidism and other causes of thyrotoxicosis. Thyroid. 2016;26(10):1343-1421.', '["Inorganic iodine","Prednisone","Propylthiouracil","Plasmapheresis"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'According to guidelines from the American Gastroenterological Association, which one of the following is recommended as the best pharmacologic treatment of typical symptoms in diarrhea-predominant irritable bowel syndrome?', 4, 'According to the 2022 American Gastroenterological Association guidelines for diarrhea-predominant irritable bowel syndrome (IBS-D), the nonabsorbable antibiotic rifaximin has the best evidence for controlling diarrhea, discomfort, bloating, and abdominal pain. It is prescribed as a 14-day course for acute and recurrent symptoms. Linaclotide and lubiprostone are used for constipation-predominant IBS.', 'Lembo A, Sultan S, Chang L, Heidelbaugh JJ, Smalley W, Verne GN. AGA clinical practice guideline on the pharmacological management of irritable bowel syndrome with diarrhea. Gastroenterology. 2022;163(1)137-151.', '["Amitriptyline","Dicyclomine","Linaclotide (Linzess)","Lubiprostone (Amitiza)","Rifaximin (Xifaxan)"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 56-year-old female with moderately controlled type 2 diabetes presents with painful diabetic neuropathy in her feet. You address her diabetic control and other risk factors, but she says the pain continues and is affecting her life adversely. Which one of the following is considered a first-line treatment for pain relief in this condition?', 2, 'First-line treatments for the relief of painful diabetic neuropathy include amitriptyline, duloxetine, gabapentin, and pregabalin. Second-line treatments include topical lidocaine and capsaicin, with less evidence of benefit. Opioids such as hydrocodone should be avoided in the treatment of neuropathic pain.', 'Bragg S, Marrison ST, Haley S. Diabetic peripheral neuropathy: prevention and treatment. Am Fam Physician. 2024;109(3):226-232.', '["Topical capsaicin","Topical lidocaine","Oral gabapentin","Oral hydrocodone","Peripheral transcutaneous electrical nerve stimulation"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A generally healthy 60-year-old female presents to your office because she is concerned about urinary leakage. Her symptoms started a couple of years ago and have worsened. The leakage occurs when she coughs or laughs, but can also happen if she waits too long to urinate. She has a remote surgical history of a hysterectomy. Today she has a blood pressure of 120/70 mm Hg and a BMI of 32 kg/m2. Which one of the following would be the most appropriate next step in the workup?', 1, 'Urinalysis should be ordered for all patients with urinary incontinence to evaluate for transient causes. Renal and bladder ultrasonography, urodynamic testing, and cystoscopy are not recommended for the initial evaluation of uncomplicated urinary incontinence.', 'Hu JS, Pierre EF. Urinary incontinence in women: evaluation and management. Am Fam Physician. 2019;100(6):339-348.', '["No testing","Urinalysis","Renal and bladder ultrasonography","Urodynamic testing","Cystoscopy"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 68-year-old female with previously diagnosed immune thrombocytopenia presents to your office to establish care. She has no current bleeding. A CBC is normal except for a platelet count of 47,000/mm3 (N 130,000-400,000). You refer her to a hematologist for long-term management. Which one of the following is the most appropriate treatment for this patient''s current thrombocytopenia?', 0, 'The American Society of Hematology recommends not to treat immune thrombocytopenia (ITP) unless there is active bleeding or very low platelet counts, defined as <30,000/mm3. This patient does not require treatment at this time because she does not have any current bleeding and her platelet count is above the threshold for treatment.', 'Liu XG, Hou Y, Hou M. How we treat primary immune thrombocytopenia in adults. J Hematol Oncol. 2023;16(4).', '["No treatment","Oral hydroxychloroquine sulfate (Plaquenil)","Oral prednisone","Intravenous methylprednisolone sodium succinate (Solu-Medrol)","Intravenous rituximab (Rituxan)"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 45-year-old male who is living with HIV and has been on highly active antiretroviral therapy (HAART) for the past 10 years presents for routine follow-up. Which one of the following would be part of an appropriate screening strategy for long-term complications associated with HAART?', 4, 'The Infectious Diseases Society of America recommends performing urinalysis at least once yearly and obtaining a glomerular filtration rate at least twice yearly in stable patients on highly active antiretroviral therapy (HAART) to detect kidney function abnormalities and drug nephrotoxicity.', 'Lucas GM, Ross MJ, Stock PG, et al. Clinical practice guideline for the management of chronic kidney disease in patients infected with HIV: 2014 update. Clin Infect Dis. 2014;59(9):e96-e138.', '["Calculation of the Framingham Risk Score now, and a fasting lipid profile annually","Neurocognitive screening annually","Transient elastography annually","A DXA scan annually","Urinalysis annually, and a glomerular filtration rate twice yearly"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 40-year-old male with type 2 diabetes presents to the emergency department with chest pain and shortness of breath. The patient has normal vital signs. A physical examination and laboratory tests, including serial troponin levels, are normal. Outpatient records from about 6 months ago include a normal cardiac stress test that was negative for myocardial ischemia. Which one of the following would be the most appropriate next step in evaluation?', 1, 'For this intermediate-risk patient with no history of coronary artery disease (CAD) who presents with angina and a negative workup for acute coronary syndrome plus negative stress testing within 1 year, coronary CT angiography would be the next step to determine if he has obstructive CAD or atherosclerotic plaques.', 'Gulati M, Levy PD, Mukherjee D, et al. 2021 AHA/ACC/ASE/CHEST/SAEM/SCCT/SCMR guideline for the evaluation and diagnosis of chest pain. Circulation. 2021;144(22):e368-e454.', '["Stress echocardiography","Coronary CT angiography","Fractional flow reserve with CT","Cardiac MRI"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 40-year-old male with a history of alcohol use disorder presents to your office for help abstaining from alcohol. Over the past 2 weeks, he has been able to wean himself off alcohol and has joined a sobriety group. He requests medication to help him maintain his sobriety. Which one of the following medications should you recommend for this patient?', 0, 'Acamprosate is recommended for patients who have achieved abstinence and desire to maintain it (SOR A). Gabapentin is useful for the prevention of withdrawal and is safe for those who are still drinking. Topiramate is useful in decreasing heavy drinking.', 'Poorman E, McQuade BM, Messmer S. Medications for alcohol use disorder. Am Fam Physician. 2024;109(1):71-78.', '["Acamprosate","Disulfiram","Gabapentin (Neurontin)","Topiramate (Topamax)"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 15-year-old male presents to your office with an intensely pruritic rash 2 days after returning from a camping trip in the woods. On examination you observe a rash on the hands, arms, face, and genitals with vesicles and a few bullae. Which one of the following would be the most appropriate treatment option?', 2, 'Systemic corticosteroids are indicated for facial, genital, or significant vesiculobullous involvement of poison ivy (allergic contact dermatitis). The most effective treatment is a 15-day prednisone taper, starting with 1 mg/kg (60 mg at maximum). Short courses (like a 5-day dose pack) frequently lead to a rebound in rash.', 'Lawley LP, Cheeley JT, Swerlick RA. Eczema, psoriasis, cutaneous infections, acne, and other common skin disorders. In: Harrison''s Principles of Internal Medicine. 21st ed. 2022:375-376.', '["Topical clobetasol, applied twice daily to affected areas until symptoms resolve","Oral methylprednisolone, starting at 1 mg/kg and tapering over 5 days","Oral prednisone, starting at 1 mg/kg and tapering over 15 days","Subcutaneous triamcinolone, 80 mg once","Draining the bullae and large vesicles"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 50-year-old male sees you for follow-up of a pulmonary nodule. He recently presented to the emergency department (ED) after a motor vehicle accident in which he sustained a broken clavicle. A CT scan in the ED showed a 6-mm, incidental, solid pulmonary nodule. Today the patient is asymptomatic. He does not have any history of smoking. Which one of the following would be the most appropriate next step in management?', 1, 'A solid nodule between 6 mm and 8 mm should be monitored with CT of the chest in 6-12 months according to Fleischner Society guidelines. Primary care physicians should consider referral to a pulmonologist for patients with a larger solid nodule (8-30 mm) or a subsolid nodule due to their higher risk of malignancy.', 'Mazzone PJ, Lam L. Evaluating the patient with a pulmonary nodule: a review. JAMA. 2022;327(3):264-273.', '["No additional follow-up","A repeat CT scan in 6-12 months","A repeat CT scan in 18-24 months","Biopsy of the nodule to determine pathology","Referral to a pulmonologist"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 42-year-old male presents with a 3-month history of intermittent abdominal pain and fatigue. He takes 600-800 mg of ibuprofen and drinks 6-8 beers nightly. Labs show Sodium 137, Potassium 4.9, Creatinine 1.0, BUN 37, Hemoglobin 8.8 g/dL. He is hemodynamically stable. Which one of the following would be the most appropriate next step in management?', 0, 'This patient likely has an upper gastrointestinal bleed from erosive gastritis or peptic ulcer disease. Given that the patient is hemodynamically stable and his hemoglobin level is above the transfusion threshold, guidelines recommend initiating a proton pump inhibitor on presentation with no delay regardless of status for endoscopy. Urgent endoscopy is only indicated in patients with hemodynamic instability.', 'Wilkins T, Wheeler B, Carpenter M. Upper gastrointestinal bleeding in adults: evaluation and management. Am Fam Physician. 2020; 101(5):294-300.', '["A high-dose proton pump inhibitor","Endoscopy","Nasogastric lavage","Blood transfusion","Arterial embolization"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'You see a 6-month-old infant for a routine visit. The child has started teething and the parents are concerned about preventing cavities, as their municipality does not fluoridate the water. In addition to providing daily oral fluoride supplementation, which one of the following should you recommend?', 0, 'It is recommended for parents to brush the teeth of infants and toddlers once or twice daily with a rice-sized amount of fluoridated toothpaste, increasing to a pea-sized amount at age 3. Mouthwash should not be used in children younger than 6 years. Fluoride varnish should be applied every 3-6 months starting at the emergence of the first tooth.', 'Clark MB, Keels MA, Slayton RL; Section on Oral Health. Fluoride use in caries prevention in the primary care setting. Pediatrics. 2020;146(6):e2020034637.', '["Brushing the emerging teeth daily with a rice-sized amount of fluoridated toothpaste","Using mouthwash as an adjunct to toothbrushing until age 5","Application of fluoride varnish to teeth annually, starting at age 1","Application of fluoride varnish to teeth twice yearly, starting at age 3"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 75-year-old male presents to your office with his family. They have noticed a gradual progression of neurologic symptoms over the past 6 months, including a noticeably slower gait and a tremor of his right hand. You observe a shuffling gait and a resting pill-rolling tremor of his right hand. You also note cogwheel rigidity of his right arm. Which one of the following would be the most appropriate initial medication for the treatment of this patient''s condition?', 1, 'This patient likely presents with Parkinson disease based on the hallmark symptoms and physical examination findings. First-line medications for Parkinson disease are carbidopa/levodopa, monoamine oxidase-B inhibitors, and nonergot dopamine agonists.', 'Halli-Tierney AD, Luker J, Carroll DG. Parkinson disease. Am Fam Physician. 2020;102(11):679-691.', '["Amitriptyline","Carbidopa/levodopa (Sinemet)","Fluoxetine (Prozac)","Gabapentin (Neurontin)","Propranolol hydrochloride"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 26-year-old female presents to your clinic because of headache and vision changes. She has also noticed an increase in the size of her hands and feet, changes to her facial features, carpal tunnel symptoms, proximal muscle weakness, fatigue, and menstrual irregularities. MRI of the brain shows a 7-mm pituitary adenoma. Which one of the following diagnostic tests is most likely to be abnormal in this patient?', 3, 'Somatotroph adenomas secrete growth hormone and cause symptoms consistent with acromegaly, including an increase in hand and foot size, enlargement of the mandible, and carpal tunnel symptoms. Somatotroph adenomas are diagnosed by a high serum insulin-like growth factor 1 (IGF-1) level.', 'Tritos NA, Miller KK. Diagnosis and management of pituitary adenomas: a review. JAMA. 2023;329(16):1386.', '["A dexamethasone suppression test","A serum prolactin level","A TSH level","A serum insulin-like growth factor 1 level"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'An otherwise healthy 52-year-old female with a past surgical history of hysterectomy for the treatment of uterine fibroids presents with increasing episodes of hot flashes lasting 3-5 minutes and occurring 5-10 times per day over the past 5 months. She finds the symptoms highly disruptive and is interested in options for medical therapy. Which one of the following would be the most effective therapy for this patient''s symptoms?', 0, 'Oral or transdermal estrogen is the most effective treatment for vasomotor symptoms in menopausal women (SOR A). Because she has had a hysterectomy, estrogen monotherapy is appropriate and she does not need a progestin for endometrial protection.', 'American College of Obstetricians and Gynecologists. ACOG Practice Bulletin No. 141: management of menopausal symptoms. Obstet Gynecol 2014;123(1):202-216.', '["A transdermal estradiol patch (Climara)","Transdermal testosterone gel (AndroGel)","Vaginal estradiol cream (Estrace Vaginal)","Soy phytoestrogen supplementation","Paroxetine (Paxil)"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 25-year-old male is brought to the level 1 trauma center with a gunshot wound. He is awake, alert, and oriented, and has full capacity for decision-making. The patient then becomes hemodynamically unstable. Whole blood transfusion is indicated, but the patient refuses blood products as he is a practicing Jehovah''s Witness. An advance directive on file confirms this. He is aware that not administering blood will most likely cause his death. You disagree with the patient and would like to administer a whole blood transfusion. Which one of the following would be the most appropriate next step?', 1, 'When a patient has either an advance directive or demonstrates decision-making capacity, their autonomous refusal of treatment must be respected, even if it leads to adverse medical outcomes or conflicts with the physician''s values or ethical beliefs. Blood refusal directives are considered legally binding.', 'Wiser Z, Gauer R. Approaches to a patient with anemia who is refusing a blood transfusion. Am Fam Physician. 2024;109(1):online.', '["Presenting the case to the ethics committee","Respecting the patient''s wishes by avoiding transfusion","Consulting the patient''s family and administering whole blood with their approval","Administering packed RBCs","Administering whole blood"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A 72-year-old male presents with a 45-minute history of persistent bleeding from his left nostril. He has a medical history of aortic stenosis with a mechanical aortic valve replacement. His medications include warfarin. A physical examination reveals a blood pressure of 170/100 mm Hg and a heart rate of 90 beats/min. Which one of the following would be the most appropriate first step in the treatment of this patient''s nosebleed?', 0, 'The initial treatment of a hemodynamically stable patient with epistaxis is to pinch the lower third of the nose for 15-20 minutes. If digital compression is not successful, then topical vasoconstrictors, chemical/electrical cautery, or anterior nasal packing would be indicated.', 'Seikaly H. Epistaxis. N Engl J Med. 2021;384(10):944-951.', '["Digital compression of the lower nares for 20 minutes","Topical vasoconstrictors","Anterior nasal packing","Electrical cauterization","Reversal of anticoagulation"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'An 80-year-old male presents to your office for follow-up of stable angina. His current medications include Aspirin 81 mg daily, Carvedilol 12.5 mg twice daily, Empagliflozin 10 mg daily, and Losartan 50 mg daily. On examination he has a blood pressure of 140/85 mm Hg, a heart rate of 52 beats/min, and an oxygen saturation of 98% on room air. Which one of the following changes to this patient''s medication regimen would be most appropriate to decrease his anginal symptoms?', 3, 'Beta-blockers, calcium channel blockers, and long-acting nitrates are first-line medications to decrease symptoms in patients with angina. Adding isosorbide mononitrate is the most appropriate option for this patient. Increasing his carvedilol or adding ivabradine is not recommended due to his relative bradycardia (HR 52).', 'Virani SS, Newby LK, Arnold SV, et al. 2023 AHA/ACC/ACCP/ASPC/NLA/PCNA guideline for the management of patients with chronic coronary disease. J Am Coll Cardiol. 2023;82(9):833-955.', '["Increasing carvedilol","Increasing empagliflozin","Adding clopidogrel (Plavix)","Adding isosorbide mononitrate","Adding ivabradine (Corlanor)"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 35-year-old female presents because of a 4-week history of difficulty sleeping following the death of her partner of 2 years. She requests nonpharmacologic treatment for her insomnia. Which one of the following is a component of sleep hygiene education for cognitive behavioral therapy for insomnia?', 2, 'Cognitive behavioral therapy for insomnia (CBT-I) is an effective treatment. Waking up at the same time every day and not napping during the day are among the 8 components of sleep hygiene education. Decreasing time spent in bed is part of sleep restriction, not general sleep hygiene.', 'Vargas I, Nguyen AM, Muench A, Bastien CH, Ellis JG, Perlis ML. Acute and chronic insomnia: what has time and/or hyperarousal got to do with it? Brain Sci. 2020;10(2):71.', '["Decreasing time spent in bed","Increasing daytime napping","Waking up at the same time every day","Placing a digital clock next to the bed"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 32-year-old female presents with classic symptoms of mild hypothyroidism including cold intolerance, mild fatigue, and constipation. Her TSH level is 6.0 uU/mL (N 0.4-4.2) and her free T4 level is within normal limits. A pregnancy test is negative. Which one of the following factors, if present, would be an indication for prescribing levothyroxine (Synthroid)?', 3, 'Subclinical hypothyroidism is defined by an abnormal TSH level <10 uU/mL while the free T4 level remains within normal range. Nonpregnant patients with subclinical hypothyroidism should not be treated with thyroid hormone replacement therapy unless the thyroid peroxidase antibody level is elevated or the TSH level is >10 uU/mL (SOR A).', 'Wilson SA, Stem LA, Bruehlman RD. Hypothyroidism: diagnosis and treatment. Am Fam Physician. 2021;103(10):605-613.', '["A repeat TSH level in 4-6 weeks remains at 6.0 uU/mL","A repeat TSH level in 4-6 weeks increases to 8.0 uU/mL","An elevated free T3 level","An elevated thyroid peroxidase antibody level","Treatment-resistant constipation"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 44-year-old female presents to the emergency department for evaluation of heavy vaginal bleeding. She reports soaking a pad every hour for the past 6 hours. She has a past medical history of breast cancer for which she underwent lumpectomy 6 months ago. Her vital signs are stable. A hemoglobin level is 8.0 g/dL (N 12.0-16.0). Which one of the following would be the most appropriate next step?', 2, 'While this patient''s bleeding is severe, her vital signs indicate hemodynamic stability. The most appropriate next step is to administer intravenous tranexamic acid. Given this patient''s recent breast cancer history, therapies with estrogen or progesterone should be avoided if clinically appropriate. Intravenous estrogen is reserved for hemodynamically unstable patients.', 'Wouk N, Helton M. Abnormal uterine bleeding in premenopausal women. Am Fam Physician. 2019;99(7):435-443.', '["A high-dose combined oral contraceptive","Intravenous conjugated estrogens (Premarin)","Intravenous tranexamic acid","Depot medroxyprogesterone acetate (Depo-Provera CI)","A levonorgestrel IUD (Mirena)"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 45-year-old female presents with a 1-year history of central facial erythema, telangiectasias, and inflammatory pustules and papules. The symptoms are worsened by alcohol and excessive sun exposure. You diagnose rosacea. She has not had any previous success with moisturizers, aggressive sun protection, or mild facial soap. Which one of the following would be the most appropriate first step in the management of this condition?', 2, 'Topical metronidazole is a first-line treatment for rosacea. Topical azelaic acid is also first-line. Oral doxycycline is a reasonable next step if topical metronidazole is not successful. Brimonidine and laser therapies are second-line treatments.', 'Frazier W, Zemtsov RK, Ge Y. Rosacea: common questions and answers. Am Fam Physician. 2024;109(6):533-542.', '["Topical brimonidine (Mirvaso)","Topical cyclosporine","Topical metronidazole","Oral doxycycline","Laser or light-based therapy"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 67-year-old female presents for a wellness examination. She reports that her last Papanicolaou test was 15 years ago. She has no known history of abnormal cervical cytology in the past. According to the U.S. Preventive Services Task Force, which one of the following should you recommend regarding further cervical cancer screening?', 4, 'The USPSTF recommends against cervical cancer screening in women older than 65 years only if they have had adequate prior screening (3 consecutive negative cytology results or 2 consecutive negative co-testing results within 10 years). Because this patient has not had adequate prior screening, she requires either 2 consecutive negative co-testing results that are 5 years apart or 3 consecutive negative cytology results that are 3 years apart before stopping.', 'Final recommendation statement: cervical cancer: screening. US Preventive Services Task Force. Updated August 21, 2018.', '["No further screening due to the patient''s age","Cervical cytology alone now, with no further screening if the result is normal","Cervical cytology alone now, then repeated in 3 years with no further screening if the results are normal","Cervical cytology with HPV co-testing now, with no further screening if the results are normal","Cervical cytology with HPV co-testing now, then repeated in 5 years with no further screening if the results are normal"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 46-year-old male comes in for an acute visit for low back pain. During triage, a Patient Health Questionnaire-2 (PHQ-2) screen is positive. You then administer the PHQ-9. You ask, ''Over the last 2 weeks, how often have you been bothered by thoughts that you would be better off dead, or of hurting yourself?'' He responds, ''Nearly every day.'' His total PHQ-9 score is 19. Which one of the following would be the most appropriate next step?', 0, 'Suicidal ideation should be carefully addressed. Current recommendations for evaluating suicidal ideation suggest focusing on individual assessment and understanding certain risk factors that may exacerbate suicidal ideation for a given patient (e.g., plan, means, underlying mental illness). This patient requires further evaluation for suicide risk before initiating pharmacologic therapy or considering hospital transfer.', 'Norris DR, Clark MS. The suicidal patient: evaluation and management. Am Fam Physician. 2021;103(7):417-421.', '["Suicidal ideation assessment and evaluation of risk factors for suicide completion","Escitalopram (Lexapro), and cognitive behavioral therapy","Escitalopram plus lithium, and cognitive behavioral therapy","Intravenous ketamine","Transportation to the emergency department"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A healthy 58-year-old patient presents for an annual health maintenance examination. They had an initial screening colonoscopy 3 years ago in which 2 polyps were removed. The polyps were found to be 6-mm and 8-mm tubular adenomas. The patient does not have a family history of colon cancer. Which one of the following is the most appropriate ongoing colon cancer screening for this patient?', 4, 'For average-risk patients with 1-2 tubular adenomas <10 mm in size found on screening colonoscopy, repeat colonoscopy in 7-10 years is recommended, as the risk of small adenomas progressing to malignancy is quite low and the rate of progression is slow.', 'Gupta S, Lieberman D, Anderson JC, et al. Recommendations for follow-up after colonoscopy and polypectomy: a consensus update by the US Multi-Society Task Force on Colorectal Cancer. Gastroenterology. 2020;158(4):1131-1153.e5.', '["No further follow-up","Fecal immunochemical testing (FIT) now","Stool DNA testing (Cologuard) now","Repeat colonoscopy within the next 2 years","Repeat colonoscopy 7-10 years after the initial colonoscopy"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 27-year-old gravida 1 para 0 at 38 weeks'' estimated gestation based on a first-trimester ultrasound presents for routine prenatal care. Her pregnancy has been uncomplicated. You discuss the potential risks and benefits of inducing labor at 39 weeks compared to expectant management. In this discussion, you should tell the patient that inducing labor at 39 weeks reduces', 3, 'The 2018 ARRIVE trial showed that elective induction of labor at 39 weeks in low-risk nulliparous patients resulted in a significantly lower rate of cesarean delivery (18.6% vs 22.2%) and lower rates of gestational hypertension/preeclampsia compared to expectant management. It did not reduce NICU admissions or risk of postpartum hemorrhage.', 'Grobman WA, Rice MM, Reddy UM, et al. Labor induction versus expectant management in low-risk nulliparous women. N Engl J Med. 2018;379(6):513-523.', '["the risk of low birth weight","length of stay in the labor and delivery unit","risk for neonatal ICU admission","the rate of cesarean delivery","the risk of postpartum hemorrhage"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 75-year-old female presents to your office with a 1-year history of gradually worsening right-sided groin pain on standing. The pain improves with rest. These symptoms have been marginally relieved with ibuprofen and acetaminophen, but her use of these medications has been limited by gastric irritation. A physical examination is most notable for pain in the groin with passive flexion, adduction, and internal rotation (FADIR) testing. Which one of the following treatments would be most helpful in relieving her symptoms?', 3, 'This patient presents with hip osteoarthritis. Intra-articular corticosteroid injections have been shown to relieve hip osteoarthritis pain for at least 4 months and improve activity levels. Intra-articular hyaluronic acid injections and topical lidocaine patches lack evidence of substantial benefit. Opioids and tramadol carry significant risks and are advised against.', 'Arnold MJ. Hip osteoarthritis: guidelines from the American Academy of Orthopaedic Surgeons. Am Fam Physician. 2025;111(1):90-91.', '["A topical lidocaine patch (Lidoderm)","Hydrocodone","Tramadol","Intra-articular corticosteroid injection","Intra-articular hyaluronic acid injection"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 65-year-old male is brought to the emergency department by his wife after developing confusion immediately after sexual intercourse. The wife reports that the patient does not remember anything from a few hours prior to the onset of symptoms. He repeatedly asks where he is and how he got here. He is alert and knows his wife, his name, and his birth date. A neurologic examination is otherwise normal. A CT scan of the head is unremarkable. It has now been 2 hours since the onset of his symptoms. Which one of the following would be most appropriate for treatment?', 0, 'This patient has transient global amnesia (TGA), characterized by the abrupt onset of anterograde amnesia without other neurologic deficits. It can be triggered by intense physical or psychological stress (like sexual intercourse) and usually resolves within 6 hours. No intervention is indicated other than reassurance.', 'Sealy D, Tiller RJ, Johnson K. Transient global amnesia. Am Fam Physician. 2022;105(1):50-54.', '["Observation and reassurance","Oral apixaban (Eliquis)","Oral aspirin and clopidogrel (Plavix)","Intravenous lorazepam (Ativan)","Intravenous thrombolytic therapy"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 55-year-old male presents to the urgent care clinic with a 24-hour history of worsening fever, chills, and body aches. He tells you that he discovered a tick on his scalp during a camping trip last week. A Lyme enzyme immunoassay and confirmatory Western blot are positive. When he has taken doxycycline in the past, he has developed headaches, severe nausea, and vomiting. Which one of the following would be the most appropriate treatment option for this patient?', 0, 'Doxycycline is the preferred first-line treatment for Lyme disease. For patients who are pregnant or do not tolerate it (e.g., severe nausea/vomiting), an appropriate alternative is amoxicillin 500 mg 3 times daily for 14-21 days or cefuroxime axetil. IV ceftriaxone is reserved for late neurologic manifestations.', 'Pace EJ, O''Reilly M. Tickborne diseases: diagnosis and management. Am Fam Physician. 2020;101(9):530-540.', '["Amoxicillin","Ceftriaxone","Chloramphenicol","Doxycycline plus promethazine"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 66-year-old female asks about options for shingles vaccine. She received the live zoster vaccine (Zostavax) previously. She underwent urgent cholecystectomy for acute cholecystitis 2 months ago and developed shingles in a dermatomal distribution soon after hospital discharge. The rash is gone but she still has mild postherpetic neuralgia. Which one of the following would be the earliest this patient can safely receive the first dose of recombinant zoster vaccine?', 0, 'The recombinant zoster vaccine (RZV) is recommended for healthy adults >=50 years of age. The CDC recommends that patients wait until the zoster rash has resolved prior to receiving RZV; it is not necessary to wait until postherpetic neuralgia has resolved. She can receive it today.', 'Shingles vaccine recommendations. Centers for Disease Control and Prevention. Updated October 22, 2024.', '["Today","After resolution of the postherpetic neuralgia","12 months after her episode of shingles","Never"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A 40-year-old male presents to the office with a 2-day history of right eye pain associated with redness and swelling. Pertinent findings on a physical examination include a temperature of 37.3 C (99.1 F), visual acuity of 20/70 in the right eye and 20/20 in the left eye, erythema and edema of the right eyelid, and pain with extraocular movements. Which one of the following would be the most appropriate next step?', 4, 'This patient''s unilateral orbital swelling, erythema, pain with extraocular movements, and decreased visual acuity are concerning for orbital cellulitis. This is an ocular emergency requiring prompt transfer to the emergency department for expedited evaluation, CT with IV contrast, urgent ophthalmology consultation, and broad-spectrum IV antibiotics.', 'Pelletier J, Koyfman A, Long B. High risk and low prevalence diseases: orbital cellulitis. Am J Emerg Med. 2023;68:1-9.', '["Frequent warm, moist compresses, and follow-up tomorrow","Empiric treatment with an oral antibiotic","A same-day evaluation with an ophthalmologist","Noncontrast CT of the orbits and sinuses","Transfer to the emergency department"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 63-year-old male presents with a 2-day history of right lower extremity edema and pain. He has a past medical history of hypertension, stage 4 chronic kidney disease, and type 2 diabetes. His last glomerular filtration rate was 22 mL/min/1.71 m2. A Doppler venous duplex ultrasound of the right thigh shows a noncompressible right femoral vein. Which one of the following would be the most appropriate initial treatment for this patient''s condition?', 3, 'This patient has an acute deep vein thrombosis (DVT). Outpatient treatment is appropriate. Direct oral anticoagulants (rivaroxaban, dabigatran) are contraindicated or not appropriate due to his GFR < 30 mL/min. Low-molecular-weight heparin like enoxaparin is a reasonable option, utilizing renal dosing (daily instead of twice-daily).', 'Stevens SM, Woller SC, Baumann Kreuziger L, et al. Antithrombotic therapy for VTE disease: compendium and review of CHEST guidelines 2012-2021. Chest. 2024;166(2):388-404.', '["Oral dabigatran (Pradaxa), 75 mg twice daily","Oral rivaroxaban (Xarelto), 15 mg twice daily for 14 days, then 20 mg daily","Oral warfarin, 5 mg daily","Subcutaneous enoxaparin (Lovenox), 70 mg daily","Admission for intravenous heparin"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 65-year-old male presents to your office with a 4-month history of ill-defined lower pelvic pain. He is afebrile. A digital rectal examination yields a boggy prostate with moderate tenderness. Urinalysis is positive for leukocyte esterase and 10-20 WBCs/hpf, and testing for common sexually transmitted infections is negative. Which one of the following would be the most appropriate next step in management?', 2, 'This patient has chronic bacterial prostatitis (CBP). Fluoroquinolones like ciprofloxacin are the first-line treatment for CBP because they penetrate prostatic tissue well and have high oral bioavailability.', 'Lam JC, Stokes W. Acute and chronic prostatitis. Am Fam Physician. 2024;110(1):45-51.', '["Amoxicillin","Ceftriaxone","Ciprofloxacin","CT of the abdomen and pelvis","Referral to a urologist"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 25-year-old male presents to the emergency department with a sudden onset of right-sided chest pain that started about 2 hours ago while he was resting and playing video games. He smokes 1 pack of cigarettes per day. On examination he has a blood pressure of 120/80 mm Hg, a heart rate of 115 beats/min, a respiratory rate of 20/min, and an oxygen saturation of 90% on room air. A chest x-ray reveals a pneumothorax involving <10% of the lung space. Which one of the following would be the most appropriate next step in management?', 1, 'For patients who are stable with a small (<15%) primary pneumothorax, conservative management with initiation of oxygen via nasal cannula and observation for at least 6 hours is recommended, followed by a repeat chest x-ray to assess for stability.', 'Brown SGA, Ball EL, Perrin K, et al. Conservative versus interventional treatment for spontaneous pneumothorax. N Engl J Med. 2020;382(5):405-415.', '["Reassurance and discharge home with return precautions for worsening symptoms","Initiation of oxygen via nasal cannula, and a repeat chest x-ray in 6 hours","CT of the chest to verify x-ray findings","Emergent needle decompression at the right second intercostal space in the anterior midclavicular line","Placement of a chest tube at the right fourth or fifth intercostal space in the midaxillary to anterior axillary line"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 17-year-old female with well-controlled diabetes mellitus is brought to your office by her mother for a sports preparticipation physical evaluation prior to playing soccer. She has intermittent knee pain when running but no other symptoms. Which one of the following, if present in this patient, would be a CONTRAINDICATION to playing soccer?', 1, 'An athlete with an acutely enlarged spleen or liver faces an increased risk of organ rupture during contact sports like soccer and should be restricted from play until evaluated. Obesity, diabetes, asymptomatic MVP, and tibial tubercle apophysitis (Osgood-Schlatter) are not contraindications.', 'Rice SG; American Academy of Pediatrics Council on Sports Medicine and Fitness. Medical conditions affecting sports participation. Pediatrics. 2008;121(4):841-848.', '["A BMI >30 kg/m2","An enlarged spleen","Insulin-dependent diabetes","Mitral valve prolapse","Tibial tubercle apophysitis"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'An otherwise healthy 26-year-old female presents to your clinic with a history of 3 episodes of vertigo occurring over the last week. Each episode lasts for several hours. During the episodes, she notes fullness in the right ear with tinnitus and hearing loss. She is currently asymptomatic and a physical examination is unremarkable. Which one of the following would be the most appropriate next step?', 2, 'This patient''s presentation of spontaneous recurring episodes of vertigo associated with unilateral hearing loss, tinnitus, and ear fullness is characteristic of Meniere disease. Audiometry should be performed in patients suspected of having this condition to evaluate for sensorineural hearing loss.', 'Basura GJ, Adams ME, Monfared A, et al. Clinical practice guideline: Meniere''s Disease Executive Summary. Otolaryngol Head Neck Surg. 2020;162(4):415-434.', '["Recommending a reduction in alcohol intake","Performing the Epley maneuver","Ordering audiometry","Initiating oral hydrochlorothiazide, 25 mg daily","Initiating oral prednisone, 20 mg daily for 5 days"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A new lipid-lowering drug is being evaluated for its cardioprotective effects. The event rate for acute myocardial infarction is 0.085 in the low-intensity treatment group and 0.045 in the high-intensity treatment group, yielding an absolute risk reduction (ARR) of 0.04. Which one of the following is the number needed to treat (NNT)?', 1, 'The number needed to treat (NNT) is the inverse of the absolute risk reduction (ARR). NNT = 1 / ARR. Therefore, 1 / 0.04 = 25.', 'Centre for Evidence-Based Medicine. Number needed to treat (NNT). University of Oxford Nuffield Department of Primary Care Health Sciences.', '["<1","25","40","50"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 75-year-old female presents to your office with a 3-month history of episodes of lightheadedness on standing. Orthostatic blood pressure testing in your office reveals an initial blood pressure of 134/76 mm Hg that drops to 104/46 mm Hg on standing. You diagnose orthostatic hypotension. Monotherapy with which one of the following would be indicated for the management of this patient''s neurogenic orthostatic hypotension?', 3, 'Midodrine has been found to be the safest and best-tolerated medication for the management of neurogenic orthostatic hypotension (SOR B). Fludrocortisone is used off-label but requires caution due to risks like LVH, renal failure, and hypokalemia. Atomoxetine is used as adjunctive therapy, not monotherapy.', 'Kim MJ, Farrell J. Orthostatic hypotension: a practical approach. Am Fam Physician. 2022;105(1):39-49.', '["Atomoxetine (Strattera)","Fludrocortisone","Methylphenidate (Ritalin)","Midodrine","Sodium bicarbonate"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 22-year-old female with a past medical history of type 1 diabetes presents to the emergency department with multiple bouts of vomiting. She has a plasma glucose level of 350 mg/dL, elevated ketones, and high anion gap metabolic acidosis. Treatment for diabetic ketoacidosis is initiated with intravenous fluids and insulin therapy. Glucose should be added to this patient''s saline infusion when her plasma glucose levels reach which one of the following ranges?', 2, 'In the management of diabetic ketoacidosis, once plasma glucose levels reach 201-250 mg/dL, glucose should be added to the saline infusion to maintain plasma glucose levels in the 150-200 mg/dL range. This prevents hypoglycemia while continuing the insulin therapy needed to resolve acidosis and ketosis.', 'Veauthier B, Levy-Grau B. Diabetic ketoacidosis: evaluation and treatment. Am Fam Physician. 2024;110(5):476-486.', '["<150 mg/dL","150-200 mg/dL","201-250 mg/dL","251-300 mg/dL","301-350 mg/dL"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 32-year-old female with a recent diagnosis of posttraumatic stress disorder presents to your clinic with difficulty sleeping. She continues to experience midsleep awakening due to hyperarousal and nightmares. Which one of the following would be the most appropriate treatment?', 2, 'Prazosin is an alpha-1-agonist that decreases sympathetic nervous tone during sleep and has been found to be helpful for midsleep awakening due to hyperarousal and nightmares in patients with posttraumatic stress disorder.', 'Sartor Z, Kelley L, Laschober R. Posttraumatic stress disorder: evaluation and treatment. Am Fam Physician. 2023;107(3):273-281.', '["Amitriptyline","Mirtazapine (Remeron)","Prazosin","Risperidone (Risperdal)","Temazepam (Restoril)"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 58-year-old female with type 2 diabetes controlled on metformin recently underwent bariatric surgery. Today, she reports feeling off balance and having a burning sensation in her bilateral hands and feet that is worse at night. She has fallen several times and has intermittent nausea, vomiting, and confusion. A physical examination is significant for absent patellar and Achilles reflexes, 4/5 strength in the bilateral lower extremities, and ataxia. Which one of the following is the most likely diagnosis?', 4, 'This patient presents with a symmetrical peripheral neuropathy with sensory and motor components, confusion, and ataxia, which are characteristic of dry beriberi caused by vitamin B1 (thiamine) deficiency. Risk factors include bariatric surgery and alcohol use. Diabetic neuropathy is typically sensory and rarely involves motor weakness.', 'Smith TJ, Johnson CR, Koshy R, et al. Thiamine deficiency disorders: a clinical perspective. Ann N Y Acad Sci. 2021;1498(1):9-28.', '["Diabetic peripheral neuropathy","Lyme disease","Myalgic encephalomyelitis/chronic fatigue syndrome (ME/CFS)","Secondary syphilis","Vitamin B1 deficiency (beriberi)"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 76-year-old female presents because of acute right knee pain that began after she sustained a mechanical fall and landed on her knee. When asked to point to the pain, she points to an area lateral to the inferior patella. Examination of the knee reveals full range of motion with pain. There is no tenderness of the patella or the fibular head with palpation. Provocative testing including an Apley grind test, a McMurray test, a Lachman test, and anterior and posterior drawer tests is negative. Which one of the following would be the most appropriate next step to aid in diagnosis?', 2, 'According to the Ottawa knee rules, a well-validated tool used to limit unnecessary radiography, a knee x-ray is indicated in this patient to rule out fracture because she is >=55 years of age. Radiography is the preferred modality over ultrasonography for diagnosing a fracture in an adult.', 'Sims JI, Chau MT, Davies JR. Diagnostic accuracy of the Ottawa Knee Rule in adult acute knee injuries: a systematic review and meta-analysis. Eur Radiol. 2020;30(8):4438-4446.', '["No further testing or imaging","Ultrasonography","Radiography","MRI","Arthrocentesis with culture and Gram stain"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 31-year-old gravida 3 para 2 at 8 weeks'' gestation presents to the urgent care clinic because of a 2-day history of headache and fever. This morning she removed an engorged tick from her leg. You suspect Rocky Mountain spotted fever. In addition to supportive care, which one of the following would be the most appropriate treatment?', 3, 'Doxycycline is the recommended treatment for all individuals with presumed Rocky Mountain spotted fever (RMSF), including pregnant women and children. RMSF can be fatal, so brief courses (5-10 days) of doxycycline are considered safe and should not be delayed.', 'Clinical care of Rocky Mountain spotted fever. Centers for Disease Control and Prevention. Reviewed March 6, 2025.', '["No additional treatment","Amoxicillin","Chloramphenicol","Doxycycline","Erythromycin"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 53-year-old female with no significant past medical history presents to the emergency department with fatigue, pruritus, and right upper quadrant discomfort. A physical examination reveals mild hepatomegaly. Laboratory findings include an Alkaline phosphatase of 450 U/L (N 44-147), AST 70 U/L (N 10-40), Total bilirubin 1.5 mg/dL (N 0.1-1.2), and positive Antimitochondrial antibodies. Which one of the following is the most likely diagnosis?', 3, 'Primary biliary cholangitis is characterized by chronic cholestasis (elevated alkaline phosphatase) and positive antimitochondrial antibodies (AMA). Positive AMA is found in >95% of cases and helps distinguish it from other liver conditions like primary sclerosing cholangitis or autoimmune hepatitis.', 'Lindor KD, Bowlus CL, Boyer J, Levy C, Mayo M. Primary biliary cholangitis: 2021 practice guidance update from the American Association for the Study of Liver Diseases. Hepatology. 2022;75(4):1012-1013.', '["Autoimmune hepatitis","Drug-induced liver injury","Metabolic dysfunction-associated steatotic liver disease (MASLD) (nonalcoholic fatty liver disease)","Primary biliary cholangitis","Primary sclerosing cholangitis"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A generally healthy 28-year-old female presents to your office because she is concerned about changes in her mood. For the last few months she has been intermittently irritable and unable to sit still. She has had some weight loss, is not sleeping well, and feels fatigued. She has been working extra hours, maxed out her credit card, and repeatedly cheated on her husband. She now feels depressed and anxious. She has had similar episodes in the past. Which one of the following would be the most appropriate therapy at this time?', 2, 'This patient has features of bipolar disorder, presenting with mixed features (symptoms of mania such as hypersexuality, impulsivity, insomnia, plus depression). Antidepressant monotherapy is contraindicated in patients with mixed features or bipolar disorder. FDA-approved medications include atypical antipsychotics such as quetiapine.', 'Marzani G, Price Neff A. Bipolar disorders: evaluation and treatment. Am Fam Physician. 2021;103(4):227-239.', '["Bupropion","Paroxetine (Paxil)","Quetiapine (Seroquel)","Sertraline (Zoloft)","Electroconvulsive therapy"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 23-year-old female presents for IUD removal because she wants to conceive. She has never been pregnant, is in good health, and takes no medications. Her blood pressure is normal and her BMI is 33 kg/m2. Which one of the following should you recommend regarding aspirin prophylaxis for preeclampsia?', 2, 'The USPSTF recommends aspirin prophylaxis for pregnant patients who are at increased risk for preeclampsia (1 high-risk factor or 2 moderate-risk factors). This patient has 2 moderate-risk factors: nulliparity and BMI >30 kg/m2. Low-dose aspirin (81 mg) should be started at 12 weeks'' gestation.', 'American College of Obstetricians and Gynecologists'' Committee on Obstetric Practice. ACOG Committee Opinion No. 743: low-dose aspirin use during pregnancy. Obstet Gynecol. 2018;132(1):254-256.', '["No aspirin as she does not meet criteria","Aspirin for 1-3 months prior to conception","Aspirin at 12 weeks'' gestation","Aspirin if her blood pressure during pregnancy is >135/80 mm Hg"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2025', 'Neurologic', 'Neurologic', '', 'A 74-year-old female presents to your office for follow-up of cardioembolic stroke 1 day after being discharged from the hospital. She presented to the hospital with acute left-sided hand and face weakness. An evaluation in the hospital revealed new atrial fibrillation, mild mitral regurgitation, and a small right-sided cerebral infarction. Cardioembolic stroke was diagnosed. She was discharged 48 hours later after her left-sided weakness had almost completely resolved. Which one of the following therapeutic options is preferred for this patient?', 0, 'In patients who have a TIA or small cardioembolic stroke and nonvalvular atrial fibrillation, guidelines recommend starting anticoagulation without antiplatelet agents 2-14 days after the event. Nonvalvular atrial fibrillation is defined by the lack of moderate to severe mitral stenosis or a mechanical heart valve; direct-acting oral anticoagulants (like apixaban) are preferred to warfarin in these patients.', 'Kleindorfer DO, Towfighi A, Chaturvedi S, et al. 2021 guideline for the prevention of stroke in patients with stroke and transient ischemic attack. Stroke. 2021;52(7):e364-e467.', '["Apixaban (Eliquis)","Aspirin","Clopidogrel (Plavix)","Warfarin","Aspirin plus clopidogrel"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 75-year-old female with an ST-elevation myocardial infarction (STEMI) diagnosed in the emergency department has been admitted to your service. She underwent a percutaneous coronary intervention with a drug-eluting stent to the circumflex artery and had been recovering well until she developed acute shortness of breath on the fourth day of hospitalization. Today, her vital signs reveal a blood pressure of 91/55 mm Hg, a heart rate of 110 beats/min, and an oxygen saturation of 89% on room air. Auscultation reveals a regular rate, normal S1 and S2, and a systolic murmur over the mitral post. Crackles are heard in all lung fields. There is no lower extremity edema. Which one of the following is the likely etiology of this condition?', 1, 'Acute papillary muscle rupture occurs 3-5 days after a transmural infarction involving the right coronary artery or circumflex artery, depending on coronary anatomy. This leads to acute mitral regurgitation, resulting in flash pulmonary edema and shock, as seen in this patient with a new systolic murmur, hypotension, and crackles.', 'Damluji AA, van Diepen S, Katz JN, et al. Mechanical complications of acute myocardial infarction: a scientific statement from the American Heart Association. Circulation. 2021;144(2):e16-e35.', '["Cardiac tamponade","Papillary muscle rupture","Pericarditis","Pulmonary embolism","Supraventricular tachyarrhythmia"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 14-year-old male sees you to establish care. He has a past medical history of asthma and uses an albuterol inhaler (Proventil, Ventolin) as needed. He normally has symptoms about 3-4 days per week. Recent pulmonary function tests showed mildly reduced lung function. Based on the Global Initiative for Asthma (GINA) guidelines, which one of the following would be the preferred treatment strategy for this patient?', 2, 'Based on the Global Initiative for Asthma (GINA) guideline, patients 12 years and older with mild asthma (symptoms <3-5 days per week) should be treated with as-needed low-dose inhaled corticosteroid plus formoterol (ICS/formoterol). This reduces the risk of severe asthma exacerbations by 60%-64% compared to as-needed short-acting beta-agonists (SABAs) such as albuterol.', 'Global Initiative for Asthma. Global Strategy for Asthma Management and Prevention (2024 Update). Updated May 2024.', '["Continuing as-needed albuterol","Switching to as-needed formoterol","Switching to an as-needed low-dose inhaled corticosteroid (ICS) plus formoterol","Continuing as-needed albuterol, and adding a low-dose ICS for maintenance","Continuing as-needed albuterol, and adding a low-dose ICS plus salmeterol for maintenance"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 37-year-old male who recently returned from a trip to Vietnam presents for evaluation of an intensely pruritic rash on his feet. Physical examination findings are normal other than an erythematous, serpiginous rash on his feet and lower legs. Which one of the following is the most likely diagnosis?', 0, 'The typical rash that occurs with cutaneous larva migrans infection is an intensely pruritic, erythematous, serpiginous rash. It is typically seen on the feet and gluteal areas, often acquired after walking barefoot in areas where animal feces contaminate the soil.', 'Rathjen NA, Shahbodaghi SD. The ill returning traveler. Am Fam Physician. 2023;108(4):396-403.', '["Cutaneous larva migrans","Cutaneous leishmaniasis","Herpesvirus B","Neisseria meningitidis","Scabies"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 10-year-old male is brought to your office by his mother for follow-up of treatment for a Cryptosporidium infection that he likely contracted during a camping trip after swimming in a freshwater lake. He has completed treatment and is asymptomatic. His mother asks when he is allowed to resume swimming. Because of concerns for ongoing asymptomatic shedding, you should recommend that the patient may return to swimming:', 4, 'Because shedding of Cryptosporidium oocysts continues even after symptoms resolve, it is recommended that patients refrain from swimming for 2 weeks after resolution of symptoms to prevent transmission.', 'Perkins A, Trimmier M. Recreational waterborne illnesses: recognition, treatment, and prevention. Am Fam Physician. 2017;95(9):554-560.', '["3 days after treatment is completed","1 week after treatment is completed","3 days after symptoms resolve","1 week after symptoms resolve","2 weeks after symptoms resolve"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A previously healthy 27-year-old female at 36 weeks'' gestation presents to the emergency department (ED) in a rural town. She reports a 1-week history of headaches, nausea, fatigue, and right upper quadrant pain. Her blood pressure is 150/95 mm Hg. Laboratory findings include Platelets 43,000/mm3, AST 112 U/L, ALT 95 U/L, and Urine protein to creatinine ratio 422 mg/g. Which one of the following would be the most appropriate next step?', 3, 'This patient has HELLP (hemolysis, elevated liver enzymes, and low platelet count) syndrome. Women with HELLP syndrome have high maternal morbidity and mortality rates due to severe complications. Early diagnosis and management are critical, and the definitive treatment is urgent delivery in patients over 34 weeks'' gestation.', 'Terrault NA, Williamson C. Pregnancy-associated liver diseases. Gastroenterology. 2022;163(1):97-117.e1.', '["Administering oral prednisone","Administering N-acetylcysteine","Consultation with a gastroenterologist","Arranging for urgent delivery"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 64-year-old female with a history of hypertension and no prior evidence of kidney disease presents for follow-up of a recent basic metabolic panel that showed an estimated glomerular filtration rate (eGFR) of 49 mL/min/1.73 m2. Which one of the following would confirm a diagnosis of chronic kidney disease?', 4, 'Before a diagnosis of chronic kidney disease can be made, evidence of renal impairment or damage must be present for at least 3 months in order to differentiate the renal abnormalities from an acute kidney injury (AKI). This is most often confirmed with an eGFR <60 mL/min/1.73 m2 persisting for at least 3 months.', 'Levey AS, Eckardt KU, Dorman NM, et al. Nomenclature for kidney function and disease: report of a Kidney Disease: Improving Global Outcomes (KDIGO) Consensus Conference. Kidney Int. 2020;97(6):1117-1129.', '["A urine albumin to creatinine ratio >30 mg/g at this time","A urine albumin to creatinine ratio >300 mg/g at this time","An additional eGFR <60 mL/min/1.73 m2 in 1 month","An additional eGFR <90 mL/min/1.73 m2 in 2 months","An additional eGFR <60 mL/min/1.73 m2 in 3 months"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 4-year-old male presents with a 6-day history of fever, rash, and an enlarged lymph node. On examination, you note erythema of the lips, bilateral conjunctivitis, and a diffuse maculopapular rash on the trunk and extremities. The right anterior cervical lymph node is nontender and 2 cm in size. Which one of the following is the most serious complication of this patient''s condition?', 0, 'This patient presents with Kawasaki disease. The most serious complication is cardiac. If untreated, 15%-25% of patients will develop cardiovascular abnormalities, including coronary artery dilation, aortic root dilation, and cardiac aneurysms.', 'Darby JB, Jackson JM. Kawasaki disease and multisystem inflammatory syndrome in children: an overview and comparison. Am Fam Physician. 2021;104(3):244-252.', '["Cardiac","Hematologic","Hepatic","Pulmonary","Renal"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 40-year-old female presents for a health maintenance examination. Her family history is significant for colorectal cancer in her father, thyroid cancer in her paternal aunt, and endometrial cancer in her maternal grandmother. She says that her friend was diagnosed with breast cancer 2 weeks ago and is BRCA2 positive. She is anxious about her risk of breast cancer and requests a mammogram and BRCA testing. According to the U.S. Preventive Services Task Force guidelines, which one of the following would be most appropriate for this patient regarding genetic testing for BRCA1/2?', 0, 'For this patient, reassurance only is indicated. The USPSTF recommends against routine screening, risk assessment, counseling, and testing in all women for BRCA1/2 mutations. Only women with a personal or family history of breast, ovarian, tubal, or peritoneum cancer or specific susceptibility to BRCA1 and BRCA2 mutations should be formally evaluated.', 'Final recommendation statement: BRCA-related cancer: risk assessment, genetic counseling, and genetic testing. US Preventive Services Task Force. Updated August 20, 2019.', '["Reassurance only","Risk assessment using the 7-Question Family History Screening Tool","Testing for BRCA1/2 mutation","Genetic counseling"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'You are seeing a patient at 12 weeks'' gestation for prenatal care. She has a family history of neural tube defects and is taking 4 mg of high-dose folic acid supplementation daily. Her pregnancy is progressing normally, and she has no concerns. Which one of the following should you recommend for this patient regarding ongoing folic acid supplementation?', 2, 'For those with pregnancies at higher risk of neural tube defects (NTDs), the recommended dose of folic acid is 4 mg per day until 12 weeks after conception, and then 0.4 mg per day after 12 weeks. The rationale for decreasing the dose after 12 weeks is that organogenesis is largely complete by this stage.', 'American College of Obstetricians and Gynecologists'' Committee on Practice Bulletins-Obstetrics. ACOG Practice Bulletin No. 187: neural tube defects. Obstet Gynecol. 2017;130(6):e279-e290.', '["Continuing with 4 mg daily for the remainder of the pregnancy","Decreasing the dosage to 1 mg daily for the remainder of the pregnancy","Decreasing the dosage to 0.4 mg daily for the remainder of the pregnancy","Discontinuing folic acid"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 55-year-old male with a history of diabetes mellitus, hypertension, and stage 3 chronic kidney disease presents for management of recurrent gout. He has had multiple attacks this year despite dietary changes. His uric acid level is 8.6 mg/dL (N 4.5-8.0) and he would like to start gout prophylaxis. Which one of the following would be most appropriate to initiate at this time?', 4, 'Allopurinol is typically used as first-line treatment for gout in all patients, even those with kidney disease. The American College of Rheumatology strongly recommends that an anti-inflammatory medication, such as colchicine, be given when allopurinol is initiated to prevent an acute flare.', 'FitzGerald JD, Dalbeth N, Mikuls T, et al. 2020 American College of Rheumatology guideline for the management of gout. Arthritis Care Res. 2020;72(6):744-760.', '["Allopurinol (Zyloprim)","Colchicine (Colcrys)","Febuxostat (Uloric)","Pegloticase (Krystexxa)","Allopurinol plus colchicine"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'In a patient with aortic stenosis, which one of the following is an indication for referral for possible valve replacement?', 4, 'Once symptoms (such as angina, syncope, or heart failure) occur in patients with aortic stenosis, the clinical outcome is extremely poor, with 2-year survival rates below 50%. It is well established that this prognosis can be reversed by valve replacement. Angina is an indication of the seriousness of the stenosis.', 'Grimard BH, Safford RE, Burns EL. Aortic stenosis: diagnosis and treatment. Am Fam Physician. 2016;93(5):371-378.', '["Calcification of the valve on an echocardiogram","Development of mitral insufficiency on an echocardiogram","Left ventricular hypertrophy noted on a chest x-ray","A systolic ejection murmur that has increased from grade 1/6 to grade 2/6","New-onset angina"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 23-year-old male presents on a spring day with a 2-3-day history of mild nasal congestion, sneezing, and slight watery discharge. He does not have a fever or other significant concerns. Which one of the following would be the most appropriate treatment?', 1, 'This patient has mild allergic rhinitis. Intranasal corticosteroids are considered first-line therapy because they are the most effective at controlling symptoms. Intranasal or oral antihistamines may be considered, but they are less effective.', 'Weaver-Agostoni J, Kosak Z, Bartlett S. Allergic rhinitis: rapid evidence review. Am Fam Physician. 2023;107(5):466-473.', '["Intranasal antihistamines","Intranasal corticosteroids","Intranasal cromolyn","Oral antibiotics","Oral corticosteroids"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 30-year-old female presents for follow-up of infertility. She and her husband have been trying to conceive for the past 12 months. She reports a history of irregular menstrual bleeding over the past several years. A physical examination is unremarkable except for a BMI of 29 kg/m2. You suspect polycystic ovary syndrome (PCOS) and recommend diagnostic testing with fasting laboratory studies scheduled for 8:00 a.m. An elevation in which one of the following hormones would most strongly support a diagnosis of PCOS in this patient?', 4, 'The diagnosis of PCOS can be made based on the presence of at least 2 of the 3 Rotterdam criteria: oligoanovulation, hyperandrogenism, and polycystic ovaries on ultrasonography. Hyperandrogenism may be diagnosed biochemically with elevated androgen levels, such as an elevated free testosterone level.', 'Williams T, Moore JB, Regehr J. Polycystic ovary syndrome: common questions and answers. Am Fam Physician. 2023;107(3):264-272.', '["17-Hydroxyprogesterone","Cortisol","Glucose","Insulin","Testosterone"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A generally healthy 36-year-old male presents to your clinic with a 36-hour history of dizziness and nausea. He says he feels as though the world is spinning and he tends to fall to the left when he tries to walk. The episodes occur spontaneously and can last from minutes to hours. On neurologic testing, he exhibits horizontal nystagmus with left lateral gaze. Head-impulse testing reveals a rapid movement of both eyes. Which one of the following would be the most appropriate next step?', 1, 'This patient''s vertigo is caused by vestibular neuritis, as evidenced by its spontaneity, rotatory vertigo, nausea, and listing to the affected side with walking. Vestibular neuritis usually resolves on its own within a few days. The treatment is reassurance and antiemetics can be used for up to 3 days.', 'Rogers TS, Noel MA, Garcia B. Dizziness: evaluation and management. Am Fam Physician. 2023;107(5):514-523.', '["Home Epley maneuvers","Reassurance and antiemetics","Prednisone, 40 mg daily for 5 days","Valacyclovir (Valtrex), 1000 mg twice daily for 7 days","MRI of the brain"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 24-year-old gravida 2 para 2 presents to your office with melasma that has not resolved since she gave birth 6 months ago. She is eager to be treated. Which one of the following topical treatments would be the most effective for this patient''s melasma?', 4, 'Melasma is a common condition in pregnancy. Topical tretinoin, hydroquinone, and a corticosteroid such as fluocinolone can all be used in the treatment of melasma, and a combination of the 3 is the most effective.', 'Erlandson M, Wertz MC, Rosenfeld E. Common skin conditions during pregnancy. Am Fam Physician. 2023;107(2):152-158.', '["Azelaic acid","Hydroquinone","Imiquimod (Aldara, Zyclara)","Benzoyl peroxide plus a corticosteroid","A combination of fluocinolone, hydroquinone, and tretinoin"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'You see a newborn for a routine wellness check. The parents tell you that there is a family history of allergies to eggs and peanuts, and they ask how to reduce their child''s risk of developing these food allergies. Evidence supports exposing the patient to these potentially allergenic foods starting at which one of the following ages?', 0, 'The lowest risk of developing future allergies to many foods, including peanuts and eggs, occurs with early exposure at 4-6 months of age. Peanut butter can be thinned with water, breast milk, or formula.', 'Bright DM, Stegall HL, Slawson DC. Food allergies: diagnosis, treatment, and prevention. Am Fam Physician. 2023;108(2):159-165.', '["4-6 months","9-12 months","1-2 years","3-5 years",">5 years"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 23-year-old female presents after a sexual assault that occurred the prior evening. She reports nonconsensual penetrative vaginal intercourse. She elects to undergo a medical forensic examination, which is completed with the help of a certified Sexual Assault Nurse Examiner. A urine pregnancy test is negative. Which one of the following would be most appropriate to offer at this time?', 3, 'Women who experience sexual assault should be offered empiric treatment for Neisseria gonorrhoeae, Chlamydia trachomatis, and Trichomonas vaginalis, which includes ceftriaxone, azithromycin, and either metronidazole or tinidazole.', 'Farahi N, McEachern M. Sexual assault of women. Am Fam Physician. 2021;103(3):168-176.', '["Emtricitabine/tenofovir alafenamide (Descovy)","Norgestimate/ethinyl estradiol (Sprintec)","Sofosbuvir/velpatasvir (Epclusa)","Azithromycin (Zithromax), ceftriaxone, and metronidazole (Flagyl)","The etonogestrel implant (Nexplanon)"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 29-year-old female presents with a long-standing history of episodes of depressed mood, headaches, and irritability that occur in the 1-2 weeks preceding her menses. She has a history of anxiety that is well controlled on fluoxetine (Prozac), 60 mg daily. She has a copper IUD (Paragard) for contraception. She has tried combined oral contraceptives to control the premenstrual symptoms, but found that they worsened her irritability. Which one of the following treatments would be most effective for this patient''s symptoms?', 1, 'Symptoms of premenstrual syndrome (PMS) with mood instability can be reduced with 1000-1200 mg of calcium carbonate daily. This patient is already on a max dose of an SSRI (fluoxetine) and did not tolerate combined oral contraceptives, which are other first-line options.', 'Hofmeister S, Bodden S. Premenstrual syndrome and premenstrual dysphoric disorder. Am Fam Physician. 2016;94(3):236-240.', '["Extended-release bupropion, 150 mg daily","Calcium carbonate, 600 mg twice daily","Dutasteride (Avodart), 0.5 mg daily","Vitamin D3 (cholecalciferol), 1000 IU daily","Acupuncture"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 72-year-old female with osteoporosis (T-score -2.8) is seen in your office for the first time. She was prescribed alendronate (Fosamax), 70 mg weekly, by her previous physician. The patient took the medication but discontinued it after 4 weeks because of gastrointestinal symptoms. Which one of the following would be the most appropriate action at this time?', 4, 'Oral bisphosphonates are considered first-line treatment for osteoporosis, but they can cause gastrointestinal irritation. If oral bisphosphonates are not tolerated despite correct administration (on an empty stomach, remaining upright for 30 minutes), intravenous bisphosphonates should be considered.', 'Harris K, Zagar CA, Lawrence KV. Osteoporosis: common questions and answers. Am Fam Physician. 2023;107(3):238-246.', '["Discontinuing the medication only","Instructing the patient to take the medication before bed","Instructing the patient to take the medication with food","Discontinuing the medication and starting raloxifene (Evista)","Discontinuing the medication and arranging for intravenous bisphosphonates"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 27-year-old patient presents to the emergency department with a fever, headache, and stiff neck. You diagnose sepsis and perform a lumbar puncture. The results are consistent with bacterial meningitis. In addition to antibiotics, which one of the following intravenous therapies is most likely to improve mortality?', 1, 'Intravenous (IV) dexamethasone, when given shortly before or at the time of administration of IV antibiotics, has been shown to improve mortality and neurologic sequelae in adults with bacterial meningitis.', 'Brouwer MC, McIntyre P, Prasad K, van de Beek D. Corticosteroids for acute bacterial meningitis. Cochrane Database Syst Rev. 2015;2015(9):CD004405.', '["Acyclovir","Dexamethasone","Furosemide","Glycerol","Immunoglobulin"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 33-year-old male presents for follow-up of long-standing heartburn. His symptoms have been present for 3 years and recent treatment for 1 month with pantoprazole (Protonix) has only provided partial relief. He has had dysphagia with solids, and a food impaction 3 months ago that resolved spontaneously. Upper endoscopy reveals eosinophilic esophagitis. Which one of the following is most likely to improve this patient''s symptoms?', 1, 'Eosinophilic esophagitis is an inflammatory condition triggered by food antigens. First-line pharmacologic treatment is an oral or swallowed topical corticosteroid such as oral budesonide suspension.', 'Arnold MJ. Eosinophilic esophagitis: management guidelines from the AGA and JTF. Am Fam Physician. 2021;103(9):573-574.', '["A clotrimazole oropharyngeal lozenge","Budesonide oral suspension (Eohilia)","Oral famotidine (Pepcid)","Oral metoclopramide (Reglan)","Oral montelukast (Singulair)"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 45-year-old male with a recent diagnosis of Crohn disease presents to your office for a health maintenance examination. His current medications include methotrexate and azathioprine (Imuran). He received a Tdap vaccine 6 years ago and recently received a seasonal influenza vaccine and an updated COVID-19 vaccine. Which one of the following vaccines should you recommend today?', 0, 'Adults with inflammatory bowel disease (IBD) are considered immunosuppressed or at increased risk, and should receive a pneumococcal vaccine. The live MMR vaccine is contraindicated in patients already on immunosuppressive treatment (methotrexate, azathioprine).', 'Farraye FA, Melmed GY, Lichtenstein GR, Kane SV. ACG clinical guideline: preventive care in inflammatory bowel disease. Am J Gastroenterol. 2017;112(2):241-258.', '["20-valent pneumococcal conjugate vaccine (PCV20, Prevnar 20)","Meningococcal","MMR","Tdap","Zoster vaccine (Shingrix)"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 19-year-old college student with a history of depression, adrenal insufficiency, and hypothyroidism is brought to the urgent care clinic after a syncopal episode. She reports progressive weakness, severe abdominal pain, nausea, and vomiting. Her blood pressure is 97/58 mm Hg. Labs show Sodium 133 mEq/L, Potassium 5.8 mEq/L, and Glucose 60 mg/dL. Which one of the following therapies should be started as soon as possible?', 2, 'This patient''s chronic corticosteroid use, symptoms, and electrolyte abnormalities (hyponatremia, hyperkalemia, hypoglycemia) suggest she is experiencing an adrenal crisis. The correct initial treatment is intravenous hydrocortisone.', 'Bornstein SR, Allolio B, Arlt W, et al. Diagnosis and treatment of primary adrenal insufficiency: an Endocrine Society clinical practice guideline. J Clin Endocrinol Metab. 2016;101(2):364-389.', '["Intramuscular glucagon, 1 mg","Intravenous dexamethasone, 1 mg","Intravenous hydrocortisone (Solu-Cortef), 100 mg","Intravenous levofloxacin, 500 mg","Intravenous ondansetron, 4 mg"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 37-year-old female is brought to the emergency department by ambulance after collapsing while standing in line at a bookstore. Her friend witnessed the episode and describes it as ''fainting.'' The patient''s past medical history and a physical examination, including vital signs and a neurologic assessment, are unremarkable. Which one of the following would be the most appropriate next step in the evaluation of this patient with suspected syncope?', 1, 'Electrocardiography (EKG) is a primary evaluation tool, along with a comprehensive history and physical examination, to investigate the etiology of a syncopal episode. Routine use of EEG, carotid ultrasound, or head CT is not recommended in patients with a normal neurologic examination.', 'Runser LA, Gauer RL, Houser A. Syncope: evaluation and differential diagnosis. Am Fam Physician. 2017;95(5):303-312B.', '["No further testing","An EKG","An EEG","Carotid ultrasonography","Head CT"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 64-year-old male presents with urinary frequency. His symptoms have been ongoing for months, but he says they have acutely worsened in the last 6-8 weeks. His symptoms are predominantly storage-related with daytime frequency, nocturia, urgency, and infrequent incontinence. He also reports difficulty voiding, noting a weak stream and hesitancy. Urinalysis is negative. In addition to behavioral and lifestyle alterations, which one of the following medications should you recommend for initial therapy?', 1, 'The most appropriate initial treatment for lower urinary tract symptoms, regardless of the predominance of storage symptoms or voiding symptoms, is an alpha-blocker (alpha-antagonist) such as tamsulosin, alfuzosin, or terazosin.', 'Lerner LB, McVary KT, Barry MJ, et al. Management of lower urinary tract symptoms attributed to benign prostatic hyperplasia: AUA guideline part I-initial work-up and medical management. J Urol. 2021;206(4):806-817.', '["A 5-a-reductase inhibitor","An a-antagonist","An anticholinergic","A B3-agonist","A phosphodiesterase-5 inhibitor"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 5-day-old male is brought to your office by his mother for an initial well child visit. The mother gave birth 102 hours ago through vaginal delivery. She is concerned that he is not getting enough milk despite exclusively breastfeeding 10-12 times per day. Which one of the following factors, if present, would indicate inadequate breastfeeding at this time?', 1, 'An infant who is feeding adequately should produce 6 or more wet diapers and 3 or more stools after 4 days of life. Four wet diapers at day 5 is inadequate and warrants further assessment and support.', 'Westerfield KL, Koenig K, Oh R. Breastfeeding: common questions and answers. Am Fam Physician. 2018;98(6):368-373.', '["Four green stools per day","Four wet diapers per day","Infant weight loss of 5% from birth weight","Maternal breasts that appear small and not full","Maternal nipple pain during the first 15 seconds of each feed"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 25-year-old male presents to the urgent care clinic with a 4-day history of fever, chills, myalgias, and cough. His temperature is 38.3 C (100.9 F), and his heart rate and blood pressure are within the normal range. Rapid antigen testing is positive for influenza B. Which one of the following is the most appropriate treatment for this patient''s influenza B?', 0, 'According to the CDC, antiviral treatment for influenza (like oseltamivir) is not recommended for non-high-risk individuals who present more than 48 hours after symptom onset. Thus, supportive therapy is most important for this patient who is at low risk for hospitalization and presents on day 4.', 'Gaitonde DY, Moore FC, Morgan MK. Influenza: diagnosis and treatment. Am Fam Physician. 2019;100(12):751-758.', '["Supportive therapy","Methylprednisolone (Medrol)","Oseltamivir (Tamiflu)","Rimantadine"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 30-year-old male with a long-standing history of obsessive-compulsive disorder presents for follow-up to discuss potential pharmacotherapy due to an inadequate treatment response to psychotherapy. Which one of the following medications would be most likely to improve this patient''s symptoms while minimizing the risk of adverse side effects?', 4, 'The most effective first-line medication therapy options for obsessive-compulsive disorder (OCD) are SSRIs, such as sertraline, fluoxetine, fluvoxamine, and paroxetine. While clomipramine is FDA-approved for OCD, it is a TCA with a higher toxicity risk and is not a first-line agent.', 'Semenya AM, Bhatnagar P. Diagnosis and management of obsessive-compulsive disorder in the primary care setting. Am Fam Physician. 2024;110(4):385-392.', '["Bupropion","Buspirone","Clomipramine (Anafranil)","Quetiapine (Seroquel)","Sertraline (Zoloft)"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 76-year-old female with hypertension sees you for a routine follow-up visit. She fell about 2 weeks ago while hurrying to answer her home telephone, and sustained bruising and swelling of the left lower leg. She does not recall feeling dizzy or lightheaded before the fall. She lives alone and performs activities of daily living independently. Which one of the following has the best evidence to prevent future falls and associated serious injury?', 2, 'In community-dwelling older adults who are identified as being at higher risk of falls, the U.S. Preventive Services Task Force found that exercise interventions lower the risk of falls and should be recommended. Both individual and group exercise programs are beneficial.', 'Final recommendation statement: falls prevention in community-dwelling older adults: interventions. US Preventive Services Task Force. Updated June 4, 2024.', '["Patient education on fall harms and prevention","Use of a cane while walking","Referral to a group exercise program, including gait, balance, and functional training","Referral to an ophthalmologist for a comprehensive vision assessment","Referral to a podiatrist for footwear assessment"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'Which one of the following would be most appropriate for initial treatment of Helicobacter pylori infection?', 3, 'Infection with Helicobacter pylori should be treated when it causes symptoms. Guidelines currently recommend optimized quadruple therapy with bismuth, metronidazole, omeprazole, and tetracycline. This combination is approximately 91% effective at eradicating H pylori infection. Dual therapy with vonoprazan and amoxicillin is an option for patients who are unable or unwilling to take quadruple therapy, but its eradiation rates only range from 70% to 80%. Regimens containing clarithromycin or levofloxacin should be limited to infections with documented susceptibility to macrolides or fluoroquinolones, respectively.', 'Chey WD, Howden CW, Moss SF, et al. ACG clinical guideline: treatment of Helicobacter pylori infection. Am J Gastroenterol. 2024;119(9):1730-1753.', '["Dual therapy with vonoprazan (Voquezna) and amoxicillin","Triple therapy with omeprazole, amoxicillin, and clarithromycin","Triple therapy with omeprazole, amoxicillin, and levofloxacin","Quadruple therapy with bismuth, omeprazole, metronidazole, and tetracycline"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'The parent of a 5-year-old male calls your office after the child sustains burns to his arms and chest while helping his father boil pasta in the kitchen. The father tells you that the burned areas of skin are red without any open areas. He estimates the size of the burns on the arms at 2-3 cm in diameter and those on the chest at 5-6 cm. The child is crying in pain and the father asks what he should do. Which one of the following immediate interventions has the best evidence of reducing burn depth, improving healing time, and decreasing skin graft requirements?', 0, 'The initial treatment goals for burn injuries include limiting the extent of the injury, cleaning the area, and managing pain. Removing clothing limits the injury related to scalding. The most effective way to limit the extent of injury is to cool the burn surface by running cool tap water over the burn surface for at least 20 minutes. This intervention has been shown to reduce burn depth, improve healing time, and decrease skin graft requirements. Applying ice to the burn surfaces is not recommended due to the risk of vasoconstriction. Wet dressings are not effective as a cooling strategy.', 'Lanham JS, Nelson NK, Hendren B, Jordan TS. Outpatient burn care: prevention and treatment. Am Fam Physician. 2020;101(8):463-470.', '["Cooling the burn surfaces with running tap water","Applying ice to the burn surfaces","Covering the burn surfaces with cool, wet gauze","Applying aloe vera gel to the burn surfaces and leaving them uncovered","Applying diclofenac gel to the burn surfaces and leaving them uncovered"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 45-year-old female with a past medical history of obesity and cigarette smoking presents with a popliteal deep vein thrombosis of the right leg, confirmed on ultrasonography. She has no prior history of venous thromboembolism and has not had any recent surgery, trauma, or immobilization. She does not take any medications. Which one of the following anticoagulation regimens would be the most appropriate initial treatment?', 0, 'Direct-acting oral anticoagulants (DOACs) are now recommended as monotherapy for outpatient management of deep vein thrombosis. DOACs reach therapeutic levels quickly; therefore, concomitant initiation of unfractionated or low-molecular-weight heparin (LMWH) is not necessary. DOACs have less major bleeding and require less monitoring, making them preferred over warfarin.', 'Stevens SM, Woller SC, Kreuziger LB, et al. Antithrombotic therapy for VTE disease: compendium and review of CHEST guidelines 2012-2021. Chest. 2024;166(2):388-404.', '["A direct-acting oral anticoagulant (DOAC) only","Low-molecular-weight heparin (LMWH) only","Warfarin only","LMWH for 7 days, followed by warfarin","Unfractionated heparin for 48 hours, followed by a DOAC"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'Which one of the following puts a patient at the highest risk of developing breast cancer?', 4, 'Women who received chest radiotherapy as children are at increased risk for breast cancer as adults, with those who received whole lung radiation at especially high risk. Other risk factors for breast cancer include the onset of menopause at >55 years of age, a first pregnancy at >35 years of age, and a first-degree relative with breast cancer. Patients with dense (not fatty) breasts have a higher amount of glandular and stromal tissue and are at higher risk.', 'Khan M, Chollet A. Breast cancer screening: common questions and answers. Am Fam Physician. 2021;103(1):33-41.', '["A first pregnancy at <30 years of age","Onset of menopause at <50 years of age","Fatty breasts on mammography","A grandmother with a history of breast cancer","Chest radiation therapy as a child"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'An 83-year-old female sees you for follow-up 2 weeks after being discharged home from an acute rehabilitation facility. She experienced an acute ischemic stroke 6 weeks ago and spent several weeks in the rehabilitation setting after an initial hospital stay. Home health services have been assisting her since she returned home. Today she reports improved mobility, speech, and swallowing, but persistent difficulties with low mood. She finds it difficult to enjoy hobbies and avoids visiting with family and friends. She has been sleeping more than usual and finds it difficult to get out of bed in the morning. You diagnose poststroke depression. In addition to talk therapy, which one of the following is recommended as first-line therapy for this condition?', 1, 'Poststroke depression (PSD) is a common complication that occurs in 20%-60% of patients with stroke. SSRIs such as escitalopram are considered first-line therapy for PSD. Other options include SNRIs, tricyclic antidepressants (TCAs), and newer multimodal agents such as vortioxetine. Bupropion may be considered if SSRIs are ineffective or cannot be tolerated. As a class, TCAs have a higher anticholinergic effect than SSRIs and are therefore not preferred.', 'Masuccio FG, Grange E, Di Giovanni R, Rolla M, Solaro CM. Post-stroke depression in older adults: an overview. Drugs Aging. 2024;41(4):303-318.', '["Bupropion","Escitalopram (Lexapro)","Nortriptyline (Pamelor)","Repetitive transcranial magnetic stimulation"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'Patients with which one of the following should be provided opioid overdose education and a prescription for naloxone?', 0, 'The 2022 CDC clinical practice guideline for prescribing opioids recommends that clinicians offer naloxone to patients at increased risk of overdose, including patients with a history of substance use, overdose, and sleep-disordered breathing, as well as patients who take higher dosages of opioids (>=50 MME/day), take benzodiazepines concurrently with opioids, or are at risk of returning to higher opioid dosages with loss of tolerance.', 'Dowell D, Ragan KR, Jones CM, Baldwin GT, Chou R. CDC clinical practice guideline for prescribing opioids for pain-United States, 2022. MMWR Recomm Rep. 2022;71(3):1-95.', '["A history of substance use disorder","A prescription for alprazolam (Xanax), 1 mg nightly as needed","A 3-day prescription for hydrocodone/acetaminophen, 5/325 mg twice daily","A prescription through hospice treatment for morphine, 10 mg as needed"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old female with a medical history of hypothyroidism, hypertension, and morbid obesity with a recent gastric bypass surgery presents with a history of dizziness, sweating, shaking, fatigue, and occasional fainting, occurring 1-2 hours after consuming beverages containing dairy products or a high sugar content. Her blood glucose levels, measured with her husband''s glucometer during each episode, range between 50 mg/dL and 55 mg/dL. Which one of the following is the most likely cause of this patient''s symptoms?', 3, 'The most likely cause of this patient''s symptoms is late dumping syndrome. Dumping syndrome is a common postbariatric surgery complication occurring in about 40% of patients. Late dumping syndrome is caused by the rapid absorption of carbohydrates, leading to exaggerated insulin secretion, resulting in chemical evidence of hypoglycemia occurring 1-3 hours after eating.', 'Vavricka SR, Greuter T. Gastroparesis and dumping syndrome: current concepts and management. J Clin Med. 2019;8(8):1127.', '["Gastroparesis","Idiopathic postprandial syndrome","Insulinoma","Late dumping syndrome"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A 10-month-old male is brought to your office with a 1-day history of fussiness and tugging at his ear. The child''s mother says that he has had a fever this morning. He is up to date on all immunizations, and he does not have a history of previous ear infections or recent illness. He has a history of hives after being given amoxicillin. On examination the child has a temperature of 39.2 C (102.6 F) but seems to be only slightly uncomfortable. When you examine his ears you note moderate bulging of the left tympanic membrane and normal findings in the right ear. According to the American Academy of Pediatrics guidelines, which one of the following would be the most appropriate initial management?', 2, 'The AAP recommends antibiotic therapy for children <24 months of age with either bilateral or unilateral acute otitis media with severe signs. Penicillin-allergic patients should be treated with an alternative antibiotic such as cefdinir, cefuroxime, cefpodoxime, or ceftriaxone. Ciprofloxacin should not be used in children, and sulfamethoxazole/trimethoprim is no longer effective due to Streptococcus pneumoniae resistance.', 'Paul CR, Frohna JG. Acute otitis media. Pediatrics in Review. 2025;46(3):139-147.', '["Amoxicillin","Amoxicillin/clavulanate (Augmentin)","Cefdinir","Ciprofloxacin (Cipro)","Sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 5-year-old male is brought to the emergency department (ED) by his parents for evaluation after falling from a kitchen table just prior to arrival. The mother states that the child climbed onto the table and fell off before she could reach him. He landed directly on the right side of his head and did not lose consciousness. She witnessed 1 episode of vomiting after the fall but no additional episodes since then. On physical examination, the patient is tearful but consolable. You note a right-sided parietal hematoma. There are no palpable skull fractures or signs of altered mental status. Which one of the following would be the most appropriate next step in management?', 0, 'This patient likely has a mild traumatic brain injury (mTBI), or concussion, based on the mechanism of injury and the presence of vomiting. This patient''s TBI would be classified as mild due to the lack of worsening symptoms or additional concerning findings on examination. For these reasons, reassurance and outpatient observation with follow-up is the most appropriate next step. Routine imaging is not recommended for mTBI in children.', 'Lumba-Brown A, Yeates KO, Sarmiento K, et al. Centers for Disease Control and Prevention guideline on the diagnosis and management of mild traumatic brain injury among children. JAMA Pediatr. 2018;172(11):e182853.', '["Providing reassurance and recommending outpatient follow-up","Observation in the ED for worsening symptoms","Radiography of the skull","CT of the head and neck","Contacting child protective services"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 32-year-old male presents for advice on smoking cessation. He has smoked 10 cigarettes per day for the past 10 years. His grandmother was recently diagnosed with lung cancer, and he is motivated to quit. You advise him that smoking cessation is the most important action that he can take for his health, and you counsel him about effective behavioral interventions. Which one of the following behavioral changes would improve this patient''s chances of smoking cessation?', 0, 'Behavioral interventions are effective treatments for smoking cessation. Advising a patient who wishes to stop smoking to create a smoke-free home and car environment is a highly effective behavioral intervention. There is no evidence to support caffeine intake, switching to menthol cigarettes, or hypnotherapy.', 'Rigotti NA, Kruse GR, Livingstone-Banks J. Treatment of tobacco smoking: a review. JAMA. 2022;327(6):566-577.', '["Creating a smoke-free home","Increasing his caffeine intake","Switching to menthol cigarettes","Undergoing hypnotherapy"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'Which one of the following medications is the recommended initial management of COPD in patients who are classified as GOLD group A?', 0, 'Long-acting muscarinic antagonists (LAMAs) such as umeclidinium are recommended as the preferred initial management of COPD that is classified as GOLD group A. Long-acting beta-agonists (LABAs) such as formoterol may be used as an alternative for these patients. LAMA/LABA combinations are recommended as initial management for GOLD group B and E.', 'Cagle SD Jr, Landrum LS, Kennedy AM. Chronic obstructive pulmonary disease: diagnosis and management. Am Fam Physician. 2023;107(6):604-612.', '["Inhaled umeclidinium (Incruse Ellipta)","Inhaled aclidinium bromide/formoterol (Duaklir Pressair)","Inhaled budesonide/formoterol (Symbicort)","Inhaled fluticasone furoate/umeclidinium/vilanterol (Trelegy Ellipta)","Nebulized formoterol (Perforomist)"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 29-year-old female with type 2 diabetes is brought to the emergency department by her family, who state that she has grown increasingly confused over the last few days, with additional symptoms of polyuria and polydipsia. Her initial vital signs demonstrate hypotension and tachycardia. Laboratory Findings reveal a Serum glucose of 750 mg/dL, Serum osmolality of 350 mOsm/kg, trace Urine ketones, Arterial pH of 7.3, and a normal Anion gap. Which one of the following would be the most appropriate initial treatment?', 2, 'The appropriate diagnosis is hyperglycemic hyperosmolar state (HHS), rather than diabetic ketoacidosis (DKA), given her lack of significant ketonuria and acidosis. She is hypovolemic and dehydrated. Initial treatment consists of intravenous fluids with isotonic solutions, such as 0.9% normal saline or lactated Ringer solution.', 'Umpierrez GE, Davis GM, ElSayed NA, et al. Hyperglycemic crises in adults with diabetes: a consensus report. Diabetes Care. 2024;47(8):1257-1275.', '["Subcutaneous short-acting insulin","Subcutaneous long-acting insulin","Intravenous isotonic fluid hydration","Intravenous isotonic fluid hydration with sodium bicarbonate"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 65-year-old male with symptomatic heart failure presents for follow-up. He currently has no symptoms of dyspnea at rest, but has moderate to significant limitations with ordinary activity. His most recent echocardiogram showed a left ventricular ejection fraction of 38%. His last hemoglobin A1c was the highest it has ever been at 6.3%, and he does not take any glucose-lowering medications. His current medications include losartan (Cozaar), carvedilol (Coreg), furosemide (Lasix), and spironolactone (Aldactone). On examination he has a blood pressure of 120/75 mm Hg and an oxygen saturation of 94% on room air, and there are no pulmonary crackles or peripheral edema. Adding which one of the following would be most likely to further reduce this patient''s mortality risk?', 2, 'Treatment with an SGLT2 inhibitor is recommended to decrease all-cause mortality in patients with heart failure with reduced ejection fraction (HFrEF), regardless of the presence or absence of diabetes mellitus.', 'Heidenreich PA, Bozkurt B, Aguilar D, et al. 2022 AHA/ACC/HFSA guideline for the management of heart failure. Circulation. 2022;145(18):e895-e1032.', '["A calcium channel blocker","A GLP-1 receptor agonist","An SGLT2 inhibitor","A thiazide diuretic","Metformin"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 45-year-old male with a past medical history of hyperlipidemia and obesity presents with concerns of polydipsia and polyuria that have progressively worsened over the last 2 weeks. His older sister was recently diagnosed with type 2 diabetes and your patient asks to be tested. Which one of the following test results would be sufficient to diagnose diabetes in this patient?', 3, 'According to guidelines from the American Diabetes Association, diabetes mellitus can be diagnosed with a random blood glucose level >=200 mg/dL in patients with classic symptoms of hyperglycemia, such as polyuria and polydipsia, as seen in this patient. Other tests (A1c >=6.5%, fasting glucose >=126 mg/dL) require a second abnormal laboratory value to confirm the diagnosis in asymptomatic patients.', 'American Diabetes Association Professional Practice Committee. 2. Diagnosis and classification of diabetes: standards of care in diabetes-2025. Diabetes Care. 2025;48(suppl 1):S27-S49.', '["A hemoglobin A1c >=6.0%","A 1-hour plasma glucose level >=140 mg/dL on 50-g oral glucose testing","A fasting plasma glucose level >=120 mg/dL","A random blood glucose level >=200 mg/dL"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 36-year-old male presents to your office with continued pain in his right arm after sustaining a right forearm fracture 6 weeks ago that was treated with cast immobilization. At the time of the injury, he noted a severe, throbbing pain in his right forearm that improved with NSAID therapy. Now, he feels a severe, sharp pain with burning and numbness throughout the arm and hand that worsens with any pressure, including clothing. He reports weakness in his right hand and notes that he drops objects such as cups. He is afebrile and his vital signs are within normal limits. An examination reveals pain to light touch in the right arm. The right arm is warmer to the touch than the left arm with trace edema noted. The patient''s right-hand grip is 4/5, and his left-hand grip is 5/5. You note 2+ radial and brachial pulses and normal bilateral reflexes. Which one of the following is the most likely etiology of this patient''s pain?', 1, 'This patient meets the Budapest criteria for complex regional pain syndrome (CRPS) including hyperalgesia, temperature asymmetry, evidence of edema, and motor weakness following trauma to the limb. CRPS is a clinical diagnosis. The absence of fever or other signs of infection makes cellulitis unlikely.', 'Harden RN, McCabe CS, Goebel A, et al. Complex regional pain syndrome: practical diagnostic and treatment guidelines, 5th edition. Pain Med. 2022;23(suppl 1):S1-S53.', '["Cellulitis","Complex regional pain syndrome","Factitious disorder","Functional neurologic symptom disorder (conversion disorder)","Peripheral neuropathy"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 28-year-old nulligravida has a 2- to 3-day history of severe lower abdominal pain. On examination the patient''s temperature is 37.7 C (99.9 F), bowel sounds are normal, and there is diffuse lower abdominal tenderness without rebound. On pelvic examination there is adnexal tenderness and pain on cervical motion. Vaginal discharge shows leukocytes. A pregnancy test is negative. In addition to sexually transmitted infection testing and empiric treatment, which one of the following should you recommend?', 0, 'This patient''s likely diagnosis is pelvic inflammatory disease (PID), and the diagnosis can be made clinically in most cases. In women at risk of PID, treatment should be initiated if any of the following are present: cervical motion tenderness, uterine tenderness, or adnexal tenderness. A pelvic ultrasound may show fluid-filled or thickened tubes in the setting of PID, but it is not routinely indicated unless tubo-ovarian abscess is suspected.', 'Curry A, Williams T, Penny ML. Pelvic inflammatory disease: diagnosis, management, and prevention. Am Fam Physician. 2019;100(6):357-364.', '["No further testing","A repeat pregnancy test in 7 days","Pelvic ultrasonography","Pelvic MRI","Laparoscopy"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 65-year-old male with a past medical history of hypertension and hyperlipidemia presents to the urgent care clinic approximately 20 hours after experiencing an episode of sudden-onset right-hand weakness. He was suddenly unable to grasp his utensils while eating dinner. These symptoms resolved after about 20 minutes. His wife had encouraged him to seek urgent evaluation, but he declined because his symptoms had resolved. Today the patient''s vital signs include a blood pressure of 124/72 mm Hg, a heart rate of 80 beats/min, and a respiratory rate of 12/min. The neurologic examination findings are normal. An EKG shows normal sinus rhythm. The ABCD2 score is 4. Further management includes which one of the following regimens?', 3, 'In patients presenting with a moderate- to high-risk TIA or minor stroke within 24 hours of symptom onset, dual antiplatelet therapy (DAPT) for 21 days prior to transitioning to a single antiplatelet agent decreases the 90-day stroke risk from 7.8% to 5.2% compared to aspirin alone. This patient has symptoms consistent with a high-risk TIA based on an ABCD2 score of 4.', 'Mendelson SJ, Prabhakaran S. Diagnosis and management of transient ischemic attack and acute ischemic stroke: a review. JAMA. 2021;325(11):1088-1098.', '["Aspirin, 81 mg daily","Clopidogrel (Plavix), 300 mg on day 1, followed by 75 mg daily","Clopidogrel, 300 mg on day 1, followed by 75 mg daily on days 2-10; plus aspirin, 81 mg daily","Clopidogrel, 300 mg on day 1, followed by 75 mg daily on days 2-21; plus aspirin, 81 mg daily"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old patient with a previous history of opioid use disorder and untreated hypertension presents to your office to establish care. They are now in recovery and would like to catch up on screening laboratory studies. Their blood pressure today is 160/90 mm Hg. Laboratory studies show elevated AST, ALT, and alkaline phosphatase levels and are positive for hepatitis C antibody and hepatitis C viral load. Testing for hepatitis B and HIV is negative. Lipids are elevated. You calculate an atherosclerotic cardiovascular disease 10-year risk score of 10%. A right upper quadrant ultrasound shows fibrotic changes of the liver. The patient is surprised that they have liver damage, as they feel well and have never consumed much alcohol. In addition to referring the patient to a gastroenterologist, which one of the following should you begin now to improve fibrotic changes?', 0, 'Treatment of hepatitis C in patients with metabolic dysfunction-associated steatohepatitis (formerly known as nonalcoholic steatohepatitis) can improve fibrotic changes, as can bariatric surgery. Prophylactic antibiotics and nonselective beta-blockers have specific indications in cirrhosis (e.g., SBP prophylaxis, variceal bleeding prophylaxis) but do not reverse fibrotic changes.', 'Smith A, Baumgartner K, Bositis C. Cirrhosis: diagnosis and management. Am Fam Physician. 2019;100(12):759-770.', '["Treatment of hepatitis C","Prophylactic antibiotics","A nonselective beta-blocker","Pre-exposure prophylaxis (PrEP) for HIV","Upper endoscopy with banding of any varices"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 46-year-old female sees you for an annual well woman visit. Her only concern is pelvic pressure that becomes more bothersome throughout the day. She notes occasional urinary incontinence of small amounts when coughing or running. She says these symptoms mildly bother her, and mostly wants to make sure there is not a more serious problem. On physical examination, using the lower half of a bivalve speculum, you note a prolapse of the anterior wall, 0.5 cm proximal to the hymenal ring. Which one of the following would be the most appropriate next step for this patient?', 1, 'A grade 2 prolapse indicates a prolapse that extends within 1 cm above or below the hymenal ring. Pelvic floor muscle training can reduce prolapse by 1-2 cm and provide subjective improvement in symptoms. Because she is only mildly bothered, surgical treatment is not recommended at this time.', 'Iglesia CB, Smithling KR. Pelvic organ prolapse. Am Fam Physician. 2017;96(3):179-185.', '["Reassurance only","Pelvic floor muscle training","Topical estrogen","Surgical consultation"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 72-year-old male with a past medical history of coronary artery disease, COPD, and hyperlipidemia sees you because of an acute onset of left lower leg pain 1 hour ago. He was in his usual state of health when the pain occurred. His left foot is numb and cold, and he is having difficulty walking. He has a 60-pack-year smoking history. Physical examination findings include a mottled appearance of the left lower leg and foot. Posterior tibial and dorsalis pedis pulses are absent. Which one of the following would be the most appropriate first step in management?', 4, 'This patient''s presentation is concerning for acute limb ischemia and he requires immediate transfer to an emergency facility with vascular surgeon accessibility (SOR C). Anticoagulation with unfractionated heparin should be started soon after arrival. Acute limb ischemia is a vascular emergency as skeletal muscle can only survive 4-6 hours without blood flow. It is characterized by the 6 P''s: pain, pallor, poikilothermia, pulselessness, paresthesia, and paralysis.', 'Rosenberg H, Rosenberg E, Kubelik D. Acute limb ischemia. CMAJ. 2023;195(40):E1383.', '["Rivaroxaban (Xarelto)","Stat duplex ultrasonography","Stat CT angiography","Expedited outpatient referral to a vascular surgeon","Transfer to the nearest emergency department with access to a vascular surgeon"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 22-year-old male presents with a 5-day history of left lower leg pain over the midshaft of his tibia. Two months ago, he started training for a half marathon. Radiographs performed yesterday at an urgent care clinic were normal. You suspect a bone stress injury. Which one of the following is the preferred definitive imaging modality to evaluate for a bone stress injury?', 3, 'Radiography is the initial imaging modality because of its high specificity, despite its low sensitivity. If the radiograph is negative and the patient remains symptomatic, then MRI is the preferred follow-up study for definitive diagnosis. It is preferred over CT and nuclear bone scintigraphy because it has higher sensitivity and specificity and avoids the use of radiation.', 'Schroeder JD, Trigg SD, Capo Dosal GE. Bone stress injuries: diagnosis and management. Am Fam Physician. 2024;110(6):592-600.', '["Repeat radiography in 1 week","Point-of-care ultrasonography","CT","MRI","Nuclear bone scintigraphy"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 32-year-old female presents to an urgent care clinic with a flare-up of her usually well-controlled chronic urticaria. She takes cetirizine (Zyrtec), 10 mg daily. Which one of the following should you recommend?', 1, 'The first-line treatment of chronic urticaria is an oral second-generation H1-antihistamine. If that is not effective, a reasonable next step is to increase the H1-antihistamine, up to 4 times the usual FDA-recommended dosing. Cyclosporine and omalizumab are reserved for severe refractory cases.', 'Schaefer P. Acute and chronic urticaria: evaluation and treatment. Am Fam Physician. 2017;95(11):717-724.', '["A pseudoallergen-free diet","Doubling the cetirizine dosage","A nasal corticosteroid","Cyclosporine (Sandimmune)","Omalizumab (Xolair)"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 35-year-old female comes to your office with an 8-day history of nasal congestion, rhinorrhea, and cough. Based on guidelines from the Infectious Diseases Society of America, this patient should be treated with antibiotic therapy if she has which one of the following additional symptoms?', 2, 'Most instances of acute bacterial rhinosinusitis improve without antibiotics, and watchful waiting for up to 10 days is recommended. Patients with severe symptoms (fever >=39 C with purulent nasal discharge and/or facial pain) or those with double sickening (new symptoms following improvement of an upper respiratory infection) should be treated immediately with empiric antibiotics.', 'Chow AW, Benninger MS, Brook I, et al. IDSA clinical practice guideline for acute bacterial rhinosinusitis in children and adults. Clin Infect Dis. 2012;54(8):e72-e112.', '["A fever up to 38.0 C (100.4 F)","Halitosis and tooth pain","An increase in nasal discharge after an initial improvement of symptoms","Purulent rhinorrhea"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'You are seeing a 44-year-old female who has a 25-pack-year smoking history. She quit smoking 6 years ago after a friend received a diagnosis of lung cancer. According to U.S. Preventive Services Task Force recommendations, lung cancer screening should be initiated at what age in this patient?', 2, 'In 2021, the U.S. Preventive Services Task Force recommended annual screening with low-dose CT in adults 50-80 years of age who have a 20-pack-year smoking history and either currently smoke or have quit within the past 15 years.', 'Final recommendation statement: lung cancer: screening. US Preventive Services Task Force. Updated March 9, 2021.', '["No screening is indicated","45","50","55","60"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 25-year-old male presents with a 5-day history of dysuria and mucopurulent penile discharge. On examination the urethral meatus is erythematous and a small amount of discharge is noted. A urine dipstick is positive for leukocyte esterase and a nucleic acid amplification test is negative for Neisseria gonorrhoeae and Chlamydia trachomatis. Which one of the following would be the most appropriate treatment?', 0, 'This patient has nongonococcal urethritis with negative gonorrhea and chlamydia testing, which should be treated with azithromycin or doxycycline (covering Mycoplasma genitalium). Of the cases with known etiologies, Mycoplasma genitalium is responsible for 15%-20%. Treatment options for M genitalium include azithromycin, 1 g orally; doxycycline, 100 mg twice daily for 1 week; or moxifloxacin.', 'Sell J, Nasir M, Courchesne C. Urethritis: rapid evidence review. Am Fam Physician. 2021;103(9):553-558.', '["Azithromycin (Zithromax), 1 g orally once","Levofloxacin, 500 mg orally for 7 days","Ceftriaxone, 500 mg intramuscularly once","Gentamicin, 240 mg intramuscularly once, plus azithromycin, 2 g orally once","Metronidazole, 2 g orally once, plus doxycycline, 100 mg orally twice daily for 7 days"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 55-year-old female presents to the emergency department with what she describes as the worst headache of her life that began suddenly 1 hour ago. Her medical history is significant for tobacco use and uncontrolled hypertension. She indicates that she has had a few headaches over the last month, but today''s headache came on suddenly and is extremely intense, unlike the previous headaches. There is no history of head trauma. Her accompanying relative adds that the patient has been experiencing waxing and waning levels of consciousness since the sudden onset of the headache. She has vomited several times, secondary to pain from the headache. Which one of the following is the most important, immediate next step in management?', 2, 'This patient''s clinical picture is most consistent with a subarachnoid hemorrhage. The most immediate and meaningful next step is to order a CT scan of the head to verify the diagnosis of subarachnoid hemorrhage. Brain MRI would take longer to obtain. A lumbar puncture should be considered if the head CT scan is negative but clinical suspicion remains high.', 'Arnold MJ. Management of patients with aneurysmal subarachnoid hemorrhage: guidelines from the AHA and ASA. Am Fam Physician. 2024;110(2):204-206.', '["Morphine","Ondansetron","Head CT","Brain MRI","Lumbar puncture"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 28-year-old male who uses cannabis daily presents with a 2-week history of persistent nausea and vomiting. He notes little relief from previously prescribed ondansetron but does feel better during a hot shower. While tapering his cannabis use, which one of the following would be most likely to improve this patient''s nausea?', 1, 'This patient has cannabinoid hyperemesis syndrome, characterized by heavy chronic cannabis use and nausea that improves with hot baths or showers. Current evidence suggests that haloperidol is more effective than more traditionally used antiemetics, such as metoclopramide or prochlorperazine, or corticosteroids in managing nausea associated with this syndrome. Topical capsaicin (not diclofenac) has also been shown to be effective.', 'Rubio-Tapia A, McCallum R, Camilleri M. AGA clinical practice update on diagnosis and management of cannabinoid hyperemesis syndrome: commentary. Gastroenterology. 2024;166(5):930-934.e1.', '["Topical diclofenac gel","Haloperidol","Metoclopramide (Reglan)","Prednisone","Prochlorperazine"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 30-year-old female with fibromyalgia sees you for follow-up. Her symptoms include widespread pain and prominent fatigue. At your advice, she has engaged in a trial of multidisciplinary, nonpharmacologic treatment including structured exercise, cognitive behavioral therapy, and therapeutic massage, and has experienced only partial improvement in her symptoms. She expresses interest in trying a medication to treat her pain. Which one of the following medications would be most likely to improve this patient''s pain?', 1, 'Duloxetine is an SNRI that is effective for treating fibromyalgia pain (SOR A). Other medications with level A evidence of effectiveness in reducing fibromyalgia-related pain include amitriptyline, cyclobenzaprine, and pregabalin. NSAIDs and acetaminophen are no better than placebo.', 'Winslow BT, Vandal C, Dang L. Fibromyalgia: diagnosis and management. Am Fam Physician. 2023;107(2):137-144.', '["Acetaminophen","Duloxetine (Cymbalta)","Gabapentin (Neurontin)","Hydrocodone/acetaminophen","Ibuprofen"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'An 8-year-old male is brought to your office by his parents because of concerns about ongoing nocturnal enuresis. He wets his bed several nights per week despite behavioral interventions. He has no daytime urinary symptoms. Physical examination findings and urinalysis are normal. You discuss treatment options and the parents indicate a preference for medication, as the patient will be attending an overnight summer camp in several weeks. Which one of the following would be the preferred pharmacologic treatment for this child''s nocturnal enuresis?', 0, 'Behavioral methods and enuresis alarms are first-line treatments for monosymptomatic nocturnal enuresis without an identifiable cause. If pharmacotherapy is initiated, intranasal or oral desmopressin is acceptable. Imipramine and oxybutynin are additional options if there is no response to oral desmopressin.', 'Lauters RA, Garcia KW, Arnold JJ. Enuresis in children: common questions and answers. Am Fam Physician. 2022;106(5):549-556.', '["Desmopressin (DDAVP)","Imipramine","Oxybutynin","Tamsulosin (Flomax)"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 25-year-old male with a childhood diagnosis of attention-deficit/hyperactivity disorder (ADHD) presents for re-evaluation of ADHD. He did not take medication for ADHD as a child. He is now having problems with attention and concentration that are affecting his work. He was recently placed on a stimulant medication, but had to discontinue it when his blood pressure and heart rate became elevated. He is still interested in pharmacologic therapy. Which one of the following would be the most appropriate next medication?', 0, 'Stimulants are first-line pharmacotherapy for adults with ADHD. When stimulants are not tolerated or do not provide an adequate response, the second-line therapy would be an SNRI such as atomoxetine or viloxazine. Clonidine and guanfacine are only approved for the treatment of ADHD in children and adolescents.', 'Olagunju AE, Ghoddusi F. Attention-deficit/hyperactivity disorder in adults. Am Fam Physician. 2024;110(2):157-166.', '["Atomoxetine (Strattera)","Clonidine","Escitalopram (Lexapro)","Guanfacine","Nortriptyline (Pamelor)"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 19-year-old college basketball player consults you for follow-up after sustaining an anterior shoulder dislocation for the first time. He initially presented to the emergency department where his shoulder was reduced and immobilized in a sling. Which one of the following is most likely to decrease the risk of future recurrence?', 3, 'Although anterior shoulder dislocations have a high rate of recurrence (up to 90%), evidence from cohort studies has consistently found a lower rate of recurrence in active patients <25 years of age who have received surgical treatment for first-time dislocations. Because of this patient''s age and activity level, referral for surgical repair would be appropriate.', 'Simon LM, Nguyen V, Ezinwa NM. Acute shoulder injuries in adults. Am Fam Physician. 2023;107(5):503-512.', '["Continued sling use for 4 weeks","Completion of a course of physical therapy","Administration of an intra-articular corticosteroid injection","Surgical repair"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A 32-year-old gravida 2 para 2 female who is 3 weeks post partum presents to the local urgent care center for left breast pain, swelling, and redness that started a few hours ago. She does not have fever or chills. A breast examination is significant for warm, tender, and mildly erythematous nodules localized to the upper outer quadrant of the left breast. In addition to initiating NSAIDs, which one of the following would be the most appropriate next step in management?', 0, 'The initial steps in managing inflammatory mastitis are supportive care with NSAIDs, cold compresses, and watchful waiting. Warm compresses and frequent breast pumping for complete breast emptying to avoid milk stasis are no longer recommended. Breast milk cultures and laboratory testing are generally not required for initial diagnosis or management.', 'Mitchell KB, Johnson HM, Rodriguez JM, et al. Academy of Breastfeeding Medicine Clinical Protocol #36: the mastitis spectrum, revised 2022. Breastfeed Med. 2022;17(5):360-376.', '["Applying cold compresses to the affected breast","Applying warm compresses to the affected breast","Using a manual breast pump on the affected breast for complete breast emptying","Obtaining a CBC and C-reactive protein levels","Obtaining a breast milk culture"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A young couple in your practice presents for preconception counseling. Both partners are known carriers of cystic fibrosis (CF). They ask what risk this poses to their future children. Which one of the following accurately reflects the risk of CF disease transmission to any potential offspring of this couple?', 1, 'Cystic fibrosis is a genetic disorder with an autosomal recessive pattern of inheritance. When both partners in a couple are carriers (heterozygous), any potential offspring has a 25% chance of being affected (homozygous recessive), a 50% chance of being an unaffected carrier, and a 25% chance of being an unaffected noncarrier.', 'Collins MS, Mansilla-Rivera K. Diagnostic and therapeutic advances in cystic fibrosis: how family physicians can partner in care. Am Fam Physician. 2024;109(5):388-390.', '["25% risk of being affected and 25% risk of being a carrier","25% risk of being affected and 50% risk of being a carrier","50% risk of being affected and 25% risk of being a carrier","50% risk of being affected and 50% risk of being a carrier"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 47-year-old nurse presents with a 9-month history of fatigue and brain fog that has kept them from working. Their symptoms began after a confirmed diagnosis of COVID-19. They report sleeping at least 7 hours per night but wake unrefreshed and experience lightheadedness throughout the day. They used to run 4 miles 5 days per week but now report feeling exhausted and experience energy crashes after showering and getting dressed. The patient''s vital signs and BMI are normal. A physical examination is unremarkable. Their Patient Health Questionnaire-9 (PHQ-9) score is 3. A CBC, TSH level, basic metabolic panel, and erythrocyte sedimentation rate are within the normal range. Which one of the following is the most likely diagnosis?', 2, 'Based on the National Academy of Medicine criteria for myalgic encephalomyelitis/chronic fatigue syndrome (ME/CFS), this patient has demonstrated the core symptoms of ME/CFS (unrefreshing sleep, new-onset fatigue, and postexertional malaise) for at least 6 months, in addition to brain fog and lightheadedness. Notably, their symptoms developed after a previous COVID-19 infection, an illness that is commonly associated with ME/CFS.', 'Latimer KM, Gunther A, Kopec M. Fatigue in adults: evaluation and management. Am Fam Physician. 2023;108(1):58-69.', '["Depression","Fibromyalgia","Myalgic encephalomyelitis/chronic fatigue syndrome (ME/CFS)","Obstructive sleep apnea","Systemic lupus erythematosus"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 62-year-old male is brought to the clinic by his wife for fatigue. His wife says he has been sleeping in the recliner rather than in bed and has been less active over the last several weeks. He reports that his clothes have been fitting tightly and he has gained weight despite feeling full early in a meal. He also notes difficulty bending over to tie his shoes and pet the dog. He has no chest pain or pressure and has not traveled recently. His past medical history is notable for a myocardial infarction 5 years ago treated with a stent, and elevated cholesterol. He has a 30-pack-year smoking history but quit 20 years ago. His medications include aspirin, 81 mg daily; lisinopril (Zestril), 20 mg daily; and metoprolol succinate (Toprol-XL), 50 mg daily. On examination he has a blood pressure of 110/65 mm Hg, a pulse rate of 89 beats/min, and an oxygen saturation of 95% on room air. You also note mildly increased work of breathing, a regular heart rate, and a laterally displaced apical impulse. Which one of the following tests would most likely confirm this patient''s underlying diagnosis?', 1, 'Heart failure with reduced ejection fraction (HFrEF) diagnosis is best established using echocardiography. Symptoms vary and may include dyspnea, ankle edema, and fatigue. Orthopnea is also common. Physical examination may reveal signs of congestion such as elevated jugular venous pressure, S3 gallop, or a laterally displaced apical impulse. The diagnosis is made by documenting left ventricular systolic dysfunction with a left ventricular ejection fraction <=40% and an elevated BNP level.', 'Heidenreich PA, Bozkurt B, Aguilar D, et al. 2022 AHA/ACC/HFSA guideline for the management of heart failure. Circulation. 2022;145(18):e895-e1032.', '["EKG","Echocardiography","X-ray of the chest","CT angiography of the heart","CT angiography of the lungs"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 3-year-old male is brought to your office by his parents for a routine well child visit. He is up to date on vaccines and the parents have no concerns to discuss today. According to the U.S. Preventive Services Task Force, this child should be screened for which one of the following conditions?', 0, 'The U.S. Preventive Services Task Force (USPSTF) recommends vision screening at least once in all children 3-5 years of age to detect amblyopia or its risk factors (B recommendation). The USPSTF found insufficient evidence for screening for anemia, autism, and dental caries at this age.', 'Final recommendation statement: vision in children ages 6 months to 5 years: screening. US Preventive Services Task Force. Updated September 5, 2017.', '["Amblyopia","Anemia","Autism spectrum disorder","Dental caries","Hearing loss"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 50-year-old female comes to your clinic for an annual wellness examination. Her past medical history is notable for dermatomyositis diagnosed 2 years ago. She is otherwise healthy and her BMI is normal. Patients with dermatomyositis are at increased risk of which one of the following conditions?', 3, 'Malignancy screening is the most important component of the wellness visit in this patient with dermatomyositis diagnosed after the age of 40. Cancer is a leading cause of death in this patient population and is diagnosed in up to 25% of these patients within 3 years of their dermatomyositis diagnosis.', 'Oldroyd AGS, Callen JP, Chinoy H, et al. International guideline for idiopathic inflammatory myopathy-associated cancer screening. Nat Rev Rheumatol. 2023;19(12):805-817.', '["Chronic kidney disease","Diabetes mellitus","Hyperlipidemia","Malignancy","Obesity"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Of the following cognitive biases, which one best describes the practice of prioritizing data that supports an initial impression, even when the initial impression is incorrect?', 0, 'Anchoring bias describes the practice of physicians prioritizing information and data that supports their initial impressions, even when these impressions are incorrect. In other words, it is when physicians are biased toward their first impression.', 'Doherty TS, Carroll AE. Believing in overcoming cognitive biases. AMA J Ethics. 2020;22(9):E773-E778.', '["Anchoring","Availability","Implicit","Outcomes"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'An otherwise healthy 15-year-old female presents for evaluation of a 7-month history of heavy menstrual bleeding. Her periods are 10 days long, irregular, and require 10 tampons per day. She sometimes passes large clots. Other than some fatigue, she feels well today and her vital signs are normal. A point-of-care hemoglobin level is 10.2 g/dL (N 12.0-16.0). Which one of the following would be the most appropriate next step in evaluation?', 0, 'Heavy menstrual bleeding (HMB) is very common in adolescents and may be a sign of an underlying bleeding disorder. Although bleeding disorders affect 1%-2% of the general population, the prevalence increases to 20% among adolescent girls with heavy menstrual bleeding. Evaluation for bleeding disorders is indicated when there is frequent pad or tampon use, menstrual bleeding lasting >7 days, or passing large clots.', 'Oleka C, Dietrich JE. HMB in the adolescent: a review of the modern approach to diagnosis and management. Clin Obstet Gynecol. 2020;63(3):553-560.', '["Testing for a bleeding disorder","FSH and LH levels","Estrogen and progesterone levels","Pelvic ultrasonography","Pelvic MRI"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 45-year-old patient presents with a 6-month history of epigastric burning pain that occurs several days per week. The pain does not seem to have a clear correlation to eating. There has been no substernal pain or regurgitation and no weight loss, vomiting, diarrhea, constipation, fever, night sweats, or fatigue. The patient has no prior medical history and takes no medications, but has tried calcium carbonate occasionally without benefit. A physical examination reveals normal vital signs and no abdominal abnormalities or enlarged lymph nodes. Which one of the following would be the most appropriate next step?', 1, 'This patient presents with symptoms of dyspepsia. Testing for and treating Helicobacter pylori infection is recommended in patients with dyspepsia. The stool antigen test and the urea breath test are the preferred noninvasive options for detecting H pylori. Serum testing is no longer recommended.', 'Mounsey A, Barzin A, Rietz A. Functional dyspepsia: evaluation and management. Am Fam Physician. 2020;101(2):84-88.', '["Sucralfate (Carafate)","Stool antigen testing for Helicobacter pylori","Serum testing for H pylori","Abdominal ultrasonography","Referral for upper endoscopy"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 48-year-old female comes to your office for a health maintenance examination. She is currently asymptomatic but has a medical history of renal calculi. Laboratory studies reveal a serum calcium level of 12.1 mg/dL (N 8.7-10.2), confirmed by an ionized calcium level. Which one of the following would be the most appropriate next step at this time?', 1, 'After confirming hypercalcemia, the initial test should be a parathyroid hormone (PTH) level. If the PTH level is elevated, then 25-hydroxyvitamin D, creatinine, and 24-hour urinary calcium levels should be measured in addition to ordering a bone density test. The most common cause of hypercalcemia is primary hyperparathyroidism.', 'Sell J, Ramirez S, Partin M. Parathyroid disorders. Am Fam Physician. 2022;105(3):289-298.', '["A 24-hour urinary calcium level","A parathyroid hormone level","A vitamin D level","CT of the chest, abdomen, and pelvis"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 35-year-old female presents to your office with a 3-day history of right-sided facial weakness. She has flattening of the nasolabial fold and is unable to elevate the right corner of her mouth. She is able to close her right eye and raise her eyebrows. Which one of the following would be the most appropriate next step in management?', 2, 'This patient presents with a relatively acute onset of facial weakness affecting only the right side of the face, but she is able to close her right eye and raise her eyebrows. Sparing of the forehead muscles is consistent with a supranuclear lesion because the nucleus of cranial nerve VII receives fibers from both sides of the cortex for the upper face. Therefore, this presentation is not consistent with Bell palsy and warrants further evaluation, including brain MRI, to assess for a central cause.', 'Dalrymple SN, Row JH, Gazewood J. Bell palsy: rapid evidence review. Am Fam Physician. 2023;107(4):415-420.', '["Reassurance only","Prednisone plus valacyclovir (Valtrex)","MRI of the brain","Plasmapheresis","Surgical decompression"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A previously healthy 70-year-old yoga instructor is brought to the emergency department (ED) by her students after falling while practicing yoga. Her students report that she struck her head on the floor and was unresponsive for a few seconds, but recovered quickly. She was slightly confused after the injury, but was able to stand and describe the incident. On initial assessment in the ED, she is holding her head in obvious discomfort and a hematoma is developing on her forehead. She is alert and oriented, with a Glasgow Coma Scale score of 15. On examination she is neurovascularly intact. Her vital signs are normal except for an elevated heart rate of 110 beats/min and a blood pressure of 150/92 mm Hg. Which one of the following would be the most appropriate next step in the management of this patient''s injury?', 3, 'In an older adult, head trauma with a loss of consciousness, vomiting, anterograde amnesia, or a previous history of head trauma requires CT of the head. Being older than 65 years is considered an independent risk factor for head trauma, leaving them more susceptible to injury such as subdural or epidural bleeding even with minor mechanisms.', 'Mori K, Abe T, Matsumoto J, Takahashi K, Takeuchi I. Indications for computed tomography in older adult patients with minor head injury in the emergency department. Acad Emerg Med. 2021;28(4):435-443.', '["Discharging home with concussion precautions","Observation in the ED, and acetaminophen","Observation in the ED, and ibuprofen","CT of the head"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 3-day-old infant presents to your clinic for a routine check-up. The parents report that the infant has been feeding well but has had fewer wet diapers than expected. On examination, the infant appears slightly lethargic with dry skin. You need to assess the hydration status of the infant. Which one of the following would be the most reliable clinical sign for assessing dehydration in this 3-day-old infant?', 0, 'Capillary refill time is the most reliable clinical sign for assessing dehydration in infants. An abnormal capillary refill time (>2 seconds) is a strong indicator of dehydration and has been shown to have a high likelihood ratio for predicting dehydration in children. Decreased urine output is sensitive but not specific.', 'Steiner MJ, DeWalt DA, Byerley JS. Is this child dehydrated?. JAMA. 2004;291(22):2746-2754.', '["Capillary refill time","Decreased urine output","Dry mucous membranes","Skin turgor","Sunken fontanelle"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 16-year-old female presents with her parents because she has been experiencing a loss of interest in her usual activities, trouble sleeping, difficulty concentrating, and low energy over the last month. After a discussion with the patient and her parents, you refer her for cognitive behavioral therapy and start an antidepressant. Which one of the following medications is approved by the FDA to treat depression in patients such as this?', 2, 'Two SSRIs, fluoxetine and escitalopram, have been approved by the FDA for the treatment of depression in adolescents. Other SSRIs, NDRIs such as bupropion, and SNRIs such as venlafaxine are often used off-label for this purpose but have not been approved by the FDA for use in adolescents.', 'Miller L, Campo JV. Depression in adolescents. N Engl J Med. 2021;385(5):445-449.', '["Esketamine nasal spray (Spravato)","Bupropion","Fluoxetine (Prozac)","Venlafaxine"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 35-year-old patient presents with a 14-day history of a productive cough and green sputum. They report they initially had a fever but that it resolved after a few days. The cough is interfering with their sleep and daily activity, and they have tried cough drops without relief. They have a history of hypothyroidism for which they take levothyroxine (Synthroid), and do not have a history of asthma. They do not smoke, and their immunizations are up to date. On examination, the patient is afebrile and has an oxygen saturation of 98% on room air, a heart rate of 82 beats/min, and a blood pressure of 120/82 mm Hg. A lung examination reveals mild rhonchi that clear with cough, and you do not note any wheezing or egophony. Which one of the following treatments would be the most effective in reducing this patient''s cough?', 4, 'Acute bronchitis is a lower respiratory tract infection that is most commonly caused by a virus. Treatment is generally supportive as it is a self-limited illness. Guaifenesin, honey, and dextromethorphan have been shown to decrease the frequency of cough (SOR B). Antibiotics are not indicated unless there is evidence of pneumonia. Albuterol is not recommended unless wheezing is present.', 'Kinkade S, Long NA. Acute bronchitis. Am Fam Physician. 2016;94(7):560-565.', '["An albuterol inhaler (Proventil, Ventolin)","Amoxicillin/clavulanate (Augmentin)","Azithromycin (Zithromax)","Codeine/guaifenesin syrup","Dextromethorphan (Delsym)"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 20-year-old male presents to the urgent care center for left ankle pain and swelling following an ankle inversion injury that occurred a few hours earlier. A physical examination reveals mild swelling of the left ankle joint. Using the Ottawa foot and ankle rules, which one of the following findings, if present, would be an indication for radiography for an acute ankle inversion injury?', 3, 'According to the Ottawa foot and ankle rules, a foot x-ray should be obtained if any of the following requirements are met: bone tenderness at the posterior edge or the tip of the lateral or medial malleolus, bone tenderness at the base of the fifth metatarsal or navicular bone, or inability to bear weight on the affected leg or foot for at least 4 steps after the injury.', 'Silver S, Williams E, Plunkett ML. Common foot fractures. Am Fam Physician. 2024;109(2):119-129.', '["Bone tenderness at the anterior edge of the lateral malleolus","Bone tenderness at the anterior edge of the medial malleolus","Bone tenderness at the base of the fourth metatarsal","Bone tenderness of the navicular bone","Inability to bear weight on the left foot for at least 10 steps after the injury"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A generally healthy 13-year-old male presents with his parents because they are concerned that he has very large-volume stools that clog the toilet. The patient says that he averages fewer than 2 bowel movements per week and they are sometimes painful. He does not have any abdominal pain and has not seen any blood in his stools. Examination findings are unremarkable. His height, weight, and BMI percentiles have remained steady for years. A CBC, comprehensive metabolic panel, ferritin level, and TSH level are all normal. An abdominal x-ray is normal. Which one of the following would be the most appropriate next step?', 0, 'This patient meets 3 of the Rome IV diagnostic criteria for functional constipation (<=2 bowel movements per week, painful hard stools, and stools that clog the toilet). There is good evidence that polyethylene glycol is effective for treating functional constipation in children and adolescents. Probiotics lack evidence. Further imaging or endoscopy is not indicated without red flag symptoms.', 'Mulhem E, Khondoker F, Kandiah S. Constipation in children and adolescents: evaluation and treatment. Am Fam Physician. 2022;105(5):469-478.', '["Polyethylene glycol (MiraLAX) daily","Probiotics daily","Magnetic resonance enterography","Colonoscopy"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 45-year-old male sees you for routine follow-up of diabetes mellitus. He smokes 1 pack of cigarettes per day and does not have any other medical conditions. His diabetes is well controlled on liraglutide (Victoza) and metformin. He has an LDL-cholesterol level of 120 mg/dL, an HDL-cholesterol level of 55 mg/dL, and a triglyceride level of 300 mg/dL. His 10-year atherosclerotic cardiovascular disease risk is 8.2%. According to 2018 guidelines from the American College of Cardiology/American Heart Association, the most appropriate recommendation for this patient would be', 0, 'Patients 40-75 years of age with diabetes mellitus and an LDL-cholesterol level >=70 mg/dL should be treated with a moderate-intensity statin. However, high-intensity statin therapy should be considered to lower the LDL-cholesterol level by at least 50% for patients such as this one who are at elevated risk (e.g., multiple risk factors like smoking). Of the options listed, atorvastatin, 40-80 mg daily, is the only therapy that is considered high-intensity statin therapy.', 'Grundy SM, Stone NJ, Bailey AL, et al. 2018 AHA/ACC/AACVPR/AAPA/ABC/ACPM/ADA/AGS/APhA/ASPC/NLA/PCNA guideline on the management of blood cholesterol. Circulation. 2019;139(25):e1082-e1143.', '["atorvastatin (Lipitor), 40 mg daily","ezetimibe (Zetia), 10 mg daily","fenofibrate, 160 mg daily","pravastatin, 20 mg daily","simvastatin (Zocor), 40 mg daily"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 37-year-old male comes to the primary care clinic with a several-month history of worsening paresthesia in his right foot. He says that he sometimes has numbness and a hot sensation in his feet and has difficulty using the pedals of his car. Sometimes, he has pain that wakes him up at night but eases when he walks around the room. He has no significant past medical history but did sustain a severe right ankle sprain about 1 year ago. His vital signs are unremarkable. Examination of the ankle reveals pain along the medial malleolus and a positive Tinel sign at the ankle. An x-ray of the ankle is unremarkable. Which one of the following is the most likely diagnosis?', 4, 'Tarsal tunnel syndrome is an entrapment neuropathy of the foot caused by compression of the tibial nerve or one of its branches in the fibro-osseous tunnel under the flexor retinaculum. It may occur following an injury, such as a fracture or sprain of the ankle. The most helpful clinical diagnostic sign is a positive Tinel sign at the ankle.', 'Nelson SC. Tarsal tunnel syndrome. Clin Podiatr Med Surg. 2021;38(2):131-141.', '["Achilles tendinopathy","Haglund deformity","Heel pad syndrome","Plantar fasciitis","Tarsal tunnel syndrome"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A 36-year-old female comes to your office for a health maintenance examination. She mentions that she engages in amateur rifle target shooting matches. Which one of the following would be the most appropriate advice concerning this patient''s physical safety?', 0, 'Hearing protection is essential while shooting firearms because noise exposure often exceeds 140 dB. Electronic hearing protection can amplify quiet sounds such as a range safety officer''s instructions, but also safely protect against loud sounds. Noise-canceling headphones do not provide enough noise reduction for gunshots. Regular glasses do not provide sufficient eye protection.', 'Meinke DK, Finan DS, Flamme GA, et al. Prevention of noise-induced hearing loss from recreational firearms. Semin Hear. 2017;38(4):267-281.', '["She should wear electronic hearing protection that amplifies quiet sounds","She should wear noise-canceling headphones","She should wear loose-fitting clothing","She should wear her regular glasses so that she has eye protection"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 66-year-old male presents to your office with a 2-hour history of discomfort in the midsternal area that began while taking a walk earlier today. He says that he feels 90% better. He had a Welcome to Medicare visit 1 year ago, in which an EKG was normal. You order an EKG today. Which one of the following EKG findings, if present in this patient, should prompt urgent transport to the emergency department?', 2, 'The presence of new-onset left bundle branch block increases the likelihood of acute coronary syndrome (ACS) and acute myocardial infarction. Patients with suspected ACS or the aforementioned changes on EKG should be transported immediately to the emergency department.', 'McConaghy JR, Sharma M, Patel H. Acute chest pain in adults: outpatient evaluation. Am Fam Physician. 2020;102(12):721-727.', '["First-degree atrioventricular block","Frequent PVCs","Left bundle branch block","Sinus tachycardia","Voltage criteria for left ventricular hypertrophy"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A generally healthy 56-year-old female sees you for follow-up of pneumonia diagnosed in the emergency department (ED). A chest x-ray performed in the ED showed a left lower lobe infiltrate and several compression fractures involving the thoracic vertebrae. A DXA scan performed 7 months ago showed a T-score of -1.9. Her daily medications include a multivitamin; calcium, 1000 mg; and vitamin D3 (cholecalciferol), 800 IU. Today she feels well and has no concerns. This patient would be most likely to benefit from therapy for which one of the following conditions?', 1, 'Although this patient''s T-score indicates osteopenia, the presence of fragility fractures indicates osteoporosis. Osteoporosis may be diagnosed by bone mineral density or by the presence of a fragility fracture, which is a fracture that occurs with no associated trauma or after a fall from standing height or lower. Hence, osteoporosis can be diagnosed and the patient further evaluated and treated even though her T-score is >-2.5.', 'Walker MD, Shane E. Postmenopausal osteoporosis. N Engl J Med. 2023;389(21):1979-1991.', '["Osteopenia","Osteoporosis","Spondylolisthesis","Spondylolysis"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'A gravida 2 para 1 at 28 weeks'' gestation presents with an episode of second-trimester bleeding that spontaneously resolved. She has not had any prenatal laboratory studies during either of her pregnancies. Ultrasonography today shows a healthy fetus and a small placental abruption. Which one of the following would be most important to order at this time?', 2, 'Blood type/Rh factor testing should be ordered when evaluating second-trimester bleeding. This patient would require a dose of Rho(D) immune globulin (RhoGAM) if found to be Rh negative. Therefore, of all the tests listed, an Rh factor test is the most time sensitive and affects the plan of care due to the potential exposure to mixing of maternal and fetal blood.', 'American College of Obstetricians and Gynecologists'' Committee on Practice Bulletins-Obstetrics. ACOG Practice Bulletin No. 181: prevention of Rh D alloimmunization. Obstet Gynecol. 2017;130(2):e57-e70.', '["An antiphospholipid antibody profile","An HIV test","An Rh factor test","A toxoplasmosis antibody test","A urine toxicology screen for cocaine"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A generally healthy 50-year-old nurse presents to your clinic 1 day after sustaining an accidental needlestick containing the blood of a person with active hepatitis B virus infection who has not yet begun treatment. Your patient completed the hepatitis B (HepB) vaccine series at age 30 before beginning his first nursing job. Hepatitis serologies drawn yesterday at his place of employment were positive for hepatitis B surface antibody (>10 mIU/mL). Which one of the following would be recommended for this patient?', 0, 'Postexposure prophylaxis with hepatitis B immune globulin or hepatitis B vaccine is not recommended in those who have completed the hepatitis B vaccine series and have proven immunity to hepatitis B virus. The presence of hepatitis B surface antibody titers of >10 mIU/mL are indicative of immunity either from previous vaccination or from previous infection with hepatitis B.', 'Schillie S, Vellozzi C, Reingold A, et al. Prevention of hepatitis B virus infection in the United States: recommendations of the Advisory Committee on Immunization Practices. MMWR Recomm Rep. 2018;67(1):1-31.', '["No additional vaccination","Hepatitis B immune globulin (HBIG) only","Recombinant HepB vaccine only","Both HBIG and recombinant HepB vaccine"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 20-year-old female presents for a routine health maintenance examination and has no medical concerns today. She does not have a history of sexual activity, and screenings for alcohol and substance use, intimate partner violence, anxiety, depression, and suicidality are negative. An examination reveals fair skin, an elevated BMI of 31 kg/m2 and normal blood pressure. According to the U.S. Preventive Services Task Force, you should recommend screening for which one of the following?', 3, 'The U.S. Preventive Services Task Force recommends HIV screening for all persons 15-65 years of age (A recommendation). Cervical cancer screening is not recommended in women before age 21. Chlamydia screening is recommended for all sexually active females under 25 years of age, but this patient has no history of sexual activity. Diabetes mellitus screening is recommended for persons 35-70 years of age.', 'Final recommendation statement: human immunodeficiency virus (HIV) infection: screening. US Preventive Services Task Force. Updated June 11, 2019.', '["Cervical cancer","Chlamydia","Diabetes mellitus","HIV","Skin cancer"]'::jsonb
        ),(
            '2025', 'Special Sensory', 'Special Sensory', '', 'A 65-year-old male presents to your clinic with symptoms of flashing lights and increased floaters in his left eye. He does not have any pain, and he has no past medical history. His vital signs are normal. His visual acuity is at baseline when wearing his glasses, and you note a visual field defect on the left. Which one of the following is the most likely diagnosis?', 2, 'Peripheral flashing lights and floaters are common symptoms of retinal detachment. This patient should be referred for urgent ophthalmologic evaluation including a dilated fundoscopic examination.', 'Gelston CD, Deitz GA. Eye emergencies. Am Fam Physician. 2020;102(9):539-545.', '["Migraine with aura","Central retinal artery occlusion","Retinal detachment","Globe rupture","Acute ischemic stroke"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 46-year-old male presents for an acute visit due to a 2-week history of low back pain. He was moving furniture when the pain started, and he felt a pop in his right lower back area. The pain is severe enough that it keeps him from standing up straight and is causing him trouble with sleeping. He does not have fever or chills, numbness, paresthesia, or weakness in his lower extremities. He has no radicular pain on a straight leg-raising test. He went to a chiropractor who did x-rays and told him he needed to get an MRI. Which one of the following, if present, would be an indication for advanced imaging?', 4, 'While there is no consensus on what constitutes red flags for low back pain, new urinary retention is concerning for cauda equina syndrome. Other symptoms associated with cauda equina syndrome are bladder fullness and saddle anesthesia. Early advanced imaging for low back pain increases the probability of surgery and is associated with a higher use of opioids.', 'Buelt A, McCall S, Coster J. Management of low back pain: guidelines from the VA/DoD. Am Fam Physician. 2023;107(4):435-437.', '["Current cigarette use","Current intravenous drug use","Disrupted sleep due to nocturnal pain","Restricted posture due to pain","New urinary retention"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'How long after intranasal administration does naloxone (Narcan) reach peak plasma concentrations?', 3, 'After intranasal administration of naloxone, peak plasma concentrations are attained within 15-30 minutes, although its effect on the patient may be seen sooner. The half-life of naloxone is 2 hours, which is shorter than many long-acting opioids.', 'Ortega R, Nozari A, Baker W, Surani S, Edwards M. Intranasal naloxone administration. N Engl J Med. 2021;384(12):e44.', '["Immediately","30-60 seconds","3-5 minutes","15-30 minutes","1-2 hours"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 24-year-old male presents for evaluation of a bulge in his groin. He reports that it is larger at the end of the day and with straining but says it often goes away when he lies down. He reports a mild dull ache that limits his ability to lift lumber at work. On examination there is no obvious bulge in the inguinal area. When the patient bears down, a bulge becomes apparent. Which one of the following is the most appropriate next step?', 4, 'This patient presents with an inguinal hernia that is apparent on examination. When the hernia is apparent, no further imaging is needed. When the hernia is symptomatic or limits function, surgical referral is appropriate. If the hernia is asymptomatic, then watchful waiting would be a viable option.', 'Shakil A, Aparicio K, Barta E, Munez K. Inguinal hernias: diagnosis and management. Am Fam Physician. 2020;102(8):487-492.', '["Inguinal ultrasonography","Scrotal ultrasonography","Abdominal and pelvic CT","Physical therapy","Surgical referral"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 72-year-old male presents to your office with his daughter who is concerned about her father''s recent decline in memory. His history is notable for hypertension, urinary urgency with occasional incontinence, and GERD. On examination, you notice a slow, wide-based gait. A Mini-Mental State Examination (MMSE) score is 22/30. MRI of the brain is notable for diffuse dilation of the lateral, third, and fourth ventricles, and the diagnosis is confirmed with a high-volume lumbar puncture. Which one of the following is the most appropriate treatment for this condition?', 3, 'This patient presents with the classic triad symptoms associated with normal-pressure hydrocephalus: gait change, urinary incontinence, and dementia. MRI will show evidence of hydrocephalus, and gait changes will often improve with high-volume removal of cerebrospinal fluid. Treatment involves placing a ventriculoperitoneal shunt to relieve hydrocephalus.', 'Falk N, Cole A, Meredith TJ. Evaluation of suspected dementia. Am Fam Physician. 2018;97(6):398-405.', '["Carbidopa/levodopa (Sinemet), 12.5/50 mg daily","Donepezil (Aricept), 5 mg daily","Levothyroxine (Synthroid), 50 ug daily","Ventriculoperitoneal shunt","Surgery with postoperative chemotherapy"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 65-year-old male presents to the emergency department with an acute onset of bloody urine confirmed to be hematuria on urinalysis. He does not have any pain, fever, or recent trauma. His medical history is significant for hypertension that is managed with lisinopril (Zestril). A physical examination is unremarkable. Which one of the following would be the most appropriate next step in evaluation?', 3, 'The American College of Physicians recommends that all adults with gross hematuria be referred for further urologic evaluation, including cystoscopy and imaging, due to the high association with malignancy. Gross hematuria warrants immediate investigation to rule out serious underlying conditions.', 'Nielsen M, Qaseem A; High Value Care Task Force of the American College of Physicians. Hematuria as a marker of occult urinary tract cancer: advice for high-value care from the American College of Physicians. Ann Intern Med. 2016;164(7):488-497.', '["Repeating the urinalysis in 1 month","Initiating empiric antibiotic therapy and re-evaluating in 1 week","Ordering urine cytology","Referring the patient for immediate cystoscopy and imaging studies"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 40-year-old male presents to establish care. He smokes 1.5 packs of cigarettes per day and is uncertain about cutting back or quitting. While planning to enact a patient-centered strategy to help him overcome his reluctance, you recall that evidence supports the application of a counseling technique that uses open-ended questions, affirmations, reflective listening, and summary statements to help foster a sense of patient autonomy and effect positive behavioral change. Which one of the following counseling strategies best fits this description?', 2, 'Motivational interviewing (MI) is the counseling strategy that best fits the described approach. MI is an evidence-proven strategy that is particularly helpful in situations of ambivalence toward change. The key elements of MI include establishing rapport, eliciting the patient''s values, asking open-ended questions, offering affirmations, practicing reflective listening, and recapping discussions with summarizing statements (OARS).', 'Searight HR. Counseling patients in primary care: evidence-based strategies. Am Fam Physician. 2018;98(12):719-728.', '["BATHE (background, affect, troubles, handling, empathy)","The five A''s (ask, advise, assess, assist, arrange)","Motivational interviewing","Transtheoretical (stages of change) model"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 35-year-old female with type 1 diabetes presents with a skin lesion on her leg. The lesion began as a small, dusky red, elevated nodule with a sharply circumscribed border, and slowly enlarged to become a larger flattened lesion with an irregular outline and a brownish-yellow center. The most likely diagnosis is', 4, 'This patient''s most likely diagnosis is necrobiosis lipoidica diabeticorum. Its pathophysiology is poorly understood, but lesions are commonly found on the anterior and lateral surfaces of the lower legs. Lesions may begin as a small, dusky red, elevated nodule with a sharply circumscribed border. The nodule slowly enlarges, develops an irregular outline, and flattens, and has a brownish-yellow center.', 'Powers AC, Stafford JM, Rickels MR. Diabetes mellitus: complications. In: Harrison''s Principles of Internal Medicine. 21st ed. 2022:3128.', '["diabetic dermopathy","diabetic lipoatrophy","diabetic rubeosis","eruptive xanthoma","necrobiosis lipoidica diabeticorum"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'Metformin can cause which one of the following?', 3, 'Asymptomatic vitamin B12 deficiency has been reported in a significant proportion of patients taking metformin (SOR A). A randomized, placebo-controlled trial showed that patients taking metformin had a 19% decrease in vitamin B12 levels and a 7% increase in absolute risk of vitamin B12 deficiency compared to the placebo group.', 'Nabrdalik K, Hendel M, Irlik K, et al. Gastrointestinal adverse events of metformin treatment in patients with type 2 diabetes mellitus. BMC Endocr Disord. 2024;24(206).', '["Chromatopsia","Ileus","Renal failure","Vitamin B12 deficiency","Weight gain"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 3-year-old female is brought to your office by her parents with fever, cough, and decreased appetite. On examination you hear crackles in the left upper lobe and a chest x-ray confirms a left upper lobe consolidation. She appears well hydrated and her vital signs are normal. On examination she is drinking water and interacting normally. Which one of the following would be the most appropriate antibiotic for this patient''s condition?', 0, 'Given this patient''s focal lung examination and x-ray findings, the most likely causative bacteria would be a typical pathogen such as Streptococcus pneumoniae or Haemophilus influenzae. The first-line choice of antibiotics would be amoxicillin for 7 days. Azithromycin is appropriate for atypical pneumonia.', 'Smith DK, Kuckel DP, Recidoro AM. Community-acquired pneumonia in children: rapid evidence review. Am Fam Physician. 2021;104(6):618-625.', '["Amoxicillin","Azithromycin (Zithromax)","Cefdinir","Doxycycline","Sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 35-year-old male presents to the urgent care clinic with pain in his right index finger after jamming it during basketball practice. An examination demonstrates a gross deformity of the proximal interphalangeal (PIP) joint of the affected finger. There is dorsal angulation of the proximal phalanx. Capillary refill, sensation, and pulses are all intact. Because the patient has pain with attempted movement of the finger, a digital block using 1% lidocaine without epinephrine is used to complete the examination. Complete x-rays, including true lateral films, reveal a very small fracture of the middle phalanx involving a minimal (<20%) area of the articular surface. Which one of the following would be the most appropriate next step in the treatment of this patient''s finger dislocation?', 1, 'A simple, stable dorsal PIP dislocation can be managed with in-office reduction, followed by splinting in approximately 30 degrees of flexion for 2-4 weeks. Buddy taping is also recommended to prevent hyperextension deformities. Immediate surgical referral is necessary for finger fracture-dislocations that are irreducible, unstable after reduction, or involve significant soft tissue or an articular surface fracture typically >30%.', 'Childress MA, Olivas J, Crutchfield A. Common finger fractures and dislocations. Am Fam Physician. 2022;105(6):631-639.', '["Discharging home, and repeating x-rays in 1 week","Reduction, followed by splinting in a flexed position and buddy taping","MRI of the finger","Referral for physical therapy with instructions to start early range-of-motion exercises","Urgent referral to an orthopedist for hand surgery"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 27-year-old female comes to your office because she is having moderately severe, diffuse abdominal pain with nausea and approximately 5 loose, greasy stools daily. She recently returned from a 2-week backpacking trip in Nicaragua. Stool studies are positive for Giardia. Which one of the following would be the most appropriate treatment?', 4, 'Giardia is a parasite that causes diarrheal illness. Treatment is recommended for symptomatic individuals to improve their symptoms and prevent transmission to others. Metronidazole, nitazoxanide, or tinidazole are recommended for treatment of Giardia infection. Azithromycin, ciprofloxacin, and ivermectin are not correct treatments for Giardia.', 'Pyzocha N, Cuda Am. Common intestinal parasites. Am Fam Physician. 2023;108(5):487-493.', '["Supportive care only","Azithromycin (Zithromax)","Ciprofloxacin (Cipro)","Ivermectin (Stromectol)","Metronidazole (Flagyl)"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 49-year-old female with a past medical history of epilepsy presents to your office because of sadness, sleep disruption, generalized anhedonia, and a recent increase in appetite. Her Patient Health Questionnaire-9 (PHQ-9) score is elevated at 14. Which one of the following medications should be AVOIDED in this patient?', 0, 'Antidepressants including bupropion, trazodone, and tricyclic antidepressants are associated with an increased risk of seizure and should be avoided in patients with epilepsy. In general, SSRIs or SNRIs are safer choices.', 'Maguire MJ, Marson AG, Nevitt SJ. Antidepressants for people with epilepsy and depression. Cochrane Database Syst Rev. 2021;(4):CD010682.', '["Bupropion","Duloxetine (Cymbalta)","Fluoxetine (Prozac)","Mirtazapine (Remeron)","Sertraline (Zoloft)"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 20-year-old female presents for a health maintenance examination. She has no significant past medical history and no concerns. Based on U.S. Preventive Services Task Force guidelines, screening for which one of the following would be most appropriate at this time?', 0, 'The U.S. Preventive Services Task Force gives a B recommendation for screening for hepatitis C in individuals 18-79 years of age. Cervical cancer screening is not recommended until at least age 21 (A recommendation). Evidence for screening for hyperlipidemia and skin cancer is uncertain or not recommended.', 'Final recommendation statement: hepatitis C virus infection in adolescents and adults: screening. US Preventive Services Task Force. March 2, 2020.', '["Hepatitis C","Hyperlipidemia","Cervical cancer","Skin cancer"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 75-year-old male with acute confusion presents to the emergency department and is found to have a blood pressure of 280/140 mm Hg. Which one of the following potential etiologies would provide the strongest indication for lowering his systolic blood pressure to a target of 120 mm Hg within 20 minutes?', 0, 'Treatment of acute aortic dissection includes aggressive lowering of the systolic blood pressure to 100-120 mm Hg within 20 minutes and concomitant lowering of the pulse rate to <60 beats/min to reduce shear stress on the aortic wall. The optimal treatment of the other conditions requires blood pressure to be lowered more cautiously to avoid complications.', 'Peixoto AJ. Acute severe hypertension. N Engl J Med. 2019;381(19):1843-1852.', '["Acute aortic dissection","Acute ischemic stroke","Acute renal failure","Hypertensive encephalopathy","Intracerebral hemorrhage"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'A 56-year-old male sees you because he has been falling asleep at work in the afternoon. Upon questioning he notes that he is very tired all the time. Although he is in bed 8 hours per night and wakes with an alarm, he gets up 3 times nightly to urinate. He says that he has been told he snores. He does not have any constipation, dry skin, mood changes, stomach pain, changes in urine stream, shortness of breath, or chest pain. The patient is 173 cm (68 in) tall and weighs 95 kg (209 lb). His vital signs include a blood pressure of 140/88 mm Hg, a pulse rate of 79 beats/min and a respiratory rate of 16/min. Which one of the following is most likely to yield the correct diagnosis?', 4, 'The combination of obesity, loud snoring, and fatigue is suspicious for obstructive sleep apnea, and polysomnography is the definitive diagnostic study. A TSH level would be useful if hypothyroidism were suspected, but he does not have other features.', 'Semelka M, Wilson J, Floyd R. Diagnosis and treatment of obstructive sleep apnea in adults. Am Fam Physician. 2016;94(5):355-360.', '["A serum TSH level","Vitamin B12 and folate levels","Iron studies","A comprehensive metabolic panel","Polysomnography"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 16-year-old female presents for a routine well child examination. She has never been sexually active and does not use illicit substances. Based on guidelines from the U.S. Preventive Services Task Force, screening patients such as this for which one of the following has the strongest evidence of benefit?', 0, 'The U.S. Preventive Services Task Force (USPSTF) recommends screening for anxiety in children and adolescents 8-18 years of age (B recommendation). The USPSTF recommends screening for chlamydia and gonorrhea for sexually active females, but this patient is not sexually active. Screening adolescents for eating disorders, elevated blood pressure, and scoliosis all have insufficient evidence to assess the benefits and harms (I recommendation).', 'Final recommendation statement: anxiety in children and adolescents: screening. US Preventive Services Task Force. Updated October 11, 2022.', '["Anxiety","Chlamydia and gonorrhea","Eating disorders","Elevated blood pressure","Scoliosis"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 50-year-old female presents for evaluation of unilateral shoulder pain without a history of acute injury. She has tried ibuprofen with minimal symptomatic relief. Plain radiographs of the affected shoulder taken at an urgent care clinic last week demonstrated no abnormal findings. Which one of the following physical examination findings would best support a diagnosis of adhesive capsulitis as the primary etiology of this patient''s shoulder pain?', 3, 'The hallmark finding of adhesive capsulitis, also known as frozen shoulder, is pain associated with restricted passive range of motion, particularly in external rotation, flexion, and abduction.', 'Ramirez J. Adhesive capsulitis: diagnosis and management. Am Fam Physician. 2019;99(5):297-300.', '["Apprehension in a 90 degree position with abduction and external rotation","Crepitus on passive abduction with preserved passive range of abduction","Restricted active range of abduction with preserved passive range of abduction","Restricted passive range of abduction and external rotation","Weakness on resisted abduction and external rotation"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 60-year-old male with a history of type 2 diabetes presents to your office because he is concerned about an ulcer on the bottom of his right foot. He is uncertain how long the ulcer has been present. He is afebrile and otherwise asymptomatic. His most recent hemoglobin A1c is 9.7% and was obtained 9 months ago. His medications include metformin, 2000 mg daily, and insulin glargine (Lantus), 34 units nightly. He does not regularly check his blood glucose levels. On examination, the patient has an ulcer on the plantar surface of the right foot overlying the head of the fifth metatarsal, measuring 1.0 cm in diameter. The ulcer appears deep with erythema that extends approximately 2.5 cm from the margin of the ulcer. A probe-to-bone test is positive. Which one of the following would be the most appropriate next test to evaluate for osteomyelitis?', 3, 'Plain radiography is the recommended initial imaging modality in the diagnosis of osteomyelitis due to its low cost, safety, and availability. If a plain radiograph suggests osteomyelitis, advanced imaging may not be necessary. Superficial wound cultures are poorly sensitive and specific for identifying diabetes-related wound organisms compared to deep tissue cultures.', 'Matheson EM, Bragg SW, Blackwelder RS. Diabetes-related foot infections: diagnosis and treatment. Am Fam Physician. 2021;104(4):386-394.', '["A WBC count","A culture swab","Transcutaneous oximetry","Plain radiography"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 63-year-old female with hypertension sees you for routine follow-up. She has been bothered by swelling in her legs for the last several months. Her blood pressure is well controlled and she does not have any shortness of breath, cough, difficulty breathing while lying down, or pain in her legs when walking. She thinks the swelling is better earlier in the day. Her current medications include hydrochlorothiazide, lisinopril (Zestril), estrogen, levothyroxine (Synthroid), and as-needed acetaminophen. A physical examination demonstrates mild pitting edema of both legs from the ankle to the distal third of each calf. There are 2+ pedal pulses and no skin changes. Examinations of the heart and lungs are normal. Which one of the following would be the most appropriate next step?', 0, 'Adverse medication effects should always be considered when evaluating new symptoms, such as the association between estrogen use and peripheral edema. This patient''s age suggests that she is likely remote from menopause, which provides a reason to consider discontinuing estrogen therapy. ACE inhibitors do not typically cause peripheral edema.', 'Patel H, Skok CJ, DeMarco A. Peripheral edema: evaluation and management in primary care. Am Fam Physician. 2022;106(5):557-564.', '["Holding estrogen, and monitoring for improvement in peripheral edema","Holding lisinopril, and monitoring for improvement in peripheral edema","Bilateral ankle-brachial indices","Bilateral venous compression ultrasonography","Bilateral venous duplex ultrasonography with reflux"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'Which one of the following antibiotics would be recommended for the treatment of syphilis in a pregnant patient who has a history of penicillin allergy?', 3, 'Parenteral penicillin G benzathine is the only therapy with documented effectiveness for treating syphilis in a pregnant person. In pregnant patients with any stage of syphilis and a reported penicillin allergy, the CDC recommends desensitization followed by treatment with penicillin G benzathine.', 'Sexually transmitted infections treatment guidelines, 2021: syphilis during pregnancy. Centers for Disease Control and Prevention. Reviewed July 22, 2021.', '["Azithromycin (Zithromax)","Ceftriaxone","Doxycycline","Penicillin G benzathine (Bicillin L-A) after desensitization"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 7-year-old male with no significant past medical history presents with his parents for a well child visit. His BMI has consistently been above the 80th percentile. His parents have both struggled with maintaining healthy weights. To help them promote a healthy lifestyle for their child, you should tell the parents which one of the following?', 0, 'Anticipatory guidance for lifestyle management in children should incorporate multiple approaches that address nutrition, physical activity, and behaviors that contribute to possible energy imbalance. These recommendations include 60 minutes per day of moderate to vigorous physical activity for children 6-17 years of age.', 'Hampl SE, Hassink SG, Skinner AC, et al. Clinical practice guideline for the evaluation and treatment of children and adolescents with obesity. Pediatrics. 2023;151(2):e2022060640.', '["An hour per day of moderate or vigorous physical activity is recommended starting at age 6","Calorie restriction alone is sufficient in maintaining a healthy weight","Children should avoid video screen-based physical activity","Organic fruit juices can be provided to achieve the recommended daily servings of fruits and vegetables"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'A 56-year-old female presents with numbness of her bilateral feet. She first became aware of this during a recent pedicure when she had difficulty feeling the nail technician work on her toes and the plantar surface of her feet. Since that time, she has noted a feeling of ''walking on cotton gauze'' and has started wearing slippers around her home. She had intense pruritus of her feet approximately 6 months ago that persisted for several weeks, but it was not accompanied by paresthesia. She is otherwise in good health and participates in an aerobics class 3 days per week. She takes lisinopril (Zestril), 10 mg daily, for essential hypertension. She does not have any other symptoms. On examination, her cranial nerves, muscle strength, and reflexes are normal. Sensation is diminished over the plantar surface and toes of both feet. She has 2+ dorsalis pedis and posterior tibial pulses bilaterally. Routine laboratory studies, including a CBC, comprehensive metabolic panel, hemoglobin A1c, serum protein electrophoresis, and TSH, vitamin B12, and folate levels, are all in normal range. She is concerned that she may be developing multiple sclerosis. Which one of the following would be the most appropriate next step?', 3, 'This patient demonstrates a symmetric pattern of paresthesia without red flag symptoms such as ataxia, double vision, or speech issues. Because the results of her routine laboratory studies are normal, electrodiagnostic testing would be the recommended next step.', 'Castelli G, Desai KM, Cantone RE. Peripheral neuropathy: evaluation and differential diagnosis. Am Fam Physician. 2020;102(12):732-739.', '["Gabapentin (Neurontin), 100 mg 3 times daily","Vitamin B6 (pyridoxine), 50 mg daily","Lyme antibody testing","Nerve conduction testing and electromyography (EMG)","Brain MRI"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 56-year-old female presents for evaluation of right heel pain. She recently returned from a hiking trip during which she developed progressive heel discomfort. The patient''s only medication is losartan (Cozaar), which she takes for hypertension. After a thorough examination, you diagnose Achilles tendinopathy. Which one of the following would be the most appropriate next step in diagnosis and management?', 4, 'The diagnosis of Achilles tendinopathy is made clinically; therefore, additional imaging is not indicated unless there is concern for an alternate diagnosis. Current recommendations for management include physical therapy for activity modification and targeted exercises. Neither complete rest nor corticosteroid injection are currently recommended.', 'Silbernagel KG, Hanlon S, Sprague A. Current clinical concepts: conservative management of Achilles tendinopathy. J Athl Train. 2020;55(5):438-447.', '["MRI for confirmation of diagnosis","Non-weight-bearing until pain is improved","Corticosteroid injection of the Achilles tendon","Platelet-rich plasma injection","Referral for physical therapy"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 45-year-old male with a new diagnosis of type 2 diabetes is anxious about managing his condition and uncertain about his ability to meet the demands of treatment and self-care. Which one of the following would be the most appropriate strategy to help him understand his diagnosis and follow through on lifestyle and/or medication changes?', 3, 'Motivational interviewing is the communication strategy with the best evidence of leading to a change in behavior. Scare tactics have not been shown to be effective. Physicians should speak in language that the patient can understand rather than use jargon. Supplying too much detail may overwhelm the patient.', 'Miller WR, Rollnick S. Motivational Interviewing: Helping People Change and Grow. 4th ed. Guildford Press; 2023.', '["Emphasizing the seriousness of the condition by showing pictures of patients with complications","Explaining the diagnosis and treatment plan with medical language to ensure professional communication","Supplying only detailed written instructions about his condition immediately after the appointment","Using motivational interviewing to identify what is most important to the patient and create impetus for change"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A generally healthy 15-year-old female presents to your office with a history of frequent, generalized abdominal pain and loose stools daily for the last few months. She has not noted any relationship to food or a specific frequency. She has not had any previous surgeries and is up to date on routine vaccinations. At her 14-year-old well child visit, her height was at the 50th percentile and her weight was at the 60th percentile. Today, her height is at the 35th percentile and her weight at the 20th percentile. She has had a weight loss of 1 kg (2 lb). Her vital signs are normal. Which one of the following would be the most appropriate next step?', 2, 'Patients with classic symptoms of diarrhea, abdominal pain, weight loss, bloating, malabsorption, and failure to thrive should undergo evaluation for celiac disease. Serologic testing for IgA tissue transglutaminase (tTG) is the preferred initial screening in all age groups due to its high sensitivity and specificity.', 'Williams PM, Harris LM DO, Odom MR. Celiac disease: common questions and answers. Am Fam Physician. 2022;106(1):36-43.', '["Reassurance and dietary monitoring to evaluate for a relationship to symptoms","Fecal fat testing","An IgA tissue transglutaminase level","Carbohydrate breath testing","A referral for esophagogastroduodenoscopy"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 60-year-old male asks you about testosterone supplementation during a routine office visit. He reports that he has had decreased energy, decreased libido, and loss of upper and lower body strength over the last year. He would like to have his testosterone level checked today. Which one of the following symptoms, if present in this patient, would be most concerning for testosterone deficiency?', 2, 'Loss of axillary and pubic hair is one of the more specific symptoms of male hypogonadism. Memory issues, fatigue, and thinning hair at temples/eyebrows have myriad other etiologies.', 'Heidelbaugh JJ, Belakovskiy A. Testosterone replacement therapy for male hypogonadism. Am Fam Physician. 2024;109(6):543-549.', '["Difficulties with memory","Fatigue or diminished physical stamina","Loss of axillary and pubic hair","Thinning of hair at the temples","Thinning or loss of eyebrows"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 3-year-old female is brought to your office by her parents for a preschool examination. She had a normal birth and is up to date on her vaccinations. On examination she appears to be healthy, and her development is appropriate for her age. She is in the 50th percentile for height and weight. You note a grade 1-2/6 continuous murmur best heard in the infraclavicular region when she is upright. The murmur changes slightly in intensity with head movement and is absent when she is supine. Which one of the following would be the most appropriate next step?', 0, 'A venous hum is an innocent heart murmur that is caused by vein vibration. It is commonly heard in children and may appear between 3 and 6 years of age. It is typically audible only when the child is upright, and changes with head movement. In a child with a venous hum, reassurance of the parents is appropriate, and no follow-up is necessary.', 'Ford B, Lara S, Park J. Heart murmurs in children: evaluation and management. Am Fam Physician. 2022;105(3):250-261.', '["Reassuring the parents that this is a benign venous hum that needs no follow-up","Scheduling a follow-up appointment in 1 month to recheck the murmur","Recommending that the patient undergo echocardiography when she reaches adulthood","Sending the patient for evaluation for repair of a patent ductus arteriosus","Referral to a pediatric cardiologist"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 40-year-old female presents to your office after an episode of anaphylaxis. She has a known tree nut allergy and developed oral swelling, dyspnea, and chest pain after eating a muffin from a coffee shop. Her symptoms initially improved after she used her epinephrine auto-injector but began to worsen 10 minutes later. She used a second dose of her auto-injector 10 minutes prior to presentation and is feeling much better. Which one of the following would be the most appropriate next step?', 4, 'Although she is feeling better, patients with refractory anaphylaxis (requiring >1 dose of epinephrine) should be transferred to a higher level of care, such as an emergency department. Patients who have had severe or refractory anaphylaxis are at risk for a biphasic reaction and should be observed for 6-12 hours before discharge.', 'Pflipsen MC, Vega Colon KM. Anaphylaxis: recognition and management. Am Fam Physician. 2020;102(6):355-362.', '["Starting famotidine (Pepcid), 20 mg daily, and follow-up in 1 week","Starting prednisone, 40 mg for 5 days, and follow-up in 5 days","Starting fexofenadine (Allegra), 180 mg daily, and immediate follow-up with an allergist","Transfer to the emergency department (ED) with observation for 1-2 hours prior to discharge","Transfer to the ED with observation for 6-12 hours prior to discharge"]'::jsonb
        ),(
            '2025', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 42-year-old male has been admitted to the hospital for hypotension and electrolyte disturbances due to chronic diarrhea. He was stabilized in the ICU and transferred to the inpatient floor. His gastroenterologist is asking for a colonoscopy with biopsies. His medical history is significant for congenital heart disease with a mechanical aortic valve replacement, an embolic stroke resulting in right hemiparesis, a deep vein thrombosis, and a solitary kidney. He is currently anticoagulated with warfarin and has an INR of 2.6. He has a creatinine level of 2.8 mg/dL (N 0.7-1.3) and a glomerular filtration rate of 28 mL/min/1.73 m2. In addition to holding warfarin for the planned colonoscopy, how should you manage this patient''s anticoagulation while he is hospitalized?', 4, 'He has a mechanical heart valve and is at high likelihood of thromboembolic disease, so he should receive bridging with a heparin drip until his INR has normalized for the planned procedure. He is not a candidate for enoxaparin due to his glomerular filtration rate < 30.', 'Douketis JD, Spyropoulos AC, Murad MH, et al. Perioperative management of antithrombotic therapy: an American College of Chest Physicians clinical practice guideline. Chest. 2022;162(5):e207-e243.', '["Resuming warfarin post procedure with a goal INR of 2.0-3.0","Vitamin K for reversal, and resuming warfarin post procedure with a goal INR of 2.5-3.5","Enoxaparin (Lovenox), 1.5 mg/kg daily","Heparin, 5000 units subcutaneously 3 times daily","A heparin drip titrated to achieve therapeutic aPTT or anti-factor Xa levels"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 4-year-old male is brought to the emergency department by his parents after tripping and falling on his hand in an outstretched position. An x-ray reveals a buckle (torus) fracture of the distal radial metaphysis. Which one of the following management strategies would be most appropriate?', 1, 'Distal radius buckle fractures should be treated with short arm immobilization using a short arm splint, soft cast, or wrap for 3 weeks. Complete immobilization with a cast is unnecessary. According to the Choosing Wisely campaign, follow-up radiography is unnecessary unless the patient continues to experience pain or tenderness.', 'Patel DS, Statuta SM, Ahmed N. Common fractures of the radius and ulna. Am Fam Physician. 2021;103(6):345-354.', '["A short arm splint for 3 weeks with follow-up radiography","A short arm splint for 3 weeks with follow-up radiography only if pain or tenderness persists","A short arm cast for 6 weeks with follow-up radiography","A short arm cast for 6 weeks with follow-up radiography only if pain or tenderness persists"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 19-year-old female presents for a wellness visit while home on college break. According to the U.S. Preventive Services Task Force, which one of the following screenings is indicated?', 4, 'The U.S. Preventive Services Task Force (USPSTF) recommends screening for unhealthy drug use in adults >= 18 years of age (B recommendation). For this patient''s age group, evidence is insufficient to recommend screening for cavities, dyslipidemia, skin cancer, or suicide risk (I recommendation).', 'Final recommendation statement: unhealthy drug use: screening. US Preventive Services Task Force. Updated June 9, 2020.', '["Cavities or periodontal disease","Dyslipidemia","Skin cancer","Suicide risk","Unhealthy drug use"]'::jsonb
        ),(
            '2025', 'Infectious Disease', 'Infectious Disease', '', 'A 33-year-old oyster fisherman presents because of a 3-day history of diarrhea. He describes frequent, large-volume, watery stool that is milky white. His vital signs are normal and he appears nontoxic. Infection with which one of the following pathogens is most likely?', 3, 'In patients presenting with large-volume rice-water or milky-white stools, the most likely pathogen is Vibrio species. Patients with this presentation should be tested for infection regardless of exposure to undercooked shellfish or brackish waters.', 'Shane AL, Mody RK, Crump JA, et al. 2017 Infectious Diseases Society of America clinical practice guidelines for the diagnosis and management of infectious diarrhea. Clin Infect Dis. 2017;65(12):1963-1973.', '["Clostridioides difficile","Enteropathogenic Escherichia coli","Enterotoxigenic E coli","Vibrio species","Yersinia enterocolitica"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 35-year-old female with Down syndrome presents for a health maintenance examination. She does not have any new symptoms or concerns today. Her only medication is an etonogestrel implant (Nexplanon) that was placed 2 years ago. She is monogamous with a male sex partner. On examination you note normal vital signs with a BMI of 28 kg/m2. At her most recent laboratory evaluation 2 years ago, she had an LDL-cholesterol level of 104 mg/dL, a fasting glucose level of 89 mg/dL and a TSH level of 2.67 uU/mL (N 0.4-4.2). Which one of the following screening evaluations should you order today?', 2, 'In the United States, hypothyroidism is common in individuals with Down syndrome, with an estimated prevalence of approximately 50% in adults >30 years of age. Screening is therefore recommended with TSH testing every 1-2 years starting at age 21. This patient''s TSH level was last checked 2 years ago and is due today.', 'Tsou AY, Bulova P, Capone G, et al. Medical care of adults with down syndrome: a clinical guideline. JAMA. 2020;324(15):1543-1556.', '["The National Task Group-Early Detection Screen for Dementia tool","A fasting lipid panel","TSH testing","A DXA scan","Cervical spine radiography"]'::jsonb
        ),(
            '2025', 'Pulmonary', 'Pulmonary', '', 'You are participating in a continuing medical education (CME) course at a Colorado ski resort that is 9600 ft (2926 m) above sea level. You and your travel companions have had intermittent issues with headaches, loss of appetite, and difficulty sleeping. On the third day, one of your companions starts to experience shortness of breath that is not relieved with rest. Their symptoms worsen throughout the day and they become slightly tachycardic. Later that evening, they develop a cough that produces frothy sputum. Which one of the following would be the most appropriate next step?', 4, 'This patient has more severe symptoms of high-altitude pulmonary edema (HAPE), which is a medical emergency, and should begin supplemental oxygen and descend to a lower altitude if possible. Acetazolamide can be used to prevent acute mountain sickness, but it is not a treatment.', 'Luks AM, Auerbach PS, Freer L, et al. Wilderness Medical Society clinical practice guidelines for the prevention and treatment of acute altitude illness: 2019 update. Wilderness Environ Med. 2019;30(4S):S3-S18.', '["Acetazolamide","Dexamethasone","Nifedipine","A COVID-19 test","Oxygen supplementation, and descending to a lower elevation"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'Which one of the following antibiotics is most commonly associated with Stevens-Johnson syndrome?', 4, 'Sulfonamide antibiotics, such as sulfamethoxazole/trimethoprim, are associated with the majority of antibiotic-associated Stevens-Johnson syndrome (SJS) cases worldwide.', 'Lee EY, Knox C, Phillips EJ. Worldwide prevalence of antibiotic-associated Stevens Johnson syndrome and toxic epidermal necrolysis: a systematic review and meta-analysis. JAMA Dermatol. 2023;159(4):384-392.', '["Cephalexin","Ciprofloxacin","Fosfomycin","Nitrofurantoin","Sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2025', 'Reproductive/Female', 'Reproductive/Female', '', 'During an annual visit, a 62-year-old female reports an episode of vaginal spotting that lasted for a few days in May. It is now July and she has not had another recurrence. A transvaginal ultrasound shows an endometrial stripe of 4 mm, no fibroids, and no polyps. Which one of the following would be most appropriate regarding follow-up evaluation?', 0, 'An ultrasound showing an endometrial stripe <= 4 mm is associated with a >99% negative predictive value for endometrial cancer and no further evaluation is needed unless the bleeding is recurrent.', 'American College of Obstetricians and Gynecologists'' Committee on Gynecologic Practice. ACOG Committee Opinion No. 734: the role of transvaginal ultrasonography in evaluating the endometrium of women with postmenopausal bleeding. Obstet Gynecol. 2018;131(5):e124-e129.', '["No further evaluation","Endometrial biopsy","Hysteroscopy and biopsy","Dilation and curettage","Repeat ultrasonography in 1 year"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 25-year-old male presents with shoulder pain after having fallen on his arm in an outstretched position. He reports a sensation of catching and popping in the shoulder. With the patient seated and hands placed on his hips, you apply force to the elbow and direct the humerus anteriorly and superiorly, while asking the patient to resist your motion, which produces pain in the affected shoulder. Which one of the following is the most likely diagnosis?', 3, 'This patient''s history of a catching or popping sensation combined with a positive anterior slide test, as described in the physical examination, is highly suggestive of a glenoid labral tear. This combination of history and the positive anterior slide test has a positive likelihood ratio of 6.0 in diagnosing a glenoid labral tear.', 'Walsworth MK, Doukas WC, Murphy KP, Mielcarek BJ, Michener LA. Reliability and diagnostic accuracy of history and physical examination for diagnosing glenoid labral tears. Am J Sports Med. 2008;36(1):162-168.', '["Acromioclavicular joint arthritis","Adhesive capsulitis","Glenohumeral osteoarthritis","A glenoid labral tear","A rotator cuff tear"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'According to the U.S. Preventive Services Task Force, which one of the following is the recommended next step for adults who screen positive for unhealthy alcohol use?', 0, 'The U.S. Preventive Services Task Force recommends screening all adults for unhealthy alcohol use and implementing brief counseling interventions for those who screen positive (B recommendation). The screening, brief intervention, and referral to treatment (SBIRT) approach has been shown to decrease the number of patients with risky drinking after the intervention.', 'Final recommendation statement: unhealthy alcohol use in adolescents and adults: screening and behavioral counseling interventions. US Preventive Services Task Force. Updated November 13, 2018.', '["Brief counseling interventions","Cognitive behavioral therapy","Mindfulness-based therapy","Interpersonal psychotherapy","Referral for alcohol use disorder treatment"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 30-year-old female presents with constipation and severe anal pain following bowel movements. On examination, you observe an anal fissure. In addition to increasing fluids, fiber, and warm sitz baths, which one of the following would be effective and least likely to result in side effects?', 0, 'Topical calcium channel blockers such as diltiazem are best tolerated. Topical nitroglycerin is also effective but is associated with more side effects such as headaches and lightheadedness, which results in 1 in 5 patients stopping therapy.', 'Madoff RD, Melton GB. Diseases of the anus and rectum. In: Goldman L, Cooney KA, eds. Goldman-Cecil Medicine. 27th ed. Elsevier; 2024:980.', '["Topical calcium channel blockers","Topical capsaicin","Topical nitroglycerin","Oral calcium channel blockers"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'Which one of the following interventions lowers the risk of diverticulitis?', 2, 'Consuming a vegetarian diet may help to prevent diverticulitis. Red meat intake, long-term NSAID use, and tobacco use are risk factors for diverticulitis. After years of research, it was concluded that consumption of nuts, seeds, and popcorn is not a risk factor for diverticulitis (SOR B).', 'Bailey J, Dattani S, Jennings A. Diverticular disease: rapid evidence review. Am Fam Physician. 2022;106(2):150-156.', '["Avoiding consumption of popcorn, nuts, and seeds","Regular consumption of red meat","A vegetarian diet","Long-term NSAID use"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'An 82-year-old male presents to your office because he has been experiencing severe, stabbing pain that feels like an electric shock on the left side of his face in his cheek, lips, and chin. The episodes are usually triggered by light touch or eating and last for a few seconds. Which one of the following cranial nerves is associated with this disorder?', 0, 'Trigeminal neuralgia is characterized by severe paroxysms of pain in the distribution of 1 or more branches of cranial nerve V. Impairment of cranial nerve VII results in paralysis of facial muscles.', 'Zakrzewska JM, Linskey ME. Trigeminal neuralgia. Am Fam Physician. 2016;94(2):133-135.', '["V","VII","X","XI","XII"]'::jsonb
        ),(
            '2025', 'Neurologic', 'Neurologic', '', 'Which one of the following social determinants of health has a protective effective against Alzheimer disease and related types of dementia?', 3, 'Several social determinants of health affect cognition and risk of Alzheimer disease and related dementias (ADRDs). Higher levels of social engagement have a protective effect against ADRDs. Conversely, early-life adversity, low education level, and decreasing BMI with older age are associated with a greater risk.', 'Majoka MA, Schimming C. Effect of social determinants of health on cognition and risk of Alzheimer disease and related dementias. Clin Ther. 2021;43(6):922-929.', '["Decreasing BMI with older age","Early-life adversity","Low education level","Social engagement"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 72-year-old male with a history of type 2 diabetes comes to your office for evaluation of muscle aches and fatigue. His current medications include rosuvastatin (Crestor), dapagliflozin (Farxiga), and semaglutide (Ozempic). Over the past month he has noticed increasing pain in his hips, thighs, and shoulders without any apparent trigger. He feels so stiff in the morning that it is becoming difficult to get out of bed. On examination his strength is diminished (4/5) in the proximal muscle groups. You do not note any swelling or redness of any joints, muscles, or extremities. He has normal reflexes and no clonus. Laboratory Findings include a normal Creatine kinase and negative Antinuclear antibody, but elevated Erythrocyte sedimentation rate (88 mm/hr) and C-reactive protein (9.2 mg/L). Which one of the following is the most likely cause of this patient''s myalgias?', 1, 'These findings are concerning for polymyalgia rheumatica (PMR), an inflammatory condition that typically affects adults >= 50 years of age. This patient''s proximal muscle pain, fatigue, and decreased proximal muscle strength are consistent with this diagnosis, as are the elevated inflammatory markers (ESR and CRP). A normal creatine kinase level is expected in patients with PMR.', 'Raleigh MF, Stoddard J, Darrow HJ. Polymyalgia rheumatica and giant cell arteritis: rapid evidence review. Am Fam Physician. 2022;106(4):420-426.', '["Fibromyalgia","Polymyalgia rheumatica","Polymyositis","Statin-induced myopathy","Systemic lupus erythematosus"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'The U.S. Preventive Services Task Force recommends which one of the following regarding screening asymptomatic adolescents and adults for herpes simplex virus?', 0, 'The U.S. Preventive Services Task Force concluded with moderate certainty that the harms outweighed the benefits for routine, population-based serologic screening for infection with herpes simplex virus (HSV) in asymptomatic adolescents and adults, including pregnant patients (D recommendation). High false-positive rates are common in asymptomatic patients.', 'Final recommendation statement: genital herpes infection: serologic screening. US Preventive Services Task Force. Updated February 14, 2023.', '["No testing","HSV-1 antibody testing","HSV-2 antibody testing","HSV-1 and HSV-2 antibody testing","HSV-1 and HSV-2 antigen testing"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 2-year-old child is brought to the urgent care clinic by their parents with a 2-day history of abdominal pain and vomiting. The child has been irritable over the past 2 days with intermittent abdominal pain and several episodes of associated emesis, and just had a bloody stool that the parents describe as resembling jelly. The child appears uncomfortable but is alert and afebrile, with normal blood pressure. Which one of the following is the most likely diagnosis?', 0, 'Intussusception is a condition in which a part of the intestine slides or ''telescopes'' into an adjacent section. It presents with a classic triad of intermittent abdominal pain, emesis, and blood-tinged mucous stools that are sometimes called ''red currant jelly'' stools.', 'Buel KL, Wilcox J, Mingo PT. Acute abdominal pain in children: evaluation and management. Am Fam Physician. 2024;110(6):621-631.', '["Intussusception","Necrotizing enterocolitis","Pyloric stenosis","Volvulus"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A generally healthy 54-year-old male with a 20-pack-year smoking history presents to discuss smoking cessation. His first grandchild was just born and he is eager for help in quitting cigarette smoking. He quit smoking 2 years ago using nicotine gum (Nicorette Gum), but resumed smoking 5 months later. He has also explored telephone helplines and support groups, but did not find them beneficial. He currently smokes 1 pack of cigarettes per day. Which one of the following would be most likely to help this patient quit smoking?', 4, 'Varenicline plus NRT is more likely to result in sustained smoking cessation compared to bupropion plus NRT. Recent meta-analyses suggest that a combination of pharmacotherapies is more effective than monotherapy.', 'Gaddey HL, Dakkak M, Jackson NM. Smoking cessation interventions. Am Fam Physician. 2022;106(5):513-522.', '["Nicotine gum only","Extended-release bupropion (Wellbutrin SR) only","Varenicline only","Nicotine gum plus extended-release bupropion","Nicotine gum plus varenicline"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 60-year-old female returns to discuss management of her recurrent nephrolithiasis. She has a history of calcium stones and just recently passed her fourth stone this year despite appropriate lifestyle changes, including a fluid intake of 3 L per day and a diet high in fiber and low in animal protein. She would like a medication to help prevent the development of more kidney stones. She has a past medical history of asthma for which she takes a budesonide/formoterol inhaler (Symbicort) as needed. Today, her vital signs and a physical examination are normal. A recent basic metabolic panel was normal. Which one of the following would be the most appropriate prevention strategy?', 2, 'If patients continue to develop recurrent calcium stones despite appropriate lifestyle changes, it is reasonable to initiate pharmacologic therapy. Appropriate medications include high-dose thiazide diuretics, allopurinol, and potassium citrate.', 'Fontenelle LF, Sarti TD. Kidney stones: treatment and prevention. Am Fam Physician. 2019;99(8):490-496.', '["Lifestyle modifications only","Furosemide (Lasix), 20 mg daily","Hydrochlorothiazide, 50 mg daily","Magnesium oxide, 400 mg twice daily","Tamsulosin (Flomax), 0.4 mg daily"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 72-year-old female is brought to the emergency department after her neighbor found her on the floor in her home. She is drowsy and confused, and unable to provide any history. An initial laboratory evaluation reveals the following: Sodium 118 mEq/L (N 135-145). Which one of the following would be the most appropriate intervention at this time?', 2, 'This patient presents with symptomatic severe hyponatremia (sodium level <125 mEq/L). The most appropriate intervention at this time is a 100-mL bolus of 3% hypertonic saline (SOR B), which may be repeated up to 2 times at 10-minute intervals with the goal of increasing the sodium level by 4-6 mEq/L.', 'Miller NE, Rushlow D, Stacey SK. Diagnosis and management of sodium disorders: hyponatremia and hypernatremia. Am Fam Physician. 2023;108(5):476-486.', '["Free water restriction","Normal saline infusion","3% hypertonic saline bolus","Intravenous desmopressin (DDAVP)"]'::jsonb
        ),(
            '2025', 'Musculoskeletal', 'Musculoskeletal', '', 'A 35-year-old construction worker presents to your office with an acute onset of lower back pain that began 3 days ago. The patient describes the pain as a burning sensation that radiates down his left leg. He has no bowel or bladder dysfunction and has been in good health. A straight leg-raising test is positive at 45 degrees on the left without motor deficit. Which one of the following does evidence support as the first step in treatment of this patient''s condition?', 1, 'In the absence of red flags (fracture, malignancy, epidural abscess, or cauda equina syndrome), the approach to acute lumbar radiculopathy should be conservative. Most patients improve over the first 2 weeks, and there is level B evidence that mobilization and manipulation is of benefit. Bed rest was previously recommended, but current data supports allowing the patient to be as active as the pain allows.', 'Thoomes E, Falla D, Cleland JA, et al. Conservative management for lumbar radiculopathy based on the stage of the disorder: a Delphi study. Disabil Rehabil. 2023;45(21):3539-3548.', '["Bed rest for 3 days","Mobilization and manipulation","A short-term corticosteroid","Cyclobenzaprine","MRI"]'::jsonb
        ),(
            '2025', 'Cardiovascular', 'Cardiovascular', '', 'A 46-year-old male with chronic hypertension presents to your clinic for routine follow-up. Due to issues with insurance coverage, he has not been taking his antihypertensive medications for the last 2 months. Today, he is asymptomatic and an examination is normal, except for a blood pressure of 162/100 mm Hg, which is confirmed on repeat testing. In addition to addressing insurance and social determinants of health, which one of the following would be most appropriate for this patient?', 2, 'The vast majority of patients treated for essential hypertension will require 2 or more agents to achieve adequate blood pressure control. Combination therapy with a calcium channel blocker and an ACE inhibitor or angiotensin receptor blocker (ARB) would be most appropriate for this patient with stage 2 hypertension. Stage 2 hypertension is defined as a systolic blood pressure >= 160 mm Hg or a diastolic blood pressure >= 100 mm Hg.', 'Smith DK, Lennon RP, Carlsgaard PB. Managing hypertension using combination therapy. Am Fam Physician. 2020;101(6):341-349.', '["Monotherapy with a calcium channel blocker (CCB)","Monotherapy with a thiazide-like diuretic","Combination therapy with a CCB and an ACE inhibitor","Combination therapy with a diuretic and a beta-blocker","Combination therapy with a diuretic and an aldosterone antagonist"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 14-year-old female presents to your office with her mother who is concerned about her daughter''s recent 15-lb weight loss and severe fatigue. After ruling out other etiologies, you diagnose anorexia nervosa. Which one of the following findings, if present in this patient, would indicate the need for inpatient care?', 3, 'A potassium level of 2.6 mEq/L would indicate the need for inpatient care of this patient''s anorexia nervosa. Eating disorders can often be treated in the outpatient setting, however, certain findings, including severe hypokalemia, require higher levels of care because severe electrolyte abnormalities can lead to life-threatening cardiac complications and require immediate treatment.', 'Klein DA, Sylvester JE, Schvey NA. Eating disorders in primary care: diagnosis and management. Am Fam Physician. 2021;103(1):22-32.', '["Hair loss","Muscle atrophy","Parotid gland enlargement","A potassium level of 2.6 mEq/L (N 3.5-4.9)","A sodium level of 146 mEq/L (N 134-145)"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 30-year-old female presents to your office for an annual wellness visit. She reports a family history of Lynch syndrome and recently tested positive herself. Which one of the following should you recommend regarding colon cancer screening in this patient?', 2, 'Hereditary nonpolyposis colorectal cancer (HNPCC), formerly called Lynch syndrome, is a hereditary cancer syndrome that increases the risk for several types of cancer, especially colon cancer. Guidelines recommend that patients with HNPCC should start colon cancer screening with colonoscopy between 20 and 25 years of age and repeat every 1-2 years.', 'Wilkins T, McMechan D, Talukder A, Herline A. Colorectal cancer screening and surveillance in individuals at increased risk. Am Fam Physician. 2018;97(2):111-116.', '["Fecal occult blood testing annually","Stool DNA testing (Cologuard) every 3 years","Colonoscopy starting this year","Colonoscopy starting at age 45","Sigmoidoscopy"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 53-year-old male without a significant past medical history presents to the emergency department for evaluation of abdominal pain, nausea, and vomiting. Pertinent findings on presentation include notable tenderness in the epigastrium and a lipase level >3 times the upper limit of normal. He is admitted for acute pancreatitis. Intravenous lactated Ringer solution, antiemetics, and pain control are initiated. At the time of your evaluation he has normal vital signs and reports improved symptoms, although you still note abdominal tenderness. When entering admission orders for this patient, which one of the following diets would be most appropriate?', 2, 'Patients with acute pancreatitis benefit from early enteral feeding within 24 hours of admission. Enteral feeding provides calories and increases splanchnic blood flow, leading to improved integrity of the bowel wall and improved gut motility. Liquid and soft diets have no evidence of benefit over a low-fat solid diet, and some studies found a shorter length of stay in patients started on solid diets rather than liquid diets.', 'Mederos MA, Reber HA, Girgis MD. Acute pancreatitis: a review. JAMA. 2021;325(4):382-390.', '["Full liquids","Low-carbohydrate","Low-fat","NPO"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A healthy 57-year-old female presents for an annual health maintenance visit. Her last menstrual period was 2 years ago. She exercises 5 times per week, does not smoke, and rarely drinks alcohol. Her BMI is 23 kg/m2. Her 80-year-old mother has no history of fractures, but takes alendronate (Fosamax), 70 mg weekly. According to the U.S. Preventive Services Task Force, which one of the following would be the preferred strategy to screen for osteoporosis in this patient?', 3, 'According to the U.S. Preventive Services Task Force (USPSTF), women >=65 years of age should be screened for osteoporosis using DXA bone mineral density testing, regardless of fracture risk assessment. Postmenopausal women <65 years of age with 1 or more additional risk factors such as smoking, excessive alcohol consumption, or parental history of hip fracture should also be screened with DXA. This patient does not have any significant risk factors. Tools such as FRAX are not intended to be used to determine who should receive further screening with DXA.', 'Final recommendation statement: osteoporosis to prevent fractures: screening. US Preventive Services Task Force. January 14, 2025.', '["Using the FRAX tool now to determine the need for DXA screening","Using the FRAX tool at age 65 to determine the need for DXA screening","Screening now with DXA","Screening at age 65 with DXA"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'You are evaluating a patient with acute-on-chronic kidney disease and a serum potassium level of 6.5 mEq/L (N 3.3-5.0). In addition to peaked T waves, which one of the following additional electrocardiogram changes is most likely to be present?', 1, 'EKG changes associated with hyperkalemia include peaked T waves, prolonged PR interval, loss of P waves, and prolonged QRS interval. Findings associated with hypokalemia (potassium level <3.5 mEq/L) include flattened T waves, prolonged QT interval, ST segment depression, U waves, and T wave inversion.', 'Kim MJ, Valerio C, Knobloch GK. Potassium disorders: hypokalemia and hyperkalemia. Am Fam Physician. 2023;107(1):59-70.', '["Delta waves","Prolonged QRS interval","Prolonged QT interval","ST segment depression","U waves"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'A 15-year-old male comes to your clinic 30 minutes after being hit in the face by a baseball during practice. He is alert and answers questions appropriately. After clearing the blood, you find that his upper front tooth (No. 8) is quite loose and the root is visible. The tooth is lying lower than his other teeth. The tooth appears intact and without fracture. There is no crepitus or pain when palpating the alveolar and mandibular bones. You immediately call his dentist to arrange an emergency appointment. Which one of the following would be the most appropriate next step prior to sending the patient to the dentist''s office?', 1, 'For dislodged or fully avulsed permanent teeth, immediate reimplantation or repositioning is recommended (SOR C). Time is imperative in saving teeth. If possible, replace the tooth in its anatomic position and have the patient bite down on a washcloth or gauze to keep it in place. It is not advised to remove a loose tooth, as the safest medium for the tooth is the socket.', 'Stephens MB, Wiedemer JP, Kushner GM. Dental problems in primary care. Am Fam Physician. 2018;98(11):654-660.', '["No intervention is needed","Repositioning the tooth in the socket and having the patient bite down on gauze","Gently removing the tooth and placing it in saline or milk","Ceftriaxone, 1 g intramuscularly","Imaging of the facial bones"]'::jsonb
        ),(
            '2025', 'Endocrine', 'Endocrine', '', 'A 50-year-old female presents for follow-up of laboratory studies. At her last visit, she presented with palpitations, anxiety, and unintentional weight loss. An examination was notable for exophthalmos. Her laboratory results show a very low TSH level with elevated free T4 and normal total T3 levels. A radioactive iodine uptake scan demonstrates a high, homogeneous uptake of iodine. Which one of the following medications is the most appropriate treatment for this condition?', 1, 'This patient has hyperthyroidism, specifically Graves disease. Diffusely high radioactive iodine uptake differentiates Graves disease from other thyroid conditions. Methimazole is the preferred antithyroid medication for treatment of Graves disease due to its improved safety profile compared to propylthiouracil, which has a greater risk of severe liver injury.', 'Kravets I. Hyperthyroidism: diagnosis and treatment. Am Fam Physician. 2016;93(5):363-370.', '["Levothyroxine (Synthroid)","Methimazole","Prednisone","Propylthiouracil","Verapamil"]'::jsonb
        ),(
            '2025', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'An 85-year-old male on the third day of hospitalization for the treatment of pneumonia develops symptoms of altered mental status. Evaluation of his medications does not identify a reason for his altered mental status. The nursing staff has been unable to successfully redirect him to keep him calm. Which one of the following medications would be appropriate for the management of the patient''s delirium?', 3, 'Delirium is a syndrome characterized by an acute, fluctuating disturbance of attention, awareness, and cognition. If no reversible cause is found and redirection is unsuccessful, managing delirium using medications becomes the most appropriate next step to ensure the patient''s safety. Second-generation antipsychotics such as olanzapine are preferred for this indication. Haloperidol is a less preferred option.', 'Jaqua EE, Nguyen VTN, Chin E. Delirium in older persons: prevention, evaluation, and management. Am Fam Physician. 2023;108(3):278-287.', '["Haloperidol","Lithium","Lorazepam (Ativan)","Olanzapine (Zyprexa)","Oxycodone"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'An 84-year-old male with a history of coronary artery disease, mild cognitive impairment, and type 2 diabetes is admitted to your hospital for a hip fracture after a recent fall. On examination the patient has normal speech but is confused. He is clearly unable to articulate his understanding of the risks and benefits of surgery. You should do which one of the following to determine this patient''s decision-making capacity regarding surgery?', 2, 'This patient clearly lacks the capacity to make decisions, and a surrogate decision-maker should be consulted. If designated, a durable power of attorney for health care should make decisions for this patient. Structured assessments for determining decision-making capacity or cognitive function may help in uncertain cases but are not necessary in this situation.', 'Barstow C, Shahan B, Roberts M. Evaluating medical decision-making capacity in practice. Am Fam Physician. 2018;98(1):40-46.', '["Administer the Aid to Capacity Evaluation assessment tool","Administer the Montreal Cognitive Assessment evaluation tool","Document a lack of capacity and consult his designated durable power of attorney","Consult with psychiatry","Defer to the court"]'::jsonb
        ),(
            '2025', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 36-year-old backcountry skier becomes separated from her group during a blizzard. The ski patrol locates her several hours later, sitting on the ground and not moving or shivering. She is conscious but confused. Which one of the following would be the most important initial step?', 3, 'This patient is not moving or shivering, and although she is conscious she is not alert. This patient is experiencing moderate hypothermia and requires immediate intervention. A patient with moderate hypothermia should be kept horizontal, have large warming packs placed in the axillae and around the upper chest, be wrapped in an insulated vapor barrier (the burrito method), and be prepared for transport to the nearest medical facility.', 'Pyzocha N. Accidental hypothermia: guidelines from the Wilderness Medical Society. Am Fam Physician. 2020;102(9):571-572.', '["Obtaining a core body temperature","Providing a warm drink and high-calorie snack, and reconnecting her with her group","Having her remove her wet clothes and wrapping her in an insulated vapor barrier","Placing large heat pads around her upper body and wrapping her in an insulated vapor barrier","Performing emergency rapid sequence field intubation and preparing for evacuation"]'::jsonb
        ),(
            '2025', 'Nephrologic', 'Nephrologic', '', 'A 63-year-old male presents for his annual health maintenance examination. He maintains a healthy lifestyle, eats well, and exercises regularly. A physical examination is normal. His most recent prostate cancer screening revealed a PSA level of 4.6 ng/mL (N 0.3-4.0), and his previous result 2 years ago was normal. Which one of the following would be the most appropriate next step in management?', 0, 'The American Urology Association (AUA) recommends obtaining a follow-up PSA level for individuals with newly elevated PSA before considering additional biomarkers, imaging, or biopsy. PSA may normalize in as many as 40% of individuals.', 'Wei JT, Barocas D, Carlsson S, et al. Early detection of prostate cancer: AUA/SUO guideline part I: prostate cancer screening. J Urol. 2023;210(1):46-53.', '["Repeating PSA testing in 4-8 weeks","Empiric antibiotic therapy","A digital rectal examination","Biopsy of the prostate","MRI of the prostate"]'::jsonb
        ),(
            '2025', 'Gastrointestinal', 'Gastrointestinal', '', 'An otherwise healthy 37-year-old female presents because of a 4-day history of multiple episodes of watery, nonbloody diarrhea. She has no fever, chills, abdominal pain, or vomiting. She does not have a history of recent antibiotic use, hospitalization, or travel, but does say that her teenage son recently returned from a spring break trip and has similar symptoms. Physical examination findings include dry mucous membranes and tachycardia. The abdomen is soft with mild generalized tenderness on deep palpation. Which one of the following next steps would be most appropriate at this time?', 0, 'Testing for fecal calprotectin, lactoferrin, and leukocytes is of limited value in evaluating a nontoxic patient with acute diarrhea, including infectious diarrhea. Testing for fecal occult blood and infection with Clostridioides difficile is also not recommended in these patients.', 'Meisenheimer ES, Epstein C, Thiel D. Acute diarrhea in adults. Am Fam Physician. 2022;106(1):72-80.', '["No testing","Fecal calprotectin","Fecal lactoferrin","Fecal leukocytes"]'::jsonb
        ),(
            '2025', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'Which one of the following dog bite wounds should be considered for primary closure instead of being left to heal by secondary intention?', 2, 'Dog bite wounds may be primarily closed if desired for cosmetic reasons such as wounds to the face. However, dog bite wounds that carry a higher risk of infection such crush injuries, wounds to the hand, and puncture wounds, should be left to heal by secondary intention.', 'Ortiz DD, Lezcano FO. Dog and cat bites: rapid evidence review. Am Fam Physician. 2023;108(5):501-505.', '["A crush injury to the arm","A gaping wound to the hand","A linear wound to the face","A puncture wound to the leg"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2024', 'Nephrologic', 'Nephrologic', '', 'A 34-year-old female with intellectual disability, hypothyroidism, and bipolar disorder presents for routine follow-up. Her case worker notes that she has been excessively thirsty and urinating more than usual over the past several months despite limiting her fluids. She also wakes at night to urinate. Laboratory studies reveal a therapeutic lithium level, as well as normal creatinine, electrolyte, and blood glucose levels. Which one of the following is most likely present in this patient''s case?', 0, 'This patient is at risk for nephrogenic diabetes insipidus due to lithium therapy. The combination of ongoing polydipsia, polyuria despite fluid restriction, and nocturia suggests diabetes insipidus rather than psychogenic polydipsia. Diabetes insipidus is a loss of free water in the urine due to a lack of antidiuretic hormone (central) or insensitivity to it in the kidney (nephrogenic). SIADH is associated with hyponatremia and does not cause polyuria.', '2024 ITE Critique Book, Item 1', '["Diabetes insipidus","Interstitial cystitis","Overactive bladder","Psychogenic polydipsia","Syndrome of inappropriate antidiuretic hormone secretion"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 70-year-old female is scheduled for cholecystectomy. She has a history of atrial fibrillation, stage 3a chronic kidney disease, hypertension, and an ischemic stroke 1 year ago. Her medications include amlodipine, losartan, metoprolol, sertraline, and warfarin. Her INR today is 2.2. Which one of the following would be the most appropriate perioperative anticoagulation therapy for this patient?', 4, 'Continuing warfarin is not recommended prior to elective procedures in patients taking it for stroke prevention in atrial fibrillation. The BRIDGE trial suggests that for patients with more distant strokes (over 12 weeks ago), cessation of warfarin without bridging with low-molecular-weight heparin is the appropriate management strategy.', '2024 ITE Critique Book, Item 2', '["Continuing warfarin with a goal INR of 1.4-1.6","Discontinuing warfarin 5 days prior to surgery and bridging with aspirin","Discontinuing warfarin 5 days prior to surgery and bridging with clopidogrel","Discontinuing warfarin 5 days prior to surgery and bridging with low-molecular-weight heparin","Discontinuing warfarin 5 days prior to surgery without bridging therapy"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 30-year-old female with obesity and tobacco use disorder presents for evaluation of a persistent painful lump in her axilla. You diagnose mild hidradenitis suppurativa. In addition to weight loss and smoking cessation counseling, which one of the following treatment options would be most appropriate?', 0, 'For patients with mild hidradenitis suppurativa, topical clindamycin is recommended as first-line treatment and often works well as monotherapy. Weight loss and smoking cessation have also been shown to decrease disease severity. Oral tetracyclines are reserved for moderate disease.', '2024 ITE Critique Book, Item 3', '["Topical clindamycin gel","Topical diclofenac gel","Topical triamcinolone cream","Oral azithromycin","Oral meloxicam"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 48-year-old female with a history of ductal carcinoma in situ presents with heavy vaginal bleeding passing clots (>100 mL today). Her BP is 114/65 mm Hg, pulse is 84 beats/min, and hemoglobin is 8.2 g/dL. An hCG test is negative. Which one of the following would be the most appropriate therapy at this time?', 4, 'Intravenous tranexamic acid is an appropriate option for acute severe uterine bleeding in a hemodynamically stable patient. Estrogens and progestins are contraindicated in this patient due to her history of ductal carcinoma in situ. Intravenous conjugated estrogen is generally reserved for hemodynamically unstable patients.', '2024 ITE Critique Book, Item 4', '["Oral high-dose progestins","Depot medroxyprogesterone acetate","Intravenous conjugated estrogen","Intravenous ketorolac","Intravenous tranexamic acid"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 30-year-old female with anxiety and allergies reports worsening palpitations. Her escitalopram dosage was recently increased to 20 mg daily, and she started fluticasone nasal spray and cetirizine. An EKG shows a heart rate of 85 beats/min and a QTc interval of 500 milliseconds. Which one of the following would be the most appropriate next step?', 2, 'The patient has a prolonged QTc interval (>460 ms for women). Escitalopram is associated with QT prolongation and should be discontinued to avoid risks of torsades de pointes. Cetirizine and fluticasone are not known offenders for QT prolongation.', '2024 ITE Critique Book, Item 5', '["Reassurance only","Discontinuing cetirizine","Discontinuing escitalopram","Discontinuing fluticasone","Echocardiography"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'Which one of the following medications has been shown to increase the resolution of metabolic dysfunction-associated steatotic liver disease (MASLD), formerly known as nonalcoholic fatty liver disease?', 2, 'While lifestyle modification is first-line, pioglitazone increases the resolution of nonalcoholic steatohepatitis (NASH), particularly in patients with advanced fibrosis. It should be avoided in patients with heart failure due to the risk of weight gain and edema.', '2024 ITE Critique Book, Item 6', '["Glyburide","Metformin","Pioglitazone","Repaglinide","Vitamin D"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 45-year-old male with hypertension presents for a checkup. According to USPSTF guidelines, which one of the following screenings is recommended for this patient?', 2, 'The USPSTF recommends colon cancer screening starting at age 45 (B recommendation). Screening EKG and carotid ultrasound in asymptomatic individuals are not recommended. PSA screening for prostate cancer is a Grade C recommendation for men aged 55-69 after shared decision-making.', '2024 ITE Critique Book, Item 7', '["Cardiovascular disease with EKG","Carotid artery disease with ultrasonography","Colon cancer with colonoscopy","Prostate cancer with PSA","Vitamin D deficiency level"]'::jsonb
        ),(
            '2024', 'Special Sensory', 'Special Sensory', '', 'Laser-assisted in-situ keratomileusis (LASIK) surgery is performed to treat which of the following?', 2, 'LASIK is a standard surgical procedure for correcting refractive errors like myopia, hyperopia, and astigmatism. It does not correct presbyopia (age-related farsightedness), which is due to lens elasticity loss, nor does it treat cataracts or glaucoma.', '2024 ITE Critique Book, Item 8', '["Cataracts","Closed-angle glaucoma","Myopia","Presbyopia","Retinal detachment"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old female has a DEXA T-score of -3.3 and evidence of an old thoracic compression fracture. Which one of the following would be the most appropriate initial treatment for this patient, who is considered at ''very high'' fracture risk?', 3, 'Patients with a T-score <-3.0 and a prior fragility fracture are at ''very high'' fracture risk. For these patients, an anabolic agent like teriparatide is recommended as initial therapy for 2 years. Bisphosphonates are typically first-line for high risk, but not necessarily ''very high'' risk where bone building is prioritized.', '2024 ITE Critique Book, Item 9', '["Oral alendronate","Oral raloxifene","Subcutaneous denosumab","Subcutaneous teriparatide","Intravenous zoledronic acid"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 48-year-old female presents with a second-degree (partial-thickness) burn on her left forearm from hot water. She is up to date on tetanus and has no allergies. In addition to analgesics and topical antiseptics, which of the following should you prescribe?', 0, 'Most superficial and partial-thickness burns can be managed with topical care and analgesics. Prophylactic oral antibiotics are not indicated unless there are clinical signs of infection.', '2024 ITE Critique Book, Item 10', '["No additional medications","Amoxicillin/clavulanate","Clindamycin","Levofloxacin","Sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Which one of the following medications is most likely to interfere with the results of screening for primary hyperaldosteronism (aldosterone to renin ratio)?', 4, 'Mineralocorticoid receptor antagonists like spironolactone significantly impact the renin-angiotensin-aldosterone system and should be withheld for at least 4 weeks prior to testing for primary aldosteronism. Other classes have less significant interference.', '2024 ITE Critique Book, Item 11', '["Amlodipine","Hydrochlorothiazide","Lisinopril","Metoprolol","Spironolactone"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'An 80-year-old female with urge incontinence is seeking medication. She takes atorvastatin and doxepin. Which of the following would be most likely to improve symptoms while minimizing adverse effects?', 2, 'In older patients, beta-3 agonists like mirabegron are preferred over antimuscarinics (oxybutynin, tolterodine) because they carry a lower risk of anticholinergic side effects such as confusion and dry mouth, which would be compounded by her use of doxepin.', '2024 ITE Critique Book, Item 12', '["Conjugated estrogens","Duloxetine","Mirabegron","Oxybutynin","Tolterodine"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'A 63-year-old female on chronic prednisone for giant cell arteritis presents with cough, hypoxia (O2 sat 88%), and bilateral perihilar interstitial infiltrates. Which antibiotic combination is most appropriate initial treatment?', 4, 'The clinical picture (hypoxia, interstitial infiltrates, chronic steroid use) is highly suggestive of Pneumocystis jirovecii pneumonia (PJP). Treatment must include sulfamethoxazole/trimethoprim, often alongside coverage for community-acquired bacterial pneumonia.', '2024 ITE Critique Book, Item 13', '["Azithromycin and ceftriaxone","Levofloxacin and metronidazole","Piperacillin/tazobactam and vancomycin","Azithromycin, cefepime, and vancomycin","Ceftriaxone, doxycycline, and sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 32-year-old female presents after a weeklong manic episode. She has never had an episode of depression or anhedonia. This is most consistent with which diagnosis?', 0, 'Bipolar I disorder can be diagnosed based on a single manic episode alone. A history of major depressive episodes is not required for Bipolar I, whereas Bipolar II requires at least one hypomanic and one major depressive episode.', '2024 ITE Critique Book, Item 14', '["Bipolar I","Bipolar II","Borderline personality","Cyclothymic","Disruptive mood dysregulation"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 35-year-old female presents with bilateral cyclic breast pain. Clinical breast exam and pregnancy test are normal. Which of the following is the most appropriate next step?', 1, 'Evidence supports the use of topical NSAIDs like diclofenac for the treatment of mastalgia. Caffeine avoidance has not been consistently proven effective. Imaging is generally not needed for cyclic pain in the absence of a palpable mass.', '2024 ITE Critique Book, Item 15', '["A trial of dietary caffeine elimination","A trial of topical diclofenac","Prolactin and TSH levels","Ultrasonography","Diagnostic mammography"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Which of the following is a possible adverse effect of a short-term course of systemic corticosteroids?', 4, 'Short courses of systemic corticosteroids can cause mood and sleep disturbances, hyperglycemia, elevated blood pressure, and increased risks for sepsis and fractures. Hypotension and hyperkalemia are not typical side effects.', '2024 ITE Critique Book, Item 16', '["Hair loss","Hyperkalemia","Hypoglycemia","Hypotension","Mood disturbance"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 32-year-old male with medial ankle pain and difficulty with a single-limb heel raise is diagnosed with posterior tibial tendinopathy. Which of the following is recommended next?', 1, 'Eccentric exercises are recommended over concentric exercises for treating posterior tibial tendinopathy. Corticosteroid injections should be avoided due to the risk of tendon rupture.', '2024 ITE Critique Book, Item 17', '["A stretching program","Eccentric exercises","Oral corticosteroids","Corticosteroid injection","Percutaneous needle tenotomy"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 35-year-old female presents with a 5-day history of congestion and a productive cough. She takes sertraline for depression. Which of the following is the most appropriate symptomatic treatment?', 0, 'Honey has evidence for reducing cough symptoms in viral upper respiratory infections. Dextromethorphan should be avoided in patients taking SSRIs like sertraline due to serotonin syndrome risk. Antibiotics and steroids are not indicated for uncomplicated acute cough.', '2024 ITE Critique Book, Item 18', '["Honey","Amoxicillin/clavulanate","Dextromethorphan","Hydrocodone/homatropine","Prednisone"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 44-year-old male has a clinic blood pressure of 189/119 mm Hg but no symptoms of end-organ damage (no chest pain, headache, or vision changes). Which of the following is the most appropriate next step?', 2, 'This is ''hypertensive urgency'' or severe asymptomatic hypertension. Reinitiation of the patient''s home blood pressure medications with close follow-up is the best approach. Acute lowering with clonidine or ED transfer is not indicated for asymptomatic patients.', '2024 ITE Critique Book, Item 19', '["A urine drug screen","A stat troponin level","Reinitiation of his antihypertensive medication","Clonidine, 0.3 mg orally","Transfer to the emergency department"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 12-year-old has several 1- to 2-cm annular scalp lesions with small black dots and occipital lymphadenopathy. Which of the following is the most appropriate treatment?', 4, 'The clinical presentation is classic for tinea capitis. Oral antifungals (terbinafine or griseofulvin) are necessary because topical agents do not penetrate the hair shaft. Terbinafine 2-week course is effective and often preferred.', '2024 ITE Critique Book, Item 20', '["Obtaining a scraping for culture","Initiating topical fluocinonide","Initiating topical ketoconazole shampoo","Initiating oral itraconazole","Initiating oral terbinafine"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Exclusive breastfeeding for at least 6 months is associated with which maternal or infant benefit?', 2, 'Breastfeeding for at least 6 months is associated with a lower risk of atopic dermatitis and gastroenteritis in infants. Mothers have a decreased risk for breast and ovarian cancers, but not necessarily endometrial cancer or hypothyroidism.', '2024 ITE Critique Book, Item 21', '["Higher incidence of infant peanut allergy","Higher infant HDL-cholesterol levels","Lower risk for infant atopic dermatitis","Lower maternal incidence of endometrial cancer","Lower maternal incidence of hypothyroidism"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'A mass described as a ''bag of worms'' is found in the left scrotum of a 30-year-old male seeking fertility. Which is the most likely concern?', 1, 'A varicocele is a benign mass but can impair sperm production and quality, contributing to infertility. It is not traditionally associated with an increased risk of testicular cancer.', '2024 ITE Critique Book, Item 22', '["It may become painful","It may be contributing to his infertility","It is associated with higher risk for testicular cancer","It is indicative of an inguinal hernia","It requires treatment with antibiotics"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 38-year-old female presents with acute near-syncope, shortness of breath, heart rate 105, and left lower leg swelling. Which test is the most appropriate next step in diagnosis?', 3, 'The patient has a high pretest probability for pulmonary embolism (Wells score >6). In high-probability cases, CT angiography (CTA) is the initial test of choice. D-dimer is used to rule out PE in low/intermediate risk patients.', '2024 ITE Critique Book, Item 23', '["An arterial blood gas measurement","A D-dimer level","Echocardiography","CT angiography of the chest","A ventilation-perfusion (V/Q) scan"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 64-year-old male on lisinopril and semaglutide reports dizziness upon standing. His SBP drops by 25 mm Hg 3 minutes after standing, and his pulse increases by 15 beats/min. Which is the most appropriate next step?', 1, 'The patient has orthostatic hypotension. Given his weight loss from semaglutide, his current lisinopril dosage may now be too high. Discontinuing the antihypertensive is the preferred first step over adding new medications like midodrine.', '2024 ITE Critique Book, Item 24', '["Discontinuing escitalopram","Discontinuing lisinopril","Discontinuing semaglutide","Adding carbidopa/levodopa","Adding midodrine"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 69-year-old female has a 10-year CVD risk of 13.2% and well-controlled diabetes (A1c 7.5%). Which recommendation for statin therapy is consistent with USPSTF guidelines?', 2, 'The USPSTF recommends a moderate-intensity statin for primary prevention in adults aged 40-75 with one or more risk factors (diabetes, hypertension, smoking) and a 10-year risk ≥10% (Grade B).', '2024 ITE Critique Book, Item 25', '["No statin at this time","A low-intensity statin","A moderate-intensity statin","A high-intensity statin"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A 3-cm incidental left adrenal mass is found on CT. The patient is 53 with hypertension and obesity. Which of the following is the most appropriate next step?', 4, 'Adrenal incidentalomas >1 cm require evaluation for hormonal activity (cortisol, aldosterone). Masses between 2 cm and 4 cm also require adrenal-specific imaging (MRI or washout CT) to characterize the lesion.', '2024 ITE Critique Book, Item 26', '["Reassurance and no further evaluation","Repeating CT in 1 year","1-g dexamethasone suppression test and repeat CT in 6 months","Ordering urine metanephrines and CT-guided biopsy","Ordering adrenal MRI and biochemical testing for hyperfunctioning"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 30-year-old with snuffbox tenderness after a fall on an outstretched hand has a normal initial x-ray. Which of the following is the most appropriate initial treatment?', 1, 'Clinical suspicion of a scaphoid fracture (snuffbox tenderness) warrants immobilization in a thumb spica splint for up to 8 weeks, even if initial radiographs are negative, as fractures may not show up for 2 weeks.', '2024 ITE Critique Book, Item 27', '["Gutter splint","Thumb spica splint","Volar splint","Short arm cast","Long arm cast"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 33-year-old female with a history of hypertension and a recent stroke desires reversible contraception. Which of the following is the SAFEST option?', 3, 'According to the CDC MEC, a history of stroke is a Category 4 (unacceptable risk) for combined hormonal contraceptives. A copper IUD (Category 1) is the safest option with no restrictions.', '2024 ITE Critique Book, Item 28', '["A combined oral contraceptive","A progestin-only oral contraceptive","Depot medroxyprogesterone acetate","A copper IUD","A levonorgestrel IUD"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'A 60-year-old with asthma on inhaled corticosteroids presents with white plaques in the mouth that reveal erythematous tissue when scraped. Which of the following medications likely contributed to this?', 1, 'The presentation is oral candidiasis (thrush). Inhaled corticosteroids like beclomethasone are a common risk factor for thrush, especially if the patient does not rinse their mouth after use.', '2024 ITE Critique Book, Item 29', '["Atorvastatin","Beclomethasone dipropionate","Ipratropium bromide","Isosorbide mononitrate","Losartan/hydrochlorothiazide"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 65-year-old with painful hematochezia and BP 80/40 is too unstable for endoscopy. Which of the following is the most appropriate alternative to isolate the source of bleeding?', 2, 'For patients with acute lower GI bleeding who are hemodynamically unstable and cannot tolerate colonoscopy, CT angiography is the preferred next step to identify the source of bleeding.', '2024 ITE Critique Book, Item 30', '["Radiography of the abdomen","Ultrasonography of the abdomen","CT angiography of the abdomen and pelvis","Technetium Tc 99m red blood cell scintigraphy","Laparoscopy"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'In a patient with facial weakness, which finding suggests a central brain lesion rather than Bell palsy?', 0, 'Sparing of the forehead (ability to wrinkle it) is a hallmark of a central lesion (like a stroke) because the upper face has bilateral cortical innervation. Bell palsy (peripheral CN VII) affects the entire side of the face, including the forehead.', '2024 ITE Critique Book, Item 31', '["Ability to wrinkle the forehead","Inability to close the eye","Normal extraocular movements","Flattening of the nasolabial fold","Drooping of the mouth"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A patient with Hashimoto thyroiditis is taking excess levothyroxine for weight loss, resulting in TSH <0.1. Which adverse reaction is most likely?', 0, 'Iatrogenic thyrotoxicosis increases the risk of atrial fibrillation and osteoporosis. Exophthalmos and goiter are features of Graves disease, not thyroid hormone overuse itself.', '2024 ITE Critique Book, Item 32', '["Atrial fibrillation","Exophthalmos","Goiter","Seizure","Tetany"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which community design feature is known to encourage people to walk more?', 1, 'Public transit systems encourage walking to and from stops. Walking decreases when destinations are >0.5 miles away or if safety is a concern due to high-speed traffic.', '2024 ITE Critique Book, Item 33', '["Destinations located at least 1 mile away","High-quality public transit systems","High-speed roadways in neighborhoods","Moving sidewalks and escalators"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 60-year-old transgender female has had breast augmentation, vaginoplasty, and orchiectomy, but still has a prostate. Which screening should be discussed?', 2, 'Transgender women retain their prostate after gender-affirming surgery. PSA screening should be offered after a discussion of risks and benefits. USPSTF mammography guidelines do not specifically cover transgender women at this time.', '2024 ITE Critique Book, Item 34', '["Digital rectal examination","Anal Papanicolaou smear","Prostate-specific antigen testing","Mammography","Bone density screening"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A 48-year-old with Crohn''s and BMI 15 has lost 18% body weight. Which strategy is recommended for refeeding?', 0, 'To prevent refeeding syndrome in high-risk patients (BMI <16), initial caloric intake should be 25%-50% of requirements and electrolytes (Phos, K, Mg) should be replenished and monitored closely.', '2024 ITE Critique Book, Item 35', '["Providing less than expected calorie requirements and replenishing electrolytes immediately","Providing full expected calorie requirements and replenishing electrolytes immediately","Providing full expected calorie requirements and delaying replenishment for 6 hours","Providing more than expected calorie requirements and replenishing electrolytes immediately","Providing more than expected calorie requirements and delaying replenishment for 6 hours"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 62-year-old female has chronic bilateral lower extremity edema. Routine labs and lower extremity ultrasound are normal. Which diagnosis should you consider?', 3, 'Obstructive sleep apnea (OSA) is an increasingly recognized cause of peripheral edema, possibly due to nocturnal hypoxemia causing sympathetic tone increases and salt/water retention.', '2024 ITE Critique Book, Item 36', '["Celiac disease","Cushing syndrome","Lyme disease","Obstructive sleep apnea","Raynaud disease"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A 42-year-old with adrenal insufficiency reports fatigue and weight loss. Which is the most appropriate initial management step?', 0, 'Symptoms like fatigue and weight loss in a patient with treated adrenal insufficiency suggest under-replacement. Increasing the daily hydrocortisone dose is the appropriate next step.', '2024 ITE Critique Book, Item 37', '["Increasing the hydrocortisone dosage","A random cortisol level","A cortisol stimulation test","CT of the adrenal glands"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'Which finding on a HINTS exam suggests a central etiology (like stroke) in a patient with vertigo?', 3, 'A ''central'' HINTS result includes a negative head-impulse test (no saccade), direction-changing nystagmus, or vertical deviation on the test of skew. Unidirectional horizontal nystagmus and saccade with head thrust are peripheral signs.', '2024 ITE Critique Book, Item 38', '["Saccade with head thrust","Unidirectional horizontal nystagmus","Suppression of nystagmus with fixation","Vertical deviation on test of skew"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 32-year-old female requests breast cancer screening because her 45-year-old sister was diagnosed with it. Which is the most appropriate next step?', 3, 'USPSTF recommends using a familial risk assessment tool for women with family history of breast/ovarian cancer. If positive, they should be referred for genetic counseling.', '2024 ITE Critique Book, Item 39', '["Monthly breast self-examinations","Screening mammography","Screening breast ultrasonography","Genetic counseling"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A patient has numbness in the ring and little fingers and a positive Tinel sign over the medial epicondyle. What is the most likely diagnosis?', 2, 'Numbness in the ulnar distribution (ring/little finger) and a positive Tinel sign at the medial elbow (the ''funny bone'' area) indicate cubital tunnel syndrome (ulnar nerve compression).', '2024 ITE Critique Book, Item 40', '["Axillary nerve compression","Carpal tunnel syndrome","Cubital tunnel syndrome","Median nerve neuropathy","Radial tunnel syndrome"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'In the case of severe symptomatic hyponatremia (sodium 104 mEq/L), what should be administered first?', 0, 'Acute, symptomatic hyponatremia is treated with a 100-mL bolus of 3% hypertonic saline to quickly raise sodium levels and prevent cerebral edema/seizures.', '2024 ITE Critique Book, Item 41', '["100 mL of 3% sodium chloride over 10 minutes","150 mL of 5% sodium chloride over 30 minutes","500 mL of 3% sodium chloride over 30 minutes","1 L of 0.9% sodium chloride over 1 hour","1 L of 3% sodium chloride over 1 hour"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A cyclist has point tenderness 2 cm proximal to the lateral knee joint line during flexion. What is the most likely diagnosis?', 0, 'Tenderness over the lateral femoral epicondyle (proximal to the joint line) is characteristic of iliotibial band (ITB) syndrome, common in runners and cyclists.', '2024 ITE Critique Book, Item 42', '["Iliotibial band syndrome","Lateral compartment osteoarthritis","Patellar tendinitis","Patellofemoral syndrome","Pes anserine bursitis"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'To prevent sudden infant death syndrome (SIDS), where should an infant sleep?', 0, 'Safe sleep recommendations include placing the infant on their back on a firm surface in their own crib but in the same room as the caregiver for at least 6 months.', '2024 ITE Critique Book, Item 43', '["In a crib on their back in the parents'' room","In a crib on their stomach in the parents'' room","In a crib on their back in their own room","In the parents'' bed on their back","In the parents'' bed on their stomach"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Progressive fatigue, weight loss, and hyperpigmentation of the buccal mucosa with low cortisol are consistent with which diagnosis?', 0, 'Hyperpigmentation and low cortisol are hallmark features of primary adrenal insufficiency (Addison disease).', '2024 ITE Critique Book, Item 44', '["Addison disease","Cushing disease","Pheochromocytoma","Primary hyperaldosteronism","Syndrome of inappropriate antidiuretic hormone secretion"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'Hearing loss in older adults is an independent risk factor for which of the following?', 1, 'Untreated hearing loss is strongly associated with an increased risk of cognitive decline and dementia in the elderly.', '2024 ITE Critique Book, Item 45', '["Benign paroxysmal positional vertigo","Dementia","Ear infection","Heart failure","Temporomandibular joint dysfunction"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 32-year-old with long-standing dysmenorrhea and heavy bleeding is now experiencing infertility. Which of the following would confirm the diagnosis?', 3, 'The clinical history is highly suggestive of endometriosis. Laparoscopy is the gold standard for definitive diagnosis and can also provide treatment.', '2024 ITE Critique Book, Item 46', '["A 6-month trial of oral contraceptives","A trial of letrozole","Placement of a levonorgestrel IUD","Diagnostic laparoscopic surgery"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 70-year-old smoker has a pulsatile mass above the umbilicus and sudden abdominal pain. What is the greatest risk factor for this condition?', 0, 'Smoking is the single most important modifiable risk factor for the development and expansion of abdominal aortic aneurysms (AAA).', '2024 ITE Critique Book, Item 47', '["Cigarette smoking","Hypertension","Male sex","Stroke","Type 2 diabetes"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'Which of the following is the most effective abortive treatment for cluster headache?', 4, 'Sumatriptan (SQ or intranasal) and 100% high-flow oxygen are the first-line abortive treatments for cluster headache.', '2024 ITE Critique Book, Item 48', '["Hydromorphone","Ketorolac","Ondansetron","Propranolol","Sumatriptan"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which of the following is recommended to reduce a family''s risk for skin cancer related to sun exposure?', 1, 'Sun rays are strongest from 10 am to 4 pm. Sunscreen is not recommended for infants under 6 months; they should be kept in the shade. Hats should shade ears and the neck, which a baseball cap does not do effectively.', '2024 ITE Critique Book, Item 49', '["Applying sunscreen with SPF 15 to a 4-month-old","Avoiding the pool mid-day and taking shade breaks","Going to the beach only on cloudy days","Wearing a baseball cap while gardening"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 36-year-old with antiphospholipid syndrome has a recurrent DVT. Which medication is most appropriate for long-term treatment?', 4, 'Warfarin is the preferred long-term anticoagulant for patients with antiphospholipid antibody syndrome because DOACs like apixaban have been associated with increased arterial thrombotic events in this specific population.', '2024 ITE Critique Book, Item 50', '["Apixaban","Aspirin","Clopidogrel","Enoxaparin","Warfarin"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 5-month-old has a rapidly enlarging red lesion on the earlobe. What is the first-line medical treatment?', 1, 'Oral propranolol is the first-line treatment for infantile hemangiomas that are at risk for causing disfigurement or functional impairment.', '2024 ITE Critique Book, Item 51', '["Topical hydrocortisone 0.5%","Oral propranolol hydrochloride","Embolization","Excisional surgery"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 24-year-old has depression and hypomanic symptoms (decreased need for sleep, racing thoughts). Which of the following is CONTRAINDICATED?', 2, 'Antidepressant monotherapy is contraindicated in patients with mixed features or bipolar disorder because it can precipitate or worsen a manic episode.', '2024 ITE Critique Book, Item 52', '["Cariprazine monotherapy","Quetiapine monotherapy","Sertraline monotherapy","Lurasidone plus valproic acid","Quetiapine plus lithium"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 59-year-old has asymmetric upper extremity weakness, hyperreflexia, and quadriceps atrophy with absent patellar reflexes. What is the most likely diagnosis?', 0, 'The presence of both upper motor neuron signs (hyperreflexia) and lower motor neuron signs (atrophy, absent reflexes) in an asymmetric pattern is highly characteristic of amyotrophic lateral sclerosis (ALS).', '2024 ITE Critique Book, Item 53', '["Amyotrophic lateral sclerosis","Guillain-Barre syndrome","Hypothyroidism","Multiple sclerosis","Myasthenia gravis"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 49-year-old with sharp ''deep ear'' pain has clicking in the left jaw and limited mouth opening. What is the most appropriate next step?', 1, 'The symptoms (limited opening, clicking, ear pain) point to temporomandibular joint (TMJ) dysfunction. Initial management involves NSAIDs and muscle relaxants.', '2024 ITE Critique Book, Item 54', '["Reassurance and follow-up in 4 weeks","A trial of naproxen and cyclobenzaprine","Noncontrast CT of the facial bones","Referral to an otolaryngologist","Referral to a maxillofacial surgeon"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'A 6-month-old has an undescended right testicle that can be moved into the upper scrotum but immediately retracts. What is the most appropriate next step?', 4, 'Infants with cryptorchidism that does not resolve by 6 months of age should be referred to a surgical specialist (urologist) for evaluation and potential orchidopexy.', '2024 ITE Critique Book, Item 55', '["Reassurance","Follow-up in 2 months","Ultrasound of the scrotum","Referral to an endocrinologist","Referral to a urologist"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'In a 23-year-old with confirmed group A strep pharyngitis, which statement regarding antibiotic treatment is true?', 1, 'Antibiotic treatment for group A strep reduces the duration of symptoms and the risk of rheumatic fever, but it does NOT change the risk for acute poststreptococcal glomerulonephritis.', '2024 ITE Critique Book, Item 56', '["Her current symptoms will not be reduced","Her risk for developing poststreptococcal glomerulonephritis will not change","Her risk for developing rheumatic fever will not change","She will remain contagious for 7-10 days even with treatment"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'Which of these medications should be discontinued in a patient at 6 weeks'' gestation?', 0, 'Topical retinoids like adapalene are generally contraindicated in pregnancy due to a lack of safety data and potential risks observed with oral formulations.', '2024 ITE Critique Book, Item 57', '["Adapalene","Famotidine","Fluticasone propionate","Hydroxyzine","Polyethylene glycol"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 17-year-old football player needs transport for a potential neck injury. Which equipment should be removed before transport?', 3, 'Ideally, both the helmet and shoulder pads should remain in place during transport to maintain neutral alignment of the cervical spine. If one must be removed, both must be removed simultaneously by a trained team.', '2024 ITE Critique Book, Item 58', '["Only the helmet if required","Only the shoulder pads if required","Both the helmet and the shoulder pads","Neither the helmet nor the shoulder pads"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 16-year-old desires confidential contraception. Which course of action is most consistent with AAP ethical guidelines?', 1, 'Physicians should respect an adolescent''s confidentiality while encouraging them to involve their parents. Forced involvement can lead to barriers in care and patient safety issues.', '2024 ITE Critique Book, Item 59', '["Provide without informing parents and don''t document it","Offer confidential options while encouraging open communication with parents","Insist on parental involvement","Refer to a mental health professional first","Refuse without parental consent"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A patient is discharged after a minor noncardioembolic stroke. What is the recommended pharmacotherapy for the first 21-90 days?', 4, 'For a minor noncardioembolic ischemic stroke, dual antiplatelet therapy (DAPT) with aspirin and clopidogrel for 21-90 days is recommended to reduce the risk of recurrent stroke.', '2024 ITE Critique Book, Item 60', '["A direct oral anticoagulant","Low-molecular-weight heparin","A vitamin K antagonist","Single antiplatelet therapy","Dual antiplatelet therapy"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'Which medication is most effective for midsleep awakening and nightmares in a patient with PTSD?', 3, 'Prazosin (an alpha-blocker) is specifically effective for treating nightmares and sleep disturbances associated with PTSD by reducing sympathetic tone.', '2024 ITE Critique Book, Item 61', '["Amitriptyline","Clonazepam","Fluoxetine","Prazosin","Extended-release venlafaxine"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 2-year-old has a 3-minute simple febrile seizure that has now ended. What is the most appropriate management?', 0, 'Simple febrile seizures that have resolved do not require routine lab work, imaging, or long-term antiseizure medication. Reassurance and monitoring are sufficient.', '2024 ITE Critique Book, Item 62', '["Reassurance and return precautions","A CBC and comprehensive metabolic panel","Oral levetiracetam","Rectal diazepam","Electroencephalography"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 35-year-old has hypertension, high BMI, and family history of CAD. What does the USPSTF recommend for primary prevention?', 3, 'For adults with CVD risk factors (like hypertension and obesity), the USPSTF recommends referral to behavioral counseling interventions to promote a healthy diet and physical activity.', '2024 ITE Critique Book, Item 63', '["Aspirin, 81 mg daily","Low- to moderate-intensity statin therapy","Moderate-intensity exercise for 120 minutes per week","Referral to behavioral counseling for healthy diet and activity"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'Which compression stocking is appropriate for managing a venous ulcer over the medial malleolus in a patient with intact pulses?', 1, 'Venous ulcers significant enough to cause wounds should be treated with high-pressure graduated compression stockings, typically 30-40 mm Hg.', '2024 ITE Critique Book, Item 64', '["Nongraduated 10-20 mm Hg","Graduated 30-40 mm Hg","Graduated 50-60 mm Hg","An Unna boot"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Hypocalcemia can cause which of the following symptoms?', 2, 'Hypocalcemia leads to neuromuscular irritability, causing paresthesias and muscle spasms (tetany). Constipation and hypertension are more associated with hypercalcemia.', '2024 ITE Critique Book, Item 65', '["Constipation","Hypertension","Paresthesias","Respiratory suppression","Tachycardia"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 60-year-old with a prior MI has a new holosystolic grade 3/6 murmur at the apex that radiates to the axilla. What is the most likely cause?', 1, 'A holosystolic murmur at the apex radiating to the axilla is classic for mitral regurgitation, which can develop after left ventricular remodeling following an MI.', '2024 ITE Critique Book, Item 66', '["Aortic stenosis","Mitral regurgitation","Mitral stenosis","Pericardial effusion","Tricuspid regurgitation"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'A 32-year-old with a history of IV drug use has fever, lymphadenopathy, pharyngeal edema, shallow oral ulcers, and a rash. Rapid HIV antibody testing is negative. What is the most appropriate next step?', 1, 'The clinical picture is highly suggestive of acute (primary) HIV infection. Serologic tests (antibodies) can be negative during the window period. An HIV viral load (RNA) is needed to confirm the diagnosis.', '2024 ITE Critique Book, Item 67', '["Herpes simplex virus IgM testing","An HIV viral load","A Western blot for HIV","Prednisone","A skin lesion biopsy"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which of the following screenings is recommended by the USPSTF for a sexually active 20-year-old female?', 1, 'The USPSTF recommends screening for chlamydia and gonorrhea in all sexually active females aged 24 and younger.', '2024 ITE Critique Book, Item 68', '["Bacterial vaginosis","Chlamydia and gonorrhea","Genital herpes simplex virus","HPV","Mycoplasma genitalium"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'Which of these pharmacologic agents is most likely to improve pain in a patient with fibromyalgia?', 3, 'Pregabalin, duloxetine, and amitriptyline have shown proven benefits in treating fibromyalgia pain. NSAIDs and opioids are generally ineffective.', '2024 ITE Critique Book, Item 69', '["Acetaminophen","Gabapentin","Naproxen","Pregabalin","Tramadol"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A hemoglobin level ≤8 g/dL is the appropriate transfusion threshold for which hospitalized patient?', 3, 'A slightly less restrictive threshold (Hgb ≤8) is used for patients with pre-existing cardiovascular disease or those undergoing major cardiac/orthopedic surgery. Stable patients usually have a threshold of ≤7.', '2024 ITE Critique Book, Item 70', '["19-year-old with sickle cell pain crisis","63-year-old stable after major trauma","79-year-old with inoperable fractures","81-year-old who had cardiac bypass surgery 3 days ago","85-year-old with chronic anemia"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'Which EKG finding is a rare but serious potential complication of methadone treatment?', 1, 'Methadone is known to cause QTc prolongation, which increases the risk for torsades de pointes. Baseline and periodic EKGs are recommended.', '2024 ITE Critique Book, Item 71', '["Paroxysmal atrial fibrillation","QTc prolongation","First-degree heart block","Mobitz type II block","Complete heart block"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'Enlarged lymph nodes in which of the following sites would most strongly suggest malignancy in an adult?', 4, 'Supraclavicular lymphadenopathy has a very high risk of underlying intra-abdominal malignancy (34%-50%) and warrants immediate evaluation.', '2024 ITE Critique Book, Item 72', '["Anterior cervical","Posterior cervical","Axillary","Inguinal","Supraclavicular"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'Which of the following is recommended as first-line therapy for anorexia nervosa in adolescents?', 4, 'Family-based therapy (Maudsley approach) has shown higher remission rates and weight gain outcomes than individual therapy for adolescents with anorexia.', '2024 ITE Critique Book, Item 73', '["Self-guided treatment","Cognitive behavioral therapy","Focal psychodynamic psychotherapy","Interpersonal psychotherapy","Family-based therapy"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 67-year-old smoker (1 pack/day) has a history of tubular adenomas. Which screening is most appropriate?', 4, 'The USPSTF recommends annual low-dose CT lung cancer screening for adults aged 50-80 with a 20-pack-year history who smoke or quit within 15 years. This patient qualifies.', '2024 ITE Critique Book, Item 74', '["Urinalysis for bladder cancer","Stool DNA testing for colon cancer","Cytology and HPV co-testing","Annual EKG","Annual low-dose CT for lung cancer"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'Which diuretic is the agent of choice for managing edema in a patient with severe chronic kidney disease?', 1, 'Loop diuretics like furosemide are the most effective for removing excess fluid in patients with significant renal impairment.', '2024 ITE Critique Book, Item 75', '["Chlorthalidone","Furosemide","Hydrochlorothiazide","Mannitol","Spironolactone"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 32-year-old has right upper quadrant pain and jaundice (bilirubin 6.5) after a recent cholecystectomy. Labs show ALP 1382 and GGT 120. What is the most likely cause?', 1, 'The cholestatic pattern (elevated bilirubin, extremely high ALP/GGT) and jaundice after cholecystectomy strongly suggest a retained or recurrent stone in the common bile duct (choledocholithiasis).', '2024 ITE Critique Book, Item 76', '["Ascending cholangitis","Choledocholithiasis","NASH","Oral contraceptives","Surgical stricture"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 24-month-old speaks fewer than 50 words. Which factor puts him at increased risk for speech impairment?', 4, 'Male sex is the most significant risk factor for speech and language impairment. Multilingualism does not delay speech milestones.', '2024 ITE Critique Book, Item 77', '["First born","Last born","Birth weight ≥5000 g","Multilingual household","Male sex"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'In a patient with microscopic colitis, what is the most common finding on colonoscopy?', 1, 'Microscopic colitis is characterized by chronic diarrhea but often has entirely normal-appearing mucosa on colonoscopy; the diagnosis requires a tissue biopsy.', '2024 ITE Critique Book, Item 78', '["Granulomas","Normal mucosa","Patchy ulcerations","Pseudomembranes"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 3-cm clean laceration on the arm can be primarily sutured up to how many hours after the injury?', 2, 'Noninfected clean wounds on the body can undergo primary closure up to 18 hours after the injury without significant increase in infection risk. Head wounds can wait up to 24 hours.', '2024 ITE Critique Book, Item 79', '["2","10","18","24","36"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'Which cause of bloody diarrhea should prompt monitoring for hemolytic uremic syndrome (HUS)?', 3, 'STEC (Shiga toxin-producing E. coli) is the primary cause of HUS, a potentially life-threatening complication involving renal failure, anemia, and low platelets.', '2024 ITE Critique Book, Item 80', '["Campylobacter","Entamoeba histolytica","Salmonella","Shiga toxin-producing E. coli","Shigella"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'Which of these cardiovascular changes is part of normal physiology in the first trimester of pregnancy?', 2, 'Normal pregnancy involves an increase in preload (plasma volume expansion) and a decrease in afterload (systemic vascular resistance). The resting heart rate increases.', '2024 ITE Critique Book, Item 81', '["Decreased resting heart rate","Increased afterload","Increased preload","Increased systemic vascular resistance","Increased systolic blood pressure"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A proximal fracture of which metatarsal is at the greatest risk for nonunion due to poor blood supply?', 4, 'Proximal fifth metatarsal fractures (Zone 2 and 3) have a high risk of nonunion and delayed healing because of a watershed area with poor blood supply.', '2024 ITE Critique Book, Item 82', '["First","Second","Third","Fourth","Fifth"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which statement regarding exercise for preventing falls in community-dwelling older adults is true?', 2, 'Evidence shows that exercise interventions reduce the overall rate of falls in older adults living in the community.', '2024 ITE Critique Book, Item 83', '["It decreases fall risk for women but not men","It decreases health-related quality of life","It reduces the rate of falls","It reduces the rate of falls requiring hospital admission"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 76-year-old on liraglutide and insulin has memory impairment and vitamin B12 deficiency. What is the most likely cause?', 4, 'This patient has a history of a ''remote partial ileocolectomy.'' Since B12 is absorbed in the terminal ileum, this surgery is the most likely cause of his malabsorption/deficiency.', '2024 ITE Critique Book, Item 84', '["Diet","Diabetic therapy","Statin therapy","Esophageal condition","Surgical history"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'Which combination of smoking cessation aids is considered most effective?', 3, 'Evidence suggests that adding nicotine replacement therapy (NRT) to varenicline is more effective than varenicline monotherapy.', '2024 ITE Critique Book, Item 85', '["Bupropion only","Varenicline only","Bupropion plus nicotine gum","Varenicline plus nicotine gum","Nicotine patch plus nicotine gum"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 78-year-old with vascular disease and bloody diarrhea has severe lower abdominal pain. What is the most likely diagnosis?', 4, 'The sudden onset of painful bloody diarrhea in an elderly patient with vascular risk factors is highly suspicious for ischemic colitis.', '2024 ITE Critique Book, Item 86', '["Angiodysplasia","Arteriovenous malformation","Colon cancer","Irritable bowel syndrome","Ischemic colitis"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A hiker with cold sensitive ''pins and needles'' fingers has pale left index and middle fingers. Core temp is normal. What is the most appropriate initial treatment?', 3, 'For frostbite, rapid rewarming in a warm water bath (37-39 C) is recommended. Slow rewarming and dry heat are less effective and potentially harmful.', '2024 ITE Critique Book, Item 87', '["Slow rewarming indoors","Rapid rewarming in the axilla","Rapid rewarming with dry heat","Rapid rewarming in a warm water bath","Rapid rewarming with chemical pads"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'Which hormonal contraceptive is most associated with abnormal uterine bleeding that is less likely to improve over time?', 3, 'Abnormal bleeding occurs in up to 23% of patients with the etonogestrel implant, and this bleeding is less likely to improve over time compared to other methods.', '2024 ITE Critique Book, Item 88', '["Combined oral contraceptive (continuous)","Combined oral contraceptive (cyclic)","Medroxyprogesterone acetate injection","Etonogestrel implant","Levonorgestrel IUD"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 55-year-old with lateral hip pain does not respond to NSAIDs and physical therapy. What alternative diagnosis is most likely?', 1, 'If greater trochanteric pain syndrome doesn''t respond to conservative measures, a gluteus medius tendon tear should be considered.', '2024 ITE Critique Book, Item 89', '["Femoroacetabular impingement","Gluteus medius tendon tear","Ischiofemoral impingement","Labral tear","Piriformis syndrome"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'According to the AHA 14-point screening evaluation for youth sports, which finding warrants an EKG?', 0, 'An EKG is recommended prior to sports clearance if an athlete has a positive screening result, such as elevated blood pressure, on the initial evaluation.', '2024 ITE Critique Book, Item 90', '["Elevated systemic blood pressure","Recovery from mild COVID-19","CAD in a 65-year-old grandfather","Mitral stenosis in a 45-year-old aunt","Coach''s request"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 50-year-old with stable hypertension has a platelet count of 110,000. Repeat count is 115,000. What is the most appropriate initial test?', 1, 'The first step in evaluating mild thrombocytopenia is a peripheral blood smear to rule out platelet clumping (pseudothrombocytopenia) or giant platelets.', '2024 ITE Critique Book, Item 91', '["PT and PTT","Peripheral blood smear","Serum haptoglobin","Serum protein electrophoresis","Bone marrow aspiration"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 68-year-old smoker has a cold, painful, mottled right leg with absent pulses and loss of pinprick sensation. What is the most appropriate next step?', 2, 'This is acute limb ischemia (ALI), a medical emergency. Emergent referral for revascularization is needed within 4-6 hours to prevent limb loss.', '2024 ITE Critique Book, Item 92', '["Urgent outpatient echocardiography","Urgent outpatient arteriography","Emergent referral to vascular surgery","Aspirin and sublingual nitroglycerin","Hospital admission for heparin"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'A 23-month-old has her first febrile UTI. After antibiotics, what follow-up study is recommended?', 2, 'The AAP recommends renal ultrasound after the first febrile UTI in children ≤24 months to screen for structural abnormalities like vesicoureteral reflux.', '2024 ITE Critique Book, Item 93', '["A repeat urine culture","Antibiotic prophylaxis","Renal and bladder ultrasonography","A voiding cystourethrogram","A DMSA scan"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 38-year-old with PCOS and hypertension has not had a period in 5 months. What is the most appropriate treatment to prevent endometrial hyperplasia?', 3, 'In patients with PCOS and oligomenorrhea who have a relative contraindication to estrogen (like hypertension), intermittent progestin therapy can stabilize the endometrium and reduce cancer risk.', '2024 ITE Critique Book, Item 94', '["No medication","Oral combined contraceptive","Continuous cycle combined contraceptive","Medroxyprogesterone for 10 days every 3 months","Copper IUD"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 65-year-old received the live zoster vaccine 8 years ago. What do you recommend now?', 3, 'The recombinant zoster vaccine (Shingrix) is recommended for adults 50 and older as a 2-dose series, regardless of prior receipt of the live zoster vaccine.', '2024 ITE Critique Book, Item 95', '["No further vaccination","No further vaccination if labs show immunity","One dose of recombinant zoster vaccine","Two doses of recombinant zoster vaccine","Two doses of live varicella vaccine"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which study should be obtained in ALL toddlers with suspected physical abuse?', 1, 'AAP guidelines recommend a skeletal survey for all children ≤2 years of age when physical abuse is suspected to identify occult fractures.', '2024 ITE Critique Book, Item 96', '["A funduscopic examination","Skeletal survey radiography","Head CT without contrast","Abdominal CT with contrast","A bone scan"]'::jsonb
        ),(
            '2024', 'Special Sensory', 'Special Sensory', '', 'Which of the following has the best evidence for improving quality of life in a patient with severe, distressing tinnitus?', 2, 'Cognitive behavioral therapy is the treatment with the best evidence for improving quality of life in patients with bothersome tinnitus.', '2024 ITE Critique Book, Item 97', '["Carbamazepine","Acupuncture","Cognitive behavioral therapy","Transcranial magnetic stimulation","Surgical decompression"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 72-year-old has plantar midfoot bruising after missing a step. X-rays are normal. What is the most appropriate next step?', 0, 'Plantar bruising is a red flag for a Lisfranc injury. Because x-rays have low sensitivity, the patient should be non-weight bearing and receive advanced imaging (CT or MRI).', '2024 ITE Critique Book, Item 98', '["Non-weight bearing status, plus CT or MRI","Corticosteroid injection","Heel splints and physical therapy","Rigid ankle support and physical therapy","Rigid ankle support and referral to surgery"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 67-year-old has normocytic anemia, hypercalcemia, and weight loss. Which test helps confirm the diagnosis?', 4, 'The clinical triad of anemia, hypercalcemia, and renal failure is highly suspicious for multiple myeloma. Serum free light chain assay and protein electrophoresis are the preferred initial tests.', '2024 ITE Critique Book, Item 99', '["Anti-CCP antibody","Antimitochondrial antibody","CPK","ESR","Serum free light chains"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which group does the USPSTF recommend for routine screening for obstructive sleep apnea (OSA)?', 4, 'The USPSTF currently states that evidence is insufficient (Grade I) to recommend for or against routine OSA screening in asymptomatic adults.', '2024 ITE Critique Book, Item 100', '["Adults >50 years","Adults with first-degree relative with OSA","Adults with BMI ≥35","Adults with hypertension","No groups should be routinely screened"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 62-year-old male presents with a 3-month history of increasing dyspnea and cough. He has a history of allergic rhinitis and uses fluticasone propionate nasal spray daily. He has a 15-pack-year smoking history but quit more than 20 years ago. He has a family history of asthma in both his mother and one sibling. Examination findings include a respiratory rate of 18/min and an oxygen saturation of 92% on room air. Lung sounds are diminished with scattered rhonchi and no wheezes. Spirometry shows an FEV1/FVC ratio of 0.6 and an FEV1 of 70% of predicted with no improvement after administration of a bronchodilator. Which one of the following is the most likely cause of his dyspnea?', 2, 'The patient has an obstructive pattern on spirometry (FEV1/FVC <0.7) and no improvement with a bronchodilator, which is consistent with COPD and helps rule out asthma. Bronchiectasis is associated with purulent cough and recurrent infections, while pulmonary fibrosis typically shows a restrictive pattern on spirometry.', '2024 ITE Critique Book, Item 101', '["Asthma","Bronchiectasis","COPD","Heart failure","Pulmonary fibrosis"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 17-year-old student-athlete is evaluated for a head injury that occurred earlier today while playing soccer. She performed a header and reported a subsequent frontal headache and mild nausea. A neurologic examination is normal. Which one of the following would be the most appropriate management?', 0, 'Guidelines recommend a brief rest period of at least 24-48 hours following a concussion. After this period, individuals should be encouraged to gradually return to normal daily activities as tolerated. Children do not need to be completely symptom-free before returning to school.', '2024 ITE Critique Book, Item 102', '["A rest period of at least 24-48 hours","A brief course of prednisone","Returning to normal daily activities only when she is symptom-free","Head CT","Immediate return to play"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 68-year-old male presents for an annual wellness visit. A routine alcohol screen finds that he consumes two drinks every night, and twice per month he consumes five or more drinks. However, the screening does not reveal symptoms of alcohol use disorder. Which one of the following is the most appropriate clinical response to address his alcohol use?', 1, 'A brief counseling intervention is recommended for adults who engage in risky or unhealthy drinking behaviors even if they do not meet the full criteria for alcohol use disorder. Medical therapy and specialist referrals are generally reserved for established alcohol use disorder.', '2024 ITE Critique Book, Item 103', '["No intervention","A brief counseling intervention","Disulfiram","Naltrexone","Referral for cognitive behavioral therapy"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 25-year-old primigravida at 30 weeks'' gestation presents with a 2-week history of intense pruritus of the palms and soles. There are no skin lesions. A metabolic panel reveals ALT 85 U/L (N 7-55), AST 75 U/L (N 8-48), and bilirubin 1.8 mg/dL (N 0.1-1.2). Which one of the following tests is most likely to confirm the diagnosis?', 1, 'Intrahepatic cholestasis of pregnancy is characterized by severe pruritus, often on the palms and soles, and elevated serum bile acid levels. Fetal surveillance and delivery at 36-37 weeks are often recommended due to risks of fetal demise.', '2024 ITE Critique Book, Item 104', '["An acute hepatitis profile","A bile acid level","A gamma-glutamyl transferase level","Ultrasonography of the liver","A punch biopsy of the skin"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Which one of the following endocrine abnormalities is associated with an increased rate of hidradenitis suppurativa?', 0, 'Hidradenitis suppurativa is associated with metabolic syndrome and an increased risk of type 2 diabetes mellitus. Associations have also been noted with increased BMI and smoking.', '2024 ITE Critique Book, Item 105', '["Diabetes mellitus","Hyperparathyroidism","Hyperthyroidism","Hypopituitarism","Hypothyroidism"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A new vaccine is being developed. The risk for infection after vaccination is 19%. The risk for infection without vaccination is 47%. What is the relative risk of the subjects who received the newly manufactured vaccine?', 2, 'Relative risk (risk ratio) is calculated by dividing the risk in the exposed/treated group by the risk in the unexposed group: 0.19 / 0.47 = 0.40. This means vaccinated participants were 40% as likely to contract the infection.', '2024 ITE Critique Book, Item 106', '["0.1","0.28","0.4","0.66","0.9"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 39-year-old female presents with long-standing dysmenorrhea and menorrhagia. On bimanual examination, the uterus is slightly enlarged and mildly tender. You suspect adenomyosis. Which one of the following is the most appropriate next step to confirm the diagnosis?', 0, 'Transvaginal ultrasound is the preferred initial diagnostic test for suspected adenomyosis. While MRI has higher specificity, ultrasound is more cost-effective and available as a first choice.', '2024 ITE Critique Book, Item 107', '["Transvaginal ultrasonography","CT of the pelvis","MRI of the pelvis","Hysteroscopy","Endometrial biopsy"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 76-year-old female presents after a fall. She is unable to bear weight, and her left lower extremity is shortened and externally rotated. The left anterior groin is tender. Which one of the following would be the most appropriate next step?', 0, 'Shortening and external rotation of the limb after trauma are classic signs of a hip fracture. Initial evaluation should be with plain radiography of the hip and pelvis.', '2024 ITE Critique Book, Item 108', '["Radiography of the hip and pelvis","Ultrasonography of the left leg to evaluate for a blood clot","CT of the hip and pelvis","MRI of the left hip","Evaluation by a physical therapist"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 26-year-old nulliparous female presents for evaluation of a 4x3-cm nonpainful breast mass in the upper outer quadrant of the right breast. Which one of the following should you recommend?', 2, 'For palpable breast masses in women younger than 30, ultrasonography is the preferred initial imaging modality because it is more sensitive in younger patients with denser breast tissue.', '2024 ITE Critique Book, Item 109', '["Screening mammography","Diagnostic mammography","Ultrasonography of the breast","MRI of the breast","Surgical referral for excision"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 30-year-old female with a sedentary lifestyle wants an exercise program to reduce her risk for cardiovascular disease. According to ACC/AHA guidelines, 5 days per week of which one of the following would meet the minimum recommendation for this patient?', 2, 'The recommendation is a minimum of 150 minutes of moderate-intensity aerobic activity per week. 30 minutes of water aerobics (moderate intensity) 5 days per week equals 150 minutes. Casual walking is considered light-intensity activity.', '2024 ITE Critique Book, Item 110', '["10 minutes of running","20 minutes of brisk walking","30 minutes of water aerobics","40 minutes of stretching","50 minutes of casual walking"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 6-year-old female is evaluated for a dry, nonproductive cough that has persisted for 2 months and worsens in cold weather. She has no wheezing or shortness of breath. Vital signs and examination are normal, and a chest x-ray is unremarkable. Which one of the following is the most appropriate next step in evaluation?', 2, 'Chronic cough in children should be evaluated with a chest x-ray and spirometry. This patient''s symptoms (worsening in cold) are highly suggestive of cough-variant asthma.', '2024 ITE Critique Book, Item 111', '["Reassurance only","PCR testing for pertussis","Spirometry","Bronchoscopy","24-hour esophageal pH monitoring"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 45-year-old female reports chronic insomnia characterized by frequent nighttime awakenings and difficulty falling back asleep. She has failed melatonin and cognitive behavioral therapy and wants a non-habit-forming prescription medication. Which one of the following has the best evidence of efficacy and safety for her condition?', 1, 'Low-dose doxepin (3-6 mg) has the best evidence for sleep maintenance insomnia and has a safety profile similar to placebo. Diphenhydramine is too sedating, quetiapine should not be used without a primary psychiatric condition, and benzodiazepines like temazepam carry a risk of dependence.', '2024 ITE Critique Book, Item 112', '["Diphenhydramine","Doxepin","Quetiapine","Temazepam","Trazodone"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which one of the following reflects the current USPSTF recommendation regarding screening for prediabetes and type 2 diabetes in asymptomatic children and adolescents?', 4, 'The USPSTF currently states there is insufficient evidence to recommend for or against screening for prediabetes and type 2 diabetes in children and adolescents.', '2024 ITE Critique Book, Item 113', '["They should not be screened","Screen only with a family history of type 2 diabetes","Screen only if they have morbid obesity","Routine screening for all adolescents","Insufficient evidence to make a recommendation"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A 30-year-old female who is 2 weeks postpartum and breastfeeding presents with palpitations and a heart rate of 120/min. Laboratory studies show a TSH level of 0.2 uU/mL (N 0.5-4.0). Which one of the following is the most appropriate initial management?', 3, 'Postpartum thyroiditis often presents with a hyperthyroid phase. Beta-blockers are the preferred treatment for symptomatic relief during this phase. Antithyroid drugs are not effective because the condition is due to the release of stored hormone from a damaged gland, and radioactive scans are contraindicated during breastfeeding.', '2024 ITE Critique Book, Item 114', '["Observation only","Discontinuing sertraline","Adding an antithyroid medication","Adding a beta-blocker","Radioactive iodine uptake scan"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 4-year-old male with sickle cell disease presents with left upper quadrant pain and a hemoglobin level of 7.0 g/dL (usual is 10.0 g/dL). He has an elevated reticulocyte count and a platelet count of 125,000/mm3. What is the most likely diagnosis?', 3, 'Splenic sequestration is an emergency characterized by acute anemia, LUQ pain/tenderness, and often a low platelet level as cells are trapped in the spleen. Aplastic crises are usually associated with a very low reticulocyte count.', '2024 ITE Critique Book, Item 115', '["Acute chest syndrome","Acute pain crisis","Aplastic anemia","Splenic sequestration","Upper gastrointestinal bleed"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 58-year-old female presents with thinning hair at the center frontal hairline. You diagnose female pattern hair loss. Which one of the following is the most appropriate initial pharmacologic treatment?', 1, 'Topical minoxidil is the first-line treatment for female pattern hair loss. Spironolactone may be effective in combination with minoxidil, but there is no evidence for it as monotherapy.', '2024 ITE Critique Book, Item 116', '["Topical estradiol","Topical minoxidil","Transdermal testosterone","Oral medroxyprogesterone","Oral spironolactone monotherapy"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 55-year-old female hospitalized for pancreatitis and alcohol intoxication requests discharge against medical advice. Which one of the following factors represents a contraindication to immediate discharge?', 2, 'To have decision-making capacity, a patient must be able to understand the information, appreciate the situation and consequences, demonstrate logical reasoning, and communicate a choice. An inability to appreciate the situation is a contraindication to discharge without further evaluation.', '2024 ITE Critique Book, Item 117', '["Mild alcohol withdrawal syndrome","History of depression with a past suicide attempt","Inability to demonstrate appreciation of her medical situation","Lack of health insurance","Unstable housing situation"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 55-year-old female presents with focal weakness on dorsiflexion of her left foot and extension of her toes. What is the most likely cause of these findings?', 3, 'Foot drop is most commonly caused by compression of the peroneal (common fibular) nerve at the fibular head. L5 nerve root impingement can also cause foot drop, but L4 does not typically result in this specific weakness.', '2024 ITE Critique Book, Item 118', '["Cervical myelopathy","Diabetic neuropathy","L4 nerve root impingement","Peroneal nerve compression","Tarsal tunnel syndrome"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 71-year-old male quit smoking 18 years ago after a 60-pack-year history. According to USPSTF guidelines, which screening is recommended for this patient?', 2, 'USPSTF recommends a one-time screening for Hepatitis C in all adults aged 18-79. Lung cancer screening with LDCT is only recommended if the person currently smokes or quit within the last 15 years.', '2024 ITE Critique Book, Item 119', '["Bone density testing","Hemoglobin A1c","Hepatitis C antibody testing","HIV testing","Low-dose chest CT"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 4-year-old female presents with rapid onset of flaccid limb weakness, weak tongue muscles, and ptosis following a febrile URI. Reflexes are absent in the affected limbs. What is the most appropriate next step?', 4, 'The clinical picture is highly suggestive of acute flaccid myelitis (AFM). Suspected cases require immediate admission to a facility capable of intensive care support due to the risk of rapid progression to respiratory failure.', '2024 ITE Critique Book, Item 120', '["Starting oral amoxicillin/clavulanate","Starting oral prednisone","Checking EBV and CMV titers","Obtaining MRI of the hip","Sending to the emergency department for hospital admission"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'When performing a mental status examination, asking a patient to spell ''world'' backward primarily assesses which component?', 0, 'Attention is assessed by tasks such as spelling a word backward or counting backward by 7s. Drawing a clock face tests executive function, while repeating words after a delay tests memory.', '2024 ITE Critique Book, Item 121', '["Attention","Executive function","Memory","Orientation","Visuospatial proficiency"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 3-month-old male has a 6-week history of stridor that worsens when lying down and during feeding. He is growing well and appears in no distress. What is the most likely diagnosis?', 4, 'Laryngomalacia is a common chronic condition in infants where supraglottic structures collapse during inhalation, causing stridor that often worsens with feeding or supine positioning. It typically resolves as the child grows.', '2024 ITE Critique Book, Item 122', '["Bacterial tracheitis","Croup","Epiglottitis","Foreign body aspiration","Laryngomalacia"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 35-year-old female has a transverse distal phalanx fracture that does not involve the joint after a crush injury. What is the optimal treatment?', 3, 'Simple distal phalanx fractures are managed with splinting in full extension for 4-6 weeks. Referral is indicated for complex fractures or those extending into the joint.', '2024 ITE Critique Book, Item 123', '["Ice, NSAIDs, and DIP flexion as tolerated","Draining the subungual hematoma and bandaging","Buddy taping for 3-4 weeks","Splinting the DIP joint in full extension for 4-6 weeks","Referral to an orthopedic surgeon"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'Which of the following is an effective topical treatment for postinflammatory hyperpigmentation in persons with Fitzpatrick skin types IV, V, and VI?', 3, 'Hydroquinone, azelaic acid, and tretinoin are effective topical therapies for postinflammatory hyperpigmentation in patients with darker skin tones.', '2024 ITE Critique Book, Item 124', '["Ammonium lactate 12% lotion","Clindamycin 1% gel","Hydrocortisone 1% cream","Hydroquinone 4% cream","Metronidazole 0.75% gel"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 12-year-old female has a systolic, nonradiating murmur at the left upper sternal border that decreases with the Valsalva maneuver. What is the most likely diagnosis?', 3, 'A pulmonary flow murmur is an innocent adolescent murmur heard at the LUSB that decreases with the Valsalva maneuver. HCM murmurs increase with the Valsalva maneuver.', '2024 ITE Critique Book, Item 125', '["Atrial septal defect","Hypertrophic obstructive cardiomyopathy","Mitral valve prolapse","Pulmonary flow murmur","Tricuspid stenosis"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'In a 36-year-old with fever of unknown origin and an unremarkable initial workup, which of the following is the most appropriate next step to identify an etiology?', 2, 'When the initial workup for FUO is unremarkable, FDG-PET/CT is helpful in identifying inflammatory, infectious, or neoplastic causes. Empiric antibiotics are generally not recommended.', '2024 ITE Critique Book, Item 126', '["Oral naproxen","Empiric ceftriaxone and azithromycin","Fluorodeoxyglucose (FDG)-PET/CT","Exploratory laparotomy","Bone marrow biopsy"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 72-year-old male develops delirium with severe agitation after surgery. Which of the following oral medications would be most appropriate?', 3, 'Second-generation antipsychotics like risperidone or olanzapine are preferred over haloperidol for the pharmacological management of delirium due to a better side-effect profile. Benzodiazepines should be avoided unless the delirium is due to alcohol or sedative withdrawal.', '2024 ITE Critique Book, Item 127', '["Diazepam","Haloperidol","Lorazepam","Risperidone","Sertraline"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 69-year-old male is started on amiodarone for atrial fibrillation. He should be monitored for toxicity with which of the following?', 3, 'Amiodarone is associated with pulmonary fibrosis. Baseline and periodic monitoring with pulmonary function tests (including DLCO) and chest x-ray is recommended.', '2024 ITE Critique Book, Item 128', '["Amiodarone plasma levels","Blood glucose monitoring","CBC with differential","Pulmonary function testing","Urinalysis"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 39-year-old female with chronic hypertension and a bicornuate uterus desires contraception. Which one of the following is most appropriate?', 2, 'A structural abnormality (bicornuate uterus) is a contraindication for IUD use. Estrogen-containing methods are relatively contraindicated due to hypertension and age over 35. The etonogestrel implant is highly effective and safe for this patient.', '2024 ITE Critique Book, Item 129', '["Oral levonorgestrel/ethinyl estradiol","Etonogestrel/ethinyl estradiol vaginal ring","Etonogestrel subdermal implant","Levonorgestrel IUD","Copper IUD"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which medication in an 77-year-old patient''s regimen is most likely to increase the risk of falls?', 2, 'SSRIs like fluoxetine are known to increase fall risk in older adults. Anticoagulants like apixaban increase bleeding risk if a fall occurs but do not increase the risk of the fall itself.', '2024 ITE Critique Book, Item 130', '["Apixaban","Budesonide/formoterol inhaler","Fluoxetine","Levothyroxine","Prednisone"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 42-year-old with a BRCA mutation has undergone bilateral mastectomy and salpingo-oophorectomy but still has her uterus. She has vasomotor symptoms. What hormone therapy is recommended?', 2, 'Hormone therapy until age 50 mitigates health risks of early menopause. Because she still has a uterus, she requires combined estrogen and progesterone therapy to prevent endometrial hyperplasia.', '2024 ITE Critique Book, Item 131', '["No hormone therapy","Estrogen monotherapy until age 50","Estrogen and progesterone therapy until age 50","Estrogen and progesterone therapy after age 50"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 5-month-old has cough, fever, wheezing, and grunting. Oxygen saturation is 94% on room air. Diagnosis is uncomplicated RSV bronchiolitis. What is the most appropriate intervention?', 0, 'Treatment for uncomplicated bronchiolitis is primarily supportive. Hydration and nutrition should be ensured. Antibiotics, steroids, and routine x-rays do not improve outcomes.', '2024 ITE Critique Book, Item 132', '["Adequate hydration and nutrition","Azithromycin","Dexamethasone","Viral testing","Chest x-ray"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'An overdose of which of the following is most likely to cause a decreased respiratory rate of 10/min in a comatose patient?', 3, 'Opioid overdose typically presents with the toxidrome of apnea (or low RR <=12), stupor, and miosis. While ethanol and hypnotics cause CNS depression, severe respiratory depression is a hallmark of opioids.', '2024 ITE Critique Book, Item 133', '["Anticonvulsants","Antipsychotics","Ethanol","Opioids","Sedative-hypnotics"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 65-year-old smoker has calf pain after walking 100 yards that improves with rest. What is the most appropriate initial treatment?', 0, 'Supervised exercise is the first-line treatment for mild, non-limb-threatening peripheral artery disease (claudication). Aspirin reduces CVD risk but does not improve claudication symptoms.', '2024 ITE Critique Book, Item 134', '["A supervised exercise program","Cilostazol","Pentoxifylline","Revascularization","Low-dose aspirin"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 28-year-old nulligravida seeks preconception advice. Which of the following should you recommend?', 2, 'Folic acid supplementation (400 mcg daily) is recommended for all women planning pregnancy to prevent neural tube defects.', '2024 ITE Critique Book, Item 135', '["Asymptomatic bacteriuria treatment","Calcium carbonate 500 mg twice daily","Folic acid 400 ug daily","Vitamin B12 1000 ug daily","Vitamin D3 2000 IU daily"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 52-year-old fell from his bicycle and has patellar tenderness and joint effusion. He can bear weight with a limp. According to the Ottawa knee rule, imaging is indicated due to which factor?', 4, 'Criteria for the Ottawa knee rule include age >=55, isolated patellar tenderness, fibular head tenderness, inability to flex to 90 degrees, or inability to bear weight for 4 steps. Patellar tenderness alone warrants an x-ray.', '2024 ITE Critique Book, Item 136', '["His age","His range of motion","A limping gait","Moderate joint effusion","Tenderness over the patella"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which of the following statements is true regarding the Medicaid program in the United States?', 2, 'Medicaid is the primary insurer for long-term care, funding 62% of nursing home residents. The majority of recipients are from racial and ethnic minorities, reflecting economic inequality.', '2024 ITE Critique Book, Item 137', '["Fewer than half of states participated in the expansion","Federal funding decreased during the pandemic","It is the predominant insurer for long-term care","The distribution of recipients reflects the general U.S. population"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A patient with a history of seizures presents with focal weakness and a tongue injury that resolved within 24 hours. A CT shows no acute findings. What is the most likely diagnosis?', 4, 'The clinical history of resolved weakness, tongue biting, and negative imaging is consistent with Todd paralysis, a postictal neurologic deficit.', '2024 ITE Critique Book, Item 138', '["Conversion disorder","Hemiplegic migraine","Hypoglycemia","Multiple sclerosis","Postictal paralysis (Todd paralysis)"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 45-year-old with daily asthma symptoms and twice-weekly nocturnal awakenings requires a maintenance prescription. Which one is recommended?', 4, 'Daily symptoms and nighttime awakenings indicate moderate persistent asthma. Single maintenance and reliever therapy (SMART) with an ICS/LABA combination is the recommended management. LABA monotherapy is contraindicated due to increased death risk.', '2024 ITE Critique Book, Item 139', '["An interleukin-5 antagonist","A leukotriene receptor antagonist","A long-acting beta-agonist (LABA) monotherapy","A long-acting muscarinic antagonist","An inhaled corticosteroid/LABA combination"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 40-year-old female presents with jaundice, hepatomegaly, and dark urine after returning from South America. Which of the following tests would confirm the diagnosis of acute Hepatitis A?', 1, 'Acute Hepatitis A is confirmed by the presence of anti-hepatitis A IgM antibodies. IgG antibodies appear later and remain elevated for life.', '2024 ITE Critique Book, Item 140', '["Anti-hepatitis A IgG antibodies","Anti-hepatitis A IgM antibodies","Anti-hepatitis B surface antibodies","A serum creatinine level of 2.5 mg/dL","Elevated serum transaminase levels"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which of the following screenings is most appropriate for a healthy 15-year-old female based on USPSTF guidelines?', 1, 'The USPSTF recommends depression screening for adolescents beginning at age 12. Routine vision and lipid screenings are not recommended for this age group by the USPSTF.', '2024 ITE Critique Book, Item 141', '["A vision examination","Depression screening","A CBC","A lipid panel","HPV testing"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 62-year-old male has substernal chest pain radiating to his left arm. An EKG shows a new left bundle branch block. What is the most appropriate next step?', 3, 'A new LBBB in the setting of chest pain is treated as an ST-elevation myocardial infarction equivalent (acute coronary syndrome). The patient needs emergent transport for urgent coronary angiography and potential PCI.', '2024 ITE Critique Book, Item 142', '["High-sensitivity cardiac troponin in the office","Coronary CT angiography","Referral for treadmill stress testing","Transportation to a hospital capable of urgent coronary intervention"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 29-year-old female presents with an itchy rash on her elbows and lower back described as thick, well-circumscribed plaques with silvery scale. What is the most likely diagnosis?', 2, 'The presence of silvery scales on the extensor surfaces (elbows) and lower back is a classic presentation for psoriasis.', '2024 ITE Critique Book, Item 143', '["Drug eruption","Pityriasis rosea","Psoriasis","Seborrheic dermatitis","Tinea corporis"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'Which laboratory finding is most likely to be found in a patient with chronic kidney disease-mineral and bone disorder (CKD-MBD)?', 2, 'In CKD, kidneys lose the ability to excrete phosphate, leading to elevated serum levels. This triggers secondary hyperparathyroidism (elevated PTH) and low calcium levels.', '2024 ITE Critique Book, Item 144', '["An elevated 25-hydroxyvitamin D level","An elevated calcium level","An elevated phosphate level","A low parathyroid hormone level"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 62-year-old male with colon cancer has nausea, vomiting, and abdominal distention with no bowel movement for a week. What is the most appropriate next step in evaluation?', 1, 'The clinical picture suggests a malignant bowel obstruction. CT of the abdomen and pelvis with contrast is the study of choice to determine the location and cause, and to guide surgical planning.', '2024 ITE Critique Book, Item 145', '["Ultrasonography of the right upper quadrant","CT of the abdomen and pelvis with contrast","A PET/CT scan","A HIDA scan","MRCP of the abdomen"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'Which medication class has been shown to reduce heart failure-related hospitalizations in patients without diabetes mellitus?', 3, 'SGLT2 inhibitors have been shown to reduce heart failure-related hospitalizations and improve mortality in patients with heart failure regardless of whether they have diabetes.', '2024 ITE Critique Book, Item 146', '["Calcium channel blockers","DPP-4 inhibitors","Insulin","SGLT2 inhibitors","Statins"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 46-year-old female has intermenstrual bleeding. Endometrial biopsy reveals endometrial hyperplasia with atypia. What should you recommend?', 4, 'Hysterectomy is the treatment of choice for endometrial hyperplasia with atypia because of the high risk of coexisting or subsequent endometrial cancer.', '2024 ITE Critique Book, Item 147', '["Oral progesterone","Combined oral contraceptives","A levonorgestrel IUD","Uterine MRI","Hysterectomy"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'Which recommendation is most appropriate to decrease the risk of food allergies in children?', 0, 'Evidence supports the early introduction (between 4 and 6 months) of allergenic foods like peanuts to reduce the risk of developing allergies. Maternal diet restriction and breastfeeding do not consistently reduce food allergy risk.', '2024 ITE Critique Book, Item 148', '["Early sequential exposure to allergenic food between 4 and 6 months of life","Exclusive breastfeeding for the first 3-4 months of life","Regular antibiotics in the first 2 years of life","Restricted cow''s milk supplementation in the first 3 months","Restricted maternal diet during pregnancy"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 30-year-old female has malabsorption symptoms and recurrent sinus infections. An IgA tissue transglutaminase (tTG) test was negative. What is the most appropriate next step?', 1, 'IgA deficiency is common in celiac disease and can cause recurrent sinus infections and false-negative tTG results. A total IgA level is necessary to ensure the celiac screen is valid.', '2024 ITE Critique Book, Item 149', '["A repeat IgA tTG level","A total IgA level","Vitamin D and B12 levels","A 24-hour fecal fat collection","CT of the abdomen and pelvis"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'A 54-year-old female has positive hepatitis C antibody and a high viral load. She does not have cirrhosis (FIB-4 0.93). When should treatment with glecaprevir/pibrentasvir be initiated?', 0, 'Guidelines recommend initiating HCV treatment as soon as the diagnosis is confirmed in patients without contraindications. Delaying for vaccinations or alcohol abstinence is not required.', '2024 ITE Critique Book, Item 150', '["At this visit","After she has abstained from alcohol for 3 months","If a repeat viral load is increased in 3 months","After completing the hepatitis A and B vaccination series","If a Doppler ultrasound is negative for thrombosis"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2024', 'Endocrine', 'Endocrine', '', 'A 63-year-old with diabetes presents with vomiting, abdominal pain, and Kussmaul respirations. Laboratory studies show glucose 190 mg/dL, low bicarbonate, and an anion gap of 23. Which medication likely contributed to this?', 1, 'SGLT2 inhibitors like canagliflozin can cause euglycemic diabetic ketoacidosis, where the patient has metabolic acidosis and ketones but a relatively normal serum glucose level.', '2024 ITE Critique Book, Item 151', '["Atorvastatin","Canagliflozin","Lisinopril","Metformin","Semaglutide"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'A 45-year-old female has milky nipple discharge and a 7-mm enhancing mass on pituitary MRI. Prolactin is 95 ng/mL. What is the most appropriate pharmacotherapy?', 1, 'Cabergoline is the first-line treatment for hyperprolactinemia due to a microadenoma and is more effective than bromocriptine at shrinking tumors and normalizing prolactin levels.', '2024 ITE Critique Book, Item 152', '["Bromocriptine","Cabergoline","Levonorgestrel/ethinyl estradiol","Metoclopramide","Risperidone"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'During a sports physical, you hear a systolic murmur. Which characteristic would raise the most concern for hypertrophic cardiomyopathy?', 2, 'The HCM murmur intensifies with maneuvers that reduce preload, such as the Valsalva maneuver or moving from squatting to standing. Maneuvers that increase preload (squatting, leg raise) cause it to soften.', '2024 ITE Critique Book, Item 153', '["Decreased intensity with an isometric handgrip","Decreased intensity with the Valsalva maneuver","Increased intensity with moving from squatting to standing","Increased intensity with passive leg raise"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'A 45-year-old male with sickle cell disease presents with a painful erection that has lasted 5 hours. What is the most appropriate next step?', 4, 'Ischemic priapism (common in sickle cell disease) is a medical emergency requiring urgent urologic evaluation and intervention within 4-6 hours to prevent permanent damage.', '2024 ITE Critique Book, Item 154', '["Analgesia within 30 minutes","A penile blood gas measurement","Intracavernosal alprostadil","Intracavernosal phenylephrine","Urgent evaluation by a urologist"]'::jsonb
        ),(
            '2024', 'Nephrologic', 'Nephrologic', '', 'A 71-year-old male smoker presents with gross hematuria and no other symptoms. Which of the following should be ordered?', 2, 'Patients at high risk for bladder cancer (age >=60, heavy smoking history, gross hematuria) should undergo both CT urography and cystoscopy.', '2024 ITE Critique Book, Item 155', '["Cytology","CT urography only","CT urography plus cystoscopy","Urinary tract ultrasonography plus cystoscopy","Urinary tract MRI plus cystoscopy"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 32-year-old male is diagnosed with panic disorder. Which of the following is most appropriate for initial treatment?', 2, 'SSRIs like escitalopram and SNRIs are first-line pharmacologic treatments for panic disorder. Benzodiazepines are generally avoided as first-line due to the risk of tolerance and dependence.', '2024 ITE Critique Book, Item 156', '["Bupropion","Buspirone","Escitalopram","Hydroxyzine","Lorazepam"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 46-year-old plans a ski trip to an altitude of 3000 m. Which of the following is most appropriate for the prevention of acute altitude sickness?', 2, 'Acetazolamide is the mainstay for pharmacological prophylaxis of altitude sickness. Dexamethasone is generally reserved for treatment or prevention of severe edema in specific cases.', '2024 ITE Critique Book, Item 157', '["Overhydration","Full genome sequencing","Acetazolamide, 125 mg twice daily","Dexamethasone, 6 mg daily","Ibuprofen, 800 mg 3 times daily"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A biopsy of an enlarging erythematous 1.0-cm papule with a central plug shows keratoacanthoma. This lesion requires removal because it may be associated with which of the following?', 2, 'Keratoacanthoma is a rapidly growing lesion that can be difficult to distinguish from cutaneous squamous cell carcinoma (CSCC) and may actually contain CSCC at its base.', '2024 ITE Critique Book, Item 158', '["Actinic keratosis","Basal cell carcinoma","Cutaneous squamous cell carcinoma","Malignant melanoma"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 72-year-old male with dilated cardiomyopathy now has an improved ejection fraction of 55%-60%. He is asymptomatic on carvedilol, dapagliflozin, sacubitril/valsartan, and spironolactone. What change to his cardiomyopathy regimen is recommended?', 0, 'Guideline-directed medical therapy should be continued indefinitely in patients with heart failure even if their ejection fraction recovers, to prevent relapse.', '2024 ITE Critique Book, Item 159', '["No change to his current regimen","Changing spironolactone to as-needed","Discontinuing carvedilol","Discontinuing dapagliflozin","Discontinuing sacubitril/valsartan"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 9-year-old has a buckle fracture of the distal radius. What is the most appropriate management?', 1, 'Buckle (torus) fractures are incomplete fractures common in children. They can be safely managed with a removable splint and often do not require formal follow-up if symptoms improve.', '2024 ITE Critique Book, Item 160', '["No treatment","Immobilization in a prefabricated removable splint for 2-3 weeks","Immobilization in a short arm cast for 6 weeks","Immobilization in a long arm cast for 6 weeks","Referral to an orthopedic surgeon"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 25-year-old male undergoing chemotherapy for lymphoma needs vaccinations. Which of the following is CONTRAINDICATED at this time?', 2, 'Live virus vaccines like MMR and varicella are contraindicated in immunocompromised patients, including those receiving chemotherapy. Inactivated vaccines are generally safe and indicated.', '2024 ITE Critique Book, Item 161', '["COVID-19","Hepatitis B","MMR","Pneumococcal","Tdap"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 74-year-old has a DVT provoked by immobilization in a cast for a fracture. What is the indicated duration of anticoagulation therapy?', 1, 'For an initial episode of a DVT provoked by a major transient risk factor (like surgery or immobilization), 3 months of anticoagulation is recommended.', '2024 ITE Critique Book, Item 162', '["No anticoagulation","Anticoagulation for 3 months","Anticoagulation for 6 months","Anticoagulation for 12 months","Extended anticoagulation indefinitely"]'::jsonb
        ),(
            '2024', 'Special Sensory', 'Special Sensory', '', 'Which nutritional deficiency is most likely to be responsible for a patient''s taste disorder (gustatory dysfunction)?', 2, 'A deficiency of Vitamin B3 (niacin) can cause taste disturbances. Other common causes of taste disorders include zinc deficiency and various medications.', '2024 ITE Critique Book, Item 163', '["Calcium","Selenium","Vitamin B3","Vitamin D","Vitamin E"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 40-year-old female has heartburn and regurgitation twice weekly that affect her quality of life. She has failed lifestyle modifications. What is the most appropriate initial management?', 3, 'For frequent GERD symptoms that impact quality of life, a daily PPI for 4-8 weeks is the most effective initial strategy to provide relief and heal any potential esophagitis.', '2024 ITE Critique Book, Item 164', '["An antacid as needed","An H2-receptor antagonist as needed","A PPI as needed","A PPI daily for 4-8 weeks","Esophageal pH monitoring"]'::jsonb
        ),(
            '2024', 'Endocrine', 'Endocrine', '', 'Which one of the following is true regarding bariatric surgery?', 2, 'Bariatric surgery is highly effective at inducing remission of type 2 diabetes mellitus and reducing obesity-related mortality. Roux-en-Y gastric bypass typically leads to the greatest weight loss.', '2024 ITE Critique Book, Item 165', '["It has no effect on obesity-related mortality","Weight loss is equivalent to behavioral interventions","It is effective for treating diabetes mellitus","Laparoscopic sleeve banding leads to the greatest weight loss"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Bruising in which of the following locations would most likely suggest a diagnosis of child abuse in a preschooler?', 1, 'Accidental bruises are common on bony prominences like the forehead, shins, and knees. Bruises on soft tissue areas like the neck, ears, or torso (''TEN-4'' mnemonic) are much more suspicious for abuse.', '2024 ITE Critique Book, Item 166', '["Forehead","Neck","Elbows","Knees","Shins"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 55-year-old male has acute pain and swelling in the right first MTP joint after drinking beer and eating hot dogs. Which laboratory test would best support the likely diagnosis?', 4, 'The clinical picture is classic for a gout flare. While CRP and ESR are often elevated, an elevated uric acid level specifically supports the diagnosis of gout.', '2024 ITE Critique Book, Item 167', '["C-reactive protein","CBC","Comprehensive metabolic panel","Erythrocyte sedimentation rate","A uric acid level"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 32-year-old female has fatigue, myalgias, hand/knee pain, and a fever. Laboratory tests show anemia, a positive ANA titer (1:80), and elevated anti-Smith antibodies. What is the most likely diagnosis?', 4, 'Anti-Smith and anti-double-stranded DNA antibodies are highly specific for the diagnosis of systemic lupus erythematosus (SLE).', '2024 ITE Critique Book, Item 168', '["Polymyalgia rheumatica","Psoriatic arthritis","Rheumatoid arthritis","Septic arthritis","Systemic lupus erythematosus"]'::jsonb
        ),(
            '2024', 'Special Sensory', 'Special Sensory', '', 'Which finding on fundoscopic examination is most concerning for glaucoma?', 3, 'An increased cup to disc ratio (cupping), typically >0.3-0.5, is a characteristic finding of optic nerve damage from glaucoma.', '2024 ITE Critique Book, Item 169', '["Constricted retinal vessels","Dilated retinal vessels","A diminished cup to disc ratio","An elevated cup to disc ratio","Papilledema"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'Which over-the-counter product has the best evidence of benefit for improving cramping and bloating in diarrhea-predominant irritable bowel syndrome (IBS-D)?', 2, 'Peppermint oil acts as an antispasmodic by relaxing smooth muscle and has proven benefit for global IBS symptoms. Soluble fiber is recommended over insoluble fiber like wheat bran.', '2024 ITE Critique Book, Item 170', '["Bismuth subsalicylate","Omega-3 fatty acids","Peppermint oil","St John''s wort","Wheat bran"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'Which finding is most predictive of community-acquired pneumonia in a 13-month-old toddler with a cough?', 3, 'Physical findings of respiratory distress, such as grunting, retractions, or tachypnea, are the most predictive signs of pneumonia in children. Nasal drainage is a negative predictor.', '2024 ITE Critique Book, Item 171', '["3-day history of low-grade fever","Cloudy nasal drainage","Coughing that wakes the child","Grunting and retractions","Recent pneumococcal vaccination"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 89-year-old in hospice for lung cancer has excessive oropharyngeal secretions (death rattle). Which medication would most effectively control this?', 1, 'Anticholinergic medications like glycopyrrolate or hyoscyamine can reduce the volume of terminal secretions. Suctioning should be avoided as it can cause distress.', '2024 ITE Critique Book, Item 172', '["Chlorpheniramine/hydrocodone suspension","Glycopyrrolate","Haloperidol","Hydroxyzine","Morphine"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Which of the following is a best practice strategy for avoiding stigmatizing language in the medical record?', 4, 'Person-first language (e.g., ''patient with diabetes'' instead of ''diabetic'') humanizes the patient and reduces bias. Neutral terms like ''chooses'' are preferred over ''refuses''.', '2024 ITE Critique Book, Item 173', '["Attributing responsibility for the condition to the patient","Documenting that a patient ''refuses'' a treatment","Including socioeconomic status in the clinical ''one-liner''","Leading the HPI with ethnic identifiers","Using person-first language"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 32-year-old reports vaginal dryness and dyspareunia since starting combined oral contraceptives 4 months ago. Which one of the following would most likely alleviate her symptoms?', 0, 'Combined oral contraceptives can be associated with vaginal dryness. Switching to a non-estrogen method like a levonorgestrel IUD often resolves the issue.', '2024 ITE Critique Book, Item 174', '["Switching to a levonorgestrel IUD","Trigger point injections","OnabotulinumtoxinA","Cognitive behavioral therapy","Myofascial pelvic physical therapy"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 32-year-old male with daily marijuana use has episodes of intractable nausea and vomiting that are relieved by hot showers. What is the most likely diagnosis?', 1, 'Intractable vomiting in a chronic cannabis user that is uniquely relieved by hot baths or showers is characteristic of cannabinoid hyperemesis syndrome.', '2024 ITE Critique Book, Item 175', '["Abdominal migraines","Cannabinoid hyperemesis syndrome","Carcinoid syndrome","Pancreatitis","Peptic ulcer disease"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'Which one of the following conditions is most associated with an increased risk for venous thromboembolism?', 0, 'Active malignancy is a very high-risk factor for VTE. Patients with active cancer often require indefinite anticoagulation following a VTE event.', '2024 ITE Critique Book, Item 176', '["Active cancer","COPD","Poorly controlled type 2 diabetes","Severe intermittent asthma","Stage 3 chronic kidney disease"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'According to the USPSTF, which risk factor in a 59-year-old postmenopausal woman should lead to a calculation of osteoporosis risk and consideration of screening now?', 1, 'For women younger than 65, screening should be considered if they have risk factors like smoking, low body weight, high alcohol consumption, or a parental (not aunt) history of hip fracture.', '2024 ITE Critique Book, Item 177', '["Low caffeine consumption","High alcohol consumption","Body weight >100 kg","A maternal aunt with hip fracture","Nonsmoking status"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 62-year-old female reports loss of hand dexterity and balance issues. Examination reveals hyperreflexia and a positive Hoffman sign. What is the most likely diagnosis?', 1, 'Loss of dexterity, ataxia, and upper motor neuron signs (hyperreflexia, Hoffman sign) are hallmark signs of degenerative cervical myelopathy (spinal cord compression).', '2024 ITE Critique Book, Item 178', '["Facet joint arthropathy","Myelopathy","Radiculopathy","Vertebral compression fracture","Vertebral osteomyelitis"]'::jsonb
        ),(
            '2024', 'Reproductive/Female', 'Reproductive/Female', '', 'A 30-year-old with PCOS, BMI 35, and normal A1c wants to conceive. What is the first-line treatment for inducing ovulation in this patient?', 1, 'Letrozole is currently considered first-line therapy for ovulation induction in women with PCOS. It is more effective than metformin.', '2024 ITE Critique Book, Item 179', '["A GLP-1 receptor agonist","Letrozole","Metformin","Spironolactone"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'Which of the following is a major diagnostic criterion for polycythemia vera?', 4, 'The presence of a JAK2 mutation is found in 98% of polycythemia vera cases and is a major diagnostic criterion. Secondary causes of polycythemia (like sleep apnea) typically have normal or high erythropoietin levels, while PV has low levels.', '2024 ITE Critique Book, Item 180', '["An a-1 antitrypsin deficiency","An elevated a-fetoprotein level","An elevated erythropoietin level","Antimitochondrial antibodies","A Janus kinase 2 mutation"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 72-year-old male has impaired balance and spasticity 3 months after a stroke and has fallen twice recently. What is the most appropriate next step in care?', 4, 'Physical therapy is essential for stroke survivors to address mobility, spasticity, and fall prevention. Repeating imaging is not indicated unless there is a new focal deficit.', '2024 ITE Critique Book, Item 181', '["Repeating neuroimaging","Increasing his basal insulin dosage","Initiating lorazepam at bedtime","Initiating sertraline","Referral to a physical therapist"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 50-year-old female asks how to reduce her risk for dementia. Which of the following should you recommend?', 3, 'Aggressive blood pressure control in midlife (SBP <=130) has been shown to reduce the risk of cognitive decline. Alcohol abstinence is not specifically required (low-to-moderate use is okay), and brain-training apps have weak evidence.', '2024 ITE Critique Book, Item 182', '["A memory training app on her smartphone","Abstaining from alcohol","Testing for Alzheimer biomarkers","A target systolic blood pressure <=130 mm Hg","Hormone therapy with estrogen and progesterone"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'Which one of the following ADHD medications is considered safest to take while breastfeeding?', 4, 'Methylphenidate levels in breast milk are extremely low (0.2% of maternal dose) and are often undetectable in infant serum. Clonidine levels can reach 50% of maternal levels and should be avoided.', '2024 ITE Critique Book, Item 183', '["Amphetamine","Atomoxetine","Clonidine","Guanfacine","Methylphenidate"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 20-year-old has a FAST examination after a motor vehicle accident that shows no signs of internal bleeding. What is the next step?', 2, 'While FAST is highly specific, it has low sensitivity (74% in adults, even lower in children). A negative FAST cannot rule out internal bleeding and must be followed by more definitive imaging like CT.', '2024 ITE Critique Book, Item 184', '["No further imaging needed","Imaging only if hemodynamics change","Additional imaging to confirm the absence of bleeding","Diagnostic peritoneal lavage"]'::jsonb
        ),(
            '2024', 'Pulmonary', 'Pulmonary', '', 'A 65-year-old male with Stage 2 COPD and a history of pneumonia hospitalizations requires initial maintenance inhaler therapy to decrease exacerbations. Which is recommended?', 4, 'For patients with frequent COPD exacerbations or hospitalizations, a long-acting muscarinic antagonist (LAMA) like tiotropium is first-line. ICS monotherapy is not recommended for COPD and increases pneumonia risk.', '2024 ITE Critique Book, Item 185', '["Budesonide/formoterol","Fluticasone propionate monotherapy","Ipratropium/albuterol","Salmeterol monotherapy","Tiotropium"]'::jsonb
        ),(
            '2024', 'Infectious Disease', 'Infectious Disease', '', 'Three symptomatic patients in a nursing home unit test positive for influenza A. To prevent additional cases, you should recommend oseltamivir chemoprophylaxis for which group?', 2, 'During an institutional outbreak, chemoprophylaxis should be given to all residents in the affected unit(s) regardless of vaccination status.', '2024 ITE Critique Book, Item 186', '["No residents or staff","Only residents of the unit who are unvaccinated","Only residents of the affected unit","Only facility residents who are unvaccinated","All residents of the facility"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 65-year-old female with prior normal Paps asks if she can stop cervical cancer screening. Which finding would be an indication to CONTINUE screening?', 1, 'Women with a history of a high-grade precancerous lesion (CIN 2 or higher) should continue screening for at least 25 years after treatment, even if it extends past age 65.', '2024 ITE Critique Book, Item 187', '["A family history of cervical cancer","Loop excision of a high-grade lesion 15 years ago","3 consecutive normal cytology results in the last 10 years","2 negative HPV co-tests in the last 10 years","Unprotected intercourse with a new partner"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 67-year-old male has severe aortic stenosis. Which finding would support surgical aortic valve replacement (AVR) at this time?', 1, 'Severe aortic stenosis is an indication for AVR if the patient is symptomatic or if the left ventricular ejection fraction falls below 50%. A normal stress test would actually be an argument against immediate surgery.', '2024 ITE Critique Book, Item 188', '["Elevated 10-year ASCVD risk","A left ventricular ejection fraction of 40%-45%","A need for an elective total knee replacement","A normal exercise stress test result"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 44-year-old has gradually developing shoulder stiffness and pain with impaired active and passive range of motion. What is most likely to lead to resolution?', 3, 'This patient has adhesive capsulitis (frozen shoulder), which affects both active and passive motion. Intra-articular corticosteroid injections combined with physical therapy provide the best relief.', '2024 ITE Critique Book, Item 189', '["Wearing a sling for 4-6 weeks","Extracorporeal shock wave therapy","Biceps tendon sheath injection","Glenohumeral corticosteroid injection and physical therapy","Surgical repair"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 6-year-old has a single, first-time unprovoked seizure and a normal EEG. What should you recommend regarding anti-epileptic drug (AED) therapy?', 0, 'AED therapy is generally not indicated after a first unprovoked childhood seizure if there are no high-risk factors (like an abnormal EEG). Remission rates are similar whether treatment is started after the first or second event.', '2024 ITE Critique Book, Item 190', '["Starting AED monotherapy only if he has a second seizure","Starting AED monotherapy now","Starting combination AED therapy only if he has a second seizure","Starting combination AED therapy now"]'::jsonb
        ),(
            '2024', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 48-year-old was stung by wasps 5 days ago. She has 10-cm erythematous patches with warmth and induration at the sites but no fever. What is the most appropriate treatment?', 3, 'Large local reactions to insect stings that occur days later are inflammatory, not infectious. Prednisone (40-60 mg daily for 3-5 days) is the appropriate treatment. Antibiotics are not indicated.', '2024 ITE Critique Book, Item 191', '["Topical neomycin/polymyxin B","Oral cephalexin","Oral diphenhydramine","Oral prednisone","Oral sulfamethoxazole/trimethoprim"]'::jsonb
        ),(
            '2024', 'Cardiovascular', 'Cardiovascular', '', 'A 39-year-old has stable supraventricular tachycardia with a pulse rate of 166. She has already tried vagal maneuvers without relief. What is the most appropriate next step?', 0, 'Intravenous adenosine (initially 6 mg) is the first-line pharmacologic treatment for stable SVT if vagal maneuvers fail. Synchronized cardioversion is reserved for unstable patients.', '2024 ITE Critique Book, Item 192', '["Adenosine","Atropine","Diltiazem","Metoprolol","Synchronized cardioversion"]'::jsonb
        ),(
            '2024', 'Musculoskeletal', 'Musculoskeletal', '', 'A 29-year-old has low back pain 3 months after childbirth. Pain occurs when climbing stairs and lying on her right side. There is tenderness inferomedial to the PSIS on the right. What is the most likely cause?', 3, 'Sacroiliac joint dysfunction is common in the postpartum period. Tenderness just below the PSIS and pain with weight-bearing or stair-climbing are typical features.', '2024 ITE Critique Book, Item 193', '["Lumbar strain","Piriformis syndrome","Pudendal nerve entrapment","Sacroiliac joint dysfunction","Spondyloarthropathy"]'::jsonb
        ),(
            '2024', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'Most elder abuse cases are perpetrated by which group?', 0, 'Approximately 90% of all elder abuse cases occur in the home and are perpetrated by family members. Only a small fraction is perpetrated by professional caregivers.', '2024 ITE Critique Book, Item 194', '["Family members","Friends","Nurses","Paid caregivers","Physicians"]'::jsonb
        ),(
            '2024', 'Neurologic', 'Neurologic', '', 'A 52-year-old presents with the ''worst headache of his life.'' After a physical exam rules out focal deficits, what is the most appropriate next step?', 0, 'CT of the head without contrast is the initial test for suspected intracranial hemorrhage. Contrast can obscure signs of bleeding. A lumbar puncture is performed if CT is negative but suspicion remains high.', '2024 ITE Critique Book, Item 195', '["CT of the head without contrast","CT of the head with contrast","MRI of the head with and without contrast","A lumbar puncture"]'::jsonb
        ),(
            '2024', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 45-year-old patient taking multiple benzodiazepines for anxiety agrees to a outpatient cessation plan. Which strategy is most appropriate?', 4, 'The recommended strategy for discontinuing benzodiazepines is to consolidate them into a single long-acting agent like diazepam and then perform a slow taper over weeks to months.', '2024 ITE Critique Book, Item 196', '["Discontinuing both and initiating buprenorphine","Discontinuing both and initiating flumazenil","Discontinuing lorazepam and decreasing alprazolam","Tapering both simultaneously over 6 months","Switching both to diazepam and then decreasing the diazepam dosage"]'::jsonb
        ),(
            '2024', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 15-year-old has recurrent spring allergies. She has seen some improvement with intranasal steroids and oral cetirizine but wants more definitive diagnosis. What is the most appropriate next step?', 1, 'Skin allergen testing is the most appropriate next step for diagnosing specific triggers in allergic rhinitis. It is more specific and provides more immediate results than serum testing.', '2024 ITE Critique Book, Item 197', '["A CBC","Skin allergen testing","Serum allergy testing","Chest radiography","Sinus CT"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'Which of the following conditions is most likely to impair the swallowing of both solids and liquids?', 0, 'Achalasia is a motility disorder that affects both solids and liquids. Anatomic obstructions (cancer, strictures, rings) typically impair solids first, with liquids only affected in severe cases.', '2024 ITE Critique Book, Item 198', '["Achalasia","Eosinophilic esophagitis","Esophageal cancer","Esophageal stricture","Schatzki ring"]'::jsonb
        ),(
            '2024', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old with intense epigastric pain, history of daily naproxen use, and exquisite abdominal tenderness is pale and tachycardic. What test should be performed to assist in the diagnosis?', 2, 'The clinical picture is highly suggestive of a perforated peptic ulcer. CT of the abdomen and pelvis is the most sensitive and diagnostic test for this condition.', '2024 ITE Critique Book, Item 199', '["Aortic ultrasonography","Abdominal radiography","Abdominal and pelvic CT","Abdominal paracentesis","Exploratory laparotomy"]'::jsonb
        ),(
            '2024', 'Special Sensory', 'Special Sensory', '', 'Which of the following additional findings in a patient with tinnitus would be an indication for head imaging?', 3, 'Imaging (MRI or CT) is indicated for tinnitus that is pulsatile, unilateral, or associated with asymmetric hearing loss or focal neurologic deficits.', '2024 ITE Critique Book, Item 200', '["Development of major depressive disorder","Bilateral hearing loss on audiometry","Lack of improvement with tricyclic antidepressants","A pulsatile quality of the tinnitus","Symptom duration of 6 months"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 4-month-old is brought to your office during the winter because of a 3-day history of rhinorrhea, cough, and wheezing. On examination the infant is afebrile with a respiratory rate of 50/min and an oxygen saturation of 94% on room air. There is no evidence of respiratory distress. Which one of the following would be the most appropriate management?', 4, 'This infant has bronchiolitis, likely due to RSV. According to AAP guidelines, the management of bronchiolitis is primarily supportive, including maintaining hydration and monitoring respiratory status. Albuterol, epinephrine, hypertonic saline, and corticosteroids are not recommended for routine use in healthy infants with a first episode of bronchiolitis.', '2023 ITE Critique, Item 20', '["Inhaled albuterol (Proventil HFA)","Inhaled epinephrine","Inhaled hypertonic saline","Oral corticosteroids","Supportive care only"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 32-year-old male presents with a 2-day history of a painful, swollen left knee. He has no significant medical history. On examination the knee is warm, erythematous, and tender. A joint aspiration reveals a white blood cell count of 60,000/mm³ with 90% neutrophils. No crystals are seen. Gram stain is negative. Which one of the following is the most likely causative organism?', 2, 'Staphylococcus aureus is the most common cause of septic arthritis in adults. Neisseria gonorrhoeae should be considered in sexually active young adults, but S. aureus remains the overall most frequent pathogen. Management requires prompt antibiotic therapy and joint drainage.', '2023 ITE Critique, Item 21', '["Borrelia burgdorferi","Neisseria gonorrhoeae","Staphylococcus aureus","Streptococcus pneumoniae","Streptococcus pyogenes"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 24-year-old female at 32 weeks gestation presents with a 2-day history of intense itching, primarily on her palms and soles. She has no rash. Laboratory testing reveals elevated serum bile acids. Which one of the following is the most appropriate treatment?', 3, 'Intrahepatic cholestasis of pregnancy presents with pruritus (often on palms and soles) and elevated bile acids. Ursodeoxycholic acid is the first-line treatment to improve symptoms and biochemical markers. Because of the increased risk of stillbirth, delivery is usually recommended between 36 0/7 and 39 0/7 weeks, depending on bile acid levels.', '2023 ITE Critique, Item 22', '["Cholestyramine (Questran)","Diphenhydramine (Benadryl)","Hydrocortisone 1% cream","Ursodeoxycholic acid (Ursodiol)","Immediate delivery"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 68-year-old male with a history of heart failure with reduced ejection fraction (HFrEF) and an ejection fraction of 30% presents for follow-up. He is currently taking lisinopril, carvedilol, and furosemide. Despite these medications, he continues to have NYHA class II symptoms. Which one of the following would be the most appropriate next step in his management?', 3, 'According to the 2022 AHA/ACC/HFSA guidelines, an ARNI (sacubitril/valsartan) is now recommended as first-line therapy (Stage C, HFrEF) to reduce morbidity and mortality. For patients already on an ACE inhibitor or ARB who remain symptomatic, switching to an ARNI is highly recommended. Spironolactone is also indicated but the switch to ARNI is a prioritized recommendation in current guidelines.', '2023 ITE Critique, Item 23', '["Add digoxin","Add hydralazine/isosorbide dinitrate","Add spironolactone","Replace lisinopril with sacubitril/valsartan (Entresto)","Replace lisinopril with losartan"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 45-year-old female reports a 3-month history of pain in her right thumb and wrist. On examination, she has tenderness over the radial styloid process. Pain is elicited when she grasps her thumb in her fist and the wrist is deviated toward the ulna. Which one of the following is the most likely diagnosis?', 1, 'The clinical presentation and positive Finkelstein test (pain with ulnar deviation of the wrist while the thumb is tucked into the fist) are diagnostic of de Quervain tenosynovitis, which involves the abductor pollicis longus and extensor pollicis brevis tendons.', '2023 ITE Critique, Item 24', '["Carpal tunnel syndrome","de Quervain tenosynovitis","Intersection syndrome","Osteoarthritis of the first carpometacarpal joint","Scaphoid fracture"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 72-year-old male with a history of chronic kidney disease and a baseline creatinine level of 2.2 mg/dL is found to have a hemoglobin level of 9.2 g/dL. Further testing shows a serum ferritin of 50 ng/mL and a transferrin saturation of 18%. Which one of the following is the most appropriate next step?', 0, 'This patient has iron deficiency anemia in the setting of CKD. For non-dialysis CKD patients with iron deficiency (TSAT ≤30% and ferritin ≤500 ng/mL), a trial of oral iron is appropriate initially. If the patient does not respond or cannot tolerate oral iron, IV iron would be the next step. ESAs should not be started until iron stores are replete.', '2023 ITE Critique, Item 25', '["Oral iron supplementation","Intravenous iron supplementation","Erythropoiesis-stimulating agent (ESA) therapy","Blood transfusion","Bone marrow biopsy"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 5-year-old male is brought to your office for evaluation of snoring and restless sleep. His mother reports that he sometimes stops breathing for a few seconds during the night. On examination, he has 3+ tonsillar hypertrophy. Which one of the following is the most appropriate next step?', 2, 'In children with symptoms of obstructive sleep apnea (OSA) and physical findings like tonsillar hypertrophy, polysomnography is the gold standard for diagnosis. Clinical history alone is not reliable for distinguishing OSA from primary snoring. Once OSA is confirmed, adenotonsillectomy is usually the first-line treatment.', '2023 ITE Critique, Item 26', '["Observation and follow-up in 6 months","Intranasal corticosteroids","Polysomnography","Adenotonsillectomy","Continuous positive airway pressure (CPAP)"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'An 80-year-old female resident of a long-term care facility is found to have 100,000 CFU/mL of Escherichia coli on a routine urine culture. She has no urinary symptoms, fever, or changes in mental status. Which one of the following is the most appropriate management?', 4, 'This patient has asymptomatic bacteriuria. Screening for and treating asymptomatic bacteriuria is not recommended in older adults, including those living in long-term care facilities, as it does not improve outcomes and increases the risk of antibiotic resistance and adverse effects.', '2023 ITE Critique, Item 27', '["Nitrofurantoin (Macrodantin) for 5 days","Fosfomycin (Monurol) as a single dose","Trimethoprim/sulfamethoxazole (Bactrim) for 3 days","Ciprofloxacin (Cipro) for 3 days","No treatment"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 55-year-old male with a 30-pack-year smoking history presents with a chronic cough and progressive shortness of breath. Spirometry shows an FEV1/FVC ratio of 0.62. His FEV1 is 65% of predicted. He reports two exacerbations in the past year that required oral steroids, but none required hospitalization. Which one of the following is the most appropriate initial maintenance therapy?', 4, 'According to the GOLD 2023 report, this patient falls into Group E (previously C or D) because he has had two exacerbations in the past year. For Group E patients, the recommended initial therapy is a combination of a LAMA and a LABA. ICS should be considered if blood eosinophils are ≥300 cells/μL.', '2023 ITE Critique, Item 28', '["Short-acting beta-agonist (SABA) as needed","Long-acting beta-agonist (LABA)","Long-acting muscarinic antagonist (LAMA)","Inhaled corticosteroid (ICS) plus LABA","LAMA plus LABA"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 28-year-old female presents with a 4-month history of excessive worry about her job, health, and finances. She reports difficulty concentrating, muscle tension, and feeling ''on edge.'' Which one of the following is the most appropriate first-line pharmacotherapy?', 2, 'This patient meets criteria for generalized anxiety disorder (GAD). First-line pharmacotherapeutic options include SSRIs and SNRIs, such as duloxetine. While buspirone is also used, SNRIs/SSRIs generally have stronger evidence for efficacy. Benzodiazepines like alprazolam are not recommended as first-line due to the risk of dependence.', '2023 ITE Critique, Item 29', '["Alprazolam (Xanax)","Buspirone (Buspar)","Duloxetine (Cymbalta)","Quetiapine (Seroquel)","Propranolol"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 35-year-old female presents with pain on the plantar surface of her foot. The pain is most severe with her first steps in the morning and improves with activity, though it worsens by the end of the day. On examination, there is maximal tenderness at the calcaneal tuberosity. Which one of the following is the most appropriate initial treatment?', 3, 'The clinical history is classic for plantar fasciitis. Initial conservative management includes stretching the plantar fascia and calf muscles, the use of prefabricated or custom orthotics, and NSAIDs. Corticosteroid injections are typically reserved for cases that fail initial conservative therapy.', '2023 ITE Critique, Item 30', '["Extracorporeal shock wave therapy","Corticosteroid injection","Custom-made orthotics","Stretching exercises for the calf and plantar fascia","Surgery"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 52-year-old male with type 2 diabetes has a blood pressure of 145/92 mm Hg. He is already taking metformin and amlodipine. His latest laboratory results show a serum creatinine of 1.1 mg/dL and a urine albumin/creatinine ratio of 150 mg/g (N <30). Which one of the following would be the most appropriate addition to his regimen?', 2, 'In patients with diabetes, hypertension, and albuminuria (urine albumin/creatinine ratio ≥30 mg/g), an ACE inhibitor or ARB is recommended as first-line therapy to slow the progression of kidney disease. Lisinopril is an ACE inhibitor and would be an appropriate choice. (Note: ARBs are also appropriate, but only one should be chosen).', '2023 ITE Critique, Item 31', '["Chlorthalidone","Hydralazine","Lisinopril","Losartan","Spironolactone"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 19-year-old male presents with a mildly itchy rash on his chest and back that began 1 week ago. He initially had a single 3-cm oval, scaly patch on his chest, followed by multiple smaller patches in a ''Christmas tree'' distribution. Which one of the following is the most likely diagnosis?', 1, 'Pityriasis rosea typically begins with a ''herald patch'' followed by a generalized eruption of smaller lesions in a ''Christmas tree'' distribution along skin cleavage lines. It is usually self-limiting. Secondary syphilis can look similar but typically involves the palms and soles.', '2023 ITE Critique, Item 32', '["Guttate psoriasis","Pityriasis rosea","Secondary syphilis","Tinea corporis","Tinea versicolor"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 64-year-old female is hospitalized for a severe flare of ulcerative colitis and develops diarrhea. A stool test is positive for Clostridioides difficile toxin. Which one of the following is the most appropriate first-line treatment?', 3, 'Current IDSA/SHEA guidelines recommend fidaxomicin as the preferred first-line treatment for C. difficile infection (CDI). Oral vancomycin is an acceptable alternative if fidaxomicin is not available. Metronidazole is no longer recommended as first-line therapy for adults.', '2023 ITE Critique, Item 33', '["Oral metronidazole","Oral vancomycin","Intravenous vancomycin","Oral fidaxomicin","Fecal microbiota transplant"]'::jsonb
        ),(
            '2023', 'Special Sensory', 'Special Sensory', '', 'A 72-year-old female reports a sudden, painless loss of vision in her right eye. On funduscopic examination, you see a pale retina with a ''cherry-red spot'' at the fovea. Which one of the following is the most likely diagnosis?', 1, 'A sudden, painless loss of vision accompanied by a ''cherry-red spot'' on fundoscopy is classic for central retinal artery occlusion (CRAO). This is a medical emergency. Central retinal vein occlusion typically presents with a ''blood and thunder'' fundus (diffuse hemorrhages).', '2023 ITE Critique, Item 34', '["Acute angle-closure glaucoma","Central retinal artery occlusion","Central retinal vein occlusion","Retinal detachment","Vitreous hemorrhage"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 13-year-old male presents with right knee pain that has been present for several weeks. He is active in basketball. On examination, there is tenderness and swelling over the tibial tuberosity. He has full range of motion of the knee. Which one of the following is the most likely diagnosis?', 0, 'Osgood-Schlatter disease (traction apophysitis of the tibial tuberosity) is a common cause of knee pain in active adolescents. Diagnosis is clinical, based on tenderness and swelling at the tibial tuberosity. Treatment is conservative, including activity modification and ice.', '2023 ITE Critique, Item 35', '["Osgood-Schlatter disease","Patellar tendonitis","Patellofemoral pain syndrome","Prepatellar bursitis","Sinding-Larsen-Johansson syndrome"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 55-year-old female presents for discussion of menopausal symptoms. She reports frequent hot flashes that disrupt her sleep. She has not had a hysterectomy. Which one of the following would be the most appropriate pharmacologic treatment for her symptoms?', 1, 'For women with an intact uterus, systemic estrogen therapy must be combined with a progestogen to prevent endometrial hyperplasia and cancer. SSRIs and gabapentin can be used for vasomotor symptoms but are generally less effective than hormone therapy.', '2023 ITE Critique, Item 36', '["Estrogen-only therapy","Estrogen and progestogen therapy","Fluoxetine (Prozac)","Gabapentin (Neurontin)","Black cohosh"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 45-year-old female presents with frequent headaches that occur 2–3 times per week. She describes them as unilateral, throbbing, and associated with nausea and light sensitivity. She has used sumatriptan with good effect but is interested in preventive therapy. Which one of the following is an FDA-approved first-line agent for migraine prophylaxis?', 3, 'Propranolol, timolol, divalproex sodium, and topiramate are all FDA-approved first-line agents for migraine prophylaxis. Amitriptyline and venlafaxine are frequently used off-label but are considered second-line by the American Academy of Neurology.', '2023 ITE Critique, Item 37', '["Amitriptyline","Lisinopril","Memantine","Propranolol","Venlafaxine"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 24-year-old male is brought to the emergency department after being found unresponsive. His respiratory rate is 6/min and his pupils are pinpoints. Which one of the following is the most appropriate immediate intervention?', 2, 'The triad of respiratory depression, pinpoint pupils, and altered mental status is highly suggestive of opioid overdose. Naloxone should be administered immediately to reverse the effects. Flumazenil is for benzodiazepine overdose and can precipitate seizures.', '2023 ITE Critique, Item 38', '["Administer activated charcoal","Administer flumazenil","Administer naloxone","Perform gastric lavage","Start a bicarbonate drip"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 75-year-old male presents with a history of recurrent falls. On examination, he has a slow, shuffling gait, difficulty initiating movement, and a resting tremor in his right hand. Which one of the following is the most appropriate initial treatment for his condition?', 1, 'This patient has the classic features of Parkinson''s disease (tremor, bradykinesia, gait changes). Carbidopa/levodopa is the most effective medication for symptomatic treatment and is generally preferred as initial therapy in older patients.', '2023 ITE Critique, Item 39', '["Amantadine","Carbidopa/levodopa (Sinemet)","Donepezil (Aricept)","Pramipexole (Mirapex)","Selegiline"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 62-year-old male presents with bothersome urinary frequency and nocturia. On digital rectal examination, his prostate is enlarged but smooth and non-tender. His PSA is 1.5 ng/mL. Which one of the following medications is most likely to provide the most rapid relief of his symptoms?', 3, 'Alpha-blockers like tamsulosin provide rapid relief of symptoms of benign prostatic hyperplasia (BPH) by relaxing smooth muscle in the bladder neck and prostate. 5-alpha-reductase inhibitors like finasteride take 6-12 months to achieve maximal effect by shrinking the prostate volume.', '2023 ITE Critique, Item 40', '["Dutasteride (Avodart)","Finasteride (Proscar)","Mirabegron (Myrbetriq)","Tamsulosin (Flomax)","Tadalafil (Cialis)"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 30-year-old female presents for a routine checkup. Her last Pap test was 3 years ago and was normal. She has no new symptoms or risk factors. According to the USPSTF, which one of the following is the most appropriate screening strategy for cervical cancer in this patient?', 0, 'For women aged 21–29, the USPSTF recommends screening with cervical cytology alone every 3 years. For women aged 30–65, options include cytology alone every 3 years, high-risk HPV (hrHPV) testing alone every 5 years, or cotesting every 5 years.', '2023 ITE Critique, Item 41', '["Cervical cytology every 3 years","High-risk HPV testing every 3 years","Cervical cytology every 5 years","High-risk HPV testing every 5 years","Annual cervical cytology"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 48-year-old female is diagnosed with hyperthyroidism. A radioactive iodine uptake scan shows low uptake. Which one of the following is the most likely diagnosis?', 1, 'Low radioactive iodine uptake in a hyperthyroid patient suggests either thyroiditis (where stored hormone is leaking out), exogenous thyroid hormone ingestion, or recent iodine exposure. Graves'' disease and toxic nodules show high uptake.', '2023 ITE Critique, Item 42', '["Graves'' disease","Subacute thyroiditis","Toxic multinodular goiter","Toxic adenoma","TSH-secreting pituitary adenoma"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 9-month-old is brought to the office for a well child check. The mother mentions that the infant is eating some solids but mostly breastfeeds. You recommend screening for which one of the following conditions?', 2, 'The AAP recommends universal screening for iron deficiency anemia at approximately 12 months of age. Infants who are primarily breastfed or not receiving iron-fortified formula are at higher risk. Lead screening is also common at this age depending on local prevalence.', '2023 ITE Critique, Item 43', '["Cystic fibrosis","Dyslipidemia","Iron deficiency anemia","Lead poisoning","Type 1 diabetes"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 28-year-old male presents with a deep laceration on his hand from a clean kitchen knife. He is certain he received a tetanus booster 8 years ago. Which one of the following is indicated for tetanus prophylaxis?', 1, 'For clean, minor wounds, a tetanus booster is indicated if the last dose was >10 years ago. For all other wounds (contaminated or deep), a booster is indicated if the last dose was >5 years ago. Since this is a deep laceration and his last booster was 8 years ago, he should receive a tetanus toxoid-containing vaccine.', '2023 ITE Critique, Item 44', '["No tetanus prophylaxis","Tetanus toxoid-containing vaccine (Tdap or Td)","Tetanus immune globulin (TIG)","Both Tdap and TIG","Wait 2 years and then give Tdap"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 65-year-old male with a history of hypertension and a 40-pack-year smoking history presents for a physical exam. According to the USPSTF, which one of the following screening tests should be performed?', 1, 'The USPSTF recommends a one-time screening for abdominal aortic aneurysm (AAA) with ultrasonography in men aged 65–75 who have ever smoked.', '2023 ITE Critique, Item 45', '["Carotid artery ultrasound","One-time ultrasound for abdominal aortic aneurysm","Exercise stress test","CT coronary artery calcium scoring","Peripheral artery disease screening with ankle-brachial index"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 40-year-old male presents with a pearly, telangiectatic papule on his nose that has been present for 6 months. Which one of the following is the most likely diagnosis?', 1, 'Basal cell carcinoma often presents as a pearly, translucent papule with telangiectasias and sometimes a central ulceration (rodent ulcer). It is the most common form of skin cancer.', '2023 ITE Critique, Item 46', '["Actinic keratosis","Basal cell carcinoma","Malignant melanoma","Squamous cell carcinoma","Seborrheic keratosis"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 60-year-old male with a history of deep vein thrombosis 2 years ago presents with sudden-onset pleuritic chest pain and shortness of breath. His heart rate is 110 beats/min and his oxygen saturation is 92%. A CT angiogram confirms a pulmonary embolism. Which one of the following is the most appropriate long-term anticoagulation strategy?', 3, 'For a provoked or first unprovoked PE, the standard duration of anticoagulation is 3–6 months. DOACs like rivaroxaban are generally preferred over warfarin for most patients.', '2023 ITE Critique, Item 47', '["Aspirin","Clopidogrel (Plavix)","Enoxaparin (Lovenox) indefinitely","Rivaroxaban (Xarelto) for 3–6 months","Warfarin (Coumadin) for 1 month"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 32-year-old female who is 10 weeks pregnant is found to have a TSH of 6.2 μU/mL (N 0.4–4.0 in nonpregnant adults). Which one of the following is the most appropriate next step?', 3, 'Overt hypothyroidism and subclinical hypothyroidism (elevated TSH with normal free T4) in pregnancy are associated with adverse outcomes. Treatment with levothyroxine is recommended if the TSH is above pregnancy-specific reference ranges (typically >4.0).', '2023 ITE Critique, Item 48', '["Repeat the TSH in 4 weeks","Check a free T4 level","Check thyroid peroxidase antibodies","Start levothyroxine","Observe only"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 25-year-old female presents for evaluation of easy bruising. Her CBC shows a platelet count of 45,000/mm³, but her white cell count and hemoglobin are normal. A peripheral smear shows large platelets but is otherwise normal. She has no other symptoms. Which one of the following is the most likely diagnosis?', 1, 'Immune thrombocytopenia (ITP) is a diagnosis of exclusion in patients with isolated thrombocytopenia and no other clear cause. In adults, it often presents with mild bruising or petechiae.', '2023 ITE Critique, Item 49', '["Disseminated intravascular coagulation","Immune thrombocytopenia (ITP)","Thrombotic thrombocytopenic purpura","Von Willebrand disease","Bernard-Soulier syndrome"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 45-year-old male presents with recurrent episodes of epigastric pain that is relieved by eating. Which one of the following is the most appropriate initial diagnostic test?', 1, 'Pain relieved by food is classic for a duodenal ulcer, which is most commonly caused by H. pylori. In a patient under 60 without ''alarm symptoms'' (weight loss, anemia, etc.), a ''test and treat'' strategy for H. pylori is recommended. The urea breath test or stool antigen test are preferred.', '2023 ITE Critique, Item 50', '["Abdominal CT","H. pylori urea breath test","Serum gastrin level","Stool occult blood test","Upper endoscopy"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 45-year-old female presents to the emergency department with a 1-week history of facial swelling and progressive dyspnea with exertion. She was diagnosed 1 week ago with non-Hodgkin lymphoma but her medical history is otherwise unremarkable. A chest radiograph is shown. After hospital admission, which one of the following would be the most appropriate urgent next step in the management of this condition?', 4, 'This patient presents with signs and symptoms related to superior vena cava syndrome, which is caused by compression of the superior vena cava. This is most often caused by lung cancer or lymphoma. After ensuring that the patient is hospitalized and stable, the initial treatment options include intravenous corticosteroids, chemotherapy, radiation, and occasionally intravascular stenting. Echocardiography and bronchoscopy are not indicated in the initial management of superior vena cava syndrome.', '2023 ITE Critique, Item 1', '["Intravenous antibiotics","Echocardiography","Plasmapheresis","Bronchoscopy","Radiation"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 22-year-old male presents for follow-up of moderate persistent asthma. After discussing his treatment options, you decide to use a single maintenance and reliever therapy (SMART) approach. Which one of the following daily inhaled therapies is appropriate to prescribe in this setting?', 1, 'In the single maintenance and reliever therapy (SMART) approach for asthma control, combination therapy with an inhaled corticosteroid and a long-acting bronchodilator is used as both controller and rescue medication. SMART is recommended as the preferred therapeutic approach in steps 3 and 4 in the 2020 National Asthma Education and Prevention Program guidelines. Formoterol is the only medication available in the United States recommended for use in SMART therapy due to its rapid onset of action.', '2023 ITE Critique, Item 2', '["Budesonide (Pulmicort)","Budesonide/formoterol (Symbicort)","Fluticasone/salmeterol (Advair Diskus)","Fluticasone/vilanterol (Breo Ellipta)","Tiotropium/olodaterol (Stiolto Respimat)"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'Which one of the following is an indication for long-term, rather than short-term, proton pump inhibitor therapy?', 1, 'While many patients remain on long-term PPI therapy without a clear indication, in some situations the benefits do clearly outweigh the risks. Such indications include Barrett esophagus, severe erosive esophagitis, eosinophilic esophagitis, and high risk for upper gastrointestinal (GI) bleeding. Risk factors for GI bleeding include prior ulcer, age >65, high-dose NSAID therapy, or concurrent use of aspirin, corticosteroids, or anticoagulants. Such patients should be advised to use PPIs indefinitely.', '2023 ITE Critique, Item 3', '["The eradication of Helicobacter pylori","Gastroprotection in users of high-dose NSAIDs at high risk for gastrointestinal bleeding","The prevention of rebleeding from a Mallory-Weiss tear","The prevention of ulcers after band ligation of esophageal varices","The treatment of an NSAID-related gastric ulcer"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'An 85-year-old male presents for an annual Medicare examination. His wife tells you that he has been repeating himself in conversations, buying the same item multiple times, and taking longer to complete routine tasks such as balancing the checkbook. He recalls 1 out of 3 items on the Mini-Cognitive Assessment Instrument (Mini-Cog) and is unable to draw a clock. A depression screening is negative. Which one of the following is the greatest risk factor for this patient''s condition?', 0, 'Dementia affects 5 million adults, with an overall prevalence of around 5%, but it is 37% in those over age 90. The greatest risk factor for dementia is older age. Strong risk factors include diabetes mellitus, midlife obesity, family history, cardiovascular disease, cerebrovascular disease, use of anticholinergic medications, and a low education level.', '2023 ITE Critique, Item 4', '["Advanced age","Atrial fibrillation","Diabetes mellitus","A history of head trauma","Smoking"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'Which one of the following would be the most appropriate initial pharmacotherapy for a temporomandibular disorder in an otherwise healthy 54-year-old male?', 2, 'The initial first-line pharmacologic therapy for temporomandibular disorders is naproxen. Cyclobenzaprine may also be added if there is evidence of muscle spasm. If this is unsuccessful, other options include a trial of amitriptyline or gabapentin. Corticosteroid injections should be avoided due to potential cartilage damage.', '2023 ITE Critique, Item 5', '["Amitriptyline, 25 mg at bedtime","Gabapentin (Neurontin), 300 mg daily","Naproxen, 500 mg twice daily","Tramadol, 50 mg every 6 hours","Corticosteroid injection into the temporomandibular joint"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 33-year-old female presents to your office concerned about feeling fatigued for the past few months. She says that she feels cold often, has intermittent joint discomfort, and has gained 5 lb. She has not experienced any pain or problems swallowing. She gave birth to her youngest child almost 3 years ago, and she recently started an oral contraceptive. She has not had any recent illnesses. Her family history is significant for rheumatoid arthritis. A physical examination reveals a mild goiter but is otherwise unremarkable. Her vital signs are stable. A CBC and comprehensive metabolic panel are normal. A TSH level is 6.48 μU/mL (N 0.4–4.5) and a thyroid peroxidase antibody level is 378 IU/mL (N <34). A free T4 level is normal. Which one of the following is the most likely diagnosis for this patient?', 1, 'This patient presents with elevated TSH and thyroid peroxidase (TPO) levels. Elevated TPO levels are found in 95% of patients with Hashimoto thyroiditis. In addition, her family history includes rheumatoid arthritis (another autoimmune disease), making Hashimoto thyroiditis the most likely diagnosis. Postpartum thyroiditis occurs within 1 year of delivery, and subacute thyroiditis is often associated with thyroid pain following a viral infection.', '2023 ITE Critique, Item 6', '["Drug-induced thyroiditis","Hashimoto thyroiditis","Postpartum thyroiditis","Subacute thyroiditis"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A first-time mother brings her 12-month-old to your office for a well child check. She and the child''s father are both your patients as well. Upon routine screening for anemia, you discover the infant has microcytic anemia with elevated red cell distribution width. You ask the parent about the child''s diet. She looks down at the floor, exhibiting poor eye contact and a flat affect, and responds that she does not shop or cook often. She says the child is happy when eating just applesauce and milk. The mother reports that she has been unmotivated and crying frequently. In addition to checking the child''s lead level and starting iron supplementation, which one of the following would be the most important next step to help this dyad?', 3, 'Postpartum depression is common and patients should be screened for a minimum of 1 year. A mother with severe postpartum depression may have trouble executing proper infant feeding practices even if she knows what to feed. In this case, treating the mother''s depression is the most likely way to successfully treat the child''s anemia. While psychiatrist referral may be helpful, it puts unnecessary barriers in place for initial testing and treatment.', '2023 ITE Critique, Item 7', '["Providing reassurance and validation for the mother","Educating the mother about nutrition and the importance of iron-rich foods for the child","Notifying the child''s father","Evaluating and treating the mother for postpartum depression","Referring the mother to a psychiatrist"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 52-year-old male presents to your office for a routine annual health maintenance examination. He has a past medical history of hypertension and well-controlled type 2 diabetes with a hemoglobin A1c of 6.6%. He is also a chronic tobacco smoker. He requests screening for testicular cancer because his close friend recently died from the disease. Other than colon cancer in his adoptive father, there is no known family history of cancer. Which one of the following is indicated for testicular cancer screening for this patient?', 0, 'Although testicular cancer is common in younger men, the U.S. Preventive Services Task Force recommends against screening for testicular cancer in asymptomatic adolescent or adult males (D recommendation). Detailed history and physical exams should be performed on symptomatic patients, but tumor markers and imaging are for staging and surveillance, not screening.', '2023 ITE Critique, Item 8', '["No screening","An α-fetoprotein level","Scrotal ultrasonography now","Scrotal ultrasonography at age 55","CT of the abdomen and pelvis at age 55"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'An 82-year-old female in your palliative care service who has stage 4 breast cancer is experiencing frequent episodes of delirium. Her pain is well controlled on long-acting oral opioid therapy. Additionally, no other reversible causes of delirium are noted. Her delirium is not responding to conservative measures, and her family asks if there are any medications that can effectively manage her symptoms. Which one of the following should you recommend?', 3, 'The first step in managing delirium is to assess for reversible causes. Antipsychotic medications, such as haloperidol or risperidone, are recommended if conservative measures fail. Benzodiazepines (like alprazolam or diazepam) should be used with caution as they can worsen delirium, especially in older patients. Melatonin is not indicated for delirium management.', '2023 ITE Critique, Item 9', '["Alprazolam (Xanax)","Diazepam (Valium)","Melatonin","Risperidone (Risperdal)"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A Black female presents with multiple insect bites on her arms and legs. This patient is at risk for developing which one of the following conditions?', 4, 'Patients with dark skin are at greater risk for postinflammatory hyperpigmentation, which can occur after external injuries like insect bites. It is particularly noticeable in Fitzpatrick skin phototypes III–VI. Other listed conditions (acanthosis nigricans, melasma, etc.) are common in skin of color but are not typically related to external injuries like insect bites.', '2023 ITE Critique, Item 10', '["Acanthosis nigricans","Acne keloidalis nuchae","Dermatosis papulosa nigra","Melasma","Postinflammatory hyperpigmentation"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'You are co-managing a 59-year-old female with stage 3b chronic kidney disease (CKD) and secondary hyperparathyroidism resulting in osteoporosis. Due to transportation issues, she has been unable to see her specialist and requests that you take over her laboratory surveillance for CKD-bone mineral disorder. In addition to serum calcium, parathyroid hormone, vitamin D, and creatinine levels and the estimated glomerular filtration rate, which one of the following laboratory values should be routinely monitored?', 3, 'Secondary hyperparathyroidism due to CKD interferes with normal calcium, phosphorus, and vitamin D regulation. PTH increases serum calcium and phosphorus levels; controlling these through diet and medication reduces fracture risk and mortality. Monitoring calcitonin, magnesium, or TSH is not useful for routine CKD-BMD management.', '2023 ITE Critique, Item 11', '["Calcitonin","Magnesium","Parathyroid hormone-related peptide","Phosphorus","TSH"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 42-year-old premenopausal female presents to your office with new-onset bilateral nipple discharge for the past 4 weeks. She describes the discharge as green and nonbloody. She has a past medical history of diabetes mellitus, dyslipidemia, hypertension, and depression. Her current medications include the following: Atorvastatin (Lipitor), Escitalopram (Lexapro), Hydrochlorothiazide, Lisinopril (Zestril), Metformin. Her vital signs are unremarkable. A physical examination is significant for nonbloody green fluid expressed from the nipples. A TSH level, comprehensive metabolic panel, and CBC are all within normal range, and a serum hCG test is negative. A prolactin level is elevated at 85 ng/mL (N <30 in nonpregnant premenopausal females). Which one of her medications is most likely to cause galactorrhea?', 1, 'Of this patient''s medications, escitalopram is most likely to induce galactorrhea. SSRIs are responsible for 95% of medication-induced galactorrhea cases. Prolactin levels <100 ng/mL are commonly due to medications, systemic pathology, or microadenomas. Lisinopril, metformin, and atorvastatin are not common causes of hyperprolactinemia.', '2023 ITE Critique, Item 12', '["Atorvastatin","Escitalopram","Hydrochlorothiazide","Lisinopril","Metformin"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 73-year-old female with a history of obesity, essential hypertension, hyperlipidemia, and well-controlled type 2 diabetes presents to the emergency department (ED) with severe, crushing chest pain. She has a blood pressure of 115/64 mm Hg, a pulse rate of 90 beats/min, a respiratory rate of 15/min, a temperature of 37.2°C (99.0°F), and an oxygen saturation of 95% on room air. A point-of-care troponin level is 1.0 ng/mL (N <0.04) and an EKG is normal, and you diagnose a non-ST-elevation myocardial infarction. Which one of the following interventions in the ED has the greatest benefit with regard to decreasing mortality in this patient?', 1, 'A large randomized trial showed that aspirin administration for suspected acute MI saves one life for every 24 patients. Supplemental oxygen has no benefit if saturation is >94%. Beta-blockers (like metoprolol) given immediately after MI do not decrease mortality and may increase cardiogenic shock. Morphine and nitroglycerin also do not show a mortality benefit.', '2023 ITE Critique, Item 13', '["Supplemental oxygen","Aspirin","Metoprolol","Morphine","Nitroglycerin"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 48-year-old male with a history of type 2 diabetes, obesity, and tobacco use disorder presents to your office for evaluation of a 4-day history of fever, malaise, and a productive cough. He smokes a half-pack of cigarettes per day but does not use recreational drugs or drink alcohol in excess. He has no known medication allergies. Aside from a temperature of 38.2°C (100.8°F) and a BMI of 32 kg/m², his vital signs, including oxygen saturation, are normal. On physical examination he appears mildly ill although well hydrated and is breathing comfortably. Lung auscultation reveals focal right-sided crackles and decreased breath sounds. Which one of the following oral treatment options would be best in this situation?', 3, 'This patient has community-acquired pneumonia (CAP) and significant comorbidities (diabetes, obesity), making him a candidate for outpatient treatment with combination therapy. Preferred options include a beta-lactam (like amoxicillin/clavulanate) plus either a macrolide (azithromycin) or doxycycline (SOR A). Amoxicillin or doxycycline monotherapy is appropriate only for adults without significant comorbidities.', '2023 ITE Critique, Item 14', '["Amoxicillin","Cefuroxime","Doxycycline","Amoxicillin/clavulanate (Augmentin) plus azithromycin (Zithromax)","Cephalexin plus sulfamethoxazole/trimethoprim (Bactrim)"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A healthy 78-year-old female with no history of osteoporosis has a family history of hip fracture. Bone density screening reveals a lumbar T-score of -2.0 and a right hip T-score of -1.5. Her FRAX score is calculated at a 20% risk of major osteoporotic fracture and an 11% risk of hip fracture. She is concerned about the possibility of breaking her hip. Which one of the following interventions would be most appropriate?', 0, 'The National Osteoporosis Foundation supports treating postmenopausal women with low bone mass and a 10-year risk >20% for any major fracture or >3% for hip fracture. First-line treatments include bisphosphonates (alendronate, etc.), which are proven to reduce both hip and vertebral fractures. Hormonal therapy is not first-line due to risks and a lack of evidence for hip fracture prevention.', '2023 ITE Critique, Item 15', '["Initiating treatment with a bisphosphonate","Initiating treatment with combined estrogen/progesterone","A repeat bone density scan in 1 year","A repeat bone density scan in 3 years","A repeat bone density scan in 5 years"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'Which one of the following tests has the highest negative predictive value to rule out celiac disease?', 3, 'Celiac disease occurs almost exclusively in people with HLA-DQ2 or HLA-DQ8 genotypes. A negative result has more than a 99% negative predictive value for the disease. While positive IgA tTG has 95% sensitivity/specificity for active disease, a negative result does not rule out future risk. Antigliadin tests have lower sensitivity and specificity.', '2023 ITE Critique, Item 16', '["An antigliadin antibody test","A C-reactive protein level","A fecal calprotectin level","Genetic testing for HLA-DQ2 and HLA-DQ8","An IgA tissue transglutaminase (tTG) antibody test"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 42-year-old male with a history of chronic low back pain managed with extended-release morphine sulfate (MS Contin) comes to your office to discuss fatigue. Among other causes, you consider the impact that long-term opioid therapy may have on the endocrine system. Which one of the following endocrine conditions is most commonly associated with long-term opioid therapy?', 2, 'Long-term opioid therapy is associated with several endocrine conditions, the most common of which is hypogonadism. A systematic review found hypogonadism in 69% of male patients taking opioids. Prolactin elevation was noted in 40% and adrenal insufficiency in 24%. Parathyroid disorders have not been reported in association with opioid use.', '2023 ITE Critique, Item 17', '["Hyperprolactinemia","Hypocortisolism","Hypogonadism","Hypoparathyroidism","Hypothyroidism"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'An unhoused 63-year-old male is brought to the emergency department in a state of agitation and confusion. He is found to be hypothermic with a body temperature of 31.1°C (88.0°F). He has a blood pressure of 90/70 mm Hg and a heart rate of 120 beats/min. While undergoing warming, which one of the following should be given to this patient?', 1, 'When fluid resuscitation is necessary in hypothermia, normal saline is preferred because hypothermic patients cannot metabolize lactate. The fluid should be warmed to 38°C–42°C (100.4°F–107.6°F). Lactated Ringer and dextrose solutions are not appropriate in this acute setting.', '2023 ITE Critique, Item 18', '["Normal saline at room temperature","Normal saline that has been warmed","Lactated Ringer solution at room temperature","Lactated Ringer solution that has been warmed","50% dextrose in water at room temperature"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'According to the American Diabetes Association, which one of the following hemoglobin A1c measurements fits the criteria for prediabetes?', 2, 'According to the American Diabetes Association, a hemoglobin A1c of 5.7%–6.4% fits the criteria for prediabetes. Patients in this range should attempt diabetes prevention including lifestyle changes, cardiovascular risk prevention, and monitoring.', '2023 ITE Critique, Item 19', '["5.00%","5.50%","6.00%","6.50%"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 44-year-old male presents with a 2-month history of pain in his right shoulder. He does not recall a specific injury but notes the pain is worse when reaching overhead or sleeping on that side. On examination, he has a positive Neer test and a positive Hawkins-Kennedy test. Strength is preserved in all directions. Which one of the following is the most likely diagnosis?', 4, 'Subacromial impingement syndrome typically presents with pain during overhead activities and a ''painful arc'' between 60° and 120°. Positive Neer and Hawkins-Kennedy tests are highly suggestive of impingement. While a rotator cuff tear also presents with these positive signs, it is usually accompanied by weakness on manual muscle testing.', '2023 ITE Critique, Item 51', '["Adhesive capsulitis","Bicipital tendonitis","Glenohumeral osteoarthritis","Rotator cuff tear","Subacromial impingement syndrome"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 3-year-old male is brought to the office with a 2-day history of low-grade fever and a barky cough that is worse at night. On examination, he has mild inspiratory stridor when agitated but no stridor at rest. There is no significant respiratory distress. Which one of the following is the most appropriate management?', 1, 'This patient has mild croup, and for all severities of croup, a single dose of dexamethasone is recommended to reduce symptoms and prevent the need for further medical evaluation. Nebulized epinephrine is indicated for more severe croup with stridor at rest or moderate-to-severe respiratory distress.', '2023 ITE Critique, Item 52', '["Humidified air only","A single dose of oral dexamethasone","Nebulized racemic epinephrine","Nebulized budesonide","Oral amoxicillin"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 78-year-old male with a history of permanent atrial fibrillation and heart failure with preserved ejection fraction (HFpEF) presents for follow-up. He is taking apixaban for anticoagulation. His blood pressure is 152/88 mm Hg and his pulse is 82 beats/min. Which one of the following is the most appropriate blood pressure goal for this patient?', 1, 'Current guidelines, including the 2017 ACC/AHA and the 2021 KDIGO, generally recommend a blood pressure goal of <130/80 mm Hg for most adults with cardiovascular disease or significant risk factors like AFib and HFpEF.', '2023 ITE Critique, Item 53', '["<120/80 mm Hg","<130/80 mm Hg","<140/90 mm Hg","<150/90 mm Hg"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 52-year-old female presents with a 6-month history of frequent heartburn and regurgitation. She has tried an over-the-counter H2-blocker twice daily with only partial relief. She does not report weight loss, dysphagia, or anemia. Which one of the following is the most appropriate next step?', 2, 'In a patient with typical GERD symptoms and no ''alarm features'' (weight loss, dysphagia, etc.), an 8-week trial of a once-daily proton pump inhibitor (PPI) is the recommended next step. Diagnostic testing is generally reserved for those who do not respond to an adequate PPI trial or those with alarm features.', '2023 ITE Critique, Item 54', '["Barium swallow","Esophageal manometry","Omeprazole once daily","Upper endoscopy","24-hour pH monitoring"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 55-year-old male presents with symptoms of low libido and decreased energy. His total testosterone level is 220 ng/dL (N 300–1000). A repeat total testosterone level is 215 ng/dL. Which one of the following laboratory tests should be performed next?', 2, 'Once a diagnosis of hypogonadism is confirmed by two morning total testosterone levels, the next step is to distinguish between primary (testicular) and secondary (pituitary/hypothalamic) hypogonadism by measuring LH and FSH levels.', '2023 ITE Critique, Item 55', '["DHEA-S","Free testosterone","Luteinizing hormone and follicle-stimulating hormone","Prolactin","TSH"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 32-year-old male presents with acute low back pain that began yesterday after lifting heavy boxes. He has no radiating pain, numbness, or weakness. He has no red flags. On examination, he has mild paraspinal muscle tenderness. Which one of the following is the most appropriate first-line treatment?', 3, 'For acute, non-specific low back pain, first-line management includes staying active and using NSAIDs like naproxen or acetaminophen. Bed rest is not recommended as it may delay recovery. Imaging and physical therapy are generally not indicated in the first few weeks for non-specific pain without red flags.', '2023 ITE Critique, Item 56', '["Bed rest for 3 days","Cyclobenzaprine (Flexeril)","Lumbar spine radiograph","Naproxen","Physical therapy"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 24-year-old female presents with a 2-day history of right-sided facial weakness. She is unable to close her right eye completely or wrinkle her right forehead. She has no other neurological symptoms and no rash. She does not live in an area where Lyme disease is endemic. Which one of the following treatments has been shown to improve the rate of full recovery?', 2, 'Bell''s palsy (idiopathic facial nerve palsy) is typically treated with oral corticosteroids (e.g., prednisone) within 72 hours of symptom onset to improve recovery rates. Antivirals (like acyclovir or valacyclovir) may be considered in addition to steroids for severe cases, but they are not recommended as monotherapy.', '2023 ITE Critique, Item 57', '["Acyclovir","Gabapentin","Oral corticosteroids","Valacyclovir","Vitamin B12 injections"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 28-year-old female at 24 weeks gestation is found to have a hemoglobin level of 10.2 g/dL and an MCV of 78 fL. Which one of the following is the most common cause of anemia in pregnancy?', 2, 'Iron deficiency anemia is the most common cause of microcytic anemia in pregnancy due to increased iron demands for both the mother and fetus. CDC guidelines recommend routine screening for anemia in pregnancy and iron supplementation as needed.', '2023 ITE Critique, Item 58', '["Dilutional anemia of pregnancy","Folate deficiency","Iron deficiency anemia","Thalassemia trait","Vitamin B12 deficiency"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 58-year-old male with a 35-pack-year smoking history presents for a physical exam. He has no cough or shortness of breath. Which one of the following is the most appropriate lung cancer screening strategy for this patient?', 2, 'The USPSTF recommends annual screening for lung cancer with low-dose CT in adults aged 50–80 who have a 20-pack-year smoking history and currently smoke or have quit within the past 15 years.', '2023 ITE Critique, Item 59', '["Chest radiograph every year","Chest radiograph every 3 years","Low-dose CT scan every year","Low-dose CT scan every 3 years","No screening"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old male with type 2 diabetes has a BMI of 34 kg/m². His hemoglobin A1c is 8.2% despite taking metformin. He is interested in a medication that might also help him lose weight. Which one of the following would be the most appropriate addition?', 2, 'GLP-1 receptor agonists, such as semaglutide, are highly effective at lowering A1c and promoting weight loss in patients with type 2 diabetes. SGLT2 inhibitors also offer weight loss benefits, but GLP-1 agonists generally produce greater weight reduction. Sulfonylureas (glimepiride), TZDs (pioglitazone), and insulin typically cause weight gain.', '2023 ITE Critique, Item 60', '["Glimepiride","Pioglitazone","Semaglutide","Sitagliptin","Humalog insulin"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 6-year-old female is brought in for an itchy rash on her hands and feet. On examination, you see small papules and some linear burrows in the finger webbing. Which one of the following is the first-line treatment for this condition?', 2, 'The clinical description is characteristic of scabies. Permethrin 5% cream is the first-line treatment and should be applied from the neck down and washed off after 8–14 hours. All close contacts should also be treated.', '2023 ITE Critique, Item 61', '["Ivermectin cream","Lindane lotion","Permethrin 5% cream","Selenium sulfide","Triamcinolone cream"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 1-week-old infant is brought to the office for a first well child check. On examination, a grade 2/6 systolic murmur is heard at the left upper sternal border. The infant is pink, feeding well, and has normal femoral pulses. Which one of the following is the most likely diagnosis?', 2, 'Peripheral pulmonary stenosis is a very common innocent murmur in neonates, typically heard as a short midsystolic murmur at the left upper sternal border with radiation to the axilla. It usually disappears by 3–6 months of age. VSD and ASD murmurs are also common but usually have different characteristics (e.g., VSD is holosystolic and louder).', '2023 ITE Critique, Item 62', '["Atrial septal defect","Coarctation of the aorta","Peripheral pulmonary stenosis","Tetralogy of Fallot","Ventricular septal defect"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 28-year-old male presents with a 1-day history of sudden-onset, severe right testicular pain. He has no fever or urinary symptoms. On examination, the right testis is swollen and high-riding. The cremasteric reflex is absent on the right. Which one of the following is the most appropriate next step?', 3, 'Testicular torsion is a surgical emergency. While Doppler ultrasonography can confirm the lack of blood flow, it should not delay surgical consultation or management if the clinical suspicion is high. Surgical detorsion within 6 hours is critical for testicular salvage. An absent cremasteric reflex is highly sensitive for torsion.', '2023 ITE Critique, Item 63', '["Ceftriaxone and doxycycline","Manual detorsion in the office","Scrotal ultrasonography","Surgical exploration and detorsion","Urinalysis and culture"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 72-year-old female presents for an annual wellness exam. She reports no memory concerns. Which one of the following is recommended by the USPSTF regarding screening for cognitive impairment in asymptomatic older adults?', 3, 'The USPSTF currently concludes that the evidence is insufficient to assess the balance of benefits and harms of screening for cognitive impairment in asymptomatic older adults (I statement). However, the Medicare Annual Wellness Visit does require an assessment of cognitive function.', '2023 ITE Critique, Item 64', '["Routine screening with the Mini-Cog","Routine screening with the MMSE","Routine screening with the MoCA","The evidence is insufficient to recommend for or against routine screening"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 55-year-old female is diagnosed with osteoporosis after a DEXA scan. She has no other medical problems. Which one of the following is the most appropriate initial treatment?', 0, 'Oral bisphosphonates, such as alendronate, are the first-line pharmacologic treatment for postmenopausal women with osteoporosis. They are effective at reducing both hip and vertebral fractures and are generally well-tolerated.', '2023 ITE Critique, Item 65', '["Alendronate (Fosamax)","Calcitonin","Denosumab (Prolia)","Raloxifene (Evista)","Teriparatide (Forteo)"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 45-year-old female reports increasingly heavy and irregular menstrual periods over the past 6 months. She has no other symptoms. Which one of the following is the most appropriate initial diagnostic test?', 3, 'In women with abnormal uterine bleeding, transvaginal ultrasonography is the preferred initial imaging study to evaluate for structural abnormalities such as fibroids, polyps, or thickened endometrium. Endometrial biopsy is often indicated in women >45 years old or those with risk factors for endometrial cancer.', '2023 ITE Critique, Item 66', '["Endometrial biopsy","Hysterosalpingogram","MRI of the pelvis","Transvaginal ultrasonography","Serum FSH and LH"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 65-year-old male with a history of hypertension and hyperlipidemia is found to have a calcium score of 150 on a recent CT. According to the current guidelines, which one of the following is the most appropriate use of this information?', 1, 'A coronary artery calcium (CAC) score of 1–99 is considered low, but a score ≥100 (or ≥75th percentile for age/sex) is an indication to initiate statin therapy. CAC scoring is most useful as a ''tie-breaker'' for patients at intermediate ASCVD risk (5.0%–19.9%).', '2023 ITE Critique, Item 67', '["Initiating aspirin therapy","Initiating high-intensity statin therapy","Ordering a stress test","Recalculating his 10-year ASCVD risk","Re-screening with a calcium score in 2 years"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 35-year-old male presents with symptoms of major depressive disorder. He is also a smoker and has expressed interest in quitting. Which one of the following antidepressants would be most appropriate to address both conditions?', 0, 'Bupropion is effective for treating major depressive disorder and is also FDA-approved for smoking cessation. It does not cause weight gain or sexual dysfunction, which are common side effects of SSRIs.', '2023 ITE Critique, Item 68', '["Bupropion (Wellbutrin)","Escitalopram (Lexapro)","Fluoxetine (Prozac)","Mirtazapine (Remeron)","Sertraline (Zoloft)"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 65-year-old female is found to have a monoclonal protein level of 1.5 g/dL on serum protein electrophoresis. Her bone marrow contains 6% plasma cells. She has no anemia, hypercalcemia, renal insufficiency, or lytic bone lesions. Which one of the following is the most likely diagnosis?', 0, 'MGUS is defined by a monoclonal (M) protein level <3.0 g/dL, <10% plasma cells in the bone marrow, and an absence of CRAB symptoms (hypercalcemia, renal insufficiency, anemia, bone lesions). Patients with MGUS require long-term monitoring for progression to multiple myeloma.', '2023 ITE Critique, Item 69', '["Monoclonal gammopathy of undetermined significance (MGUS)","Multiple myeloma","Plasmacytoma","Smoldering multiple myeloma","Waldenström macroglobulinemia"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 62-year-old female is brought to the emergency department with a 30-minute history of sudden-onset slurred speech and right-sided weakness. Her blood pressure is 190/110 mm Hg. A noncontrast CT of the head is negative for hemorrhage. Which one of the following is the most appropriate management of her blood pressure if she is a candidate for intravenous thrombolysis?', 2, 'For patients with acute ischemic stroke who are candidates for IV alteplase, the blood pressure must be reduced to <185/110 mm Hg before starting treatment and maintained <180/105 mm Hg for the first 24 hours. For patients not receiving thrombolytics, BP should only be reduced if it exceeds 220/120 mm Hg.', '2023 ITE Critique, Item 70', '["Maintain blood pressure below 140/90 mm Hg","Maintain blood pressure below 160/100 mm Hg","Reduce blood pressure below 185/110 mm Hg","Reduce blood pressure below 220/120 mm Hg","No blood pressure reduction is indicated"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 40-year-old male with a history of Crohn''s disease presents with increased abdominal pain and diarrhea. On examination, he has a tender, palpable mass in the right lower quadrant. A CT scan shows a 4-cm abscess. Which one of the following is the most appropriate next step?', 2, 'The initial management of an intra-abdominal abscess in Crohn''s disease is typically percutaneous drainage (if feasible) and intravenous antibiotics. Surgery is generally reserved for patients who do not respond to drainage or those with associated fistulas or strictures.', '2023 ITE Critique, Item 71', '["Intravenous corticosteroids","Oral metronidazole and ciprofloxacin","Percutaneous drainage and antibiotics","Surgical resection","Infliximab (Remicade) therapy"]'::jsonb
        ),(
            '2023', 'Special Sensory', 'Special Sensory', '', 'A 55-year-old male with type 2 diabetes presents for an eye exam. He has no visual complaints. Dilated eye examination reveals a few microaneurysms and occasional dot-blot hemorrhages but no neovascularization. Which one of the following is the most appropriate management?', 2, 'This patient has mild nonproliferative diabetic retinopathy. The ADA and AAO recommend annual dilated eye exams for patients with stable diabetic retinopathy. If no retinopathy is present on two or more annual exams, the interval can be extended to every 2 years.', '2023 ITE Critique, Item 72', '["Laser photocoagulation now","Intravitreal anti-VEGF injection","Follow-up in 1 year","Follow-up in 2 years","Follow-up in 3 years"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 68-year-old female with COPD presents for follow-up. She uses a LAMA daily. She reports she has been hospitalized once for a COPD exacerbation in the past 12 months. Which one of the following would be the most appropriate next step in her therapy?', 0, 'According to the GOLD guidelines, for patients who continue to have exacerbations on monotherapy (LAMA or LABA), the next step is typically dual therapy with LAMA/LABA. Triple therapy (LAMA/LABA/ICS) is reserved for those who still have exacerbations or have high eosinophil counts on dual therapy.', '2023 ITE Critique, Item 73', '["Add a LABA","Add an ICS","Add a SABA as needed","Add oral prednisone daily","Add theophylline"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 72-year-old male with a history of hypertension and a mechanical aortic valve replacement presents with a 2-day history of nosebleeds. His INR is 7.5. He has no active bleeding. Which one of the following is the most appropriate management?', 0, 'For patients with an INR between 4.5 and 10.0 and no active bleeding, the recommendation is to hold warfarin for a few doses and monitor until the INR returns to range. Giving low-dose oral vitamin K (1.0–2.5 mg) is optional if the patient is at high risk of bleeding, but holding warfarin is usually sufficient.', '2023 ITE Critique, Item 74', '["Hold warfarin and give 1 mg of oral vitamin K","Hold warfarin and give 5 mg of oral vitamin K","Hold warfarin and give intravenous vitamin K","Hold warfarin and give fresh frozen plasma","Wait for the INR to drop and continue current warfarin dose"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 65-year-old male presents for a routine checkup. He has no urinary symptoms. He asks about PSA screening. According to the USPSTF, which one of the following is the recommended approach for PSA screening in men aged 55–69?', 3, 'The USPSTF recommends that for men aged 55–69, the decision to undergo periodic PSA screening should be an individual one (C recommendation) after discussing potential benefits and harms with their clinician. Screening is not recommended for men aged 70 and older.', '2023 ITE Critique, Item 75', '["Routine screening for all men","No screening for any men","Screening only for those with a family history","Shared decision-making regarding the benefits and harms of screening","Annual screening for all men"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 22-year-old female presents with pain on the lateral side of her knee that is worse when she runs, especially downhill. On examination, there is tenderness over the lateral femoral epicondyle. Which one of the following is the most likely diagnosis?', 0, 'Iliotibial band (ITB) syndrome is a common overuse injury in runners, caused by friction between the ITB and the lateral femoral epicondyle. Pain is typically localized to the lateral knee and is exacerbated by downhill running.', '2023 ITE Critique, Item 76', '["Iliotibial band syndrome","Lateral collateral ligament sprain","Lateral meniscal tear","Patellofemoral pain syndrome","Pes anserine bursitis"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 45-year-old male presents with a 2-day history of a painful, swollen area on his forearm. On examination, there is a 3-cm fluctuant, erythematous mass without surrounding cellulitis. Which one of the following is the most appropriate management?', 0, 'For a simple cutaneous abscess without systemic signs or significant surrounding cellulitis, incision and drainage alone is the standard of care. Antibiotics are generally not required unless the patient has comorbidities, systemic symptoms, or multiple abscesses.', '2023 ITE Critique, Item 77', '["Incision and drainage only","Incision and drainage plus oral cephalexin","Incision and drainage plus oral trimethoprim/sulfamethoxazole","Oral cephalexin only","Needle aspiration only"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 58-year-old male presents for follow-up of hypertension. He is already taking lisinopril 20 mg daily. His home blood pressures average 148/92 mm Hg. On examination, he has 1+ pedal edema. Which one of the following would be the most appropriate next step?', 1, 'In patients with uncontrolled hypertension, the addition of a thiazide-type diuretic (like chlorthalidone) or a calcium channel blocker is recommended. Given the patient already has mild edema, a diuretic might be preferred over amlodipine, which can cause or worsen peripheral edema.', '2023 ITE Critique, Item 78', '["Add amlodipine","Add chlorthalidone","Add spironolactone","Increase lisinopril to 40 mg","Increase lisinopril and add amlodipine"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'An 82-year-old female is brought in by her daughter because she has become increasingly forgetful over the past year. She often misplaces items and has trouble following complex instructions. Her MoCA score is 20/30. A medical workup is negative. Which one of the following medications is a first-line treatment for her condition?', 0, 'Cholinesterase inhibitors like donepezil are first-line treatments for mild-to-moderate Alzheimer''s disease. Memantine is typically used for moderate-to-severe disease, either alone or in combination with a cholinesterase inhibitor.', '2023 ITE Critique, Item 79', '["Donepezil (Aricept)","Memantine (Namenda)","Quetiapine (Seroquel)","Risperidone (Risperdal)","Sertraline (Zoloft)"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 25-year-old female presents with a 2-month history of a persistent, scaly, erythematous rash on her face, primarily in the malar region. She also reports some joint pain and fatigue. Which one of the following is the most appropriate initial laboratory test?', 2, 'In a patient with a malar rash and systemic symptoms, systemic lupus erythematosus (SLE) should be suspected. The ANA test is the most sensitive initial screening test for SLE. If positive, more specific tests like anti-dsDNA or anti-Smith can be ordered.', '2023 ITE Critique, Item 80', '["Anti-double-stranded DNA antibody","Anti-Smith antibody","Antinuclear antibody (ANA)","C-reactive protein","Rheumatoid factor"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old male with cirrhosis and ascites presents with a 2-day history of abdominal pain and fever. Paracentesis shows an ascitic fluid neutrophil count of 350/mm³. Which one of the following is the most appropriate antibiotic treatment?', 1, 'A neutrophil count >250/mm³ in ascitic fluid is diagnostic of spontaneous bacterial peritonitis (SBP). Third-generation cephalosporins, such as cefotaxime or ceftriaxone, are the first-line treatment.', '2023 ITE Critique, Item 81', '["Amoxicillin/clavulanate","Cefotaxime","Ciprofloxacin","Metronidazole","Vancomycin"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 4-year-old male is brought in for a well child check. His parents are concerned that he is ''flat-footed.'' On examination, he has no medial arch when standing, but an arch appears when he stands on his tiptoes. He has no pain. Which one of the following is the most appropriate management?', 0, 'Flexible flatfoot (pes planus) is a common, normal variant in young children and is typically asymptomatic. No treatment is needed if the patient is not experiencing pain or functional limitations. Reassurance is the most appropriate management.', '2023 ITE Critique, Item 82', '["Observation and reassurance","Over-the-counter arch supports","Custom orthotics","Physical therapy","Referral to orthopedic surgery"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 62-year-old female is found to have a TSH of 0.1 μU/mL and a normal free T4 and free T3 level. She is asymptomatic and has no history of thyroid disease. Which one of the following is the most common consequence of untreated subclinical hyperthyroidism in older adults?', 0, 'Subclinical hyperthyroidism (low TSH with normal free T4/T3) is associated with an increased risk of atrial fibrillation and osteoporosis, particularly in patients >65 years old or those with a TSH <0.1 μU/mL.', '2023 ITE Critique, Item 83', '["Atrial fibrillation","Hypocalcemia","Hyperlipidemia","Thyroid storm","Weight gain"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male presents with a blood pressure of 142/92 mm Hg. He has no other medical conditions and his 10-year ASCVD risk is 4.5%. According to the 2017 ACC/AHA guidelines, which one of the following is the most appropriate initial management?', 2, 'For patients with Stage 1 hypertension (130–139/80–89 mm Hg) and a 10-year ASCVD risk <10%, lifestyle modifications are recommended with a recheck in 3–6 months. This patient''s BP is 142/92, which is Stage 2 (>140/90). For Stage 2, medication is generally recommended along with lifestyle changes, but since his risk is very low, initial lifestyle focus is often emphasized in board scenarios.', '2023 ITE Critique, Item 84', '["Initiate lisinopril","Initiate amlodipine","Lifestyle modifications only","Recheck blood pressure in 1 year","Recheck blood pressure in 3 years"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 32-year-old female with a history of asthma presents with symptoms that occur almost daily and wake her up once a week. She uses her albuterol inhaler daily. Which one of the following is the most appropriate next step in her maintenance therapy?', 2, 'This patient has moderate persistent asthma. According to the NHLBI/NAEPP guidelines, the preferred treatment for persistent asthma is an inhaled corticosteroid. If she is already on a SABA as needed, the next step is a low-dose ICS (Step 2).', '2023 ITE Critique, Item 85', '["Add a long-acting beta-agonist (LABA)","Add a long-acting muscarinic antagonist (LAMA)","Add a low-dose inhaled corticosteroid (ICS)","Add a leukotriene receptor antagonist (LTRA)","Increase her albuterol use"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old male with a history of GERD presents for a screening endoscopy. Biopsies show Barrett esophagus without dysplasia. Which one of the following is the most appropriate follow-up strategy?', 1, 'For patients with Barrett esophagus and no dysplasia, endoscopic surveillance is recommended every 3 to 5 years to monitor for progression to esophageal adenocarcinoma.', '2023 ITE Critique, Item 86', '["Endoscopy every year","Endoscopy every 3–5 years","Endoscopy every 10 years","No further endoscopy is needed","Surgical resection of the distal esophagus"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 50-year-old male presents with a 1-day history of severe pain and swelling in his left big toe. He reports he had a similar episode last year. On examination, the first metatarsophalangeal joint is red, swollen, and extremely tender. Which one of the following is the first-line treatment for the acute attack?', 2, 'For an acute gout attack, NSAIDs (like indomethacin), colchicine, or corticosteroids are first-line treatments. Allopurinol is for chronic management (urate-lowering therapy) and should generally not be started during an acute flare.', '2023 ITE Critique, Item 87', '["Allopurinol","Febuxostat","Indomethacin","Probenecid","Wait for the attack to resolve spontaneously"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 45-year-old male presents with sharp, stabbing pain in his right cheek that is triggered by shaving or eating. Each episode lasts only a few seconds. Which one of the following is the first-line treatment for this condition?', 1, 'The clinical description of brief, intense, triggered facial pain is characteristic of trigeminal neuralgia. Carbamazepine is the first-line pharmacologic treatment.', '2023 ITE Critique, Item 88', '["Amitriptyline","Carbamazepine","Gabapentin","Lidocaine patch","Prednisone"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 2-month-old infant is brought in for a well child check. The parents are concerned about the infant''s ''spitting up'' after most feeds. The infant is gaining weight well and is not irritable. On examination, the infant is thriving. Which one of the following is the most appropriate management?', 3, 'This is physiologic gastroesophageal reflux (GER), often called ''happy spitting.'' In a thriving infant without irritability or poor weight gain, no medication is needed. Management includes reassurance, positioning, and smaller, more frequent feeds.', '2023 ITE Critique, Item 89', '["Change to a soy-based formula","Initiate omeprazole","Initiate ranitidine","Reassurance and smaller, more frequent feeds","Thickening feeds with rice cereal"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 22-year-old male with sickle cell disease presents with a 1-day history of fever and a cough. He has no other new symptoms. Which one of the following is the most important management step?', 3, 'Fever in a patient with sickle cell disease is a medical emergency due to the risk of life-threatening infection with encapsulated organisms (e.g., S. pneumoniae). Prompt evaluation and initiation of broad-spectrum antibiotics are mandatory.', '2023 ITE Critique, Item 90', '["Blood transfusion","Folic acid supplementation","Hydroxyurea therapy","Prompt initiation of broad-spectrum antibiotics","Observation only"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 32-year-old female at 35 weeks gestation is found to have a blood pressure of 152/96 mm Hg. She has no headache, visual changes, or abdominal pain. A 24-hour urine collection shows 450 mg of protein. Which one of the following is the most likely diagnosis?', 2, 'Preeclampsia is defined by hypertension (>140/90 mm Hg) and proteinuria (>300 mg in 24 hours or a protein/creatinine ratio >0.3) after 20 weeks gestation. Since she lacks ''severe features'' (e.g., BP >160/110, low platelets, renal failure, liver dysfunction), it is preeclampsia without severe features.', '2023 ITE Critique, Item 91', '["Chronic hypertension","Gestational hypertension","Preeclampsia without severe features","Preeclampsia with severe features","Eclampsia"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 68-year-old male with a history of heart failure with reduced ejection fraction (HFrEF) presents with a heart rate of 78 beats/min and a blood pressure of 122/74 mm Hg. He is already taking lisinopril, carvedilol, and spironolactone. Which one of the following has been shown to reduce mortality in this patient?', 3, 'Replacing an ACE inhibitor or ARB with an ARNI (sacubitril/valsartan) has been shown to further reduce morbidity and mortality in patients with HFrEF who remain symptomatic on standard therapy.', '2023 ITE Critique, Item 92', '["Amlodipine","Digoxin","Furosemide","Sacubitril/valsartan (Entresto)","Verapamil"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 35-year-old female presents for follow-up of a thyroid nodule found on examination. Ultrasound shows a 1.5-cm solid nodule with microcalcifications. Her TSH is normal. Which one of the following is the most appropriate next step?', 0, 'In a patient with a thyroid nodule and a normal TSH, FNA is indicated if the nodule meets certain size and ultrasound criteria (e.g., solid, hypoechoic, microcalcifications). If TSH were low, a radioactive iodine scan would be the next step to look for a ''hot'' nodule.', '2023 ITE Critique, Item 93', '["Fine-needle aspiration (FNA)","Radioactive iodine uptake scan","Repeat ultrasound in 6 months","Serum calcitonin level","Thyroidectomy"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 24-year-old male presents for screening for sexually transmitted infections. He has no symptoms. According to the USPSTF, which one of the following infections should be screened for in all sexually active men?', 2, 'The USPSTF recommends screening for HIV in all adolescents and adults aged 15–65. Routine screening for chlamydia and gonorrhea is recommended for all sexually active women <25, but not for all men unless they are at increased risk.', '2023 ITE Critique, Item 94', '["Chlamydia","Gonorrhea","HIV","Herpes simplex virus","Syphilis"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 45-year-old male presents with numbness and tingling in his thumb, index, and middle fingers that is worse at night. On examination, he has a positive Phalen test. Which one of the following is the most appropriate initial management?', 3, 'Wrist splinting in a neutral position, especially at night, is the recommended first-line conservative treatment for mild-to-moderate carpal tunnel syndrome.', '2023 ITE Critique, Item 95', '["Corticosteroid injection","Oral prednisone","Surgical decompression","Wrist splinting at night","Physical therapy"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'An 80-year-old male with end-stage renal disease and heart failure is hospitalized. He is at risk for delirium. Which one of the following has been shown to reduce the incidence of delirium in hospitalized older adults?', 3, 'Multi-component nonpharmacologic interventions (e.g., ensuring adequate sleep, reorientation, mobilization, hearing/visual aids) have been proven to reduce the incidence of delirium. Medications like haloperidol are used for treatment of symptoms but not for prevention.', '2023 ITE Critique, Item 96', '["Low-dose haloperidol","Low-dose risperidone","Melatonin","Multi-component nonpharmacologic interventions","Physical restraints"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 6-month-old infant is brought in for a well child check. The parents ask about the influenza vaccine. Which one of the following is the recommended strategy for this infant?', 1, 'Children aged 6 months to 8 years require two doses of the influenza vaccine (separated by at least 4 weeks) the first season they are vaccinated to achieve an adequate immune response.', '2023 ITE Critique, Item 97', '["One dose of the inactivated influenza vaccine","Two doses of the inactivated influenza vaccine, 4 weeks apart","One dose of the live-attenuated influenza vaccine","Delay the vaccine until age 1 year","Influenza vaccine is not recommended for this age"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 55-year-old male presents with microscopic hematuria found on a routine urinalysis. He has no symptoms and a normal physical exam. A repeat urinalysis again shows 5 RBCs/hpf. Which one of the following is the most appropriate next step?', 0, 'For asymptomatic microscopic hematuria (>3 RBCs/hpf), the current AUA guidelines recommend a risk-based approach. For most adults at intermediate or high risk, both upper tract imaging (usually CT urogram) and cystoscopy are recommended to evaluate for malignancy.', '2023 ITE Critique, Item 98', '["CT urogram and cystoscopy","Renal ultrasound only","Repeat urinalysis in 6 months","Serum creatinine only","No further evaluation is needed"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 19-year-old male presents with inflammatory acne on his face. He has tried over-the-counter benzoyl peroxide and salicylic acid without much improvement. Which one of the following would be the most appropriate next step?', 3, 'For mild-to-moderate inflammatory acne, the first-line treatment is typically a combination of a topical retinoid (like adapalene) and a topical antibiotic (like clindamycin) or benzoyl peroxide.', '2023 ITE Critique, Item 99', '["Oral isotretinoin","Oral minocycline","Topical clindamycin","Topical retinoid plus topical antibiotic","Topical retinoid only"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old female is found to have a serum calcium of 10.8 mg/dL (N 8.5–10.2). Her PTH is elevated. Which one of the following is the most likely diagnosis?', 2, 'Primary hyperparathyroidism is the most common cause of hypercalcemia in the outpatient setting and is characterized by elevated serum calcium and inappropriately normal or elevated PTH levels.', '2023 ITE Critique, Item 100', '["Familial hypocalciuric hypercalcemia","Malignancy-associated hypercalcemia","Primary hyperparathyroidism","Secondary hyperparathyroidism","Vitamin D intoxication"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 45-year-old male presents with a 4-month history of pain in the right elbow. He reports the pain is worst when he is shaking hands or lifting a coffee cup. On examination, there is maximal tenderness 1 cm distal to the lateral epicondyle. Pain is elicited with resisted wrist extension. Which one of the following is the most likely diagnosis?', 1, 'Lateral epicondylitis (tennis elbow) is characterized by pain over the lateral epicondyle and the origin of the extensor carpi radialis brevis muscle. It is typically worsened by resisted wrist extension and activities involving a strong grip. Medial epicondylitis (golfer''s elbow) causes pain over the medial epicondyle and is worsened by resisted wrist flexion.', '2023 ITE Critique, Item 101', '["Bicipital tendonitis","Lateral epicondylitis","Medial epicondylitis","Olecranon bursitis","Radial tunnel syndrome"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'An 82-year-old female presents with a 2-month history of fatigue and exertional dyspnea. On examination, a grade 3/6 late-peaking systolic crescendo-decrescendo murmur is heard at the right upper sternal border with radiation to the carotids. The second heart sound (S2) is soft. Which one of the following is the most likely diagnosis?', 1, 'The classic physical findings of aortic stenosis include a late-peaking systolic murmur at the right upper sternal border that radiates to the carotids, and a diminished or absent S2. A delay in the carotid upstroke (pulsus parvus et tardus) may also be present. Echocardiography is the gold standard for diagnosis and staging.', '2023 ITE Critique, Item 102', '["Aortic regurgitation","Aortic stenosis","Mitral regurgitation","Mitral stenosis","Tricuspid regurgitation"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 45-year-old male with a history of HIV presents with a 2-week history of progressive shortness of breath, a nonproductive cough, and low-grade fever. His CD4 count is 150/mm³. On examination, his oxygen saturation is 88% on room air. A chest radiograph shows bilateral, diffuse interstitial infiltrates. Which one of the following is the most appropriate initial treatment?', 4, 'This clinical presentation is classic for Pneumocystis jirovecii pneumonia (PCP) in a patient with HIV and a low CD4 count. Trimethoprim/sulfamethoxazole is the first-line treatment. Adjunctive corticosteroids (e.g., prednisone) are indicated if the PaO2 is <70 mm Hg or the alveolar-arterial oxygen gradient is >35 mm Hg to reduce mortality.', '2023 ITE Critique, Item 103', '["Amoxicillin/clavulanate","Azithromycin","Ceftriaxone","Pentamidine","Trimethoprim/sulfamethoxazole and prednisone"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 28-year-old female presents for evaluation of irregular periods and increased facial hair growth. Her BMI is 32 kg/m². A physical examination reveals terminal hair growth on the chin and upper lip. Laboratory testing shows an elevated serum testosterone level and a normal DHEA-S. Which one of the following is the most appropriate first-line treatment for her symptoms?', 3, 'This patient has polycystic ovary syndrome (PCOS). For women not seeking pregnancy, combined oral contraceptive pills (COCs) are the first-line treatment for menstrual irregularity and hirsutism. COCs suppress ovarian androgen production and increase sex hormone–binding globulin, reducing free testosterone. Spironolactone can be added if COCs are insufficient after 6 months.', '2023 ITE Critique, Item 104', '["Clomiphene citrate","Finasteride","Metformin","Oral contraceptive pills","Spironolactone"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 2-year-old female is brought in with a 2-day history of honey-colored, crusted lesions around her nose and mouth. She is otherwise well and afebrile. Which one of the following is the most appropriate treatment?', 2, 'Nonbullous impetigo is characterized by honey-colored crusting and is most commonly caused by S. aureus or S. pyogenes. For localized disease, topical mupirocin is the treatment of choice. Oral antibiotics (e.g., cephalexin) are reserved for patients with widespread lesions or systemic symptoms.', '2023 ITE Critique, Item 105', '["Oral amoxicillin","Oral cephalexin","Topical mupirocin","Topical nystatin","Topical triamcinolone"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 68-year-old male with a history of hypertension and hyperlipidemia presents for follow-up. He is taking lisinopril and atorvastatin. His blood pressure is 128/78 mm Hg. He has no chest pain or shortness of breath. He asks if he should be taking aspirin for primary prevention of cardiovascular disease. Which one of the following is the most appropriate recommendation according to the USPSTF?', 3, 'The 2022 USPSTF recommendation states that for adults aged 60 and older, the initiation of low-dose aspirin for the primary prevention of CVD has no net benefit (Grade D). For adults aged 40–59 with a 10% or greater 10-year CVD risk, the decision should be individualized (Grade C).', '2023 ITE Critique, Item 106', '["Aspirin is recommended for all adults >60 years old","Aspirin is recommended if his ASCVD risk is >10%","Aspirin is recommended if his ASCVD risk is >20%","Aspirin is not recommended for primary prevention in adults >60 years old","Aspirin is only recommended for secondary prevention"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 24-year-old female presents with a 3-month history of ''binge eating'' episodes twice a week, followed by self-induced vomiting and excessive exercise to ''undo the damage.'' She is of normal weight. Which one of the following is the most appropriate first-line pharmacotherapy for this condition?', 1, 'This patient meets the criteria for bulimia nervosa. Fluoxetine is the only FDA-approved medication for bulimia and is the first-line pharmacotherapy. Bupropion is strictly contraindicated in patients with eating disorders due to an increased risk of seizures. Lisdexamfetamine is used for binge-eating disorder (without purging).', '2023 ITE Critique, Item 107', '["Bupropion (Wellbutrin)","Fluoxetine (Prozac)","Lisdexamfetamine (Vyvanse)","Olanzapine (Zyprexa)","Topiramate (Topamax)"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 52-year-old male presents with a 2-month history of frequent, watery diarrhea. He has lost 5 lb and reports that the diarrhea continues even when he fasts. Laboratory testing shows a fecal osmotic gap of 25 mOsm/kg. Which one of the following is the most likely mechanism of his diarrhea?', 4, 'Secretory diarrhea is characterized by high-volume, watery stools that persist during fasting. It has a low fecal osmotic gap (<50 mOsm/kg). Osmotic diarrhea (e.g., lactose intolerance) usually improves with fasting and has a high fecal osmotic gap (>100 mOsm/kg).', '2023 ITE Critique, Item 108', '["Exudative diarrhea","Malabsorptive diarrhea","Motility-related diarrhea","Osmotic diarrhea","Secretory diarrhea"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 75-year-old male presents with a 6-month history of progressive difficulty walking. He describes a ''magnetic'' gait, where his feet feel ''stuck to the floor.'' He also reports increased urinary urgency and mild forgetfulness. On examination, he has no tremor or rigidity. Which one of the following is the most likely diagnosis?', 1, 'The classic triad of normal pressure hydrocephalus (NPH) is gait disturbance (''magnetic'' or ''apractic'' gait), urinary incontinence/urgency, and cognitive impairment (''wet, wobbly, and wacky''). Imaging showing ventriculomegaly out of proportion to sulcal atrophy is diagnostic.', '2023 ITE Critique, Item 109', '["Alzheimer''s disease","Normal pressure hydrocephalus","Parkinson''s disease","Progressive supranuclear palsy","Vascular dementia"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 22-year-old male presents with acute pain in his right ankle after ''rolling it'' while playing basketball. He is unable to bear weight for more than four steps. On examination, there is tenderness over the posterior edge of the lateral malleolus. No tenderness is noted over the midfoot. Which one of the following is the most appropriate next step?', 2, 'According to the Ottawa Ankle Rules, radiographs are indicated if there is bone tenderness at the posterior edge or tip of either malleolus, or an inability to bear weight both immediately and in the emergency department (or clinic).', '2023 ITE Critique, Item 110', '["Compression wrap and ice only","Physical therapy referral","Radiographs of the ankle","Radiographs of the foot","Walking boot for 2 weeks"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old male with type 2 diabetes presents for follow-up. He is taking metformin and glipizide. His hemoglobin A1c is 8.5%. He has a history of atherosclerotic cardiovascular disease (ASCVD) including a myocardial infarction 2 years ago. Which one of the following is the most appropriate next step to improve his long-term outcomes?', 3, 'For patients with type 2 diabetes and established ASCVD, current ADA and AACE guidelines recommend the use of a GLP-1 receptor agonist or an SGLT2 inhibitor with proven cardiovascular benefit, regardless of the baseline A1c or metformin use.', '2023 ITE Critique, Item 111', '["Add pioglitazone","Add sitagliptin","Increase glipizide dose","Switch glipizide to a GLP-1 receptor agonist or SGLT2 inhibitor","Switch glipizide to NPH insulin"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 62-year-old male with a history of COPD presents with worsening shortness of breath. His oxygen saturation is 86% on room air. According to the Medicare guidelines, which one of the following is the threshold for prescribing long-term home oxygen therapy in a patient with stable COPD?', 0, 'Medicare covers home oxygen therapy for patients with a PaO2 ≤55 mm Hg or an SaO2 ≤88% at rest on room air. It is also covered for patients with a PaO2 of 56–59 mm Hg or an SaO2 of 89% if there is evidence of cor pulmonale, pulmonary hypertension, or erythrocytosis (hematocrit >56%).', '2023 ITE Critique, Item 112', '["PaO2 ≤55 mm Hg or SaO2 ≤88%","PaO2 ≤60 mm Hg or SaO2 ≤89%","PaO2 ≤65 mm Hg or SaO2 ≤90%","PaO2 ≤70 mm Hg or SaO2 ≤92%"]'::jsonb
        ),(
            '2023', 'Special Sensory', 'Special Sensory', '', 'A 4-year-old female is brought in for ear pain. On examination, she has a bulging, erythematous tympanic membrane with impaired mobility. She has a temperature of 38.5°C (101.3°F). She has not had an ear infection in over a year and has no known allergies. Which one of the following is the first-line antibiotic treatment?', 0, 'For acute otitis media in children who have not received amoxicillin in the past 30 days and who do not have concurrent purulent conjunctivitis, high-dose amoxicillin (80–90 mg/kg/day) remains the first-line treatment. Amoxicillin/clavulanate is used for those who have recently had amoxicillin or have failed initial therapy.', '2023 ITE Critique, Item 113', '["Amoxicillin","Amoxicillin/clavulanate","Cefdinir","Ceftriaxone","Azithromycin"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 35-year-old female presents with an itchy rash on her shins. On examination, you see purple, polygonal, flat-topped papules. Some of the papules have fine white lines on the surface. Which one of the following is the most likely diagnosis?', 1, 'The ''6 Ps'' of lichen planus are planar (flat-topped), purple, polygonal, pruritic, papules, and plaques. The fine white lines on the surface are called Wickham striae. It is often associated with hepatitis C.', '2023 ITE Critique, Item 114', '["Atopic dermatitis","Lichen planus","Psoriasis","Tinea corporis","Urticaria"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 28-year-old female presents for a preconception visit. She is otherwise healthy. Which one of the following is the recommended daily dose of folic acid for a woman of childbearing age with no prior history of a child with a neural tube defect?', 0, 'The USPSTF and CDC recommend that all women of childbearing age who are planning or capable of pregnancy take a daily supplement containing 0.4 to 0.8 mg (400 to 800 μg) of folic acid. Women at high risk (e.g., prior child with a neural tube defect) should take 4.0 mg daily.', '2023 ITE Critique, Item 115', '["0.4 mg","1.0 mg","2.0 mg","4.0 mg","5.0 mg"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 72-year-old male is found to have an incidentally discovered white blood cell count of 25,000/mm³. The differential shows 80% mature-appearing lymphocytes. A peripheral smear shows ''smudge cells.'' He has no lymphadenopathy or splenomegaly. Which one of the following is the most likely diagnosis?', 1, 'Chronic lymphocytic leukemia (CLL) is the most common leukemia in adults and is often discovered incidentally on routine CBC. The presence of ''smudge cells'' (fragile lymphocytes that rupture during slide preparation) is a hallmark of CLL.', '2023 ITE Critique, Item 116', '["Acute lymphoblastic leukemia","Chronic lymphocytic leukemia","Chronic myeloid leukemia","Hairy cell leukemia","Multiple myeloma"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 55-year-old male presents to the emergency department with a 30-minute history of severe, tearing chest pain that radiates to his back. His blood pressure is 180/100 mm Hg in the right arm and 140/80 mm Hg in the left arm. Which one of the following is the most likely diagnosis?', 0, 'Sudden-onset, ''tearing'' or ''ripping'' chest pain radiating to the back, combined with a blood pressure differential between arms (>20 mm Hg systolic), is highly suggestive of acute aortic dissection. A widened mediastinum on chest radiograph is often seen, but CT angiography is the diagnostic study of choice.', '2023 ITE Critique, Item 117', '["Aortic dissection","Myocardial infarction","Pericarditis","Pulmonary embolism","Tension pneumothorax"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 45-year-old male with a history of alcohol use disorder presents with hematemesis. His blood pressure is 90/60 mm Hg and his heart rate is 115 beats/min. Which one of the following is the most appropriate first step in his management?', 2, 'In any patient with acute upper gastrointestinal bleeding and hemodynamic instability, the immediate priority is stabilization with intravenous fluid resuscitation and airway management if necessary. Octreotide and endoscopy are performed after the patient is stabilized.', '2023 ITE Critique, Item 118', '["Administration of intravenous octreotide","Emergency upper endoscopy","Intravenous fluid resuscitation","Nasogastric tube placement and lavage","Oral administration of a proton pump inhibitor"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 75-year-old female presents with a 2-week history of depressed mood, insomnia, and loss of appetite. She reports she has been having ''scary'' thoughts and believes her neighbors are spying on her with cameras. Which one of the following is the most appropriate treatment?', 3, 'This patient has major depressive disorder with psychotic features (delusions). First-line treatment is the combination of an antidepressant and an antipsychotic, or electroconvulsive therapy (ECT), which is particularly effective in severe or psychotic depression in older adults.', '2023 ITE Critique, Item 119', '["Fluoxetine (Prozac) only","Sertraline (Zoloft) only","Quetiapine (Seroquel) only","Sertraline plus an antipsychotic like risperidone","Cognitive-behavioral therapy"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 28-year-old female presents with a 3-day history of dysuria and frequency. She has no fever, flank pain, or vaginal discharge. She has no chronic medical conditions. Which one of the following is the most appropriate management according to current guidelines?', 0, 'In a healthy, nonpregnant woman with typical symptoms of uncomplicated cystitis and no ''red flags'' (e.g., fever, flank pain), empiric treatment without a culture is appropriate. Nitrofurantoin (for 5 days), trimethoprim/sulfamethoxazole (for 3 days), or fosfomycin (single dose) are first-line agents.', '2023 ITE Critique, Item 120', '["Empiric treatment with nitrofurantoin","Empiric treatment with ciprofloxacin","Urine culture and treat based on results","Urinalysis only; no treatment if negative","Wait for 2 days for symptoms to resolve"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 15-year-old male presents with a persistent cough for 4 weeks. He describes the cough as occurring in ''fits'' that sometimes end in a high-pitched sound. He is otherwise healthy but has not received any vaccinations since age 5. Which one of the following is the most likely diagnosis?', 3, 'Pertussis (whooping cough) should be suspected in any adolescent or adult with a paroxysmal cough lasting more than 2 weeks, especially if they are under-vaccinated. The ''whoop'' is more common in children but can occur in adolescents. Post-tussive emesis is also a classic sign.', '2023 ITE Critique, Item 121', '["Asthma","Cystic fibrosis","Mycoplasma pneumonia","Pertussis","Post-viral cough"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old female presents with a 6-month history of bilateral knee pain that is worse at the end of the day. On examination, she has bony enlargement of the PIP and DIP joints of her hands. Which one of the following is the most likely diagnosis?', 1, 'The clinical picture of progressive knee pain exacerbated by use, along with Heberden nodes (DIP joints) and Bouchard nodes (PIP joints), is classic for osteoarthritis. Rheumatoid arthritis typically involves the MCP and PIP joints but spares the DIP joints.', '2023 ITE Critique, Item 122', '["Gout","Osteoarthritis","Psoriatic arthritis","Rheumatoid arthritis","Septic arthritis"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male with a history of heavy tobacco use presents for evaluation of leg pain. He reports that his calves cramp after walking two blocks and the pain is relieved by rest. Which one of the following is the most appropriate initial diagnostic test?', 0, 'Intermittent claudication is the classic symptom of peripheral artery disease (PAD). The initial diagnostic test is the ankle-brachial index (ABI). An ABI ≤0.90 is diagnostic of PAD.', '2023 ITE Critique, Item 123', '["Ankle-brachial index (ABI)","CT angiography","D-dimer","Duplex ultrasonography","Venography"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 65-year-old male presents with bothersome nocturia and a weak urinary stream. A digital rectal exam reveals a smooth, symmetrically enlarged prostate. A PSA is 2.5 ng/mL. He has failed a trial of tamsulosin. Which one of the following medications works by inhibiting the conversion of testosterone to dihydrotestosterone?', 1, '5-alpha-reductase inhibitors, such as finasteride and dutasteride, inhibit the enzyme that converts testosterone to the more potent dihydrotestosterone, leading to a reduction in prostate size over time. Alpha-blockers like doxazosin relax smooth muscle.', '2023 ITE Critique, Item 124', '["Doxazosin (Cardura)","Finasteride (Proscar)","Mirabegron (Myrbetriq)","Sildenafil (Viagra)","Tadalafil (Cialis)"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old female presents with a 10-lb weight gain and feeling cold all the time. Her TSH is 15 μU/mL (N 0.4–4.5) and her free T4 is 0.6 ng/dL (N 0.8–1.8). Which one of the following is the most appropriate initial dose of levothyroxine for this otherwise healthy patient?', 3, 'For young, healthy adults with overt hypothyroidism, the full replacement dose of levothyroxine (approximately 1.6 μg/kg/day) can be started. In older patients or those with coronary artery disease, a lower starting dose (e.g., 25–50 μg) is recommended.', '2023 ITE Critique, Item 125', '["25 μg daily","50 μg daily","75 μg daily","1.6 μg/kg daily","2.5 μg/kg daily"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 40-year-old male presents with a persistent, scaly plaque on his elbow. On examination, the plaque is well-demarcated, erythematous, and covered with silver scales. Which one of the following is the most appropriate first-line treatment?', 0, 'Plaque psoriasis is typically treated first-line with high-potency topical corticosteroids (e.g., clobetasol). Low-potency steroids are generally ineffective for thick plaques but can be used on the face or intertriginous areas.', '2023 ITE Critique, Item 126', '["Topical clobetasol (high-potency corticosteroid)","Topical hydrocortisone 1% (low-potency corticosteroid)","Topical ketoconazole","Oral methotrexate","Oral prednisone"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 24-year-old male is brought in after being bitten by a stray dog. The bite is a deep puncture wound on his forearm. The dog appeared healthy but ran away and cannot be quarantined. Which one of the following is indicated in addition to wound care and tetanus prophylaxis?', 2, 'Post-exposure prophylaxis for rabies (in an unvaccinated individual) consists of both rabies immune globulin (RIG) and a series of rabies vaccines (days 0, 3, 7, and 14). This should be initiated if the animal is not available for testing or quarantine and is a species known to carry rabies in the area.', '2023 ITE Critique, Item 127', '["Rabies vaccine only","Rabies immune globulin (RIG) only","Rabies vaccine and RIG","Observation of the patient for 10 days","No further treatment is needed"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 55-year-old male with a 30-pack-year smoking history presents for a physical exam. He has no symptoms. According to the USPSTF, which one of the following is the correct age range for annual lung cancer screening with low-dose CT?', 2, 'In 2021, the USPSTF expanded the lung cancer screening recommendation to include adults aged 50 to 80 years who have a 20-pack-year smoking history and currently smoke or have quit within the past 15 years.', '2023 ITE Critique, Item 128', '["40–70 years","45–75 years","50–80 years","55–80 years","60–85 years"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 62-year-old female is found to have a blood pressure of 145/92 mm Hg on two separate occasions. Her 10-year ASCVD risk is 12%. According to the 2017 ACC/AHA guidelines, which one of the following is the most appropriate initial management?', 1, 'This patient has Stage 2 hypertension (≥140/90 mm Hg). For Stage 2, the recommendation is lifestyle modifications and initiation of blood pressure–lowering medication. If the BP were >160/100, starting with two medications would be considered.', '2023 ITE Critique, Item 129', '["Lifestyle modifications only","Lifestyle modifications and initiate one antihypertensive medication","Lifestyle modifications and initiate two antihypertensive medications","Recheck blood pressure in 1 year","Recheck blood pressure in 3 years"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'A 45-year-old female presents with frequent tension-type headaches. She is already using relaxation techniques and over-the-counter NSAIDs. Which one of the following is the most effective pharmacologic agent for the prevention of tension-type headaches?', 0, 'Amitriptyline is the most widely used and effective medication for the prevention of chronic tension-type headaches. SSRIs like fluoxetine have not been shown to be effective for this purpose.', '2023 ITE Critique, Item 130', '["Amitriptyline","Fluoxetine","Propranolol","Topiramate","Valproic acid"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 52-year-old male presents with a 6-month history of bloating and flatulence. He notes that his symptoms are worse after drinking milk or eating ice cream. Which one of the following is the most appropriate initial diagnostic test?', 2, 'In a patient with symptoms classic for lactose intolerance, a trial of a lactose-free diet is often the most practical and cost-effective initial diagnostic approach. If symptoms resolve, the diagnosis is confirmed.', '2023 ITE Critique, Item 131', '["Celiac serology","Hydrogen breath test","A trial of a lactose-free diet","Stool culture","Upper endoscopy"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 22-year-old female presents for a routine checkup. She is sexually active with one male partner. According to the USPSTF, which one of the following infections should be screened for in all sexually active women in this age group?', 0, 'The USPSTF recommends annual screening for chlamydia and gonorrhea in all sexually active women younger than 25 years, as well as in older women at increased risk.', '2023 ITE Critique, Item 132', '["Chlamydia and gonorrhea","Hepatitis B","Herpes simplex virus","Syphilis","Trichomoniasis"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 65-year-old male with type 2 diabetes has a hemoglobin A1c of 7.2% on metformin. He has no other medical problems. According to the ADA guidelines, which one of the following is the generally recommended hemoglobin A1c goal for most healthy adults with type 2 diabetes?', 1, 'The ADA generally recommends a hemoglobin A1c goal of <7.0% for most nonpregnant adults. More stringent goals (<6.5%) may be appropriate for some patients if they can be achieved without significant hypoglycemia, while less stringent goals (<8.0%) may be appropriate for older patients or those with multiple comorbidities.', '2023 ITE Critique, Item 133', '["<6.5%","<7.0%","<7.5%","<8.0%","<8.5%"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 4-day-old infant is brought in for a weight check. The infant was born at 39 weeks and weighed 3500 g at birth. Today, the infant weighs 3300 g. The infant is breastfeeding well. Which one of the following is the most appropriate management?', 3, 'It is normal for neonates to lose up to 10% of their birth weight in the first few days of life. They should typically return to their birth weight by 10 to 14 days of age. This infant has lost about 6% of birth weight, which is normal. Reassurance is appropriate.', '2023 ITE Critique, Item 134', '["Initiate formula supplementation","Refer to a lactation consultant","Admit for failure to thrive","Reassurance and follow-up in 1 week","Check a serum bilirubin level"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 45-year-old female presents with pain in her left foot. On examination, there is tenderness in the third webspace and a palpable ''click'' when the metatarsal heads are squeezed together. Which one of the following is the most likely diagnosis?', 1, 'The clinical findings of pain in the third webspace and a positive Mulder''s click (squeezing the metatarsals together) are diagnostic of Morton neuroma, a benign neuroma of an intermetatarsal plantar nerve.', '2023 ITE Critique, Item 135', '["Metatarsal stress fracture","Morton neuroma","Plantar fasciitis","Rheumatoid arthritis","Sesamoiditis"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'An 82-year-old male is hospitalized for a hip fracture. He is found to have a positive COVID-19 test but has no respiratory symptoms. According to the CDC, for how many days should this patient be in isolation if he remains asymptomatic?', 0, 'As of current CDC guidelines for the general public, isolation for asymptomatic individuals with a positive COVID-19 test is 5 days from the date of the positive test, followed by wearing a mask for an additional 5 days. Requirements for healthcare settings may vary.', '2023 ITE Critique, Item 136', '["5 days","7 days","10 days","14 days","Until he has a negative test"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 65-year-old male with a history of atrial fibrillation is found to have a CHA2DS2-VASc score of 4. Which one of the following is the most appropriate long-term anticoagulation strategy?', 3, 'For patients with nonvalvular atrial fibrillation and a CHA2DS2-VASc score ≥2 in men (or ≥3 in women), oral anticoagulation is recommended to reduce the risk of stroke. DOACs (e.g., apixaban, rivaroxaban) are generally preferred over warfarin unless the patient has a mechanical heart valve or moderate-to-severe mitral stenosis.', '2023 ITE Critique, Item 137', '["Aspirin only","Aspirin plus clopidogrel","Warfarin","Direct oral anticoagulant (DOAC)","No anticoagulation"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 6-year-old male is brought in with multiple small, flesh-colored, dome-shaped papules with a central umbilication on his trunk. Which one of the following is the most likely cause?', 1, 'Molluscum contagiosum is a common viral skin infection in children caused by a poxvirus. The lesions are typically small, dome-shaped, and umbilicated. They are self-limiting but can last for several months.', '2023 ITE Critique, Item 138', '["Human papillomavirus","Molluscum contagiosum virus","Staphylococcus aureus","Varicella-zoster virus","Sarcoptes scabiei"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 45-year-old female presents with a 2-day history of right upper quadrant pain that radiates to her right shoulder. She also has nausea and a low-grade fever. On examination, she has a positive Murphy sign. Which one of the following is the most appropriate initial diagnostic test?', 1, 'In a patient with symptoms suggestive of acute cholecystitis (RUQ pain, fever, positive Murphy sign), abdominal ultrasound is the preferred initial diagnostic study. A HIDA scan is used if the ultrasound is inconclusive.', '2023 ITE Critique, Item 139', '["Abdominal CT","Abdominal ultrasound","HIDA scan","MRCP","Upper endoscopy"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 35-year-old female presents for evaluation of ''panic attacks.'' She reports sudden episodes of racing heart, sweating, and a feeling of impending doom. These episodes occur ''out of the blue.'' Which one of the following is the most appropriate long-term pharmacologic treatment?', 2, 'SSRIs (like fluoxetine) or SNRIs are the first-line long-term pharmacologic treatment for panic disorder. Benzodiazepines like alprazolam may be used for acute symptoms but are not recommended as first-line for long-term management due to the risk of dependence.', '2023 ITE Critique, Item 140', '["Alprazolam as needed","Buspirone","Fluoxetine","Propranolol","Quetiapine"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 55-year-old male with asthma reports that he has to use his albuterol inhaler several times a week, but not every day. He has about three nighttime awakenings per month. Which one of the following is the most appropriate classification of his asthma severity?', 1, 'Mild persistent asthma is characterized by symptoms occurring >2 days per week (but not daily) and 3–4 nighttime awakenings per month. Intermittent asthma involves symptoms ≤2 days per week and ≤2 nighttime awakenings per month.', '2023 ITE Critique, Item 141', '["Intermittent","Mild persistent","Moderate persistent","Severe persistent"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 24-year-old female is found to have a hemoglobin of 10.5 g/dL and an MCV of 72 fL. Her serum ferritin is 10 ng/mL. Which one of the following is the most likely diagnosis?', 1, 'A microcytic anemia with a low serum ferritin is diagnostic of iron deficiency anemia. In a young woman, menstrual blood loss is the most common cause.', '2023 ITE Critique, Item 142', '["Anemia of chronic disease","Iron deficiency anemia","Sideroblastic anemia","Thalassemia trait","Vitamin B12 deficiency"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 72-year-old male is found to have a 4.5-cm abdominal aortic aneurysm on screening ultrasound. According to the current guidelines, which one of the following is the most appropriate follow-up strategy?', 1, 'For an abdominal aortic aneurysm (AAA) between 4.0 and 4.9 cm, follow-up with ultrasound every 6 to 12 months is recommended. For smaller AAAs (3.0–3.9 cm), follow-up every 3 years is sufficient. Referral for repair is usually recommended when the AAA reaches 5.5 cm in men.', '2023 ITE Critique, Item 143', '["Repeat ultrasound in 6 months","Repeat ultrasound in 12 months","CT angiography now","Surgical repair now","No further follow-up needed"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 40-year-old female presents with a 2-day history of a painful, red rash on her leg. On examination, the area is well-demarcated, bright red, and warm. She has a fever of 38.2°C (100.8°F). Which one of the following is the most likely diagnosis?', 1, 'Erysipelas is a superficial form of cellulitis, characteristically well-demarcated and bright red, often involving the face or lower extremities. It is most commonly caused by S. pyogenes. Cellulitis is typically deeper and less well-demarcated.', '2023 ITE Critique, Item 144', '["Cellulitis","Erysipelas","Necrotizing fasciitis","Stasis dermatitis","Urticaria"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 55-year-old female is found to have a serum calcium of 11.2 mg/dL. Her albumin is 4.0 g/dL. Which one of the following is the most appropriate next step in the evaluation of her hypercalcemia?', 2, 'The first step in evaluating hypercalcemia is to determine if it is PTH-mediated by measuring the serum PTH level. If PTH is elevated or inappropriately normal, primary hyperparathyroidism is likely. If PTH is suppressed, other causes such as malignancy or vitamin D intoxication should be explored.', '2023 ITE Critique, Item 145', '["Fine-needle aspiration of the thyroid","Measure serum 25-hydroxyvitamin D","Measure serum parathyroid hormone (PTH)","Order a bone scan","Repeat serum calcium in 6 months"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 28-year-old female presents with a 1-day history of high fever, chills, and right-sided flank pain. She also has dysuria. On examination, she has significant costovertebral angle tenderness on the right. Which one of the following is the most likely diagnosis?', 3, 'The triad of fever, flank pain, and symptoms of lower urinary tract infection (dysuria, frequency) is classic for acute pyelonephritis.', '2023 ITE Critique, Item 146', '["Cystitis","Nephrolithiasis","Pelvic inflammatory disease","Pyelonephritis","Renal abscess"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 45-year-old female presents for discussion of contraception. She smokes 1 pack of cigarettes per day. Which one of the following contraceptive methods is contraindicated in this patient?', 1, 'Combined oral contraceptives (containing estrogen) are contraindicated in women >35 years old who smoke >15 cigarettes per day due to a significantly increased risk of myocardial infarction and stroke. Progestin-only methods and IUDs are safe options.', '2023 ITE Critique, Item 147', '["Copper IUD","Combined oral contraceptive pills","Depot medroxyprogesterone acetate","Levonorgestrel IUD","Progestin-only pills"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 4-year-old female is brought in for a well child check. According to the current CDC guidelines, which one of the following vaccines should she receive at this visit?', 0, 'The standard 4-to-6-year-old vaccines include the fifth dose of DTaP, the fourth dose of IPV, the second dose of MMR, and the second dose of Varicella.', '2023 ITE Critique, Item 148', '["DTaP, IPV, MMR, and Varicella","Hib, PCV13, and Rotavirus","HPV and Meningococcal","Tdap and Meningococcal","No vaccines are needed at this age"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old male presents with a 1-day history of sudden, severe pain in his right knee. On examination, the knee is swollen, red, and warm. Synovial fluid analysis shows positively birefringent, rhomboid-shaped crystals. Which one of the following is the most likely diagnosis?', 1, 'Pseudogout is caused by the deposition of calcium pyrophosphate crystals, which are characteristically rhomboid-shaped and positively birefringent. Gout is caused by monosodium urate crystals, which are needle-shaped and negatively birefringent.', '2023 ITE Critique, Item 149', '["Gout","Pseudogout (Calcium pyrophosphate deposition)","Rheumatoid arthritis","Septic arthritis","Osteoarthritis"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old male is found to have a 2-cm polyp in the sigmoid colon on screening colonoscopy. Pathology shows it is a tubular adenoma. According to the current guidelines, when should he have his next colonoscopy?', 1, 'For a patient with 1 or 2 small (<10 mm) tubular adenomas, the recommended follow-up interval is 7 to 10 years. For a larger adenoma (≥10 mm), 3 or more adenomas, or an adenoma with high-grade dysplasia or villous features, a 3-year interval is recommended.', '2023 ITE Critique, Item 150', '["1 year","3 years","5 years","7 years","10 years"]'::jsonb
        );
INSERT INTO public.questions (year, category, system, abfm_category, question_text, correct_index, explanation, resource_link, options) VALUES (
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male with a history of hypertension and a BMI of 31 kg/m² presents for a follow-up visit. He is currently taking lisinopril, 20 mg daily. His home blood pressure readings have averaged 145/92 mm Hg. In addition to recommending weight loss and a low-sodium diet, which one of the following would be the most appropriate next step in his pharmacologic management?', 0, 'According to current hypertension guidelines (ACC/AHA), for patients with Stage 2 hypertension whose blood pressure is not controlled on a single agent, the addition of a second first-line agent is recommended. First-line agents include ACE inhibitors, ARBs, calcium channel blockers (CCBs), and thiazide-type diuretics. Amlodipine is a CCB and is an appropriate choice. Increasing the dose of the initial agent is often less effective than adding a second agent from a different class.', '2023 ITE Critique, Item 151', '["Add amlodipine (Norvasc)","Add atenolol (Tenormin)","Add clonidine (Catapres)","Add doxazosin (Cardura)","Increase lisinopril to 40 mg daily"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 4-year-old female is brought to your office with a 3-day history of low-grade fever, malaise, and a rash. On examination, she has an erythematous, ''slapped-cheek'' rash on her face and a lace-like, erythematous maculopapular rash on her trunk and extremities. Which one of the following is the most likely causative agent?', 3, 'The clinical presentation is classic for erythema infectiosum (fifth disease), which is caused by parvovirus B19. It typically presents with a ''slapped-cheek'' appearance followed by a reticulated or lace-like rash on the body.', '2023 ITE Critique, Item 152', '["Coxsackievirus A16","Human herpesvirus 6","Measles virus","Parvovirus B19","Rubella virus"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 35-year-old female presents with a 2-month history of pain and stiffness in her hands, particularly in the mornings. On examination, there is symmetrical swelling and tenderness of the MCP and PIP joints. Laboratory testing reveals a positive rheumatoid factor and an elevated cyclic citrullinated peptide (CCP) antibody level. Which one of the following is the most appropriate initial disease-modifying antirheumatic drug (DMARD) for this patient?', 3, 'Methotrexate is the first-line DMARD for most patients with rheumatoid arthritis unless there are contraindications such as pregnancy or significant liver disease. It has the best evidence for long-term efficacy and safety.', '2023 ITE Critique, Item 153', '["Adalimumab (Humira)","Hydroxychloroquine (Plaquenil)","Leflunomide (Arava)","Methotrexate","Sulfasalazine (Azulfidine)"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 48-year-old female presents with a 3-month history of abdominal bloating and diarrhea that occurs after eating. She notes that her symptoms are improved when she avoids wheat products. Her IgA tissue transglutaminase (tTG) level is significantly elevated. Which one of the following is required to confirm the diagnosis of celiac disease?', 2, 'While an elevated IgA tTG is highly suggestive of celiac disease, a small bowel biopsy showing villous atrophy and crypt hyperplasia remains the gold standard for confirmation in adults.', '2023 ITE Critique, Item 154', '["A gluten-free diet for 6 months","HLA-DQ2/DQ8 testing","Small bowel biopsy","Stool for ova and parasites","Upper GI series with small bowel follow-through"]'::jsonb
        ),(
            '2023', 'Neurologic', 'Neurologic', '', 'An 82-year-old male with a history of hypertension and diabetes is brought in for a follow-up of ''memory problems.'' His wife reports that his symptoms fluctuate significantly; some days he is relatively clear, and other days he is very confused. He has also had a few vivid visual hallucinations. On examination, he has a slow gait and mild rigidity. Which one of the following is the most likely diagnosis?', 1, 'Dementia with Lewy bodies is characterized by fluctuating cognition, vivid visual hallucinations, and spontaneous features of parkinsonism (rigidity, bradykinesia).', '2023 ITE Critique, Item 155', '["Alzheimer''s disease","Dementia with Lewy bodies","Frontotemporal dementia","Normal pressure hydrocephalus","Vascular dementia"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 30-year-old male presents with a persistent, scaly, itchy rash on his elbows and knees. On examination, the plaques are well-demarcated with silver scales. When you scrape a scale, pinpoint bleeding occurs. This finding is known as which one of the following?', 0, 'Auspitz sign is the appearance of pinpoint bleeding after the removal of a psoriasis scale. It occurs because the epidermis is thin over the dermal papillae and the vessels are dilated.', '2023 ITE Critique, Item 156', '["Auspitz sign","Darier sign","Koebner phenomenon","Nikolsky sign","Wickham striae"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 68-year-old male with a history of heart failure with reduced ejection fraction (HFrEF) and a baseline ejection fraction of 30% presents for a routine visit. He is taking lisinopril, carvedilol, and furosemide. He is stable but has persistent NYHA class II symptoms. Which one of the following would be the most appropriate addition to his regimen to reduce mortality?', 4, 'Mineralocorticoid receptor antagonists (MRAs) such as spironolactone or eplerenone are recommended for patients with HFrEF and NYHA class II–IV symptoms to reduce morbidity and mortality, provided the potassium and renal function are within acceptable limits.', '2023 ITE Critique, Item 157', '["Amlodipine","Digoxin","Hydralazine","Isosorbide mononitrate","Spironolactone"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 24-year-old female presents with a 2-day history of vaginal discharge and itching. On examination, the discharge is thin, white, and has a ''fishy'' odor. The pH of the discharge is 5.0. Microscopy reveals ''clue cells.'' Which one of the following is the most appropriate treatment?', 2, 'The clinical findings of thin white discharge, fishy odor, pH >4.5, and clue cells are diagnostic of bacterial vaginosis. The first-line treatment is oral or topical metronidazole or topical clindamycin.', '2023 ITE Critique, Item 158', '["Oral azithromycin","Oral fluconazole","Oral metronidazole","Topical clotrimazole","Intramuscular ceftriaxone"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old male with type 2 diabetes has a hemoglobin A1c of 7.8% on metformin and glipizide. He is also taking lisinopril for hypertension. His urine albumin/creatinine ratio is 150 mg/g (N <30). Which one of the following additions would be most beneficial for both glucose control and slowing the progression of kidney disease?', 0, 'SGLT2 inhibitors, such as dapagliflozin or empagliflozin, are recommended for patients with type 2 diabetes and chronic kidney disease with albuminuria, as they have been shown to reduce the risk of progression to end-stage renal disease and cardiovascular events.', '2023 ITE Critique, Item 159', '["Dapagliflozin (Farxiga)","Pioglitazone (Actos)","Sitagliptin (Januvia)","Glyburide","NPH insulin"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old female presents with a 3-month history of bilateral hip and shoulder pain and stiffness that is worse in the morning. She reports difficulty getting out of a chair and brushing her hair. Her erythrocyte sedimentation rate (ESR) is 65 mm/hr (N <30). Which one of the following is the most likely diagnosis?', 2, 'Polymyalgia rheumatica typically presents in patients over 50 with symmetrical proximal muscle pain and stiffness (shoulders and hips) and a significantly elevated ESR or CRP. It is highly responsive to low-dose corticosteroids.', '2023 ITE Critique, Item 160', '["Fibromyalgia","Osteoarthritis","Polymyalgia rheumatica","Polymyositis","Rheumatoid arthritis"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 22-year-old male presents with a painless, 2-cm cervical lymph node that has been present for 4 weeks. He also reports drenching night sweats and a 10-lb weight loss over the last month. Which one of the following is the most appropriate next step?', 2, 'A persistent, painless lymph node associated with ''B symptoms'' (night sweats, weight loss, fever) is highly suspicious for lymphoma. An excisional biopsy is preferred over fine-needle aspiration to preserve the architecture of the node for accurate diagnosis.', '2023 ITE Critique, Item 161', '["A 10-day course of antibiotics","Fine-needle aspiration of the node","Excisional biopsy of the node","Repeat examination in 1 month","Chest radiograph only"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 45-year-old female presents with a 6-month history of low mood, low energy, and loss of interest in her usual activities. She also reports feeling guilty and having trouble sleeping. She has not had any episodes of abnormally elevated mood. Which one of the following is the most appropriate first-line pharmacotherapy?', 3, 'For major depressive disorder, SSRIs (like sertraline) are generally considered first-line due to their efficacy and favorable side effect profile compared to older classes like TCAs (amitriptyline).', '2023 ITE Critique, Item 162', '["Amitriptyline","Lithium","Quetiapine","Sertraline","Valproic acid"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 1-month-old infant is brought to the office for a well child check. The mother reports that the infant breathes fast and sweats during feedings. On examination, a grade 3/6 holosystolic murmur is heard at the left lower sternal border. The infant''s liver is palpable 3 cm below the costal margin. Which one of the following is the most likely diagnosis?', 4, 'A large ventricular septal defect (VSD) often presents in infancy with symptoms of heart failure (fast breathing, sweating with feeds, poor growth) as pulmonary vascular resistance drops. The murmur is typically holosystolic at the left lower sternal border.', '2023 ITE Critique, Item 163', '["Atrial septal defect","Coarctation of the aorta","Patent ductus arteriosus","Tetralogy of Fallot","Ventricular septal defect"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 35-year-old male presents with a 5-day history of fever, nonproductive cough, and malaise. He is otherwise healthy. On examination, he is afebrile and has no respiratory distress. Lung auscultation reveals crackles at the right base. A chest radiograph shows a right lower lobe infiltrate. Which one of the following is the most appropriate treatment?', 0, 'For healthy outpatients with community-acquired pneumonia and no risk factors for MRSA or Pseudomonas, the ATS/IDSA guidelines recommend monotherapy with amoxicillin, doxycycline, or a macrolide (only if local pneumococcal resistance is <25%). Amoxicillin is often preferred due to its high efficacy against S. pneumoniae.', '2023 ITE Critique, Item 164', '["Amoxicillin","Azithromycin","Ceftriaxone","Levofloxacin","Oseltamivir"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 22-year-old male presents with a 2-day history of dysuria and urethral discharge. He reports having a new sexual partner recently. On examination, he has a purulent urethral discharge. Which one of the following is the most appropriate treatment?', 4, 'Current CDC guidelines for the treatment of gonorrhea recommend ceftriaxone 500 mg IM once. If chlamydia has not been excluded, doxycycline 100 mg twice daily for 7 days should also be given. In practice, combination therapy is frequently administered empirically for urethritis.', '2023 ITE Critique, Item 165', '["Azithromycin 1 g orally once","Ceftriaxone 500 mg IM once","Ciprofloxacin 500 mg orally once","Doxycycline 100 mg twice daily for 7 days","Ceftriaxone 500 mg IM once plus doxycycline 100 mg twice daily for 7 days"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 55-year-old male presents for a routine visit. He has a history of hypertension but no known cardiovascular disease. His blood pressure is 135/85 mm Hg. His calculated 10-year ASCVD risk is 8.5%. According to the 2018 AHA/ACC multisociety guideline on the management of blood cholesterol, which one of the following is the most appropriate recommendation regarding statin therapy?', 1, 'For adults aged 40–75 without diabetes or clinical ASCVD and a 10-year risk of 7.5% to 19.9% (intermediate risk), a clinician-patient risk discussion is recommended to consider moderate-intensity statin therapy.', '2023 ITE Critique, Item 166', '["Initiate low-intensity statin therapy","Initiate moderate-intensity statin therapy","Initiate high-intensity statin therapy","Statin therapy is not recommended at this time","Repeat risk assessment in 1 year"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 28-year-old female who is 12 weeks pregnant presents with a 3-day history of vaginal itching and a thick, white, ''cottage cheese'' discharge. Which one of the following is the most appropriate treatment?', 2, 'For vulvovaginal candidiasis in pregnancy, topical azoles (such as miconazole or clotrimazole) for 7 days are the recommended treatment. Oral fluconazole should be avoided, particularly in the first trimester, due to a possible increased risk of miscarriage and birth defects.', '2023 ITE Critique, Item 167', '["Oral fluconazole (Diflucan) single dose","Oral metronidazole","Topical miconazole for 7 days","Topical metronidazole","Observation only"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 58-year-old female is found to have a TSH of 7.5 μU/mL and a normal free T4 level. She is asymptomatic and has no history of thyroid disease. Which one of the following is the most appropriate management?', 2, 'This patient has subclinical hypothyroidism (elevated TSH with normal free T4). In an asymptomatic patient with a TSH <10 μU/mL, the recommended approach is to repeat the TSH in 3 to 6 months to see if it remains elevated before considering treatment.', '2023 ITE Critique, Item 168', '["Initiate levothyroxine full replacement dose","Initiate levothyroxine 25 μg daily","Repeat the TSH in 3 to 6 months","Order a thyroid ultrasound","Check thyroid peroxidase antibodies only"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 45-year-old male presents with a persistent, scaly rash on his scalp and in his eyebrows. The skin underneath is erythematous and slightly greasy. Which one of the following is the most likely diagnosis?', 3, 'Seborrheic dermatitis typically presents with erythematous plaques and greasy yellow scales in areas with a high density of sebaceous glands, such as the scalp, eyebrows, and nasolabial folds. It is associated with the Malassezia yeast.', '2023 ITE Critique, Item 169', '["Atopic dermatitis","Contact dermatitis","Psoriasis","Seborrheic dermatitis","Tinea capitis"]'::jsonb
        ),(
            '2023', 'Special Sensory', 'Special Sensory', '', 'A 45-year-old female presents with frequent episodes of intense vertigo that last for about 30 seconds and occur when she rolls over in bed. She has no hearing loss or tinnitus. Which one of the following is the most likely diagnosis?', 0, 'BPPV is characterized by short episodes of vertigo triggered by changes in head position. It is caused by calcium carbonate crystals (otoconia) being displaced into the semicircular canals. The Dix-Hallpike maneuver is used for diagnosis, and the Epley maneuver is used for treatment.', '2023 ITE Critique, Item 170', '["Benign paroxysmal positional vertigo (BPPV)","Meniere''s disease","Vestibular neuritis","Vestibular migraine","Acoustic neuroma"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 65-year-old male with a history of GERD presents with progressive difficulty swallowing solids over the past 3 months. He also reports an unintentional 15-lb weight loss. Which one of the following is the most appropriate next step?', 3, 'Progressive dysphagia and weight loss are ''alarm symptoms'' for esophageal cancer. Upper endoscopy is the preferred initial test to visualize the esophagus and obtain biopsies if a lesion is found.', '2023 ITE Critique, Item 171', '["Increase his PPI dose","Barium swallow","Esophageal manometry","Upper endoscopy","24-hour pH monitoring"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 4-year-old male is brought in because his parents noticed he ''stops breathing'' for short periods while sleeping. He is also a noisy snorer. On examination, he has significant tonsillar hypertrophy. Which one of the following is the gold standard for diagnosing obstructive sleep apnea in this child?', 1, 'In-lab polysomnography is the gold standard for diagnosing obstructive sleep apnea in children. Unlike adults, home sleep studies are not currently recommended for the initial diagnosis in children.', '2023 ITE Critique, Item 172', '["Home sleep study","In-lab polysomnography","Lateral neck radiograph","Overnight pulse oximetry","Questionnaire-based screening"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 22-year-old male presents with acute low back pain after a sports injury. He has no radiating pain, no weakness, and no bowel or bladder symptoms. On examination, his neurological exam is normal. Which one of the following is indicated at this visit?', 3, 'For acute, non-specific low back pain without red flags (neurological deficit, fever, weight loss), imaging is not indicated. Management should focus on conservative measures like staying active and using NSAIDs.', '2023 ITE Critique, Item 173', '["Lumbar spine radiograph","Lumbar spine MRI","Bed rest","NSAIDs and staying active","Immediate physical therapy"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 24-year-old female presents with a 2-day history of a painful rash on her right side. On examination, she has a cluster of vesicles on an erythematous base in a dermatomal distribution on her right flank. She has no other medical problems. Which one of the following is the most appropriate treatment?', 0, 'The clinical presentation is classic for herpes zoster (shingles). Oral antiviral therapy (acyclovir, valacyclovir, or famciclovir) started within 72 hours of rash onset reduces the duration of the rash and the severity of associated pain.', '2023 ITE Critique, Item 174', '["Oral acyclovir","Oral cephalexin","Topical mupirocin","Topical corticosteroids","Observation only"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'An 80-year-old female is found to have a hemoglobin of 10.2 g/dL and an MCV of 82 fL. Her serum ferritin is 250 ng/mL and her serum iron is low. Which one of the following is the most likely diagnosis?', 0, 'Anemia of chronic disease (also called anemia of inflammation) typically presents as a normocytic anemia with low serum iron and normal or elevated ferritin stores. Iron deficiency would have a low ferritin.', '2023 ITE Critique, Item 175', '["Anemia of chronic disease","Iron deficiency anemia","Folate deficiency","Sideroblastic anemia","Vitamin B12 deficiency"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 72-year-old male with a history of hypertension presents for a wellness exam. He has a 40-pack-year smoking history but quit 5 years ago. According to the USPSTF, he should be screened for which one of the following with a one-time ultrasound?', 0, 'The USPSTF recommends a one-time screening for abdominal aortic aneurysm (AAA) with ultrasonography in men aged 65 to 75 who have ever smoked.', '2023 ITE Critique, Item 176', '["Abdominal aortic aneurysm","Carotid artery stenosis","Deep vein thrombosis","Peripheral artery disease","Renal artery stenosis"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 19-year-old male presents with a target-like rash on his hands and forearms. He also reports a recent outbreak of ''cold sores.'' Which one of the following is the most likely diagnosis?', 0, 'Erythema multiforme is an acute immune-mediated condition characterized by target-like skin lesions. It is most commonly triggered by herpes simplex virus infections.', '2023 ITE Critique, Item 177', '["Erythema multiforme","Erythema nodosum","Lyme disease","Stevens-Johnson syndrome","Urticaria"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 55-year-old male with a history of COPD presents with worsening shortness of breath. His oxygen saturation is 88% on room air at rest. According to the Medicare guidelines, for how many hours a day should he use his supplemental oxygen to derive the most benefit?', 4, 'In patients with chronic hypoxemia, long-term oxygen therapy has been shown to improve survival when used for at least 15 hours per day.', '2023 ITE Critique, Item 178', '["As needed for shortness of breath","Only while sleeping","At least 4 hours per day","At least 8 hours per day","At least 15 hours per day"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 45-year-old male presents with a 2-day history of steady, severe epigastric pain that radiates to his back. He also reports nausea and vomiting. On examination, he has epigastric tenderness. His serum lipase is three times the upper limit of normal. Which one of the following is the most common cause of this condition in the United States?', 1, 'Acute pancreatitis is most commonly caused by gallstones and alcohol use in the United States, with gallstones being the most frequent cause overall.', '2023 ITE Critique, Item 179', '["Alcohol use","Gallstones","Hypercalcemia","Hypertriglyceridemia","Medications"]'::jsonb
        ),(
            '2023', 'Psychiatric/Behavioral', 'Psychiatric/Behavioral', '', 'A 25-year-old female presents with a 2-month history of ''voices'' that she hears when she is alone. She also believes that the television is sending her secret messages. Her symptoms have caused her to stop going to work. Which one of the following is the most likely diagnosis?', 4, 'Schizophreniform disorder is the diagnosis when symptoms of schizophrenia (hallucinations, delusions) have been present for at least 1 month but less than 6 months. If they persist beyond 6 months, the diagnosis becomes schizophrenia.', '2023 ITE Critique, Item 180', '["Bipolar disorder","Major depressive disorder with psychotic features","Schizoaffective disorder","Schizophrenia","Schizophreniform disorder"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old female is found to have a T-score of -2.8 on a DXA scan. She has no history of fractures. Which one of the following is the most appropriate management according to current guidelines?', 0, 'Osteoporosis is defined by a T-score of -2.5 or lower. Treatment with a bisphosphonate (like alendronate) is recommended for postmenopausal women with osteoporosis to reduce the risk of fractures.', '2023 ITE Critique, Item 181', '["Initiate alendronate","Initiate hormone replacement therapy","Calcium and vitamin D only","Repeat DXA in 1 year","No treatment needed unless she has a fracture"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male with a history of hypertension and a 30-pack-year smoking history presents with a 30-minute history of crushing chest pain. His EKG shows ST-segment elevation in leads II, III, and aVF. Which one of the following is the most likely location of his myocardial infarction?', 1, 'ST-segment elevation in leads II, III, and aVF is characteristic of an inferior wall myocardial infarction, which typically involves the right coronary artery.', '2023 ITE Critique, Item 182', '["Anterior","Inferior","Lateral","Posterior","Right ventricular"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 45-year-old male presents with sudden, severe pain and swelling in his right big toe that began overnight. He also has a fever of 38.0°C (100.4°F). On examination, the joint is red, warm, and extremely tender. Which one of the following is the most appropriate initial diagnostic test?', 0, 'While the clinical presentation is highly suggestive of gout, joint aspiration is necessary to confirm the diagnosis and to rule out septic arthritis, which can present similarly.', '2023 ITE Critique, Item 183', '["Joint fluid aspiration and crystal analysis","Radiograph of the foot","Serum uric acid level","MRI of the foot","Blood culture"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 24-year-old male is brought in after being bitten by a tick while hiking in a Lyme-endemic area. The tick was attached for about 48 hours and is partially engorged. He has no rash or symptoms. Which one of the following is the most appropriate management?', 0, 'A single dose of 200 mg of doxycycline is recommended for the prevention of Lyme disease if the tick was an Ixodes scapularis tick, was attached for at least 36 hours, and the prophylaxis can be started within 72 hours of tick removal in an endemic area.', '2023 ITE Critique, Item 184', '["A single dose of 200 mg of doxycycline","Doxycycline 100 mg twice daily for 10 days","Lyme titers now","Repeat Lyme titers in 4 weeks","Observation only"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 32-year-old female presents for evaluation of ''heavy periods'' that interfere with her daily life. She has no other symptoms. A pelvic ultrasound shows a 2-cm intramural fibroid. She does not desire pregnancy in the near future. Which one of the following is the most effective nonsurgical treatment for her heavy menstrual bleeding?', 0, 'The levonorgestrel IUD is highly effective at reducing menstrual blood loss and is often considered first-line for women with heavy menstrual bleeding who do not desire immediate pregnancy.', '2023 ITE Critique, Item 185', '["Levonorgestrel intrauterine device (IUD)","Oral contraceptive pills","Oral medroxyprogesterone acetate","Tranexamic acid","NSAIDs"]'::jsonb
        ),(
            '2023', 'Special Sensory', 'Special Sensory', '', 'A 65-year-old male presents with a 2-day history of shingles on his face. He also reports that his right eye is red and painful and he is having trouble seeing. On examination, he has vesicles on the tip of his nose. This finding is known as which one of the following?', 2, 'Hutchinson sign is the presence of zoster vesicles on the tip, side, or root of the nose, indicating involvement of the nasociliary branch of the trigeminal nerve. This is a strong predictor of ocular involvement (herpes zoster ophthalmicus) and warrants urgent ophthalmology referral.', '2023 ITE Critique, Item 186', '["Auspitz sign","Darier sign","Hutchinson sign","Koebner phenomenon","Nikolsky sign"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 52-year-old male with a history of alcohol use disorder presents with a 2-month history of abdominal swelling. On examination, he has shifting dullness and a fluid wave. A paracentesis is performed, and the serum-ascites albumin gradient (SAAG) is 1.5 g/dL. Which one of the following is the most likely cause of his ascites?', 0, 'A SAAG ≥1.1 g/dL indicates portal hypertension as the cause of the ascites, which is most commonly due to cirrhosis. A SAAG <1.1 g/dL points to non-portal hypertensive causes like malignancy or infection.', '2023 ITE Critique, Item 187', '["Cirrhosis","Malignancy","Nephrotic syndrome","Pancreatitis","Tuberculosis"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 1-week-old infant is brought in for a weight check. The infant was born at 39 weeks and weighed 3500 g at birth. Today, the infant weighs 3300 g. The infant is breastfeeding well. Which one of the following is the most appropriate management?', 3, 'It is normal for neonates to lose up to 10% of their birth weight in the first few days of life. They should typically return to their birth weight by 10 to 14 days of age. This infant has lost about 6% of birth weight, which is normal. Reassurance is appropriate.', '2023 ITE Critique, Item 188', '["Initiate formula supplementation","Refer to a lactation consultant","Admit for failure to thrive","Reassurance and follow-up in 1 week","Check a serum bilirubin level"]'::jsonb
        ),(
            '2023', 'Skin/Subcutaneous', 'Skin/Subcutaneous', '', 'A 45-year-old female presents with a persistent, scaly plaque on her elbow. On examination, the plaque is well-demarcated, erythematous, and covered with silver scales. Which one of the following is the most appropriate first-line treatment?', 0, 'Plaque psoriasis is typically treated first-line with high-potency topical corticosteroids (e.g., clobetasol). Low-potency steroids are generally ineffective for thick plaques but can be used on the face or intertriginous areas.', '2023 ITE Critique, Item 189', '["Topical clobetasol (high-potency corticosteroid)","Topical hydrocortisone 1% (low-potency corticosteroid)","Topical ketoconazole","Oral methotrexate","Oral prednisone"]'::jsonb
        ),(
            '2023', 'Pulmonary', 'Pulmonary', '', 'A 62-year-old male with a history of COPD presents for follow-up. He uses a LAMA daily. He reports he has been hospitalized once for a COPD exacerbation in the past 12 months. Which one of the following would be the most appropriate next step in his therapy?', 0, 'According to the GOLD guidelines, for patients who continue to have exacerbations on monotherapy (LAMA or LABA), the next step is typically dual therapy with LAMA/LABA.', '2023 ITE Critique, Item 190', '["Add a LABA","Add an ICS","Add a SABA as needed","Add oral prednisone daily","Add theophylline"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male with a blood pressure of 142/92 mm Hg. He has no other medical conditions and his 10-year ASCVD risk is 4.5%. According to the 2017 ACC/AHA guidelines, which one of the following is the most appropriate initial management?', 2, 'For patients with Stage 2 hypertension (≥140/90) and low ASCVD risk, lifestyle modification is the initial recommendation, though clinicians may consider starting medication early depending on patient factors.', '2023 ITE Critique, Item 191', '["Initiate lisinopril","Initiate amlodipine","Lifestyle modifications only","Recheck blood pressure in 1 year","Recheck blood pressure in 3 years"]'::jsonb
        ),(
            '2023', 'Hematologic/Immune', 'Hematologic/Immune', '', 'A 24-year-old female is found to have a hemoglobin of 10.5 g/dL and an MCV of 72 fL. Her serum ferritin is 10 ng/mL. Which one of the following is the most likely diagnosis?', 1, 'A microcytic anemia with a low serum ferritin is diagnostic of iron deficiency anemia.', '2023 ITE Critique, Item 192', '["Anemia of chronic disease","Iron deficiency anemia","Sideroblastic anemia","Thalassemia trait","Vitamin B12 deficiency"]'::jsonb
        ),(
            '2023', 'Nephrologic', 'Nephrologic', '', 'A 65-year-old male presents with bothersome nocturia and a weak urinary stream. A digital rectal exam reveals a smooth, symmetrically enlarged prostate. A PSA is 2.5 ng/mL. He has failed a trial of tamsulosin. Which one of the following medications works by inhibiting the conversion of testosterone to dihydrotestosterone?', 1, '5-alpha-reductase inhibitors like finasteride inhibit the conversion of testosterone to dihydrotestosterone, reducing prostate size.', '2023 ITE Critique, Item 193', '["Doxazosin (Cardura)","Finasteride (Proscar)","Mirabegron (Myrbetriq)","Sildenafil (Viagra)","Tadalafil (Cialis)"]'::jsonb
        ),(
            '2023', 'Endocrine', 'Endocrine', '', 'A 45-year-old female presents with a 10-lb weight gain and feeling cold all the time. Her TSH is 15 μU/mL (N 0.4–4.5) and her free T4 is 0.6 ng/dL (N 0.8–1.8). Which one of the following is the most appropriate initial dose of levothyroxine for this otherwise healthy patient?', 3, 'For healthy adults with overt hypothyroidism, the full replacement dose of levothyroxine is approximately 1.6 μg/kg/day.', '2023 ITE Critique, Item 194', '["25 μg daily","50 μg daily","75 μg daily","1.6 μg/kg daily","2.5 μg/kg daily"]'::jsonb
        ),(
            '2023', 'Infectious Disease', 'Infectious Disease', '', 'A 28-year-old female presents with a 3-day history of dysuria and frequency. She has no fever, flank pain, or vaginal discharge. She has no chronic medical conditions. Which one of the following is the most appropriate management according to current guidelines?', 0, 'Empiric treatment with nitrofurantoin for 5 days is a first-line option for uncomplicated cystitis in healthy women.', '2023 ITE Critique, Item 195', '["Empiric treatment with nitrofurantoin","Empiric treatment with ciprofloxacin","Urine culture and treat based on results","Urinalysis only; no treatment if negative","Wait for 2 days for symptoms to resolve"]'::jsonb
        ),(
            '2023', 'Musculoskeletal', 'Musculoskeletal', '', 'A 65-year-old female presents with a 6-month history of bilateral knee pain that is worse at the end of the day. On examination, she has bony enlargement of the PIP and DIP joints of her hands. Which one of the following is the most likely diagnosis?', 1, 'Bilateral knee pain worse at the end of the day and DIP/PIP involvement (Heberden/Bouchard nodes) is characteristic of osteoarthritis.', '2023 ITE Critique, Item 196', '["Gout","Osteoarthritis","Psoriatic arthritis","Rheumatoid arthritis","Septic arthritis"]'::jsonb
        ),(
            '2023', 'Cardiovascular', 'Cardiovascular', '', 'A 52-year-old male with a history of heavy tobacco use presents for evaluation of leg pain. He reports that his calves cramp after walking two blocks and the pain is relieved by rest. Which one of the following is the most appropriate initial diagnostic test?', 0, 'The ABI is the initial diagnostic test for peripheral artery disease.', '2023 ITE Critique, Item 197', '["Ankle-brachial index (ABI)","CT angiography","D-dimer","Duplex ultrasonography","Venography"]'::jsonb
        ),(
            '2023', 'Reproductive/Female', 'Reproductive/Female', '', 'A 45-year-old female presents for discussion of contraception. She smokes 1 pack of cigarettes per day. Which one of the following contraceptive methods is contraindicated in this patient?', 1, 'Combined oral contraceptives are contraindicated in women >35 who smoke >15 cigarettes per day.', '2023 ITE Critique, Item 198', '["Copper IUD","Combined oral contraceptive pills","Depot medroxyprogesterone acetate","Levonorgestrel IUD","Progestin-only pills"]'::jsonb
        ),(
            '2023', 'Population Health/Epidemiology', 'Population Health/Epidemiology', '', 'A 4-year-old female is brought in for a well child check. According to the current CDC guidelines, which one of the following vaccines should she receive at this visit?', 0, 'The 4–6 year boosters include DTaP, IPV, MMR, and Varicella.', '2023 ITE Critique, Item 199', '["DTaP, IPV, MMR, and Varicella","Hib, PCV13, and Rotavirus","HPV and Meningococcal","Tdap and Meningococcal","No vaccines are needed at this age"]'::jsonb
        ),(
            '2023', 'Gastrointestinal', 'Gastrointestinal', '', 'A 55-year-old male is found to have a 2-cm polyp in the sigmoid colon on screening colonoscopy. Pathology shows it is a tubular adenoma. According to the current guidelines, when should he have his next colonoscopy?', 1, 'A tubular adenoma ≥10 mm (1 cm) is considered a high-risk finding requiring a 3-year follow-up interval.', '2023 ITE Critique, Item 200', '["1 year","3 years","5 years","7 years","10 years"]'::jsonb
        );
